window.PACTO.acts["reg-2012-966"]={"label": "REGOLAMENTO (UE, EURATOM) N. 966/2012 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 966/2012", "file": "ext-reg-2012-966.html", "external": true, "version": "consolidato 2017-01-01", "eurlex": "https://eur-lex.europa.eu/eli/reg/2012/966/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">1.  Il presente regolamento specifica le norme relative alla formazione e all'esecuzione del bilancio generale dell'Unione europea e alla presentazione e alla revisione dei conti.</p>"], [null, "<p class=\"norm\">2.  Il presente regolamento si applica all'esecuzione del bilancio dell'agenzia di approvvigionamento dell'Euratom.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si intende per:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>\"Unione\", l'Unione europea, la Comunità europea dell'energia atomica, o ambedue, a seconda del contesto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>\"istituzione\", il Parlamento europeo, il Consiglio europeo, il Consiglio, la Commissione europea, la Corte di giustizia dell'Unione europea, la Corte dei conti, il Comitato economico e sociale europeo, il Comitato delle regioni, il Mediatore europeo, il Garante europeo della protezione dei dati e il Servizio europeo per l'azione esterna (\"SEAE\"); la Banca centrale europea non è considerata un'istituzione dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>\"bilancio\", lo strumento che prevede e autorizza, per ciascun esercizio, tutte le entrate e le spese ritenute necessarie per l'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>\"atto di base\", un atto giuridico che fornisce una base giuridica per un'azione e per l'esecuzione delle spese corrispondenti iscritte in bilancio.</p>\n</div>"], [null, "<p class=\"list\">Un atto di base può assumere una delle seguenti forme:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>in applicazione del trattato sul funzionamento dell'Unione europea (TFUE) e del trattato che istituisce la Comunità europea per l'energia atomica (il trattato Euratom), la forma di un regolamento, di una direttiva o di una decisione ai sensi dell'articolo 288 TFUE; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>in applicazione del titolo V del trattato sull'Unione europea (TUE), una delle forme specificate all'articolo 26, paragrafo 2, all'articolo 28, paragrafo 1, all'articolo 29, all'articolo 31, paragrafo 2, all'articolo 33 e all'articolo 37 TUE.</p>\n</div>"], [null, "<p class=\"list\">Le raccomandazioni e i pareri non costituiscono atti di base;</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>\"metodo di esecuzione\", il metodo d'esecuzione del bilancio descritto agli articoli 58, 59 o 60;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>\"accordo di delega\", un accordo concluso con entità e persone alle quali sono affidati compiti d'esecuzione del bilancio ai sensi dell'articolo 58, paragrafo 1, lettera c), punti da i) a viii);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>\"beneficiario\", una persona fisica o giuridica con cui è stata firmata una convenzione di finanziamento o a cui è stata notificata una decisione di sovvenzione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">h)<span style=\"word-spacing: 15pt\"> </span>\"contraente\", una persona fisica o giuridica con cui è stata conclusa una procedura d'aggiudicazione di appalti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>\"destinatario\", un beneficiario, un contraente o un'altra persona fisica o giuridica che è destinataria di premi o fondi a titolo di uno strumento finanziario;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">j)<span style=\"word-spacing: 18pt\"> </span>\"premi\" contributo finanziario attribuito a titolo di ricompensa in seguito a un concorso;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">k)<span style=\"word-spacing: 15pt\"> </span>\"prestito\", un accordo ai sensi del quale il mutuante è tenuto a mettere a disposizione del mutuatario una somma convenuta di denaro per un periodo di tempo concordato e in forza del quale il mutuatario è tenuto a ripagare tale importo entro il termine concordato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">l)<span style=\"word-spacing: 19pt\"> </span>\"garanzia\", l'impegno scritto ad assumersi, in parte o nella sua interezza, la responsabilità del debito o dell'obbligazione di un terzo o del risultato positivo da parte di un terzo dei propri obblighi nel caso di un evento che inneschi tale garanzia, come un inadempimento del prestito;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">m)<span style=\"word-spacing: 13pt\"> </span>\"investimento azionario\", il conferimento di capitale a una impresa, investito direttamente o indirettamente in contropartita della totale o parziale proprietà di quella stessa impresa laddove l'investitore azionario può assumere un certo controllo della gestione e condividere gli utili;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">n)<span style=\"word-spacing: 15pt\"> </span>\"investimento quasi azionario\", un tipo di finanziamento che si colloca tra investimento e debito e ha un rischio più elevato del debito privilegiato e un rischio inferiore rispetto al patrimonio di qualità primaria. Gli investimenti quasi azionari possono essere strutturati come debito, di norma non garantito e subordinato e in alcuni casi convertibile in azioni o azioni privilegiate;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">o)<span style=\"word-spacing: 15pt\"> </span>\"strumento di condivisione del rischio\", uno strumento finanziario che consente la condivisione di un determinato rischio tra due o più entità, se del caso in contropartita di una remunerazione convenuta;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">p)<span style=\"word-spacing: 15pt\"> </span>\"strumenti finanziari\", le misure di sostegno finanziario dell'Unione fornite a titolo complementare dal bilancio per conseguire uno o più obiettivi strategici specifici dell'Unione. Tali strumenti possono assumere la forma di investimenti azionari o quasi-azionari, prestiti o garanzie, o altri strumenti di condivisione del rischio, e possono, se del caso, essere associati a sovvenzioni;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">q)<span style=\"word-spacing: 15pt\"> </span>\"statuto dei funzionari\", lo statuto dei funzionari dell'Unione europea e il regime applicabile agli altri agenti dell'Unione europea definiti dal regolamento (CEE, Euratom, CECA) n. 259/68 del Consiglio (\n<span class=\"superscript\">1</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">r)<span style=\"word-spacing: 17pt\"> </span>\"controllo\", qualsiasi misura adottata al fine di garantire con ragionevole sicurezza l'efficacia, l'efficienza e l'economia delle operazioni, nonché l'affidabilità delle relazioni, la salvaguardia degli attivi e l'informazione, la prevenzione, l'individuazione e la rettifica di frodi e irregolarità e il seguito dato a tali frodi e irregolarità e l'adeguata gestione dei rischi connessi alla legittimità e alla regolarità delle operazioni sottostanti, tenendo conto del carattere pluriennale dei programmi, nonché della natura dei pagamenti in questione. I controlli possono comportare varie verifiche, nonché l'attuazione delle politiche e delle procedure per raggiungere gli obiettivi illustrati nella prima frase;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">s)<span style=\"word-spacing: 15pt\"> </span>\"verifica\", la verifica di un aspetto specifico di un'operazione di entrata o di spesa.</p>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Conformità della legislazione secondaria al presente regolamento", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">1.  Le disposizioni relative all'esecuzione del bilancio in entrate e in spese e contenute in un atto di base rispettano i principi di bilancio enunciati nella parte prima, titolo II.</p>"], [null, "<p class=\"norm\">2.  Fatto salvo il paragrafo 1, ogni proposta o modifica di proposta presentata all'autorità legislativa comportante deroghe alle disposizioni diverse da quelle di cui alla parte prima, titolo II o agli atti delegati adottati a norma del presente regolamento, indica con chiarezza tali deroghe e precisa nei considerando e nella relazione di ciascuna proposta i motivi specifici che giustificano tali deroghe.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Periodi di tempo, date e termini", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Salvo altrimenti disposto, il regolamento (CEE, Euratom) n. 1182/71 del Consiglio, del 3 giugno 1971, che stabilisce le norme applicabili ai periodi di tempo, alle date e ai termini (\n<span class=\"superscript\">2</span>\n), si applica ai termini fissati dal presente regolamento.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Protezione dei dati personali", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">Il presente regolamento non pregiudica i requisiti della direttiva 95/46/CE del Parlamento europeo e del Consiglio, del 24 ottobre 1995, relativa alla tutela delle persone fisiche con riguardo al trattamento dei dati personali e alla libera circolazione di tali dati (\n<span class=\"superscript\">3</span>\n), né quelli del regolamento (CE) n. 45/2001.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Rispetto dei principi di bilancio", "anchor": "art_6", "frags": [[null, "<p class=\"norm\">Alle condizioni di cui al presente regolamento, la formazione e l'esecuzione del bilancio rispettano i principi dell'unità, della verità del bilancio, dell'annualità, del pareggio, dell'unità di conto, dell'universalità, della specializzazione, della sana gestione finanziaria, che richiede un controllo interno efficace ed efficiente, e della trasparenza.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "7": {"label": "Articolo 7", "heading": "Ambito di applicazione del bilancio", "anchor": "art_7", "frags": [[null, "<p class=\"norm\">1.  Il bilancio comprende quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le entrate e le spese dell'Unione, comprese le spese amministrative che derivano alle istituzioni dalle disposizioni del TUE nel settore della politica estera e di sicurezza comune, nonché le spese operative connesse con l'attuazione di dette disposizioni quando sono a carico del bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le entrate e le spese della Comunità europea dell'energia atomica.</p>\n</div>"], [null, "<p class=\"norm\">2.  Sono iscritte nel bilancio le garanzie per le operazioni di assunzione ed erogazione di prestiti contratti dall'Unione, inclusi il meccanismo europeo di stabilizzazione finanziaria e le operazioni a titolo del meccanismo di sostegno delle bilance dei pagamenti, conformemente all'articolo 49, paragrafo 1, lettera d).</p>"]]}, "8": {"label": "Articolo 8", "heading": "Norme specifiche sui principi dell'unità e della verità del bilancio", "anchor": "art_8", "frags": [[null, "<p class=\"norm\">1.  Fatto salvo l'articolo 83, nessuna riscossione delle entrate e nessun pagamento delle spese possono essere effettuati a meno che siano imputati a una linea del bilancio.</p>"], [null, "<p class=\"norm\">2.  Nessuna spesa può essere impegnata né oggetto di un ordine di pagamento in eccedenza agli stanziamenti autorizzati.</p>"], [null, "<p class=\"norm\">3.  Uno stanziamento può essere iscritto in bilancio solo se corrisponde a una spesa ritenuta necessaria.</p>"], [null, "<p class=\"norm\">4.  Gli interessi generati da versamenti di prefinanziamenti effettuati a partire dal bilancio non sono dovuti all'Unione salvo diversamente disposto negli accordi di delega, ad eccezione di quelli conclusi con i paesi terzi o gli organismi che hanno designato. Nei casi in cui ciò sia previsto, siffatti interessi sono riutilizzati per l'azione corrispondente, sono detratti da richieste di pagamento conformemente all'articolo 23, paragrafo 1, primo comma, lettera c), o sono recuperati.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la contabilità degli interessi generati da versamenti di prefinanziamenti.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "9": {"label": "Articolo 9", "heading": "Definizione", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">Gli stanziamenti iscritti nel bilancio sono autorizzati per la durata di un esercizio, che inizia il 1<span class=\"superscript\">o</span> gennaio e termina il 31 dicembre.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Tipologia degli stanziamenti", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">1.  Il bilancio comporta stanziamenti dissociati, che danno luogo a stanziamenti d'impegno e a stanziamenti di pagamento, e stanziamenti non dissociati.</p>"], [null, "<p class=\"norm\">2.  Gli stanziamenti d'impegno coprono il costo totale degli impegni giuridici sottoscritti durante l'esercizio, alle condizioni di cui l'articolo 86, paragrafo 4, e l'articolo 189, paragrafo 2.</p>"], [null, "<p class=\"norm\">3.  Gli stanziamenti di pagamento coprono i pagamenti derivanti dall'esecuzione degli impegni giuridici sottoscritti durante l'esercizio o durante gli esercizi precedenti.</p>"], [null, "<p class=\"norm\">4.  I paragrafi 1 e 2 del presente articolo fanno salve le disposizioni speciali dei titoli I, IV e VI della parte seconda e non precludono la facoltà di impegnare gli stanziamenti globalmente o di procedere a impegni di bilancio per frazioni annue.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Contabilità per entrate e stanziamenti", "anchor": "art_11", "frags": [[null, "<p class=\"norm\">1.  Le entrate sono imputate a un esercizio sulla base degli importi riscossi nel corso dell'esercizio stesso. Tuttavia, le risorse proprie del mese di gennaio dell'esercizio successivo possono essere rese disponibili a titolo di anticipo conformemente al regolamento (CE, Euratom) n. 1150/2000 del Consiglio, del 22 maggio 2000, recante applicazione della decisione 2007/436/CE, Euratom, relativa al sistema delle risorse proprie delle Comunità europee (\n<span class=\"superscript\">4</span>\n).</p>"], [null, "<p class=\"norm\">2.  Le iscrizioni delle risorse proprie provenienti dall'imposta sul valore aggiunto, della risorsa complementare basata sul prodotto nazionale lordo e, se necessario, dei contributi finanziari, possono essere rettificate conformemente al regolamento (CE, Euratom) n. 1150/2000.</p>"], [null, "<p class=\"norm\">3.  Gli stanziamenti assegnati a titolo di un esercizio sono utilizzati solo per coprire le spese impegnate e pagate nel corso di tale esercizio e per coprire gli importi dovuti a titolo di impegni relativi a esercizi precedenti.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti gli stanziamenti per l'esercizio.</p>"], [null, "<p class=\"norm\">4.  Gli impegni di stanziamenti sono contabilizzati sulla base degli impegni giuridici contratti fino al 31 dicembre. A titolo eccezionale, gli impegni globali di bilancio di cui all'articolo 86, paragrafo 4, e le convenzioni di finanziamento di cui all'articolo 189, paragrafo 2, concluse con paesi terzi, sono contabilizzati sulla base degli impegni di bilancio contratti fino al 31 dicembre.</p>"], [null, "<p class=\"norm\">5.  I pagamenti sono contabilizzati a titolo di un esercizio sulla base dei pagamenti effettuati dal contabile entro il 31 dicembre dell'esercizio stesso.</p>"], [null, "<p class=\"norm\">6.  In deroga ai paragrafi 3, 4 e 5, le spese del Fondo europeo agricolo di garanzia sono imputate a un esercizio secondo le norme di cui al titolo I della parte seconda.</p>"]]}, "12": {"label": "Articolo 12", "heading": "Impegno di stanziamenti", "anchor": "art_12", "frags": [[null, "<p class=\"norm\">Gli stanziamenti iscritti in bilancio possono essere impegnati con decorrenza di effetti dal 1<span class=\"superscript\">o</span> gennaio, non appena il bilancio è stato definitivamente adottato, fatte salve le deroghe previste alla parte seconda, titoli I e VI.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Annullamento e riporto di stanziamenti", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">1.  Gli stanziamenti non utilizzati entro la fine dell'esercizio per il quale sono stati iscritti sono annullati.</p>"], [null, "<p class=\"norm\">Tuttavia, possono essere oggetto di una decisione di riporto limitato unicamente all'esercizio successivo, presa entro il 15 febbraio dall'istituzione interessata conformemente ai paragrafi 2 e 3 o possono essere oggetto di un riporto di diritto conformemente al paragrafo 4.</p>"], [null, "<p class=\"norm\">2.  Per gli stanziamenti d'impegno dissociati e gli stanziamenti non dissociati non ancora impegnati alla fine dell'esercizio il riporto può riguardare:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>gli importi corrispondenti agli stanziamenti d'impegno, o agli stanziamenti non dissociati relativi ai progetti immobiliari, per i quali la maggior parte delle fasi preparatorie della procedura d'impegno è stata completata al 31 dicembre. Tali importi possono essere impegnati fino al 31 marzo dell'anno successivo o fino al 31 dicembre dell'anno successivo per gli importi relativi ai progetti immobiliari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>gli importi che risultano necessari quando l'autorità legislativa ha adottato un atto di base nel corso dell'ultimo trimestre dell'esercizio e la Commissione non ha potuto stanziare gli impegni previsti a tale scopo entro il 31 dicembre;</p>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>gli importi corrispondenti agli stanziamenti d’impegno per la riserva per aiuti d’urgenza.</p>\n</div>"], [null, "<p class=\"norm\">Gli importi di cui alla lettera c) del primo comma possono essere oggetto di un riporto limitato unicamente all’esercizio successivo.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">3.  Per gli stanziamenti di pagamento il riporto può riguardare gli importi necessari per coprire impegni anteriori o impegni connessi a stanziamenti d'impegno riportati, se gli stanziamenti di pagamento previsti alle rispettive linee del bilancio dell'esercizio successivo non sono sufficienti per coprire il fabbisogno.</p>"], [null, "<p class=\"norm\">L'istituzione interessata impiega in via prioritaria gli stanziamenti autorizzati per l'esercizio in corso e ricorre agli stanziamenti riportati soltanto quando i primi siano esauriti.</p>"], [null, "<p class=\"norm\">4.  Gli stanziamenti non dissociati corrispondenti a obblighi regolarmente contratti alla fine dell'esercizio sono riportati di diritto unicamente all'esercizio successivo.</p>"], [null, "<p class=\"norm\">5.  L'istituzione interessata informa il Parlamento europeo e il Consiglio, entro il 15 marzo, in merito alla decisione di riporto da essa presa, precisando per ogni linea di bilancio in qual modo i criteri di cui ai paragrafi 2 e 3 sono stati applicati a ciascun riporto.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">6.  Fatti salvi il paragrafo 2, primo comma, lettera c), del presente articolo e l’articolo 14, gli stanziamenti iscritti in riserva e gli stanziamenti relativi alle spese di personale non sono oggetto di riporto. Ai fini del presente articolo, le spese di personale comprendono le retribuzioni e le indennità dei membri e del personale delle istituzioni a cui si applica lo statuto dei funzionari.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">7.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'annullamento e il riporto di stanziamenti.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Norme in materia di riporto delle entrate con destinazione specifica", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">Al riporto delle entrate con destinazione specifica di cui all'articolo 21, e degli stanziamenti non utilizzati e disponibili al 31 dicembre a titolo di tali entrate, si applicano le seguenti disposizioni:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le entrate con destinazione specifica esterne sono oggetto di un riporto di diritto e sono utilizzate integralmente entro il completamento di tutte le operazioni connesse al programma o all'azione cui sono destinate. Le entrate con destinazione specifica esterne riscosse nell'ultimo anno del programma o dell'azione possono essere utilizzate durante il primo anno del programma o dell'azione seguente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le entrate con destinazione specifica interne sono oggetto di riporto per un unico esercizio, fatta eccezione per le entrate con destinazione specifica interne di cui all'articolo 21, paragrafo 3, lettera g), che sono oggetto di un riporto di diritto.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Disimpegno di stanziamenti", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">Fatti salvi gli articoli 178 e 182, i disimpegni che intervengono nel corso degli esercizi successivi all'esercizio per il quale gli stanziamenti sono stati iscritti in bilancio, conseguenti all'inesecuzione totale o parziale delle azioni alle quali gli stanziamenti sono stati assegnati, danno luogo all'annullamento degli stanziamenti corrispondenti.</p>"]]}, "16": {"label": "Articolo 16", "heading": "Norme applicabili in caso di tardiva adozione del bilancio", "anchor": "art_16", "frags": [[null, "<p class=\"norm\">1.  Se all'inizio dell'esercizio il bilancio non è stato ancora definitivamente adottato, si applica la procedura di cui all'articolo 315, primo comma, TFUE (regime dei dodicesimi provvisori). Le operazioni d'impegno e di pagamento possono essere effettuate entro i limiti stabiliti al paragrafo 2 del presente articolo.</p>"], [null, "<p class=\"norm\">2.  Le operazioni d'impegno possono essere effettuate, per capitolo, entro i limiti di un quarto dell'insieme degli stanziamenti autorizzati per il pertinente capitolo per l'esercizio precedente, aumentato di un dodicesimo per ciascun mese trascorso.</p>"], [null, "<p class=\"norm\">Il limite degli stanziamenti previsti nel progetto di bilancio non é superato.</p>"], [null, "<p class=\"norm\">Le operazioni di pagamento possono essere effettuate mensilmente, per capitolo, entro i limiti di un dodicesimo degli stanziamenti autorizzati per il pertinente capitolo per l'esercizio precedente, senza poter superare il dodicesimo degli stanziamenti previsti nello stesso capitolo del progetto di bilancio.</p>"], [null, "<p class=\"norm\">3.  Come stanziamenti autorizzati nel pertinente capitolo dell'esercizio precedente, di cui ai paragrafi 1 e 2, si intendono gli stanziamenti votati in bilancio, compresi i bilanci rettificativi, dopo le rettifiche apportate in funzione degli storni effettuati nel corso di tale esercizio.</p>"], [null, "<p class=\"norm\">4.  Se richiesto dalla continuità dell'azione dell'Unione e dalle esigenze di gestione, il Consiglio, deliberando a maggioranza qualificata su proposta della Commissione, può autorizzare simultaneamente spese superiori a un dodicesimo provvisorio, ma non superiori al totale di quattro dodicesimi provvisori, salvo in casi debitamente giustificati, sia per le operazioni d'impegno sia per le operazioni di pagamento in aggiunta a quelli resi automaticamente disponibili a norma dei paragrafi 1 e 2. Esso trasmette senza indugio la decisione di autorizzazione al Parlamento europeo.</p>"], [null, "<p class=\"norm\">Tale decisione entra in vigore 30 giorni dopo l'adozione tranne se il Parlamento europeo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>deliberando a maggioranza dei membri che lo compongono, decide di ridurre dette spese entro tale termine, nel qual caso la Commissione presenta una nuova proposta; o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>informa il Consiglio e la Commissione che non intende ridurre dette spese, nel qual caso la decisione entra in vigore prima della scadenza del termine di 30 giorni.</p>\n</div>"], [null, "<p class=\"norm\">I dodicesimi supplementari sono autorizzati per intero e non sono frazionabili.</p>"], [null, "<p class=\"norm\">5.  Se, per un determinato capitolo, l'autorizzazione di quattro dodicesimi provvisori, accordata conformemente al paragrafo 4, non permette di fare fronte alle spese necessarie per evitare un'interruzione della continuità dell'azione dell'Unione nel settore contemplato dal capitolo in questione, può essere autorizzato, a titolo eccezionale, il superamento dell'importo degli stanziamenti iscritti nel corrispondente capitolo del bilancio dell'esercizio precedente. Il Parlamento europeo e il Consiglio deliberano secondo le procedure di cui al paragrafo 4. L'importo globale degli stanziamenti disponibile nel bilancio dell'esercizio precedente o nel progetto di bilancio proposto non può tuttavia in nessun caso essere superato.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "17": {"label": "Articolo 17", "heading": "Definizione e portata", "anchor": "art_17", "frags": [[null, "<p class=\"norm\">1.  Entrate e stanziamenti di pagamento risultano in pareggio.</p>"], [null, "<p class=\"norm\">2.  L'Unione e gli organismi di cui all'articolo 208 non possono accendere prestiti entro il quadro del bilancio.</p>"]]}, "18": {"label": "Articolo 18", "heading": "Saldo dell'esercizio", "anchor": "art_18", "frags": [[null, "<p class=\"norm\">1.  Il saldo di ogni esercizio viene iscritto nel bilancio dell'esercizio successivo, in entrate o in stanziamenti di pagamento a seconda che si tratti di un'eccedenza o di un disavanzo.</p>"], [null, "<p class=\"norm\">2.  Le stime appropriate di tali entrate o degli stanziamenti di pagamento sono iscritte in bilancio nel corso della procedura di bilancio e mediante una lettera rettificativa presentata a norma dell'articolo 39. Le stime sono determinate conformemente al regolamento (CE, Euratom) n. 1150/2000.</p>"], [null, "<p class=\"norm\">3.  Dopo la presentazione dei conti provvisori di ogni esercizio, la differenza tra questi conti e le stime è iscritta nel bilancio dell'esercizio successivo mediante un bilancio rettificativo riguardante esclusivamente tale differenza. In tal caso, la Commissione presenta il progetto di bilancio rettificativo contemporaneamente al Parlamento europeo e al Consiglio entro 15 giorni dalla presentazione dei conti provvisori.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "19": {"label": "Articolo 19", "heading": "Utilizzo dell'euro", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">1.  Il quadro finanziario pluriennale e il bilancio sono formati, sono eseguiti e sono oggetto di rendiconto in euro. Tuttavia, per le esigenze della tesoreria di cui all'articolo 68, paragrafo 1, il contabile e, nel caso delle casse di anticipi, l'amministratore degli anticipi e, per la gestione amministrativa della Commissione e del SEAE, l'ordinatore responsabile sono autorizzati a effettuare operazioni in altre monete, alle condizioni precisate negli atti delegati adottati ai sensi del presente regolamento.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il tasso di conversione tra l'euro e altre valute.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "20": {"label": "Articolo 20", "heading": "Definizione e portata", "anchor": "art_20", "frags": [[null, "<p class=\"norm\">Fatto salvo l'articolo 21, l'insieme delle entrate copre l'insieme degli stanziamenti di pagamento. Fatto salvo l'articolo 23, tutte le entrate e le spese sono iscritte senza contrazione fra di esse,.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Entrate con destinazione specifica", "anchor": "art_21", "frags": [[null, "<p class=\"norm\">1.  Le entrate con destinazione specifica esterne e le entrate con destinazione specifica interne sono destinate a finanziare spese determinate.</p>"], [null, "<p class=\"norm\">2.  Costituiscono entrate con destinazione specifica esterne:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>i contributi finanziari degli Stati membri per taluni programmi di ricerca conformemente al regolamento (CE, Euratom) n. 1150/2000;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i contributi finanziari degli Stati membri e dei paesi terzi, incluse in entrambi i casi le rispettive agenzie pubbliche, entità o persone fisiche, per taluni progetti o programmi di aiuti esterni finanziati dall'Unione e gestiti per loro conto dalla Commissione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>gli interessi sui depositi e le ammende previsti dal regolamento (CE) n. 1467/97 del Consiglio, del 7 luglio 1997, per l'accelerazione e il chiarimento delle modalità di attuazione della procedura per i disavanzi eccessivi (\n<span class=\"superscript\">5</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>le entrate aventi una destinazione specifica, quali redditi da fondazioni, sussidi, donazioni e legati, comprese le entrate aventi una destinazione specifica proprie a ciascuna istituzione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>i contributi finanziari, non coperti dalla lettera b), di paesi terzi o di organismi non dell'Unione ad attività dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>le entrate con destinazione specifica di cui agli articoli 181, paragrafo 2, e 183, paragrafo 2;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>le entrate con destinazione specifica interne di cui al paragrafo 3, nella misura in cui sono accessorie rispetto alle altre entrate di cui al presente paragrafo.</p>\n</div>"], [null, "<p class=\"norm\">3.  Costituiscono entrate con destinazione specifica interne:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le entrate provenienti da terzi per forniture, prestazioni di servizi o lavori effettuati su loro richiesta;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i proventi della vendita di autoveicoli, macchinari, impianti, materiali e apparecchiature scientifiche e tecniche che sono sostituiti o rottamati quando il valore contabile è completamente ammortizzato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>le entrate provenienti dalla restituzione, a norma dell'articolo 80, di somme indebitamente pagate;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>le entrate provenienti da interessi sui versamenti di prefinanziamenti, alle condizioni di cui all'articolo 8, paragrafo 4;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>i proventi di forniture, prestazioni di servizi e lavori effettuati a favore di altri servizi all'interno di un'istituzione, istituzioni o organismi, compreso l'importo delle indennità di missione pagate per conto di altre istituzioni o organismi e da questi ultimi rimborsati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>l'importo delle indennità di assicurazione riscosse;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>le entrate provenienti da indennità locative;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">h)<span style=\"word-spacing: 15pt\"> </span>le entrate provenienti dalla vendita di pubblicazioni e film, anche su supporto elettronico;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>i rimborsi a strumenti finanziari a norma dell'articolo 140, paragrafo 6;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">j)<span style=\"word-spacing: 18pt\"> </span>le entrate provenienti da successivi rimborsi di oneri fiscali a norma dell'articolo 23, paragrafo 3, lettera b).</p>\n</div>"], [null, "<p class=\"norm\">4.  Un atto di base può anche prescrivere di destinare le entrate da esso previste a spese determinate. Salvo diversamente specificato nell'atto di base, tali entrate costituiscono entrate con destinazione specifica interne.</p>"], [null, "<p class=\"norm\">5.  Il bilancio prevede per le entrate con destinazione specifica esterne e per le entrate con destinazione specifica interne una struttura d'accoglienza e, per quanto possibile, il loro importo.</p>"], [null, "<p class=\"norm\">Le entrate con destinazione specifica possono essere incluse nel progetto di bilancio soltanto per gli importi certi alla data di formazione del progetto di bilancio.</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo all'istituzione della struttura per incorporare le entrate interne ed esterne con destinazione specifica e la fornitura degli stanziamenti corrispondenti nonché alla definizione delle norme concernenti il contributo degli Stati membri ai programmi di ricerca. Inoltre, alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo ai proventi delle sanzioni imposte ai sensi dell'articolo 126, paragrafo 11, TFUE e riguardanti le entrate con destinazione specifica risultanti dalla partecipazione degli Stati EFTA ad alcuni programmi dell'Unione.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Atti di liberalità", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">1.  La Commissione può accettare qualsiasi atto di liberalità a favore dell'Unione, in particolare fondazioni, sussidi, donazioni e legati.</p>"], [null, "<p class=\"norm\">2.  L'accettazione di una liberalità per un valore pari o superiore a 50 000  EUR comportanti oneri finanziari, compresi i costi correlati all'accettazione, superiori al 10 % del valore della liberalità effettuata, è soggetta all'autorizzazione del Parlamento europeo e del Consiglio, i quali si pronunciano entro due mesi dal ricevimento della domanda della Commissione. Se entro questo termine non viene formulata alcuna obiezione, la Commissione delibera in via definitiva sull'accettazione della donazione.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'accettazione di liberalità offerte all'Unione.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Norme in materia di detrazioni e compensazione del tasso di cambio", "anchor": "art_23", "frags": [[null, "<p class=\"norm\">1.  Si possono effettuare le seguenti detrazioni dall'importo delle richieste di pagamento, che in tal caso sono oggetto di un ordine di pagamento al netto:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>sanzioni imposte alle parti di contratti d'appalto o ai beneficiari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>sconti, rimborsi e ribassi concessi su singole fatture e rendiconti di spesa;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>interessi prodotti da versamenti di prefinanziamenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>ripetizioni delle somme indebitamente pagate.</p>\n</div>"], [null, "<p class=\"norm\">Le ripetizioni di cui alla lettera d) del primo comma possono essere operate mediante detrazione diretta in occasione di un nuovo pagamento intermedio o di un nuovo pagamento a saldo a favore del medesimo beneficiario, effettuata sullo stesso capo, articolo ed esercizio ai quali l'indebito pagamento è stato imputato.</p>"], [null, "<p class=\"norm\">Le norme contabili dell'Unione si applicano alle detrazioni di cui al primo comma, lettere c) e d).</p>"], [null, "<p class=\"norm\">2.  I prezzi di prodotti o prestazioni forniti all'Unione, che comprendono oneri fiscali oggetto di rimborso da parte degli Stati membri in forza del protocollo sui privilegi e le immunità dell'Unione europea, sono imputati in bilancio con il loro importo al netto delle tasse.</p>"], [null, "<p class=\"norm\">3.  I prezzi di prodotti o prestazioni forniti all'Unione, che comprendono oneri fiscali oggetto di rimborso da parte di paesi terzi in forza delle pertinenti convenzioni, possono essere imputati in bilancio con il loro importo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>al netto delle tasse, o</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>al lordo delle tasse. In tal caso, i successivi rimborsi di oneri fiscali sono assimilati a entrate con destinazione specifica interne.</p>\n</div>"], [null, "<p class=\"norm\">4.  Differenze di cambio registrate nel corso dell'esecuzione di bilancio possono essere compensate. Il risultato finale, positivo o negativo, è ripreso nel saldo dell'esercizio.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i conti relativi a oneri fiscali da recuperare.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "24": {"label": "Articolo 24", "heading": "Disposizioni generali", "anchor": "art_24", "frags": [[null, "<p class=\"norm\">Gli stanziamenti sono specificati per titoli e per capitoli. I capitoli sono suddivisi in articoli e in voci.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Storni a opera di istituzioni diverse dalla Commissione", "anchor": "art_25", "frags": [[null, "<p class=\"norm\">1.  Ogni istituzione diversa dalla Commissione può procedere, all'interno della propria sezione di bilancio, a storni di stanziamenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>da titolo a titolo fino ad un massimo del 10 % degli stanziamenti dell'esercizio iscritti alla linea dalla quale viene effettuato lo storno;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>da capitolo a capitolo e da articolo ad articolo senza limiti.</p>\n</div>"], [null, "<p class=\"norm\">2.  Tre settimane prima di procedere a uno storno di cui al paragrafo 1, l'istituzione informa il Parlamento europeo e il Consiglio della sua intenzione. Se durante tale periodo il Parlamento europeo o il Consiglio avanza motivi debitamente giustificati, si applica la procedura di cui all'articolo 27.</p>"], [null, "<p class=\"norm\">3.  Ogni istituzione, diversa dalla Commissione, può proporre al Parlamento europeo e al Consiglio storni da titolo a titolo, all'interno della propria sezione di bilancio, superiori al limite del 10 % degli stanziamenti dell'esercizio iscritti nella linea di bilancio dalla quale s'intende effettuare lo storno. Tali storni sono soggetti alla procedura di cui all'articolo 27.</p>"], [null, "<p class=\"norm\">4.  Ogni istituzione, diversa dalla Commissione, può procedere, all'interno della propria sezione di bilancio, a storni da articolo ad articolo senza informarne preventivamente il Parlamento europeo e il Consiglio.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il calcolo delle percentuali degli storni effettuati da istituzioni diverse dalla Commissione.</p>"]]}, "26": {"label": "Articolo 26", "heading": "Storni a opera della Commissione", "anchor": "art_26", "frags": [[null, "<p class=\"norm\">1.  La Commissione può procedere autonomamente ai seguenti storni all'interno della propria sezione del bilancio:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>storni di stanziamenti all'interno di ciascun capitolo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>con riguardo alle spese di personale e di funzionamento comuni a diversi titoli, storni di stanziamenti da titolo a titolo fino a un massimo del 10 % degli stanziamenti dell'esercizio iscritti alla linea dalla quale si procede allo storno e fino ad un massimo del 30 % degli stanziamenti dell'esercizio iscritti nella linea verso la quale viene effettuato lo storno;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>con riguardo alle spese operative, storni di stanziamenti tra capitoli all'interno dello stesso titolo, fino a un massimo del 10 % degli stanziamenti dell'esercizio iscritti alla linea a partire dalla quale si procede allo storno.</p>\n</div>"], [null, "<p class=\"norm\">Tre settimane prima di procedere agli storni di cui al primo comma, lettera b), la Commissione informa il Parlamento europeo e il Consiglio della sua intenzione. Se durante tale periodo il Parlamento europeo o il Consiglio avanza motivi debitamente giustificati, si applica la procedura di cui all'articolo 27.</p>"], [null, "<p class=\"norm\">In droga al secondo comma, la Commissione può, negli ultimi due mesi dell'esercizio, trasferire autonomamente stanziamenti relativi a spese per il personale, il personale esterno e altri agenti da titolo a titolo entro un limite complessivo pari al 5 % degli stanziamenti per l'esercizio. La Commissione informa il Parlamento europeo e il Consiglio nelle due settimane successive alla decisione relativa a tali storni.</p>"], [null, "<p class=\"norm\">2.  La Commissione può decidere di procedere, all'interno della propria sezione del bilancio, ai seguenti storni di stanziamenti da titolo a titolo, purché comunichi immediatamente la sua decisione al Parlamento europeo e al Consiglio:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>storni di stanziamenti dal titolo \"stanziamenti accantonati\" di cui all'articolo 43, ove l'unica condizione per sciogliere la riserva è l'adozione di un atto di base a norma dell'articolo 294 TFUE;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>in casi eccezionali debitamente giustificati, quali catastrofi umanitarie e crisi internazionali, che si verifichino dopo il 1<span class=\"superscript\">o</span> dicembre dell'esercizio, storni di stanziamenti non utilizzati di detto esercizio ancora disponibili dai titoli di bilancio della rubrica 4 del quadro finanziario pluriennale ai titoli di bilancio riguardanti gli aiuti erogati per situazioni di crisi e operazioni di aiuto umanitario.</p>\n</div>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il calcolo delle percentuali degli storni interni effettuati dalla Commissione e i motivi alla base delle richieste di storno.</p>"]]}, "27": {"label": "Articolo 27", "heading": "Proposte di storni sottoposte al Parlamento europeo e al Consiglio dalle istituzioni", "anchor": "art_27", "frags": [[null, "<p class=\"norm\">1.  Ogni istituzione presenta le sue proposte di storni contemporaneamente al Parlamento europeo e al Consiglio.</p>"], [null, "<p class=\"norm\">2.  Il Parlamento europeo e il Consiglio decidono gli storni di stanziamenti di cui ai paragrafi da 3 a 6 del presente articolo, fatte salve le deroghe di cui al titolo I della parte seconda.</p>"], [null, "<p class=\"norm\">3.  Salvo in casi urgenti, il Parlamento europeo e il Consiglio, deliberando quest'ultimo a maggioranza qualificata, si pronunciano su ciascuna proposta di storno entro sei settimane dalla sua ricezione da parte delle due istituzioni.</p>"], [null, "<p class=\"norm\">4.  La proposta di storno è approvata se, entro il periodo di sei settimane, si verifica una delle situazioni seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il Parlamento europeo e il Consiglio approvano la proposta;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il Parlamento europeo o il Consiglio approva la proposta e l'altra istituzione si astiene dal deliberare;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il Parlamento europeo e il Consiglio si astengono dal deliberare oppure non adottano una decisione per modificare o respingere la proposta di storno.</p>\n</div>"], [null, "<p class=\"norm\">5.  Il periodo di sei settimane di cui al paragrafo 3 è ridotto a tre settimane, salvo domanda contraria del Parlamento europeo o del Consiglio, nei casi seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>lo storno rappresenta meno del 10 % degli stanziamenti della linea da cui è effettuato e non supera i 5 000 000  EUR;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>lo storno riguarda unicamente stanziamenti di pagamento e il suo importo globale non supera i 100 000 000  EUR.</p>\n</div>"], [null, "<p class=\"norm\">6.  Se il Parlamento europeo o il Consiglio ha modificato l'importo dello storno mentre l'altra istituzione lo ha approvato o si è astenuta dal deliberare, oppure se il Parlamento europeo e il Consiglio hanno entrambi modificato l'importo dello storno, si considera approvato il minore dei due importi, a meno che l'istituzione interessata non ritiri la sua proposta di storno.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Norme specifiche in materia di storni", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">1.  Possono essere dotate di stanziamenti mediante storno solo le linee di bilancio per le quali il bilancio autorizza uno stanziamento o che recano la menzione \"per memoria\".</p>"], [null, "<p class=\"norm\">2.  Gli stanziamenti corrispondenti a entrate con destinazione specifica possono essere oggetto di storno solo a condizione che tali entrate conservino la loro destinazione.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Storni oggetto di disposizioni speciali", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">1.  Gli storni all'interno dei titoli del bilancio previsti per gli stanziamenti del Fondo europeo agricolo di garanzia, dei Fondi strutturali, del Fondo di coesione, del Fondo europeo per la pesca, del Fondo europeo agricolo per lo sviluppo rurale e della ricerca, sono disciplinati dalle disposizioni speciali contenute nei titoli I, II e III della parte seconda.</p>"], [null, "<p class=\"norm\">2.  Gli storni destinati a permettere l'impiego della riserva per aiuti d'urgenza sono decisi dal Parlamento europeo e dal Consiglio su proposta della Commissione. Per ogni azione urgente è presentata una proposta distinta.</p>"], [null, "<p class=\"norm\">Ai fini del presente paragrafo si applica la procedura di cui all'articolo 27, paragrafi 3 e 4. Se il Parlamento europeo e il Consiglio non approvano la proposta della Commissione e se non si può raggiungere una posizione comune sull'impiego di tale riserva, essi non adottano decisioni sulla proposta di storno della Commissione.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti le domande di storno a partire dalla riserva per aiuti d'urgenza.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "30": {"label": "Articolo 30", "heading": "Principi di economia, efficienza ed efficacia", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">1.  Gli stanziamenti sono utilizzati secondo il principio di una sana gestione finanziaria, vale a dire secondo i principi di economia, efficienza ed efficacia.</p>"], [null, "<p class=\"norm\">2.  Secondo il principio dell'economia, le risorse impiegate dall'istituzione nella realizzazione delle proprie attività sono messe a disposizione in tempo utile, nella quantità e qualità appropriate e al prezzo migliore.</p>"], [null, "<p class=\"norm\">Secondo il principio dell'efficienza, deve essere ricercato il miglior rapporto tra i mezzi impiegati e i risultati conseguiti.</p>"], [null, "<p class=\"norm\">Secondo il principio dell'efficacia, gli obiettivi specifici fissati devono essere raggiunti e devono essere conseguiti i risultati attesi.</p>"], [null, "<p class=\"norm\">3.  Sono stabiliti obiettivi specifici, misurabili, realizzabili, pertinenti e corredati di un termine per tutti i settori di attività contemplati dal bilancio. La realizzazione di tali obiettivi è verificata mediante indicatori di performance stabiliti per ciascuna attività e le autorità incaricate della spesa trasmettono al Parlamento europeo e al Consiglio le informazioni di cui all'articolo 38, paragrafo 3, lettera e). Tali informazioni sono fornite ogni anno entro i termini più brevi e al più tardi nei documenti che accompagnano il progetto di bilancio.</p>"], [null, "<p class=\"norm\">4.  Per migliorare il processo decisionale, le istituzioni procedono a valutazioni <span class=\"italics\">ex ante</span> ed <span class=\"italics\">ex post</span> in conformità degli orientamenti definiti dalla Commissione. Sono soggetti a valutazione tutti i programmi e le attività che comportano spese importanti e i risultati di tale valutazione sono comunicati al Parlamento europeo, al Consiglio e alle autorità amministrative incaricate della spesa.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti le valutazioni <span class=\"italics\">ex ante</span>, intermedie ed <span class=\"italics\">ex post</span>.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Scheda finanziaria obbligatoria", "anchor": "art_31", "frags": [[null, "<p class=\"norm\">1.  Le proposte o iniziative presentate all'autorità legislativa dalla Commissione, dall'alto rappresentante dell'Unione per gli affari esteri e la politica di sicurezza (\"l'alto rappresentante\") o da uno Stato membro, che possano avere un'incidenza sul bilancio, compresa un'incidenza sul numero dei posti, sono corredate di una scheda finanziaria e di una valutazione <span class=\"italics\">ex ante</span> di cui all'articolo 30, paragrafo 4.</p>"], [null, "<p class=\"norm\">Le modifiche a una proposta o iniziativa presentate all'autorità legislativa che possano avere un'incidenza rilevante sul bilancio, compresa un'incidenza sul numero dei posti, sono corredate di una scheda finanziaria preparata dall'istituzione che propone la modifica.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i requisiti della scheda finanziaria.</p>"], [null, "<p class=\"norm\">2.  Nel corso della procedura di bilancio la Commissione fornisce tutte le informazioni che consentono un raffronto tra l'evoluzione del fabbisogno di stanziamenti e le previsioni iniziali riportate nella scheda finanziaria in funzione dello stato di avanzamento delle deliberazioni sulla proposta o sull'iniziativa presentata all'autorità legislativa.</p>"], [null, "<p class=\"norm\">3.  Al fine di ridurre i rischi di frode e irregolarità, la scheda finanziaria di cui al paragrafo 1 riporta informazioni sul sistema di controllo interno istituito, una stima dei costi e dei benefici dei controlli che tale sistema comporta e una valutazione del previsto livello di rischio di errore, nonché le misure di prevenzione e di tutela esistenti e previste.</p>"], [null, "<p class=\"norm\">Tale analisi tiene conto della probabile portata e tipologia degli errori, nonché delle particolari condizioni del settore interessato e delle norme ad esso applicabili.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Controllo interno dell'esecuzione del bilancio", "anchor": "art_32", "frags": [[null, "<p class=\"norm\">1.  Il bilancio viene eseguito secondo il principio di un controllo interno efficace ed efficiente, adeguato per ogni metodo di esecuzione, e in conformità della normativa settoriale pertinente.</p>"], [null, "<p class=\"norm\">2.  Ai fini dell'esecuzione del bilancio, il controllo interno è definito come un processo applicabile a tutti i livelli di gestione e destinato a fornire ragionevoli garanzie quanto al conseguimento dei seguenti obiettivi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>efficacia, efficienza ed economia delle operazioni,</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>affidabilità delle relazioni,</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>salvaguardia degli attivi e informazione,</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>prevenzione, individuazione e rettifica delle frodi e irregolarità e seguito dato a tali frodi e irregolarità;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>adeguata gestione dei rischi connessi alla legittimità e regolarità delle operazioni sottostanti, tenendo conto del carattere pluriennale dei programmi, nonché della natura dei pagamenti in questione.</p>\n</div>"], [null, "<p class=\"norm\">3.  Un controllo interno efficace si basa sulle migliori pratiche internazionali e include, in particolare, quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>separazione dei compiti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un'adeguata strategia di gestione e controllo dei rischi, compresi i controlli presso i beneficiari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>prevenzione dei conflitti d'interesse;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>adeguate piste di controllo e integrità dei dati nei sistemi informatici;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>procedure per la vigilanza sul rendimento e su eventuali inadeguatezze e lacune individuate nei controlli interni;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>verifica periodica del valido funzionamento del sistema di controllo interno.</p>\n</div>"], [null, "<p class=\"norm\">4.  Un controllo interno efficiente si basa sugli elementi seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>attuazione di un'adeguata strategia di gestione e controllo dei rischi, coordinata tra le persone addette alle varie fasi del controllo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>accessibilità per tutte le persone addette alle varie fasi del controllo dei risultati dei controlli svolti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>ricorso, se del caso, alle dichiarazioni di gestione redatte dai partner di esecuzione e a pareri indipendenti sulla revisione contabile, a condizione che il lavoro sottostante sia adeguato e accettabile e che sia stato svolto conformemente alle norme convenute;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>applicazione tempestiva di misure correttive, comprese, ove opportuno, sanzioni dissuasive;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>legislazione chiara e inequivocabile a fondamento degli interventi;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>eliminazione di controlli multipli;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>miglioramento del rapporto costi/benefici dei controlli.</p>\n</div>"], [null, "<p class=\"norm\">5.  Se, durante l'attuazione del programma, il livello di errore è persistentemente elevato, la Commissione identifica le lacune nei sistemi di controllo, analizza i costi e i benefici di potenziali misure correttive e adotta o propone i provvedimenti adeguati, quali la semplificazione delle disposizioni applicabili, il rafforzamento dei sistemi di controllo e la riprogettazione del programma o dei sistemi di di consegna.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Sistemi di controllo economicamente efficaci", "anchor": "art_33", "frags": [[null, "<p class=\"norm\">All'atto della presentazione di proposte di spesa riviste o nuove, la Commissione stima i costi e i benefici dei sistemi di controllo nonché il livello di errore di cui all'articolo 31, paragrafo 3.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "34": {"label": "Articolo 34", "heading": "Pubblicazione dei conti, dei bilanci e delle relazioni", "anchor": "art_34", "frags": [[null, "<p class=\"norm\">1.  Il bilancio è formato, eseguito ed è oggetto di rendiconto conformemente al principio della trasparenza.</p>"], [null, "<p class=\"norm\">2.  Il bilancio e i bilanci rettificativi definitivamente adottati sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> a cura del presidente del Parlamento europeo.</p>"], [null, "<p class=\"norm\">La pubblicazione avviene entro tre mesi dalla data della constatazione dell'adozione definitiva del bilancio.</p>"], [null, "<p class=\"norm\">I conti annuali consolidati e le relazioni della gestione finanziaria e di bilancio elaborate da ciascuna istituzione sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la pubblicazione provvisoria del bilancio.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Pubblicazione di informazioni sui destinatari e di altre informazioni", "anchor": "art_35", "frags": [[null, "<p class=\"norm\">1.  Le operazioni di assunzione ed erogazione di prestiti contratte dall'Unione a favore di terzi figurano in un allegato del bilancio.</p>"], [null, "<p class=\"norm\">2.  La Commissione mette a disposizione, nella forma appropriata e in modo tempestivo, le informazioni sui destinatari nonché sulla natura e sullo scopo delle misure finanziate dal bilancio, laddove quest'ultimo sia eseguito direttamente conformemente all'articolo 58, paragrafo 1, lettera a), e le informazioni sui destinatari fornite dalle entità, dalle persone e dagli Stati membri cui siano stati affidati compiti d'esecuzione del bilancio conformemente ad altri metodi di esecuzione.</p>"], [null, "<p class=\"norm\">L' obbligo di cui al primo comma si applica anche alle altre istituzioni nei confronti dei loro beneficiari.</p>"], [null, "<p class=\"norm\">3.  Tali informazioni sono messe a disposizione nel debito rispetto dei requisiti in materia di riservatezza e di sicurezza, in particolare la tutela dei dati personali.</p>"], [null, "<p class=\"norm\">Qualora si tratti di persone fisiche, la pubblicazione si limita al nome e all'ubicazione del beneficiario, all'importo concesso e alla finalità della sovvenzione. La divulgazione di questi dati si basa su criteri pertinenti quali la periodicità della sovvenzione ovvero il tipo o l'importanza della sovvenzione. I criteri di pubblicazione e il grado di specificità tengono conto delle peculiarità del settore e di ciascun metodo di esecuzione.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la pubblicazione di informazioni relative ai destinatari. Ove applicabile, il livello di dettaglio e i criteri sono definiti nella pertinente normativa settoriale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "36": {"label": "Articolo 36", "heading": "Stati di previsione delle entrate e delle spese", "anchor": "art_36", "frags": [[null, "<p class=\"norm\">1.  Ogni istituzione diversa dalla Commissione redige uno stato di previsione delle sue entrate e delle sue spese, che trasmette alla Commissione, e in parallelo, a titolo informativo, al Parlamento europeo e al Consiglio, anteriormente al 1<span class=\"superscript\">o</span> luglio di ogni anno.</p>"], [null, "<p class=\"norm\">2.  L'alto rappresentante consulta i membri della Commissione responsabili per la politica di sviluppo, la politica di vicinato e la cooperazione internazionale, gli aiuti umanitari e la risposta alle crisi, relativamente ai loro rispettivi ambiti di competenza.</p>"], [null, "<p class=\"norm\">3.  La Commissione redige il proprio stato di previsione che trasmette anche, subito dopo la sua adozione, al Parlamento europeo e al Consiglio.</p>"], [null, "<p class=\"norm\">Nella preparazione del proprio stato di previsione la Commissione utilizza le informazioni indicate all'articolo 37.</p>"]]}, "37": {"label": "Articolo 37", "heading": "Bilancio di previsione degli organismi di cui all'articolo 208", "anchor": "art_37", "frags": [[null, "<p class=\"norm\">Entro il 31 marzo di ogni anno ciascun organismo di cui all'articolo 208, conformemente allo strumento che l'ha istituito, trasmette alla Commissione, al Parlamento europeo e al Consiglio uno stato di previsione delle proprie entrate e spese, compresi la tabella del suo organico e il progetto di programma di lavoro.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Progetto di bilancio", "anchor": "art_38", "frags": [[null, "<p class=\"norm\">1.  Entro il 1<span class=\"superscript\">o</span> settembre dell'anno precedente quello dell'esecuzione del bilancio la Commissione presenta al Parlamento europeo e al Consiglio una proposta contenente il progetto di bilancio. Essa trasmette tale proposta a titolo informativo anche ai parlamenti nazionali.</p>"], [null, "<p class=\"norm\">Il progetto di bilancio presenta uno stato generale riassuntivo delle entrate e delle spese dell'Unione e raggruppa gli stati di previsione di cui all'articolo 36. Esso può anche contenere previsioni divergenti da quelle elaborate dalle istituzioni.</p>"], [null, "<p class=\"norm\">Il progetto di bilancio rispetta la struttura e la presentazione stabilite agli articoli da 44 a 49.</p>"], [null, "<p class=\"norm\">Ciascuna sezione del progetto di bilancio è preceduta da un'introduzione redatta dall'istituzione interessata.</p>"], [null, "<p class=\"norm\">La Commissione redige l'introduzione generale al progetto di bilancio. L'introduzione generale comprende tabelle finanziarie che riportano i dati principali per titoli e le motivazioni delle variazioni negli stanziamenti da un esercizio all'altro per categorie di spesa del quadro finanziario pluriennale.</p>"], [null, "<p class=\"norm\">2.  Per fornire previsioni più precise e affidabili riguardo alle implicazioni di bilancio degli atti legislativi in vigore e delle proposte legislative in fase di adozione, la Commissione unisce al progetto di bilancio la programmazione finanziaria per gli esercizi successivi.</p>"], [null, "<p class=\"norm\">La programmazione finanziaria è aggiornata dopo l'adozione del bilancio, al fine di incorporare i risultati della procedura di bilancio ed eventuali altre decisioni pertinenti.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la programmazione finanziaria.</p>"], [null, "<p class=\"norm\">3.  La Commissione acclude al progetto di bilancio:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>se del caso, i motivi per i quali il progetto di bilancio comporta previsioni divergenti da quelle elaborate dalle altre istituzioni;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>qualsiasi documento di lavoro giudicato utile in relazione alla tabella dell'organico delle istituzioni e i contributi che la Commissione accorda agli organismi di cui all'articolo 208 e alle scuole europee. Questi documenti di lavoro, che contengono l'ultima tabella dell'organico approvata, presentano:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>tutto il personale impiegato dall'Unione, incluse le sue entità giuridicamente distinte, ripartito per tipo di contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>una dichiarazione sulla politica relativa agli effettivi, al personale esterno e all'equilibrio di genere;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>il numero di posti effettivamente coperti all'inizio dell'anno in cui è presentato il progetto di bilancio, indicando la loro ripartizione per grado e per unità amministrativa;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>una ripartizione del personale per settore;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">v)<span style=\"word-spacing: 15pt\"> </span>per ogni categoria di personale esterno, il numero iniziale stimato di equivalenti a tempo pieno in base agli stanziamenti autorizzati e il numero di persone effettivamente in servizio all'inizio dell'anno in cui è presentato il progetto di bilancio, indicando la ripartizione per gruppo di funzioni e, se del caso, per grado;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>un documento di lavoro sull'esecuzione degli stanziamenti prevista per l'esercizio e sugli impegni da liquidare, sugli organismi di cui all'articolo 208 e sulle scuole europee, nonché sui progetti pilota e sulle azioni preparatorie;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>per quanto riguarda i finanziamenti a favore delle organizzazioni internazionali, un documento di lavoro contenente:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>un riepilogo di tutti i contributi in oggetto, ripartiti per ciascun programma o fondo dell'Unione e per ciascuna organizzazione internazionale;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>una spiegazione dei motivi per cui è risultato più efficiente per l'Unione finanziare le organizzazioni internazionali, anziché intervenire direttamente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>rendiconti di attività o qualsiasi altro documento pertinente contenenti:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>informazioni sulla realizzazione di tutti gli obiettivi specifici, misurabili, realizzabili, pertinenti e corredati di un termine, precedentemente fissati per le varie attività, compresi i nuovi obiettivi misurati mediante indicatori;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>una giustificazione esauriente, compresa un'analisi costi/benefici, per le modifiche proposte riguardanti il livello degli stanziamenti;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>una chiara motivazione dell'intervento a livello dell'Unione, in conformità, tra l'altro, del principio di sussidiarietà;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>informazioni sui tassi d'esecuzione dell'attività dell'esercizio precedente e sui tassi d'esecuzione per l'esercizio in corso;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">v)<span style=\"word-spacing: 15pt\"> </span>una sintesi dei risultati della valutazione, se rilevanti ai fini delle modifiche del bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">vi)<span style=\"word-spacing: 19pt\"> </span>informazioni sui premi aventi un valore unitario pari o superiore a 1 000 000  EUR;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>uno stato riepilogativo delle scadenze dei pagamenti da effettuare nel corso degli esercizi successivi in base agli impegni di bilancio assunti nel corso di esercizi precedenti.</p>\n</div>"], [null, "<p class=\"norm\">4.  Quando affida l'esecuzione del bilancio a partenariati pubblico-privati (PPP), la Commissione acclude al progetto di bilancio un documento di lavoro che presenta:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>una relazione annuale sui risultati dei PPP esistenti nel corso dell'esercizio precedente, comprese informazioni sulla forma giuridica e sugli azionisti delle entità delegate di cui all'articolo 58, paragrafo 1, lettera c), punto vii);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>gli obiettivi fissati per l'esercizio al quale si riferisce il progetto di bilancio, con l'indicazione di eventuali esigenze di bilancio specifiche, dedicate al raggiungimento di questo obiettivo,</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>i costi amministrativi e il bilancio eseguito in totale e per organismo di cui all'articolo 209 e per PPP nel corso dell'esercizio precedente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>l'importo dei contributi finanziari concessi a titolo del bilancio, il valore dei contributi finanziari e il valore dei contributi in natura effettuati dagli altri partner per ogni PPP.</p>\n</div>"], [null, "<p class=\"norm\">Tuttavia, quando i PPP ricorrono a strumenti finanziari, le informazioni relative a tali strumenti sono incluse nel documento di lavoro di cui al paragrafo 5.</p>"], [null, "<p class=\"norm\">5.  Quando ricorre a strumenti finanziari, la Commissione acclude al progetto di bilancio un documento di lavoro che presenta quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>gli impegni di bilancio aggregati e i pagamenti a titolo del bilancio per ciascuno strumento finanziario;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i ricavi e i rimborsi di cui all'articolo 140, paragrafo 6, e l'attribuzione delle risorse addizionali per l'esercizio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>l'importo totale degli accantonamenti per rischi e oneri, nonché eventuali informazioni sull'esposizione dell'Unione a rischi finanziari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>le riduzioni durevoli di valore delle attività di strumenti di capitale o di condivisione del rischio e le garanzie attivate per gli strumenti di garanzia, sia per quanto riguarda l'esercizio precedente che i rispettivi dati cumulativi;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>il periodo medio che intercorre tra l'impegno di bilancio relativo agli strumenti finanziari e gli impegni giuridici per i singoli progetti sotto forma di uno strumento di uno strumento di capitale o di debito, quando la loro durata è superiore a tre anni. Nella relazione di cui all'articolo 140, paragrafo 8, la Commissione illustra i motivi e se del caso presenta un piano d'azione per la riduzione di tale periodo nel quadro della proceduta di discarico annuale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>le spese amministrative derivanti da costi di gestione e da altri oneri finanziari e di funzionamento pagati per la gestione degli strumenti finanziari, qualora tale gestione sia stata affidata a terzi, in totale e per gestore e strumento finanziario gestito;</p>\n</div>"], [null, "<p class=\"norm\">6.  La Commissione acclude inoltre al progetto di bilancio qualsiasi documento di lavoro aggiuntivo ritenuto utile per corroborare le sue richieste di bilancio.</p>"], [null, "<p class=\"norm\">7.  A norma dell'articolo 8, paragrafo 5, della decisione 2010/427/UE del Consiglio, del 26 luglio 2010, che fissa l'organizzazione e il funzionamento del servizio europeo per l'azione esterna (\n<span class=\"superscript\">6</span>\n), e al fine di garantire trasparenza di bilancio nell'ambito dell'azione esterna dell'Unione, la Commissione trasmette al Parlamento europeo e al Consiglio, unitamente al progetto di bilancio, un documento di lavoro che presenta in modo completo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>tutte le spese amministrative e operative connesse all'azione esterna dell'Unione, comprese le missioni di politica estera e di sicurezza comune (PESC) e di politica di sicurezza e di difesa comune, e finanziate a titolo del bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la spesa amministrativa globale del SEAE a titolo dell'esercizio precedente, ripartita tra spesa per ciascuna delegazione dell'Unione e spesa per l'amministrazione centrale del SEAE; unitamente alle spese operative, ripartite per zona geografica (regioni, paesi), area tematica, delegazione dell'Unione e missione.</p>\n</div>"], [null, "<p class=\"norm\">8.  Inoltre, il documento di lavoro di cui al paragrafo 7:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>evidenzia il numero dei posti per grado in ciascuna categoria e il numero dei posti permanenti e temporanei, compreso il personale contrattuale e locale, di cui è autorizzata la presa a carico nei limiti degli stanziamenti in ciascuna delegazione dell'Unione e presso l'amministrazione centrale del SEAE;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>indica ogni aumento o riduzione del numero di posti per grado e categoria presso l'amministrazione centrale del SEAE e in tutte le delegazioni dell'Unione, rispetto all'esercizio precedente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>indica il numero dei posti autorizzati a titolo dell'esercizio, il numero dei posti autorizzati a titolo dell'esercizio precedente, nonché il numero dei posti occupati da personale distaccato dai servizi diplomatici degli Stati membri e da personale distaccato dal Consiglio e dalla Commissione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>fornisce un quadro dettagliato di tutto il personale presente presso delegazioni dell'Unione al momento della presentazione del progetto di bilancio, tra cui una ripartizione per zona geografica, genere, paese e missione, distinguendo tra posti nella tabella dell'organico, agenti contrattuali, agenti locali ed esperti nazionali distaccati e gli stanziamenti richiesti nel progetto di bilancio per altre categorie di personale, con la relativa stima degli effettivi equivalenti a tempo pieno che potrebbero essere impiegati entro i limiti degli stanziamenti richiesti.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Lettera rettificativa del progetto di bilancio", "anchor": "art_39", "frags": [[null, "<p class=\"norm\">Sulla base di qualsiasi nuovo elemento non ancora noto al momento della stesura del progetto di bilancio, la Commissione, di propria iniziativa o su richiesta di una delle altre istituzioni per quanto concerne la rispettiva sezione, può presentare simultaneamente al Parlamento europeo e al Consiglio lettere rettificative del progetto di bilancio prima della convocazione del comitato di conciliazione di cui all'articolo 314 TFUE. Le lettere possono comprendere una lettera rettificativa che aggiorna, in particolare, gli stati di previsione della spesa agricola.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Obblighi degli Stati membri derivanti dall'adozione del bilancio", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">1.  Il presidente del Parlamento europeo constata che il bilancio è definitivamente adottato secondo la procedura di cui all'articolo 314, paragrafo 9, TFUE e all'articolo 106 bis del trattato Euratom.</p>"], [null, "<p class=\"norm\">2.  La constatazione dell'adozione definitiva del bilancio comporta, a decorrere dal 1<span class=\"superscript\">o</span> gennaio dell'esercizio successivo o a decorrere dalla data della constatazione dell'adozione definitiva del bilancio se questa è posteriore al 1<span class=\"superscript\">o</span> gennaio, l'obbligo per ciascuno Stato membro di versare all'Unione gli importi dovuti, come specificato nel regolamento (CE, Euratom) n. 1150/2000.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Progetti di bilancio rettificativo", "anchor": "art_41", "frags": [[null, "<p class=\"norm\">1.  La Commissione può presentare progetti di bilancio rettificativo principalmente basati sulle entrate nelle circostanze seguenti:</p>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>per iscrivere nel bilancio il saldo dell'esercizio precedente, secondo la procedura di cui all'articolo 18,</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>per rivedere le previsioni relative alle risorse proprie sulla base di previsioni economiche aggiornate, nonché</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>per aggiornare le previsioni riviste delle risorse proprie e altre entrate, come anche per riesaminare la disponibilità di, e l'esigenza in fatto di, stanziamenti di pagamento.</p>\n</div>"], [null, "<p class=\"norm\">In caso di circostanze inevitabili, eccezionali e impreviste, in particolare in vista della mobilitazione del Fondo di solidarietà dell'Unione europea, la Commissione può presentare progetti di bilancio rettificativo che sono principalmente basati sulle entrate.</p>"], [null, "<p class=\"norm\">2.  Le richieste di bilancio rettificativo avanzate nelle stesse circostanze di cui al paragrafo1 dalle istituzioni diverse dalla Commissione sono trasmesse a quest'ultima.</p>"], [null, "<p class=\"norm\">Prima di presentare un progetto di bilancio rettificativo, la Commissione e le altre istituzioni esaminano la possibilità di una ridistribuzione degli stanziamenti interessati, con particolare riferimento alle previste sottoesecuzioni degli stanziamenti.</p>"], [null, "<p class=\"norm\">L'articolo 40 si applica ai bilanci rettificativi. I bilanci rettificativi sono giustificati con riferimento al bilancio di cui modificano le previsioni.</p>"], [null, "<p class=\"norm\">3.  Salvo in caso di circostanze eccezionali debitamente motivate o di mobilitazione del Fondo di solidarietà dell'Unione europea per cui un progetto di bilancio rettificativo può essere presentato in un momento qualsiasi dell'anno, la Commissione presenta simultaneamente al Parlamento europeo e al Consiglio i propri progetti di bilancio rettificativo entro il 1<span class=\"superscript\">o</span> settembre di ogni esercizio. Essa può accludere un parere alle domande di progetti di bilancio rettificativo proposti dalle altre istituzioni.</p>"], [null, "<p class=\"norm\">4.  Il Parlamento europeo e il Consiglio deliberano sui progetti di bilancio rettificativo tenendo debitamente conto dell'urgenza.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i progetti di bilancio rettificativo.</p>"]]}, "42": {"label": "Articolo 42", "heading": "Trasmissione anticipata degli stati di previsione e del progetto di bilancio", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">La Commissione, il Parlamento europeo e il Consiglio possono convenire di anticipare talune date relative alla trasmissione degli stati di previsione e all'adozione e alla trasmissione del progetto di bilancio. Tale intesa non può tuttavia determinare una riduzione o un'estensione dei periodi previsti per l'esame di tali testi a norma dell'articolo 314 TFUE e dell'articolo 106 bis del trattato Euratom.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "43": {"label": "Articolo 43", "heading": "Struttura del bilancio", "anchor": "art_43", "frags": [[null, "<p class=\"norm\">Il bilancio comporta la seguente struttura:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>uno stato generale delle entrate e delle spese;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>sezioni distinte per ciascuna istituzione, ad eccezione del Consiglio europeo e del Consiglio che rientrano nella stessa sezione del bilancio, divise in stati delle entrate e delle spese.</p>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Nomenclatura di bilancio", "anchor": "art_44", "frags": [[null, "<p class=\"norm\">1.  Le entrate della Commissione nonché le entrate e le spese delle altre istituzioni sono classificate dal Parlamento europeo e dal Consiglio in titoli, capitoli, articoli e voci secondo la loro natura o la loro destinazione.</p>"], [null, "<p class=\"norm\">2.  Lo stato delle spese della sezione della Commissione è presentato secondo una nomenclatura adottata dal Parlamento europeo e dal Consiglio e che comporta una classificazione per destinazione.</p>"], [null, "<p class=\"norm\">Ciascun titolo corrisponde a un settore politico e ciascun capitolo corrisponde, di norma, a un'attività.</p>"], [null, "<p class=\"norm\">Ciascun titolo può comportare stanziamenti operativi e stanziamenti amministrativi.</p>"], [null, "<p class=\"norm\">All'interno di ciascun titolo, gli stanziamenti amministrativi sono raggruppati in un unico capitolo.</p>"], [null, "<p class=\"norm\">3.  Quando sono presentati per destinazione, gli stanziamenti amministrativi per singoli titoli sono classificati come segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>spese relative al personale autorizzato dalla tabella dell'organico: alle menzioni corrispondono un importo di stanziamenti e un numero di posti in detta tabella dell'organico;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>spese relative al personale esterno e altre spese di cui all'articolo 26, paragrafo 1, primo comma, lettera b), finanziate a titolo della rubrica \"amministrazione\" del quadro finanziario pluriennale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>spese relative agli immobili e altre spese connesse, comprese la pulizia e la manutenzione, gli affitti, le telecomunicazioni, l'acqua, il gas e l'elettricità;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>spese relative al personale esterno e all'assistenza tecnica direttamente legati all'attuazione dei programmi.</p>\n</div>"], [null, "<p class=\"norm\">Tutte le spese amministrative della Commissione la cui natura è comune a più titoli sono riprese in uno stato riassuntivo distinto, secondo una classificazione per natura.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di classificazione del bilancio.</p>"]]}, "45": {"label": "Articolo 45", "heading": "Divieto di entrate negative", "anchor": "art_45", "frags": [[null, "<p class=\"norm\">1.  Il bilancio non tiene entrate negative.</p>"], [null, "<p class=\"norm\">2.  Le risorse proprie riscosse in applicazione della decisione 2007/436/CE, Euratom del Consiglio, del 7 giugno 2007, relativa al sistema delle risorse proprie delle Comunità europee (\n<span class=\"superscript\">7</span>\n), sono importi netti e come tali sono presentate nello stato riassuntivo delle entrate del bilancio.</p>"]]}, "46": {"label": "Articolo 46", "heading": "Stanziamenti accantonati", "anchor": "art_46", "frags": [[null, "<p class=\"norm\">1.  Ogni sezione del bilancio può comportare un titolo \"stanziamenti accantonati\". Gli stanziamenti sono iscritti in tale titolo nei seguenti casi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>al momento della formazione del bilancio non esiste un atto di base per l'azione interessata; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>vi è incertezza, sulla base di seri motivi, quanto alla sufficienza degli stanziamenti o alla possibilità di eseguire, in condizioni conformi al principio della sana gestione finanziaria, gli stanziamenti iscritti alle linee operative interessate.</p>\n</div>"], [null, "<p class=\"norm\">Gli stanziamenti di tale titolo possono essere utilizzati soltanto previo storno effettuato secondo la procedura di cui all'articolo 26, paragrafo 1, primo comma, lettera c), del presente regolamento nei casi in cui l'adozione dell'atto di base è soggetta alla procedura di cui all'articolo 294 TFUE, e secondo la procedura di cui all'articolo 27 del presente regolamento in tutti gli altri casi.</p>"], [null, "<p class=\"norm\">2.  In caso di gravi difficoltà d'esecuzione, la Commissione può proporre, nel corso dell'esercizio, uno storno di stanziamenti verso il titolo \"stanziamenti accantonati\". Il Parlamento europeo e il Consiglio decidono in merito a tali storni conformemente all'articolo 27.</p>"]]}, "47": {"label": "Articolo 47", "heading": "Riserva negativa", "anchor": "art_47", "frags": [[null, "<p class=\"norm\">La sezione del bilancio della Commissione può comportare una \"riserva negativa\", il cui importo massimo è limitato a 200 000 000  EUR. Tale riserva, che è iscritta in un titolo specifico, comprende unicamente stanziamenti di pagamento.</p>"], [null, "<p class=\"norm\">Tale riserva negativa è utilizzata entro la fine dell'esercizio, mediante storno, secondo la procedura di cui agli articoli 26 e 27.</p>"]]}, "48": {"label": "Articolo 48", "heading": "Riserva per gli aiuti d'urgenza", "anchor": "art_48", "frags": [[null, "<p class=\"norm\">1.  Il bilancio comporta, nella sezione della Commissione, una riserva per gli aiuti d'urgenza a favore di paesi terzi.</p>"], [null, "<p class=\"norm\">2.  La riserva di cui al paragrafo 1 è utilizzata entro la fine dell'esercizio, mediante storno, secondo la procedura di cui agli articoli 27 e 29.</p>"]]}, "49": {"label": "Articolo 49", "heading": "Presentazione del bilancio", "anchor": "art_49", "frags": [[null, "<p class=\"norm\">1.  Il bilancio presenta:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>nello stato generale delle entrate e delle spese:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>le previsioni di entrate dell'Unione per l'esercizio interessato ('anno n');</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>le entrate previste dell'esercizio precedente e le entrate dell'esercizio n - 2;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>gli stanziamenti d'impegno e di pagamento per l'anno n;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>gli stanziamenti d'impegno e di pagamento per l'esercizio precedente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">v)<span style=\"word-spacing: 15pt\"> </span>le spese impegnate e le spese pagate nel corso dell'esercizio n - 2, queste ultime espresse altresì come percentuale del bilancio dell'anno n;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">vi)<span style=\"word-spacing: 19pt\"> </span>i commenti appropriati a ciascuna suddivisione prevista all'articolo 44, paragrafo 1;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>in ogni sezione, le entrate e le spese nella stessa struttura di cui alla lettera a);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>con riguardo al personale:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>una tabella dell'organico che fissa, per ogni sezione, il numero dei posti per grado in ciascuna categoria e in ciascun quadro, e il numero dei posti permanenti e temporanei, di cui è autorizzata la presa a carico nei limiti degli stanziamenti;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>una tabella dell'organico retribuito sugli stanziamenti per la ricerca e lo sviluppo tecnologico per l'azione diretta e una tabella dell'organico retribuito sugli stessi stanziamenti per l'azione indiretta; le tabelle sono suddivise in categorie e gradi, con la distinzione tra posti permanenti e temporanei, di cui è autorizzata la presa a carico nei limiti degli stanziamenti;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>per quanto riguarda il personale scientifico e tecnico, la ripartizione può essere indicata per gruppi di gradi, alle condizioni stabilite per ciascun bilancio; la tabella dell'organico specifica quanti sono gli agenti del personale scientifico o tecnico altamente qualificati ai quali sono attribuiti i vantaggi speciali previsti dalle disposizioni particolari dello statuto dei funzionari;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>una tabella dell'organico che fissa, per ciascun organismo di cui all'articolo 200 che riceve un contributo a carico del bilancio, il numero dei posti, per grado e per categoria. Le tabelle dell'organico indicano, accanto al numero dei posti autorizzati a titolo dell'esercizio, il numero dei posti autorizzati a titolo dell'esercizio precedente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>con riguardo all'assunzione e all'erogazione di prestiti:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>nello stato generale delle entrate, le linee di bilancio corrispondenti alle operazioni in questione, destinate a ricevere gli eventuali rimborsi di beneficiari inizialmente inadempienti, che hanno reso necessario il ricorso alla \"garanzia di buon fine\". Tali linee recano la dicitura \"per memoria\" e sono accompagnate dai commenti del caso;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>nella sezione della Commissione:</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>le linee di bilancio che presentano la \"garanzia di buon fine\" dell'Unione per le operazioni interessate. Tali linee recano la dicitura \"per memoria\", a condizione che non sussista alcun onere effettivo a tale titolo cui si debba far fronte con risorse definitive,</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>commenti che indicano il riferimento all'atto di base e il volume delle operazioni previste, la durata, nonché la garanzia finanziaria che l'Unione fornisce per lo svolgimento di tali operazioni;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>a titolo indicativo, in un documento allegato alla sezione della Commissione:</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>le operazioni in capitale e la gestione dell'indebitamento in corso,</p>\n</div>"], [null, "<div style=\"margin-left: 12pt; text-indent: -12pt; \">\n<p class=\"norm\">—<span style=\"word-spacing: 0\"> </span>le operazioni in capitale e la gestione dell'indebitamento per l'annon;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>con riguardo agli strumenti finanziari di cui al titolo VIII della parte prima:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>un riferimento all'atto di base;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>le linee di bilancio corrispondenti alle operazioni in questione;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>una descrizione generale degli strumenti finanziari, compresi la loro durata e il loro impatto sul bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>le operazioni previste, compresi i volumi bersaglio basati sull'indice di leva finanziaria risultante dagli strumenti finanziari esistenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>per quanto riguarda il finanziamento delle entità delegate ai sensi dell'articolo 58, paragrafo 1, lettera c), punto vii):</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>un riferimento all'atto di base del programma pertinente;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>le linee di bilancio corrispondenti;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>una descrizione generale delle funzioni affidate, compresi la loro durata e il loro impatto sul bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>l'importo totale delle spese della PESC iscritto in un capitolo denominato 'PESC', con articoli specifici. Tali articoli coprono la spesa per la PESC e contengono linee specifiche che individuano quantomeno le missioni principali.</p>\n</div>"], [null, "<p class=\"norm\">2.  Oltre ai documenti di cui al paragrafo 1, il Parlamento europeo e il Consiglio possono accludere al bilancio qualsiasi altro documento pertinente.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo alla presentazione del bilancio, inclusa una definizione delle spese effettive dell'ultimo esercizio chiuso, i commenti di bilancio e le tabelle dell'organico.</p>"]]}, "50": {"label": "Articolo 50", "heading": "Norme in materia di tabelle dell'organico", "anchor": "art_50", "frags": [[null, "<p class=\"norm\">1.  Le tabelle dell'organico di cui all'articolo 49, paragrafo 1, lettera c), costituiscono per ciascuna istituzione od organismo un limite tassativo; nessuna nomina può essere fatta oltre detto limite.</p>"], [null, "<p class=\"norm\">Ogni istituzione od organismo può tuttavia procedere a modifiche delle tabelle dell'organico fino a concorrenza del 10 % dei posti autorizzati, tranne che per i gradi AD 16, AD 15 e AD 14, alle seguenti condizioni:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>non incidere sul volume degli stanziamenti per il personale corrispondenti a un esercizio pieno;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>non superare il limite del numero totale di posti autorizzati per tabella dell'organico; e</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>l'istituzione o l'organismo ha partecipato a un esercizio di analisi comparativa con altre istituzioni e altri organismi dell'Unione quale avviato dall'esercizio di screening del personale della Commissione.</p>\n</div>"], [null, "<p class=\"norm\">Tre settimane prima di procedere alle modifiche di cui al secondo comma, le istituzioni informano il Parlamento europeo e il Consiglio delle proprie intenzioni in tal senso. Se durante tale periodo il Parlamento europeo o il Consiglio avanzano motivi debitamente giustificati, l'istituzione si astiene dalle modifiche e si applica la procedura di cui all'articolo 41.</p>"], [null, "<p class=\"norm\">2.  In deroga al paragrafo 1, primo comma, possono essere compensati i casi di attività a orario ridotto autorizzati dall'autorità che ha il potere di nomina, conformemente allo statuto dei funzionari.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "51": {"label": "Articolo 51", "heading": "Conformità rispetto al quadro finanziario pluriennale", "anchor": "art_51", "frags": [[null, "<p class=\"norm\">Il bilancio è stabilito nel rispetto del quadro finanziario pluriennale.</p>"]]}, "52": {"label": "Articolo 52", "heading": "Conformità degli atti dell'Unione rispetto al bilancio", "anchor": "art_52", "frags": [[null, "<p class=\"norm\">Se l'attuazione di un atto dell'Unione comporta il superamento degli stanziamenti disponibili nel bilancio, tale atto può essere attuato in termini finanziari solo dopo la conseguente rettifica del bilancio.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "53": {"label": "Articolo 53", "heading": "Esecuzione del bilancio in conformità del principio della sana gestione finanziaria", "anchor": "art_53", "frags": [[null, "<p class=\"norm\">1.  La Commissione esegue il bilancio in entrate e in spese conformemente al presente regolamento, sotto la propria responsabilità ed entro i limiti degli stanziamenti autorizzati.</p>"], [null, "<p class=\"norm\">2.  Gli Stati membri cooperano con la Commissione affinché gli stanziamenti siano utilizzati secondo il principio della sana gestione finanziaria.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate d'esecuzione del bilancio in conformità del principio della sana gestione finanziaria e a informazioni sul trasferimento dei dati personali a fini di revisione contabile.</p>"]]}, "54": {"label": "Articolo 54", "heading": "Atto di base e deroghe", "anchor": "art_54", "frags": [[null, "<p class=\"norm\">1.  Per l'esecuzione degli stanziamenti iscritti in bilancio per qualsiasi azione dell'Unione è preliminarmente adottato un atto di base.</p>"], [null, "<p class=\"norm\">2.  In deroga al paragrafo 1, possono essere eseguiti senza atto di base e a condizione che le azioni finanziate siano di competenza dell'Unione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>gli stanziamenti relativi a progetti pilota di natura sperimentale destinati ad accertare la fattibilità e l'utilità di un'azione. I pertinenti stanziamenti d'impegno possono essere iscritti in bilancio per non più di due esercizi consecutivi.</p>\n</div>"], [null, "<p class=\"list\">L'importo totale degli stanziamenti relativi ai progetti pilota non supera 40 000 000  EUR per esercizio;</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>gli stanziamenti relativi ad azioni preparatorie nei settori di applicazione del TFUE e del trattato Euratom, destinate all'elaborazione di proposte in vista dell'adozione di azioni future. Le azioni preparatorie obbediscono a un'impostazione coerente e possono rivestire forme diverse. I relativi stanziamenti d'impegno possono essere iscritti in bilancio per non più di tre esercizi consecutivi. La procedura per l'adozione dell'atto di base pertinente é conclusa prima della chiusura del terzo esercizio. Nel corso di detta procedura l'impegno degli stanziamenti rispetta le caratteristiche proprie dell'azione preparatoria con riguardo alle attività previste, agli obiettivi perseguiti e ai destinatari. Di conseguenza, i mezzi posti in atto non corrispondono, in volume, a quelli previsti per il finanziamento dell'azione definitiva stessa.</p>\n</div>"], [null, "<p class=\"list\">L'importo totale degli stanziamenti relativi alle azioni preparatorie nuove di cui alla presente lettera non supera 50 000 000  EUR per esercizio e la somma totale degli stanziamenti effettivamente impegnati a titolo delle azioni preparatorie non supera 100 000 000  EUR;</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>gli stanziamenti relativi a misure preparatorie nell'ambito del titolo V del TUE. Tali misure sono limitate a un periodo di tempo ridotto e destinate a creare le condizioni per l'azione dell'Unione volta al conseguimento degli obiettivi della PESC e per l'adozione dei necessari strumenti giuridici.</p>\n</div>"], [null, "<p class=\"list\">Ai fini delle operazioni dell'Unione di gestione delle crisi, le misure preparatorie sono destinate fra l'altro a valutare i requisiti operativi, a consentire una rapida assegnazione iniziale delle risorse o a creare le condizioni in loco per l'avvio dell'azione.</p>"], [null, "<p class=\"list\">Le misure preparatorie sono approvate dal Consiglio, su proposta dell'alto rappresentante.</p>"], [null, "<p class=\"list\">Per assicurare la rapida attuazione delle misure preparatorie, l'alto rappresentante informa il Parlamento europeo e la Commissione con la massima tempestività dell'intenzione del Consiglio di avviare un'azione preparatoria e comunica, in particolare, una stima delle risorse necessarie a tal fine. La Commissione adotta tutte le misure necessarie per garantire un rapido esborso dei fondi.</p>"], [null, "<p class=\"list\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di finanziamento delle misure preparatorie nel settore della PESC;</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>gli stanziamenti relativi ad azioni di natura puntuale, o permanente, svolte dalla Commissione in esecuzione di compiti connessi alle sue prerogative istituzionali in virtù del TFUE e del trattato Euratom diverse dal diritto di iniziativa legislativa di cui alla lettera b), nonché in esecuzione di competenze specifiche attribuitele direttamente da detti trattati ed elencate negli atti delegati adottati conformemente al presente regolamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>gli stanziamenti destinati al funzionamento di ciascuna istituzione, in virtù della sua autonomia amministrativa.</p>\n</div>"], [null, "<p class=\"norm\">All'atto della presentazione del progetto di bilancio, la Commissione presenta al Parlamento europeo e al Consiglio una relazione sulle azioni contemplate alle lettere a) e b) del primo comma, in cui si valutano i risultati ottenuti e si stabilisce l'eventuale seguito.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'atto di base e le eccezioni elencate al paragrafo 2 del presente articolo.</p>"]]}, "55": {"label": "Articolo 55", "heading": "Esecuzione del bilancio da parte di istituzioni diverse dalla Commissione", "anchor": "art_55", "frags": [[null, "<p class=\"norm\">La Commissione riconosce alle altre istituzioni i poteri necessari all'esecuzione delle rispettive sezioni del bilancio.</p>"], [null, "<p class=\"norm\">Possono essere concordate tra il SEAE e la Commissione modalità volte a facilitare l'esecuzione degli stanziamenti amministrativi delle delegazioni dell'Unione. Tali modalità non contemplano deroghe al presente regolamento o agli atti delegati adottati a norma dello stesso.</p>"]]}, "56": {"label": "Articolo 56", "heading": "Delega dei poteri d'esecuzione del bilancio", "anchor": "art_56", "frags": [[null, "<p class=\"norm\">1.  La Commissione e ciascuna delle altre istituzioni possono delegare, nell'ambito dei loro servizi, i propri poteri d'esecuzione del bilancio alle condizioni stabilite dal presente regolamento e dalle loro regole interne ed entro i limiti che esse fissano nell'atto di delegazione. I delegati agiscono entro i limiti dei poteri che sono loro espressamente conferiti.</p>"], [null, "<p class=\"norm\">2.  Tuttavia, la Commissione può delegare i propri poteri d'esecuzione del bilancio relativamente agli stanziamenti operativi figuranti nella sua sezione ai capi delle delegazioni dell'Unione. Essa ne informa al contempo l'alto rappresentante. Quando agiscono in qualità di ordinatori sottodelegati della Commissione, i capi delle delegazioni dell'Unione applicano le norme della Commissione in materia di esecuzione del bilancio e sono soggetti agli stessi doveri, obblighi e responsabilità di tutti gli altri ordinatori sottodelegati della Commissione.</p>"], [null, "<p class=\"norm\">La Commissione può revocare la delega conformemente alla propria regolamentazione.</p>"], [null, "<p class=\"norm\">Ai fini di quanto stabilito al primo comma, l'alto rappresentante adotta i provvedimenti necessari per facilitare la collaborazione tra le delegazioni dell'Unione e i servizi della Commissione.</p>"]]}, "57": {"label": "Articolo 57", "heading": "Conflitto d'interessi", "anchor": "art_57", "frags": [[null, "<p class=\"norm\">1.  Gli agenti finanziari e le altre persone partecipanti all'esecuzione del bilancio e alla gestione, compresi i relativi atti preparatori, alla revisione contabile o al controllo non adottano azioni da cui possa derivare un conflitto tra i loro interessi e quelli dell'Unione.</p>"], [null, "<p class=\"norm\">Laddove esista un rischio di questo tipo, la persona in questione si astiene da tali azioni e ne informa l'ordinatore delegato, che conferma per iscritto l'esistenza di un conflitto d'interessi. La persona in questione informa altresì il suo superiore gerarchico. Qualora si accerti l'esistenza di un conflitto d'interessi, la persona in questione cessa ogni sua attività nella materia. L'ordinatore delegato intraprende personalmente qualsiasi altra azione appropriata.</p>"], [null, "<p class=\"norm\">2.  Ai fini del paragrafo 1, esiste un conflitto d'interessi quando l'esercizio imparziale e obiettivo delle funzioni di un agente finanziario o di un'altra persona di cui al paragrafo 1, è compromesso da motivi familiari, affettivi, da affinità politica o nazionale, da interesse economico o da qualsiasi altra comunanza d'interessi con il destinatario.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 che definiscano ciò che potrebbe dare adito a un conflitto d'interessi, nonché la procedura da seguire in tale eventualità.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "58": {"label": "Articolo 58", "heading": "Metodi d'esecuzione del bilancio", "anchor": "art_58", "frags": [[null, "<p class=\"norm\">1.  La Commissione esegue il bilancio secondo i metodi seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>direttamente (\"gestione diretta\"), a opera dei suoi servizi, compreso il suo personale presso le delegazioni dell'Unione sotto la supervisione del rispettivo capo delegazione, a norma dell'articolo 56, paragrafo 2, o tramite le agenzie esecutive di cui all'articolo 62;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>nell'ambito della gestione concorrente con gli Stati membri (\"gestione concorrente\"); oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>indirettamente (\"gestione indiretta\"), se l'atto di base lo prevede o nei casi di cui all'articolo 54, paragrafo 2, primo comma, lettere da a) a d), affidando compiti d'esecuzione del bilancio:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>a paesi terzi o organismi da questi designati;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>a organizzazioni internazionali e rispettive agenzie;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>alla BEI e al Fondo europeo per gli investimenti;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>agli organismi di cui agli articoli 208 e 209;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">v)<span style=\"word-spacing: 15pt\"> </span>a organismi di diritto pubblico;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">vi)<span style=\"word-spacing: 19pt\"> </span>organismi di diritto privato investiti di attribuzioni di servizio pubblico nella misura in cui presentano sufficienti garanzie finanziarie;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">vii)<span style=\"word-spacing: 23pt\"> </span>a organismi di diritto privato di uno Stato membro, preposti all'attuazione di un partenariato pubblico-privato e che presentano sufficienti garanzie finanziarie;</p>\n</div>"], [null, "<div style=\"margin-left: 42pt; text-indent: -42pt\">\n<p class=\"norm\">viii)<span style=\"word-spacing: 27pt\"> </span>alle persone incaricate di attuare azioni specifiche della PESC di cui al titolo V del TUE, che devono essere indicate nel pertinente atto di base.</p>\n</div>"], [null, "<p class=\"norm\">2.  La Commissione rimane responsabile dell'esecuzione del bilancio a norma dell'articolo 317 TFUE e informa il Parlamento europeo e il Consiglio delle operazioni eseguite dalle entità e dalle persone delegate conformemente al paragrafo 1, lettera c), del presente articolo. Qualora l'entità o la persona delegata sia indicata in un atto di base, la scheda finanziaria di cui all'articolo 31 comprende una giustificazione completa della scelta di quella particolare entità o persona.</p>"], [null, "<p class=\"norm\">3.  Le entità e le persone delegate conformemente al paragrafo 1, lettera c), del presente articolo cooperano pienamente nella tutela degli interessi finanziari dell'Unione. Gli accordi di delega contemplano il diritto della Corte dei conti e dell'Ufficio europeo per la lotta antifrode (OLAF) di esercitare globalmente le loro competenze previste dal TFUE nel controllo dei fondi.</p>"], [null, "<p class=\"norm\">La Commissione affida dei compiti d'esecuzione del bilancio alle entità e alle persone di cui al paragrafo 1, lettera c), del presente articolo, a condizione che esistano procedure di ricorso trasparenti, non discriminatorie, efficienti ed efficaci per quanto riguarda l'effettivo espletamento di tali compiti.</p>"], [null, "<p class=\"norm\">4.  Tutti gli accordi di delega sono messi a disposizione del Parlamento europeo e del Consiglio su loro richiesta.</p>"], [null, "<p class=\"norm\">5.  Le entità e le persone delegate conformemente al paragrafo 1, lettera c), provvedono, a norma dell'articolo 35, paragrafo 2, del presente articolo, a una corretta pubblicazione annuale a posteriori delle informazioni sui destinatari. La Commissione è informata delle misure adottate a tale riguardo.</p>"], [null, "<p class=\"norm\">6.  Le entità e le persone delegate conformemente al paragrafo 1, lettera c), non hanno lo status di ordinatore delegato.</p>"], [null, "<p class=\"norm\">7.  La Commissione non conferisce i poteri d'esecuzione a terzi, ove detti poteri implichino un ampio margine di discrezionalità tale da esprimere scelte politiche.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">8.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i metodi d'esecuzione del bilancio, inclusa la gestione diretta, l'esercizio dei poteri delegati alle agenzie esecutive e disposizioni specifiche per la gestione indiretta con le organizzazioni internazionali, con gli organismi di cui agli articoli 208 e 209, con organismi di diritto pubblico od organismi di diritto privato investiti di attribuzioni di servizio pubblico, con organismi di diritto privato di uno Stato membro incaricati dell'attuazione di un partenariato pubblico-privato e con persone incaricate di attuare azioni specifiche nel settore della PESC. Alla Commissione è conferito altresì il potere di adottare atti delegati conformemente all'articolo 210 riguardo ai criteri per assimilare le organizzazioni senza scopo di lucro a organizzazioni internazionali.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "59": {"label": "Articolo 59", "heading": "Gestione concorrente con gli Stati membri", "anchor": "art_59", "frags": [[null, "<p class=\"norm\">1.  Quando la Commissione esegue il bilancio nell'ambito della gestione concorrente, i compiti d'esecuzione sono delegati agli Stati membri. La Commissione e gli Stati membri rispettano i principi della sana gestione finanziaria, trasparenza e non discriminazione e garantiscono la visibilità dell'azione dell'Unione nella gestione dei fondi dell'Unione. A tal fine, la Commissione e gli Stati membri assolvono i rispettivi obblighi in materia di controllo e revisione contabile e assumono le conseguenti responsabilità stabilite dal presente regolamento. La normativa settoriale stabilisce disposizioni complementari.</p>"], [null, "<p class=\"norm\">2.  Nell'ambito dell'espletamento delle funzioni connesse all'esecuzione del bilancio, gli Stati membri adottano tutte le misure necessarie, comprese misure legislative, regolamentari e amministrative, per tutelare gli interessi finanziari dell'Unione, vale a dire:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>assicurano che le azioni finanziate a titolo del bilancio siano eseguite effettivamente e correttamente e in conformità della normativa settoriale applicabile, e a tal fine designano conformemente al paragrafo 3 e sorvegliano gli organismi responsabili della gestione e del controllo dei fondi dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>prevengono, individuano e rettificano le irregolarità e le frodi.</p>\n</div>"], [null, "<p class=\"norm\">Al fine di tutelare gli interessi finanziari dell'Unione, nel rispetto del principio di proporzionalità e in conformità del presente articolo nonché della normativa settoriale pertinente, gli Stati membri effettuano controlli <span class=\"italics\">ex ante</span> ed <span class=\"italics\">ex post</span>, compresi, se opportuno, controlli sul posto su campioni di operazioni rappresentativi e/o basati sul rischio. Essi recuperano inoltre i fondi versati indebitamente e, se necessario, avviano azioni legali.</p>"], [null, "<p class=\"norm\">Gli Stati membri applicano sanzioni effettive, dissuasive e proporzionate ai destinatari ove previsto dalla normativa settoriale e dalle disposizioni specifiche dell'ordinamento nazionale.</p>"], [null, "<p class=\"norm\">Nel quadro della sua valutazione del rischio e in conformità della normativa settoriale, la Commissione sorveglia i sistemi di gestione e di controllo istituiti negli Stati membri. Nel quadro della sua attività di revisione contabile, la Commissione rispetta il principio di proporzionalità e tiene conto del livello di rischio valutato in conformità della normativa settoriale.</p>"], [null, "<p class=\"norm\">3.  Conformemente ai criteri e alle procedure stabiliti nella normativa settoriale, gli Stati membri designano, al livello appropriato, organismi responsabili della gestione e del controllo dei fondi dell'Unione. Tali organismi possono espletare altresì funzioni non connesse alla gestione dei fondi dell'Unione e possono affidare taluni loro compiti ad altri organismi.</p>"], [null, "<p class=\"norm\">Per decidere in merito alla designazione degli organismi, gli Stati membri possono considerare se i sistemi di gestione e di controllo sono sostanzialmente gli stessi del periodo di programmazione precedente e se il loro funzionamento è stato efficace.</p>"], [null, "<p class=\"norm\">Se dai risultati della revisione contabile e dei controlli emerge che gli organismi designati non rispettano più i criteri stabiliti nella normativa settoriale, gli Stati membri adottano le misure necessarie per assicurare che sia posto rimedio alle carenze a livello dell'espletamento delle funzioni di tali organismi, fra l'altro mettendo fine alla designazione in conformità della normativa settoriale.</p>"], [null, "<p class=\"norm\">La normativa settoriale definisce il ruolo della Commissione nella procedura stabilita nel presente paragrafo.</p>"], [null, "<p class=\"norm\">4.  Gli organismi designati a norma del paragrafo 3:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>istituiscono un sistema di controllo interno efficace ed efficiente e ne garantiscono il funzionamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>utilizzano una contabilità che fornisce tempestivamente dati precisi, completi e attendibili;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>forniscono le informazioni richieste al paragrafo 5;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>provvedono alla pubblicazione a posteriori conformemente all'articolo 35, paragrafo 2. Il trattamento dei dati personali rispetta le disposizioni nazionali che attuano la direttiva 95/46/CE.</p>\n</div>"], [null, "<p class=\"norm\">5.  Gli organismi designati a norma del paragrafo 3 trasmettono alla Commissione, entro il 15 febbraio dell'esercizio successivo, la seguente documentazione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>i rispettivi conti relativi alle spese che sono state sostenute, durante il pertinente periodo di riferimento quale definito nella normativa settoriale, per l'esecuzione dei loro compiti e che sono state presentate alla Commissione a fini di rimborso. Tali conti includono i prefinanziamenti e gli importi per i quali sono in corso o sono state completate procedure di recupero. Essi sono corredati di una dichiarazione di gestione la quale conferma che, secondo i responsabili della gestione dei fondi:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>le informazioni sono presentate correttamente, complete ed esatte,</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>le spese sono state effettuate per le finalità previste, quali definite nella normativa settoriale,</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>i sistemi di controllo predisposti offrono le necessarie garanzie quanto alla legittimità e regolarità delle operazioni sottostanti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un riepilogo annuale delle relazioni finali di revisione contabile e dei controlli effettuati, comprese un'analisi della natura e della portata degli errori e delle carenze individuati nei sistemi, come anche le azioni correttive avviate o programmate.</p>\n</div>"], [null, "<p class=\"norm\">I conti di cui alla lettera a) del primo comma e il riepilogo di cui alla lettera b) del primo comma sono corredati del parere di un organismo di revisione contabile indipendente elaborato conformemente alle pertinenti norme internazionalmente riconosciute. Detto parere accerta se i conti forniscono un quadro fedele, se le spese per le quali la Commissione ha chiesto il rimborso sono legali e regolari e se i sistemi di controllo istituiti funzionano correttamente. Il parere riferisce altresì se l'esercizio di revisione contabile mette in dubbio le asserzioni contenute nella dichiarazione di gestione di cui alla lettera a) del primo comma.</p>"], [null, "<p class=\"norm\">Il termine del 15 febbraio può essere eccezionalmente prorogato dalla Commissione al 1<span class=\"superscript\">o</span> marzo, previa comunicazione dello Stato membro interessato.</p>"], [null, "<p class=\"norm\">Gli Stati membri possono, al livello appropriato, pubblicare le informazioni di cui al presente paragrafo.</p>"], [null, "<p class=\"norm\">Inoltre, essi possono fornire dichiarazioni firmate al livello appropriato sulla base delle informazioni di cui al presente paragrafo.</p>"], [null, "<p class=\"norm\">6.  Al fine di garantire che i fondi dell'Unione siano utilizzati secondo le norme applicabili, la Commissione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>applica procedure ai fini dell'esame e dell'accettazione dei conti degli organismi designati, stabilendo la completezza, l'esattezza e la verità dei conti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>esclude dal finanziamento dell'Unione le spese per le quali gli esborsi sono stati effettuati in violazione del diritto applicabile;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>interrompe i termini di pagamento o sospende i pagamenti se previsto dalla normativa settoriale.</p>\n</div>"], [null, "<p class=\"norm\">La Commissione pone fine in tutto o in parte all'interruzione dei termini di pagamento o alla sospensione dei pagamenti dopo che uno Stato membro ha presentato le proprie osservazioni e non appena ha adottato le misure necessarie. La relazione annuale di attività di cui all'articolo 66, paragrafo 9, comprende tutti gli obblighi previsti dal presente comma.</p>"], [null, "<p class=\"norm\">7.  La normativa settoriale tiene conto delle esigenze dei programmi europei di cooperazione territoriale per quanto riguarda, in particolare, il contenuto della dichiarazione di gestione, il processo stabilito al paragrafo 3 e la funzione di revisione contabile.</p>"], [null, "<p class=\"norm\">8.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la gestione concorrente con gli Stati membri, compresa la compilazione di un registro degli organismi responsabili della gestione e del controllo dei fondi dell'Unione, e a misure intese a promuovere le migliori pratiche.</p>"]]}, "60": {"label": "Articolo 60", "heading": "Gestione indiretta", "anchor": "art_60", "frags": [[null, "<p class=\"norm\">1.  Le entità e le persone cui sono state affidate funzioni di esecuzione del bilancio a norma dell'articolo 58, paragrafo 1, lettera c), rispettano i principi di sana gestione finanziaria, trasparenza e non discriminazione e garantiscono la visibilità dell'azione dell'Unione nella gestione dei fondi dell'Unione. Nella gestione dei fondi dell'Unione esse garantiscono un grado di tutela degli interessi finanziari dell'Unione equivalente a quello richiesto ai sensi del presente regolamento, tenendo debitamente conto dei seguenti elementi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>la natura delle funzioni loro affidate e gli importi in questione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i rischi finanziari sostenuti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il grado di affidabilità garantito dai loro sistemi, norme e procedure unitamente alle misure adottate dalla Commissione per sorvegliare e coadiuvare l'espletamento delle funzioni loro affidate.</p>\n</div>"], [null, "<p class=\"norm\">2.  Al fine di tutelare gli interessi finanziari dell'Unione, le entità e le persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), in conformità del principio di proporzionalità:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>istituiscono un sistema di controllo interno efficace ed efficiente e ne garantiscono il funzionamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>utilizzano una contabilità che fornisce tempestivamente dati precisi, completi e attendibili;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>sono sottoposte a una revisione contabile esterna indipendente, svolta, conformemente alle pertinenti norme internazionalmente riconosciute, da un servizio di revisione contabile funzionalmente indipendente dall'entità o persona interessata;</p>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>applicano idonee norme e procedure per erogare finanziamenti a titolo dei fondi dell'Unione tramite appalti, sovvenzioni, premi e strumenti finanziari, compresi gli obblighi di cui all'articolo 108, paragrafo 12;</p>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>provvedono, a norma dell'articolo 35, paragrafo 2, alla pubblicazione <span class=\"italics\">ex post</span> di informazioni sui destinatari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>garantiscono un ragionevole grado di tutela dei dati personali, come previsto dalla direttiva 95/46/CE e dal regolamento (CE) n. 45/2001.</p>\n</div>"], [null, "<p class=\"norm\">Le persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), punto viii), adottano le proprie norme finanziarie previo accordo della Commissione. Esse soddisfano i requisiti stabiliti alle lettere da a) a e) del presente paragrafo entro sei mesi dall'inizio del loro mandato. Se al termine di tale periodo esse soddisfano tali requisiti solo in parte, la Commissione adotta adeguate misure correttive per sorvegliare e coadiuvare l'espletamento delle funzioni loro affidate.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">3.  Nell'ambito dell'espletamento delle funzioni connesse all'esecuzione del bilancio, le entità e le persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), prevengono, individuano, rettificano e notificano alla Commissione le irregolarità e le frodi. A tal fine effettuano, conformemente al principio di proporzionalità, controlli ex ante ed ex post, compresi, se opportuno, controlli sul posto su campioni di operazioni rappresentativi e/o basati sul rischio, per garantire l'effettivo svolgimento e la corretta attuazione delle azioni finanziate a titolo del bilancio. Recuperano inoltre i fondi versati indebitamente, escludono dall'accesso ai fondi dell'Unione o irrogano sanzioni pecuniarie e, se necessario, avviano azioni legali a tale riguardo.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">4.  La Commissione può sospendere i pagamenti alle entità e persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), in particolare qualora vengano rilevati errori sistemici che mettono in dubbio l'attendibilità dei sistemi di controllo interno dell'entità o persona interessata ovvero della legittimità e regolarità delle operazioni sottostanti.</p>"], [null, "<p class=\"norm\">In deroga all'articolo 92, l'ordinatore responsabile può interrompere, in tutto o in parte, i pagamenti a tali entità o persone al fine di effettuare ulteriori controlli allorché:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>all'ordinatore responsabile giungano indicazioni di gravi carenze nel funzionamento del sistema di controllo interno o che le spese certificate dall'entità o persona in questione sono correlate a una irregolarità grave e non sono state rettificate,</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>l'interruzione è necessaria per evitare un grave pregiudizio per gli interessi finanziari dell'Unione.</p>\n</div>"], [null, "<p class=\"norm\">5.  Fatto salvo il paragrafo 7, le entità e le persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), trasmettono alla Commissione la seguente documentazione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>una relazione sull'espletamento delle funzioni loro affidate;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i rispettivi conti relativi alle spese sostenute per l'esecuzione dei compiti loro affidati. Tali conti sono corredati di una dichiarazione di gestione la quale conferma che, secondo i responsabili della gestione dei fondi:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>le informazioni sono presentate correttamente, complete ed esatte,</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>le spese sono state effettuate per le finalità previste, quali definite negli accordi di delega o, se del caso, nella pertinente normativa settoriale,</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>i sistemi di controllo predisposti offrono le necessarie garanzie quanto alla legittimità e regolarità delle operazioni sottostanti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>un riepilogo delle relazioni finali di revisione contabile e dei controlli effettuati, comprese un'analisi della natura e della portata degli errori e delle carenze individuati nei sistemi, come anche le azioni correttive avviate o programmate.</p>\n</div>"], [null, "<p class=\"norm\">I documenti di cui al primo comma sono corredati del parere di un organismo di revisione contabile indipendente elaborato conformemente alle pertinenti norme internazionalmente riconosciute. Detto parere accerta se i conti forniscono un quadro fedele, se i sistemi di controllo istituiti funzionano correttamente e se le operazioni sottostanti sono legittime e regolari. Il parere riferisce altresì se l'esercizio di revisione contabile mette in dubbio le asserzioni contenute nella dichiarazione di gestione di cui al primo comma, lettera b).</p>"], [null, "<p class=\"norm\">La documentazione di cui al primo comma è trasmessa alla Commissione entro il 15 febbraio dell'esercizio successivo. Il parere di cui al secondo comma è trasmesso entro il 15 marzo.</p>"], [null, "<p class=\"norm\">Gli obblighi stabiliti nel presente paragrafo fanno salve le convenzioni concluse con organizzazioni internazionali e paesi terzi. Tali convenzioni prevedono almeno l'obbligo per tali organizzazioni internazionali e paesi terzi di trasmettere ogni anno alla Commissione l'attestazione che, nell'esercizio interessato, il contributo dell'Unione è stato utilizzato e contabilizzato rispettando i requisiti di cui al paragrafo 2 e tali convenzioni</p>"], [null, "<p class=\"norm\">6.  Fatto salvo il paragrafo 7, la Commissione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>vigila affinché dette persone ed entità ottemperino alle loro responsabilità, in particolare effettuando revisioni contabili e valutazioni sull'esecuzione dei programmi;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>applica procedure ai fini dell'esame e dell'accettazione dei conti delle entità e persone delegate, che garantiscano la completezza, l'esattezza e la verità dei conti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>esclude dalle spese dell'Unione a titolo di finanziamenti gli esborsi effettuati in violazione del diritto dell'Unione.</p>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">7.  I paragrafi 5 e 6 non si applicano al contributo dell'Unione alle entità oggetto di una procedura di discarico distinta a norma degli articoli 208 e 209.</p>"], [null, "<p class=\"norm\">8.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la gestione indiretta, comprese la definizione delle condizioni, nell'ambito della gestione indiretta, alle quali i sistemi, le norme e le procedure di entità e persone devono essere equivalenti a quelle della Commissione, le dichiarazioni di gestione e le dichiarazioni di conformità, nonché le procedure per l'esame e l'accettazione dei conti, l'obbligo di notificare alla Commissione le frodi e le irregolarità individuate, l'esclusione dai finanziamenti dell'Unione delle spese sostenute in violazione delle norme applicabili e l'irrogazione di sanzioni pecuniarie.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "61": {"label": "Articolo 61", "heading": "Valutazioni ex ante e accordi di delega", "anchor": "art_61", "frags": [[null, "<p class=\"norm\">1.  Prima di affidare compiti d'esecuzione del bilancio a entità o persone a norma dell'articolo 58, paragrafo 1, lettera c), la Commissione ottiene la prova del soddisfacimento dei requisiti di cui all'articolo 60, paragrafo 2, primo comma, lettere da a) a d).</p>"], [null, "<p class=\"norm\">Qualora siano apportate variazioni sostanziali ai sistemi o alle norme di un'entità o persona delegate a norma dell'articolo 58, paragrafo 1, lettera c), o alle procedure connesse alla gestione dei fondi dell'Unione che le sono affidati, l'entità o la persona interessata informa immediatamente la Commissione al riguardo. La Commissione riesamina gli accordi di delega conclusi con l'entità o la persona interessata per garantire che continuino a essere soddisfatti i requisiti di cui all'articolo 60, paragrafo 2, primo comma, lettere da a) a d).</p>"], [null, "<p class=\"norm\">2.  Salvo indicazione dell'entità delegata nell'atto di base, la Commissione sceglie un'entità in una delle categorie di cui all'articolo 58, paragrafo 1, lettera c), punti ii), v), vi) e vii), tenendo debito conto della natura dei compiti da affidare, nonché dell'esperienza e della capacità operativa e finanziaria delle entità interessate. La scelta è trasparente, giustificata da ragioni oggettive e non dà luogo a conflitti d'interessi.</p>"], [null, "<p class=\"norm\">3.  Gli accordi di delega fissano i requisiti di cui all'articolo 60, paragrafo 2, primo comma, lettere da a) a d). Definiscono esattamente compiti affidati all'entità e comprendono un impegno da parte delle entità o persone interessate a rispettare gli obblighi stabiliti dall'articolo 60, paragrafo 2, primo comma, lettere e) e f), nonché ad astenersi da azioni che possano generare conflitti d'interessi.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la valutazione <span class=\"italics\">ex ante</span> delle norme e delle procedure nell'ambito della gestione indiretta e il contenuto degli accordi di delega.</p>"]]}, "62": {"label": "Articolo 62", "heading": "Agenzie esecutive", "anchor": "art_62", "frags": [[null, "<p class=\"norm\">1.  La Commissione può delegare alle agenzie esecutive l'attuazione in tutto o in parte di un programma o di un progetto dell'Unione, per proprio conto e sotto la sua responsabilità, a norma del regolamento (CE) n. 58/2003 del Consiglio, del 19 dicembre 2002, che definisce lo statuto delle agenzie esecutive incaricate dello svolgimento di alcuni compiti relativi alla gestione dei programmi comunitari (\n<span class=\"superscript\">8</span>\n). Le agenzie esecutive sono istituite con decisione della Commissione e sono persone giuridiche ai sensi del diritto dell'Unione.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di esercizio dei poteri delegati alle agenzie esecutive.</p>"], [null, "<p class=\"norm\">2.  Il direttore dell'agenzia esecutiva esegue gli stanziamenti operativi corrispondenti nell'ambito della gestione diretta.</p>"]]}, "63": {"label": "Articolo 63", "heading": "Limiti della delega dei poteri", "anchor": "art_63", "frags": [[null, "<p class=\"norm\">1.  La Commissione non affida compiti connessi all'esecuzione dei fondi dell'Unione, compresi il pagamento e la riscossione, a entità od organismi esterni di diritto privato, ad eccezione del caso previsto all'articolo 58, paragrafo 1, lettera c), punti v), vi) e vii), o di casi specifici in cui i pagamenti in questione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>sono da versare a beneficiari determinati dalla Commissione;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>sono soggetti a condizioni e importi stabiliti dalla Commissione; e</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>non implicano l'esercizio di potere discrezionale da parte dell'entità o dell'organismo che procede al loro versamento.</p>\n</div>"], [null, "<p class=\"norm\">2.  Ad entità od organismi esterni di diritto privato non investiti di attribuzioni di servizio pubblico la Commissione può affidare, mediante contratto, i seguenti compiti: compiti di perizia tecnica e compiti amministrativi, preparatori o accessori che non implichino l'esercizio né di potestà pubbliche, né di un potere di apprezzamento discrezionale.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di affidamento dei compiti a taluni entità od organismi esterni del settore privato in conformità delle norme in materia di appalti di cui nel titolo V della parte prima.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "64": {"label": "Articolo 64", "heading": "Separazione delle funzioni", "anchor": "art_64", "frags": [[null, "<p class=\"norm\">1.  Le funzioni di ordinatore e di contabile sono separate e tra loro esclusive.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate concernenti i diritti e gli obblighi di tutti gli agenti finanziari.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "65": {"label": "Articolo 65", "heading": "L'ordinatore", "anchor": "art_65", "frags": [[null, "<p class=\"norm\">1.  Le funzioni di ordinatore sono esercitate da ogni istituzione.</p>"], [null, "<p class=\"norm\">2.  Ai fini del presente titolo, il termine \"funzionari\" indica le persone soggette allo statuto dei funzionari.</p>"], [null, "<p class=\"norm\">3.  Ogni istituzione delega, nel rispetto delle condizioni previste dal rispettivo regolamento interno, le funzioni di ordinatore a funzionari di livello adeguato. Essa stabilisce nelle proprie regole amministrative interne i funzionari ai quali delega dette funzioni, i limiti dei poteri conferiti e se le persone alle quali sono delegati tali poteri possono sottodelegarli.</p>"], [null, "<p class=\"norm\">4.  Le deleghe e le sottodeleghe delle funzioni di ordinatore sono accordate soltanto a funzionari.</p>"], [null, "<p class=\"norm\">5.  Gli ordinatori responsabili agiscono entro i limiti stabiliti dall'atto di delega o di sottodelega. L'ordinatore responsabile può essere assistito nell'espletamento delle sue funzioni da uno o più funzionari incaricati di effettuare, sotto la sua responsabilità, determinate operazioni necessarie ai fini dell'esecuzione del bilancio e della rendicontazione.</p>"], [null, "<p class=\"norm\">6.  Quando agiscono in qualità di ordinatori sottodelegati della Commissione conformemente all'articolo 56, paragrafo 2, i capi delle delegazioni dell'Unione fanno capo alla Commissione in quanto istituzione responsabile della definizione, dell'esercizio, della sorveglianza e della valutazione delle loro funzioni e responsabilità di ordinatori sottodelegati. La Commissione ne informa allo stesso tempo l'alto rappresentante.</p>"], [null, "<p class=\"norm\">7.  L'ordinatore responsabile può essere assistito nell'espletamento delle sue funzioni da funzionari incaricati di svolgere, sotto la sua responsabilità, determinati compiti necessari ai fini dell'esecuzione del bilancio e della produzione delle informazioni finanziarie e di gestione. I funzionari che assistono gli ordinatori responsabili sono soggetti all'articolo 57.</p>"], [null, "<p class=\"norm\">8.  Ogni istituzione informa la Corte di conti, il Parlamento europeo e il Consiglio della nomina e della cessazione dalle funzioni degli ordinatori delegati, dei revisori interni e dei contabili, nonché delle regole interne che adotta in materia finanziaria.</p>"], [null, "<p class=\"norm\">9.  Ogni istituzione informa la Corte dei conti della nomina degli amministratori degli anticipi e delle deleghe a norma dell'articolo 69, paragrafo 1, e dell'articolo 70.</p>"], [null, "<p class=\"norm\">10.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di assistenza fornita agli ordinatori responsabili, e alle disposizioni interne che disciplinano le deleghe.</p>"]]}, "66": {"label": "Articolo 66", "heading": "Poteri e funzioni dell'ordinatore", "anchor": "art_66", "frags": [[null, "<p class=\"norm\">1.  L'ordinatore è incaricato in ogni istituzione di eseguire le entrate e le spese secondo il principio della sana gestione finanziaria e di garantirne la legittimità e la regolarità.</p>"], [null, "<p class=\"norm\">2.  Ai fini del paragrafo 1 l'ordinatore delegato pone in atto, conformemente all'articolo 32 e alle norme minime stabilite da ogni istituzione e tenendo conto dei rischi inerenti alle caratteristiche della gestione e alla natura delle azioni finanziate, la struttura organizzativa nonché i sistemi di controllo interno adeguati all'esecuzione dei suoi compiti. L'istituzione della struttura e dei sistemi in questione si fonda su un'analisi globale dei rischi che tiene conto del loro rapporto costo/efficacia.</p>"], [null, "<p class=\"norm\">3.  Per eseguire le spese, l'ordinatore responsabile procede agli impegni di bilancio e giuridici, alla liquidazione delle spese e all'emissione degli ordini di pagamento, nonché agli atti preliminari necessari per l'esecuzione degli stanziamenti.</p>"], [null, "<p class=\"norm\">4.  L'esecuzione delle entrate comporta la formazione delle previsioni di crediti, l'accertamento dei diritti da recuperare e l'emissione degli ordini di riscossione. Comporta anche, se necessario, la rinuncia ai crediti accertati.</p>"], [null, "<p class=\"norm\">5.  Ogni operazione è sottoposta ad almeno un controllo <span class=\"italics\">ex ante</span> fondato su un'analisi documentale e sui risultati disponibili di controlli già effettuati, concernente gli aspetti operativi e finanziari dell'operazione.</p>"], [null, "<p class=\"norm\">I controlli <span class=\"italics\">ex ante</span> comprendono l'avvio e la verifica di un'operazione.</p>"], [null, "<p class=\"norm\">Per una data operazione, la verifica è effettuata da funzionari diversi da quelli che hanno avviato l'operazione. I funzionari che effettuano la verifica non sono essi subordinati ai funzionari che hanno avviato l'operazione.</p>"], [null, "<p class=\"norm\">6.  L'ordinatore delegato può predisporre controlli <span class=\"italics\">ex post</span> per verificare operazioni già autorizzate in esito a controlli <span class=\"italics\">ex ante</span>. Tali controlli possono essere organizzati come controlli a campione in funzione del rischio.</p>"], [null, "<p class=\"norm\">I controlli <span class=\"italics\">ex ante</span> sono svolti da funzionari diversi da quelli responsabili dei controlli <span class=\"italics\">ex post</span>. I funzionari responsabili dei controlli <span class=\"italics\">ex post</span> non sono subordinati ai funzionari responsabili dei controlli <span class=\"italics\">ex ante</span>.</p>"], [null, "<p class=\"norm\">Qualora l'ordinatore delegato esegua audit finanziari di beneficiari quali controlli <span class=\"italics\">ex post</span>, le relative norme in materia di audit sono chiare, coerenti e trasparenti, e rispettano sia i diritti della Commissione che quelli dei servizi sottoposti ad audit.</p>"], [null, "<p class=\"norm\">7.  I funzionari incaricati del controllo della gestione delle operazioni finanziarie dispongono delle necessarie competenze professionali. Essi rispettano un codice deontologico deciso da ciascuna istituzione.</p>"], [null, "<p class=\"norm\">8.  Se un funzionario partecipante alla gestione finanziaria e al controllo delle operazioni ritiene irregolare o contraria al principio della sana gestione finanziaria o alle regole deontologiche che vincolano i funzionari, una decisione la cui applicazione o accettazione gli sia stata imposta da un superiore, ne informa il suo superiore gerarchico. Se il funzionario lo informa per iscritto, il superiore gerarchico risponde per iscritto. In caso d'inerzia del superiore gerarchico o qualora egli confermi la decisione o l'istruzione iniziale e il funzionario consideri tale conferma insufficiente rispetto alla sua preoccupazione, il funzionario ne informa per iscritto l'ordinatore delegato. In caso d'inerzia di quest'ultimo funzionario, il funzionario informa l'istanza pertinente di cui all'articolo 73, paragrafo 6.</p>"], [null, "<p class=\"norm\">In caso di attività illecite, di frode o di corruzione che possano ledere gli interessi dell'Unione, il funzionario informa le autorità e le istanze designate dalla legislazione in vigore. I contratti conclusi con revisori esterni che sottopongono a revisione contabile la gestione finanziaria dell'Unione prevedono, per il revisore esterno, l'obbligo di informare l'ordinatore delegato in merito a qualsiasi sospetto di attività illecita, frode o corruzione che possano ledere gli interessi dell'Unione.</p>"], [null, "<p class=\"norm\">9.  L'ordinatore delegato rende conto alla propria istituzione dell'esercizio delle sue funzioni mediante una relazione annuale di attività contenente informazioni finanziarie e di gestione, compresi i risultati dei controlli, in cui dichiara che, salvo se diversamente specificato nelle riserve collegate a determinati settori di entrate e spese, ha la ragionevole certezza che:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le informazioni figuranti nella relazione forniscono un'immagine fedele;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le risorse destinate alle attività descritte nella relazione sono state utilizzate per la finalità prevista e conformemente al principio della sana gestione finanziaria;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>le procedure di controllo predisposte danno le necessarie garanzie quanto alla legittimità e regolarità delle operazioni sottostanti.</p>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">La relazione di attività illustra i risultati delle sue operazioni a fronte degli obiettivi che gli sono stati assegnati, i rischi associati a dette operazioni, l'impiego delle risorse messe a sua disposizione e l'efficienza ed efficacia dei sistemi di controllo interno, compresa una valutazione globale dei costi e benefici dei controlli. La relazione comprende altresì informazioni sui risultati globali di tali operazioni, nonché una valutazione della misura in cui le spese operative autorizzate hanno contribuito al conseguimento di risultati strategici e hanno prodotto un valore aggiunto dell'Unione.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">La Commissione trasmette al Parlamento europeo e al Consiglio, entro il 15 giugno di ogni anno, una sintesi delle relazioni annuali di attività relative all'anno precedente. Anche le relazioni annuali di attività di ciascun ordinatore delegato sono messe a disposizione del Parlamento europeo e del Consiglio.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">Le relazioni annuali di attività degli ordinatori e, se del caso, degli ordinatori delegati delle istituzioni, degli uffici, degli organismi e delle agenzie sono pubblicate sul sito internet dell'istituzione, dell'ufficio, dell'organismo e dell'agenzia rispettivi in un modo facilmente accessibile ed entro il 1<span class=\"superscript\">o</span> luglio di ogni anno per l'anno precedente, fatte salve considerazioni debitamente giustificate in materia di riservatezza e di sicurezza.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">10.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i controlli <span class=\"italics\">ex ante</span> ed <span class=\"italics\">ex post</span>, la conservazione dei documenti giustificativi, il codice deontologico, il mancato intervento dell'ordinatore, la trasmissione di informazioni al contabile e le relazioni sulle procedure negoziate.</p>"]]}, "67": {"label": "Articolo 67", "heading": "Poteri e funzioni dei capi delle delegazioni dell'Unione", "anchor": "art_67", "frags": [[null, "<p class=\"norm\">1.  Quando i capi delle delegazioni dell'Unione agiscono in qualità di ordinatori sottodelegati conformemente all'articolo 56, paragrafo 2, essi collaborano strettamente con la Commissione con riguardo alla corretta esecuzione dei fondi, al fine di garantire in particolare la legittimità e la regolarità delle operazioni finanziarie, il rispetto del principio della sana gestione finanziaria nella gestione dei fondi e l'efficace protezione degli interessi finanziari dell'Unione.</p>"], [null, "<p class=\"norm\">A tal fine, essi adottano i provvedimenti necessari a evitare qualunque situazione che potrebbe limitare la responsabilità della Commissione relativamente all'esecuzione del bilancio a loro sottodelegata, come anche qualunque conflitto d'interessi o di priorità che possa influire sull'esecuzione dei compiti di gestione finanziaria a loro sottodelegati.</p>"], [null, "<p class=\"norm\">Se viene a crearsi una situazione o un conflitto di cui al secondo comma, i capi delle delegazioni dell'Unione ne informano senza indugio i direttori generali responsabili della Commissione e del SEAE. Tali direttori generali adottano le misure del caso per porre rimedio alla situazione.</p>"], [null, "<p class=\"norm\">2.  Qualora i capi delle delegazioni dell'Unione si trovino in una situazione di cui all'articolo 66, paragrafo 8, essi sottopongono la questione all'istanza specializzata in irregolarità finanziarie creata ai sensi dell'articolo 73, paragrafo 6. In caso di attività illecite, di frode o di corruzione che possano ledere gli interessi dell'Unione, essi informano le autorità e gli organismi designati dalla legislazione in vigore.</p>"], [null, "<p class=\"norm\">3.  I capi delle delegazioni dell'Unione che agiscono in qualità di ordinatori sottodelegati conformemente all'articolo 56, paragrafo 2, presentano una relazione al loro ordinatore delegato, in modo che questi possa integrare tali relazioni nella sua relazione annuale di attività di cui all'articolo 66, paragrafo 9. Le relazioni dei capi delle delegazioni dell'Unione contengono informazioni sull'efficienza e sull'efficacia dei sistemi interni di controllo istituiti nella loro delegazione, nonché sulla gestione delle operazioni a loro sottodelegate e forniscono la dichiarazione attestante l'affidabilità di cui all'articolo 73, paragrafo 5, terzo comma. Tali relazioni sono allegate alla relazione annuale di attività dell'ordinatore delegato e sono messe a disposizione del Parlamento europeo e del Consiglio, tenendo conto, se del caso, del loro carattere riservato.</p>"], [null, "<p class=\"norm\">I capi delle delegazioni dell'Unione cooperano pienamente con le istituzioni coinvolte nella procedura di discarico e forniscono, se del caso, ogni informazione supplementare necessaria. In questo contesto, essi possono essere chiamati ad assistere a riunioni degli organismi interessati e ad aiutare l'ordinatore delegato responsabile.</p>"], [null, "<p class=\"norm\">4.  I capi delle delegazioni dell'Unione che agiscono in qualità di ordinatori sottodelegati conformemente all'articolo 56, paragrafo 2, rispondono a ogni richiesta presentata dall'ordinatore delegato della Commissione su richiesta di quest'ultima o, nel contesto del discarico, su richiesta del Parlamento europeo.</p>"], [null, "<p class=\"norm\">5.  La Commissione si assicura che la sottodelega di poteri non sia pregiudizievole per la procedura di discarico di cui all'articolo 319 TFUE.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "68": {"label": "Articolo 68", "heading": "Poteri e funzioni del contabile", "anchor": "art_68", "frags": [[null, "<p class=\"norm\">1.  Ogni istituzione nomina un contabile che, presso la stessa, è incaricato di quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>provvedere alla corretta esecuzione dei pagamenti, all'incasso delle entrate e al recupero dei crediti accertati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>preparare e presentare i conti, conformemente al titolo IX della parte prima;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>tenere la contabilità conformemente al titolo IX della parte prima;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>definire le procedure contabili nonché il piano contabile conformemente al titolo IX della parte prima;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>definire e convalidare i sistemi contabili e, se necessario, convalidare i sistemi prescritti dall'ordinatore e destinati a fornire o giustificare informazioni contabili; al riguardo, il contabile è abilitato a verificare in qualsiasi momento il rispetto dei criteri di liquidazione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>provvedere alla gestione della tesoreria.</p>\n</div>"], [null, "<p class=\"norm\">Le responsabilità del contabile del SEAE riguardano esclusivamente la sezione del bilancio relativa al SEAE, eseguita dal SEAE. Il contabile della Commissione rimane responsabile dell'insieme della sezione del bilancio relativa alla Commissione, comprese le operazioni contabili relative agli stanziamenti la cui gestione è stata sottodelegata ai capi delle delegazioni dell'Unione.</p>"], [null, "<p class=\"norm\">Il contabile della Commissione svolge anche, alle condizioni di cui all'articolo 213, il ruolo di contabile del SEAE relativamente all'esecuzione della sezione del bilancio relativa al SEAE.</p>"], [null, "<p class=\"norm\">2.  Il contabile della Commissione è incaricato di definire le norme contabili e i piani contabili armonizzati conformemente al titolo IX della parte prima.</p>"], [null, "<p class=\"norm\">3.  I contabili ottengono dagli ordinatori tutte le informazioni necessarie all'elaborazione di conti che forniscano un'immagine fedele della situazione finanziaria delle istituzioni e dell'esecuzione del bilancio. Gli ordinatori garantiscono l'affidabilità di tali informazioni.</p>"], [null, "<p class=\"norm\">4.  Prima della loro adozione da parte dell'istituzione o dell'organismo di cui all'articolo 208, il contabile approva i conti attestando in tal modo con ragionevole certezza che i conti forniscono un'immagine fedele della situazione finanziaria dell'istituzione o dell'organismo di cui all'articolo 208.</p>"], [null, "<p class=\"norm\">A tal fine, il contabile verifica che i conti siano stati preparati nel rispetto delle norme contabili di cui all'articolo 143 e delle procedure contabili di cui al paragrafo 1, lettera d), del presente articolo e che tutte le entrate e le spese siano contabilizzate.</p>"], [null, "<p class=\"norm\">Gli ordinatori trasmettono al contabile le informazioni di cui ha bisogno per svolgere i suoi compiti.</p>"], [null, "<p class=\"norm\">Gli ordinatori restano pienamente responsabili dell'utilizzo corretto dei fondi da loro gestiti, della legittimità e regolarità delle spese sotto il loro controllo e della completezza ed esattezza delle informazioni trasmesse al contabile.</p>"], [null, "<p class=\"norm\">5.  Il contabile è abilitato a verificare le informazioni ricevute nonché a eseguire qualsiasi controllo supplementare che egli ritenga necessario per approvare i conti.</p>"], [null, "<p class=\"norm\">Il contabile formula riserve, se necessario, illustrando con precisione la natura e la portata di dette riserve.</p>"], [null, "<p class=\"norm\">6.  Salve le deroghe previste dal presente regolamento, solo il contabile è autorizzato a gestire denaro contante ed equivalenti di liquidità. Il contabile responsabile della custodia dei medesimi.</p>"], [null, "<p class=\"norm\">7.  Nell'ambito dell'attuazione di un programma o di un'azione, possono essere aperti conti fiduciari a nome e per conto della Commissione, al fine di consentirne la gestione da parte di un'entità delegata a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii), v) o vi).</p>"], [null, "<p class=\"norm\">Tali conti sono aperti sotto la responsabilità dell'ordinatore incaricato dell'attuazione del programma o dell'azione d'intesa con il contabile della Commissione.</p>"], [null, "<p class=\"norm\">Tali conti sono gestiti sotto la responsabilità dell'ordinatore.</p>"], [null, "<p class=\"norm\">8.  Il contabile della Commissione definisce norme per l'apertura, la gestione e la chiusura dei conti fiduciari, nonché per il loro uso.</p>"], [null, "<p class=\"norm\">9.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i poteri e le funzioni del contabile, incluse la sua nomina e cessazione dalle funzioni, il parere sui sistemi contabili e di inventario, la gestione della tesoreria e dei conti bancari, le firme sui conti, la gestione dei saldi dei conti, le operazioni di trasferimento e conversione, i metodi di pagamento, i dossier di entità giuridiche e la conservazione di documenti giustificativi.</p>"]]}, "69": {"label": "Articolo 69", "heading": "Funzioni che il contabile può delegare", "anchor": "art_69", "frags": [[null, "<p class=\"norm\">1.  Ai fini dell'esercizio dei suoi compiti, il contabile può delegare alcune delle proprie funzioni a funzionari subordinati.</p>"], [null, "<p class=\"norm\">L'atto di delega definisce tali funzioni.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti persone autorizzate a disporre dei conti in un'unità locale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "70": {"label": "Articolo 70", "heading": "Casse di anticipi", "anchor": "art_70", "frags": [[null, "<p class=\"norm\">1.  Possono essere create casse di anticipi per l'incasso di entrate diverse dalle risorse proprie e per il pagamento di spese di importo limitato definite dagli atti delegati adottati a norma del presente regolamento.</p>"], [null, "<p class=\"norm\">Tuttavia, nel settore degli aiuti erogati per situazioni di crisi e delle operazioni d'aiuto umanitario ai sensi dell'articolo 128, si possono utilizzare le casse di anticipi senza limite di importo, rispettando il livello di stanziamenti deciso dal Parlamento europeo e dal Consiglio per la corrispondente linea di bilancio per l'esercizio in corso.</p>"], [null, "<p class=\"norm\">2.  Le casse di anticipi sono alimentate dal contabile dell'istituzione e sono poste sotto la responsabilità di amministratori degli anticipi designati dal contabile dell'istituzione.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo alle condizioni per le casse di anticipi, compresi gli importi massimi che gli amministratori degli anticipi devono pagare e anche le norme per le azioni esterne, fra cui quelle riguardanti la scelta degli amministratori degli anticipi, la dotazione delle casse di anticipi, i controlli da parte degli ordinatori e dei contabili, e il rispetto delle procedure in materia di appalti. Inoltre, alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la creazione delle casse di anticipi e gli amministratori degli anticipi nelle delegazioni dell'Unione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "71": {"label": "Articolo 71", "heading": "Revoca e sospensione delle deleghe conferite ad agenti finanziari", "anchor": "art_71", "frags": [[null, "<p class=\"norm\">1.  L'autorità che li ha nominati può ritirare, in qualsiasi momento, temporaneamente o definitivamente, la delega o la sottodelega conferita agli ordinatori responsabili.</p>"], [null, "<p class=\"norm\">2.  L'autorità che ha nominato il contabile o l'amministratore degli anticipi o entrambi possono sospendere, in qualsiasi momento, temporaneamente o definitivamente, il contabile dalle sue funzioni.</p>"], [null, "<p class=\"norm\">3.  Il presente articolo fa salve eventuali misure disciplinari adottate rispetto agli attori finanziari di cui ai paragrafi 1 e 2.</p>"]]}, "72": {"label": "Articolo 72", "heading": "Responsabilità dell'ordinatore in caso di attività illecita, frode o corruzione", "anchor": "art_72", "frags": [[null, "<p class=\"norm\">1.  Il presente capo fa salva l'eventuale responsabilità penale degli agenti finanziari di cui all'articolo 71, secondo il diritto nazionale applicabile e le disposizioni vigenti concernenti la tutela degli interessi finanziari dell'Unione e la lotta contro la corruzione nella quale sono coinvolti funzionari dell'Unione o degli Stati membri.</p>"], [null, "<p class=\"norm\">2.  Fatti salvi gli articoli 73, 74 e 75 del presente regolamento, ogni ordinatore responsabile, contabile o amministratore degli anticipi è responsabile sotto il profilo disciplinare e patrimoniale, conformemente allo statuto dei funzionari. In caso di attività illecita, di frode o di corruzione che possono ledere gli interessi dell'Unione, sono adite le autorità e istanze designate dalla legislazione vigente, in particolare l'OLAF.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la responsabilità degli ordinatori, dei contabili e degli amministratori degli anticipi in caso di attività illecita, frode o corruzione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "73": {"label": "Articolo 73", "heading": "Disposizioni relative agli ordinatori", "anchor": "art_73", "frags": [[null, "<p class=\"norm\">1.  L'ordinatore responsabile é tenuto a risarcire il danno alle condizioni previste dallo statuto dei funzionari.</p>"], [null, "<p class=\"norm\">2.  L'obbligo di risarcire il danno si applica in particolare se l'ordinatore responsabile, intenzionalmente o per negligenza grave da parte sua:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>accerta i diritti da recuperare o emette ordini di riscossione, impegna una spesa o firma un ordine di pagamento, senza conformarsi al presente regolamento o agli atti delegati adottati a norma del presente regolamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>trascura di compilare un documento che dia luogo a un credito, trascura o ritarda l'emissione di ordini di riscossione, oppure ritarda l'emissione di un ordine di pagamento, generando in tal modo una responsabilità civile dell'istituzione nei confronti di terzi.</p>\n</div>"], [null, "<p class=\"norm\">3.  Gli ordinatori delegati o sottodelegati che ritengano che una decisione di loro competenza sia inficiata da irregolarità o contravvenga al principio della sana gestione finanziaria, ne informano per iscritto l'autorità delegante. Se l'autorità delegante dà istruzione motivata per iscritto all'ordinatore delegato o sottodelegato di prendere tale decisione, quest'ultimo è esente da responsabilità.</p>"], [null, "<p class=\"norm\">4.  In caso di sottodelega all'interno del suo servizio, l'ordinatore delegato resta responsabile dell'efficienza e dell'efficacia dei sistemi interni di gestione e di controllo istituiti e della scelta dell'ordinatore sottodelegato.</p>"], [null, "<p class=\"norm\">5.  In caso di sottodelega ai capi delle delegazioni dell'Unione, l'ordinatore delegato è responsabile della definizione dei sistemi interni di gestione e di controllo attuati, come anche della loro efficienza ed efficacia. I capi delle delegazioni dell'Unione sono responsabili dell'adeguata realizzazione e del funzionamento di tali sistemi, in conformità delle istruzioni impartite dall'ordinatore delegato, nonché della gestione dei fondi e delle operazioni effettuate nel quadro della delegazione dell'Unione di cui sono responsabili. Prima di assumere le proprie funzioni, essi frequentano corsi di formazione specifici sui compiti e sulle responsabilità degli ordinatori e sull'esecuzione del bilancio.</p>"], [null, "<p class=\"norm\">I capi delle delegazioni dell'Unione riferiscono in merito alle loro responsabilità di cui al primo comma del presente paragrafo, conformemente all'articolo 67, paragrafo 3.</p>"], [null, "<p class=\"norm\">Ogni anno, i capi delle delegazioni dell'Unione forniscono all'ordinatore delegato della Commissione la dichiarazione attestante l'affidabilità dei sistemi interni di gestione e di controllo attuati nella loro delegazione, nonché della gestione delle operazioni a loro sottodelegate e dei relativi risultati, in modo da consentire all'ordinatore di effettuare la dichiarazione di affidabilità prevista all'articolo 66, paragrafo 9.</p>"], [null, "<p class=\"norm\">6.  Ogni istituzione crea un'istanza specializzata in irregolarità finanziarie o partecipa a un'istanza comune creata da varie istituzioni. Tali istanze sono indipendenti sul piano funzionale e accertano l'esistenza di un'irregolarità finanziaria e le eventuali conseguenze.</p>"], [null, "<p class=\"norm\">Sulla base del parere di quest'istanza, l'istituzione decide l'avvio di un procedimento volto ad accertare la responsabilità disciplinare o volto ad accertare una responsabilità del risarcimento del danno. Se ha individuato problemi sistemici, l'istanza presenta all'ordinatore e all'ordinatore delegato, a meno che sia la persona in causa, nonché al revisore interno una relazione corredata di raccomandazioni.</p>"], [null, "<p class=\"norm\">7.  Quando i capi delle delegazioni dell'Unione agiscono in qualità di ordinatori sottodelegati conformemente all'articolo 56, paragrafo 2, l'istanza specializzata in irregolarità finanziarie creata dalla Commissione ai sensi del paragrafo 6 del presente articolo è competente per i casi di cui all'articolo 56, paragrafo 2.</p>"], [null, "<p class=\"norm\">Se ha individuato problemi sistemici, l'istanza presenta una relazione corredata di raccomandazioni all'ordinatore, all'alto rappresentante e all'ordinatore delegato della Commissione, a meno che questi sia la persona in causa, nonché al revisore interno.</p>"], [null, "<p class=\"norm\">Sulla base del parere dell'istanza, la Commissione può chiedere all'alto rappresentante, nella sua veste di autorità con potere di nomina, di avviare un procedimento disciplinare o volto ad accertare una responsabilità patrimoniale nei confronti di ordinatori sottodelegati, se le irregolarità riguardano competenze della Commissione a loro sottodelegate. In casi simili, l'alto rappresentante procederà come più opportuno, conformemente allo statuto dei funzionari, al fine di applicare le decisioni sull'azione disciplinare o sul risarcimento del danno, così come raccomandato dalla Commissione.</p>"], [null, "<p class=\"norm\">Gli Stati membri sostengono pienamente l'Unione nella riscossione di quanto dovuto ai sensi dell'articolo 22 dello statuto dei funzionari, a carico degli agenti temporanei a cui si applica l'articolo 2, lettera e), del regime applicabile agli altri agenti delle Comunità europee.</p>"], [null, "<p class=\"norm\">8.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate applicabili agli ordinatori delegati, inclusi la conferma delle istruzioni e il ruolo dell'istanza specializzata in irregolarità finanziarie.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "74": {"label": "Articolo 74", "heading": "Disposizioni relative ai contabili", "anchor": "art_74", "frags": [[null, "<p class=\"norm\">1.  Il contabile é responsabile disciplinarmente e del risarcimento del danno alle condizioni e secondo le procedure di cui allo statuto dei funzionari. Il contabile può rispondere personalmente in particolare nelle fattispecie seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>perdita o deterioramento di fondi, valori o documenti che ha in custodia;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>indebita modificazione di conti bancari o di conti correnti postali;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>recuperi o pagamenti non conformi ai corrispondenti ordini di riscossione o di pagamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>mancato incasso di entrate dovute.</p>\n</div>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la responsabilità degli ordinatori in caso di altre fattispecie.</p>"]]}, "75": {"label": "Articolo 75", "heading": "Disposizioni relative agli amministratori degli anticipi", "anchor": "art_75", "frags": [[null, "<p class=\"norm\">1.  Un amministratore degli anticipi impegna, alle condizioni e secondo le procedure di cui allo statuto dei funzionari, la propria responsabilità disciplinare o del risarcimento del danno. Un amministratore degli anticipi risponde personalmente in particolare nelle fattispecie seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>perdita o deterioramento di fondi, valori o documenti che ha in custodia;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>impossibilità di fornire documenti giustificativi regolari per i pagamenti eseguiti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>pagamento a soggetti non aventi diritto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>mancato incasso di entrate dovute.</p>\n</div>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la responsabilità degli amministratori degli anticipi in caso di altre fattispecie.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "76": {"label": "Articolo 76", "heading": "Risorse proprie", "anchor": "art_76", "frags": [[null, "<p class=\"norm\">1.  Le entrate costituite dalle risorse proprie di cui alla decisione 2007/436/CE, Euratom sono oggetto di una previsione iscritta nel bilancio ed espressa in euro. Sono messe a disposizione conformemente al regolamento (CE, Euratom) n. 1150/2000.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate applicabili alle risorse proprie.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "77": {"label": "Articolo 77", "heading": "Previsione di crediti", "anchor": "art_77", "frags": [[null, "<p class=\"norm\">1.  Allorché l'ordinatore responsabile è in possesso di informazioni sufficienti e attendibili in merito a ogni misura o situazione eventualmente costitutiva di un credito dell'Unione, egli procede a effettuare una previsione di crediti.</p>"], [null, "<p class=\"norm\">2.  L'ordinatore responsabile adegua la previsione di crediti non appena viene a conoscenza di un evento che modifica la misura o la situazione che ha determinato la formazione della previsione.</p>"], [null, "<p class=\"norm\">All'atto della fissazione di un ordine di riscossione relativo a una misura o a una situazione da cui era precedentemente scaturita una previsione di crediti, l'ordinatore responsabile adegua conseguentemente i relativi importi.</p>"], [null, "<p class=\"norm\">Allorché l'ordine di riscossione è emesso per lo stesso importo della previsione di crediti originaria, tale previsione è ridotta a zero.</p>"], [null, "<p class=\"norm\">3.  In deroga al paragrafo 1, le risorse proprie di cui alla decisione 2007/436/CE, Euratom, versate a scadenze fisse dagli Stati membri, non sono oggetto di una previsione di crediti preliminarmente alla messa a disposizione della Commissione degli importi a cura degli Stati membri. Esse sono oggetto di un ordine di riscossione dell'ordinatore responsabile.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la previsione di crediti.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "78": {"label": "Articolo 78", "heading": "Accertamento dei crediti", "anchor": "art_78", "frags": [[null, "<p class=\"norm\">1.  L'accertamento di un credito è l'atto con cui l'ordinatore responsabile:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>verifica l'esistenza dei debiti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>determina o verifica l'esistenza e l'importo del debito;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>verifica l'esigibilità del debito.</p>\n</div>"], [null, "<p class=\"norm\">2.  Le risorse proprie messe a disposizione della Commissione e ogni credito appurato come certo, liquido ed esigibile sono oggetto di accertamento mediante un ordine di riscossione destinato al contabile, seguito da una nota di addebito indirizzata al debitore; entrambi i documenti sono emessi dall'ordinatore responsabile.</p>"], [null, "<p class=\"norm\">3.  Gli importi indebitamente pagati sono recuperati.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di accertamento dei crediti, compresi la procedura e i documenti giustificativi, e degli interessi di mora.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "79": {"label": "Articolo 79", "heading": "Ordini di riscossione", "anchor": "art_79", "frags": [[null, "<p class=\"norm\">1.  L'ordine di riscossione è l'atto con il quale l'ordinatore responsabile impartisce al contabile l'istruzione di recuperare un credito stabilito dall'ordinatore responsabile.</p>"], [null, "<p class=\"norm\">2.  L'istituzione può formalizzare l'accertamento di un credito a carico di persone diverse dagli Stati membri con una decisione che costituisce titolo esecutivo a norma dell'articolo 299 TFUE.</p>"], [null, "<p class=\"norm\">Se la tutela efficace e tempestiva degli interessi finanziari dell'Unione lo impone, la Commissione può altresì adottare, in circostanze eccezionali, una decisione esecutiva di questo tipo a favore di altre istituzioni che lo richiedano in riferimento a crediti sorti in relazione a persone soggette allo statuto dei funzionari.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate per l'adozione dell'ordine di riscossione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "80": {"label": "Articolo 80", "heading": "Disposizioni in materia di recupero", "anchor": "art_80", "frags": [[null, "<p class=\"norm\">1.  Il contabile prende a carico gli ordini di riscossione dei crediti debitamente stabiliti dall'ordinatore responsabile. Il contabile è tenuto ad assicurare con la dovuta diligenza l'afflusso delle entrate dell'Unione e garantisce che i diritti di quest'ultima siano conservati.</p>"], [null, "<p class=\"norm\">Il contabile procede al recupero mediante compensazione e a debita concorrenza dei crediti dell'Unione, se il debitore è titolare a sua volta di un credito nei confronti dell'Unione. Tale credito é certo, liquido ed esigibile.</p>"], [null, "<p class=\"norm\">2.  Quando l'ordinatore delegato intenda rinunciare, anche parzialmente, a recuperare un credito accertato, si assicura che la rinuncia sia regolare e conforme ai principi della sana gestione finanziaria e di proporzionalità. La decisione di rinuncia é motivata. L'ordinatore può delegare l'assunzione di detta decisione di rinuncia.</p>"], [null, "<p class=\"norm\">L'ordinatore delegato può annullare, in tutto o in parte, un credito accertato. L'annullamento parziale di un credito accertato non implica la rinuncia a un credito accertato dell'Unione.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a modalità dettagliate di recupero, inclusi il recupero mediante compensazione, la procedura di recupero in caso di mancato pagamento, la concessione di dilazioni di pagamento, il recupero di ammende e altre penali, la rinuncia al recupero e l'annullamento di un credito accertato.</p>"], [null, "<p class=\"norm\">3.  Gli Stati membri sono in primo luogo responsabili dello svolgimento di controlli e revisioni contabili, e del recupero di importi spesi indebitamente, come prevede la normativa settoriale. Nella misura in cui individuano e correggono le irregolarità per proprio conto, gli Stati membri sono esonerati da rettifiche finanziarie da parte della Commissione in relazione a dette irregolarità.</p>"], [null, "<p class=\"norm\">4.  La Commissione impone rettifiche finanziarie agli Stati membri al fine di escludere dai finanziamenti dell'Unione le spese sostenute in violazione del diritto applicabile. La Commissione basa le sue rettifiche finanziarie sull'individuazione degli importi spesi indebitamente e sulle implicazioni finanziarie per il bilancio. Se non è possibile un'identificazione precisa di tali importi, la Commissione può applicare rettifiche estrapolate o forfettarie in conformità della normativa settoriale.</p>"], [null, "<p class=\"norm\">Nel decidere l'ammontare di una rettifica finanziaria, la Commissione tiene conto della natura e della gravità della violazione del diritto applicabile e delle implicazioni finanziarie per il bilancio, anche in caso di carenze a livello dei sistemi di gestione e di controllo.</p>"], [null, "<p class=\"norm\">I criteri per stabilire le rettifiche finanziarie e la procedura da applicare possono essere previsti nella normativa settoriale.</p>"], [null, "<p class=\"norm\">5.  La metodologia per l'applicazione di rettifiche estrapolate o forfettarie è stabilita conformemente alla normativa settoriale onde consentire alla Commissione di tutelare gli interessi finanziari dell'Unione.</p>"]]}, "81": {"label": "Articolo 81", "heading": "Prescrizione", "anchor": "art_81", "frags": [[null, "<p class=\"norm\">1.  Fatte salve le disposizioni di normative specifiche e l'applicazione della decisione 2007/436/CE, Euratom, i crediti dell'Unione nei confronti di terzi e i crediti di terzi nei confronti dell'Unione sono soggetti a una prescrizione di cinque anni.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la prescrizione.</p>"]]}, "82": {"label": "Articolo 82", "heading": "Trattamento nazionale dei crediti dell'Unione", "anchor": "art_82", "frags": [[null, "<p class=\"norm\">Nel caso di una procedura d'insolvenza, ai crediti dell'Unione è riservato lo stesso trattamento preferenziale concesso ai crediti di uguale natura dovuti a organismi pubblici degli Stati membri in cui ha luogo il procedimento di recupero.</p>"]]}, "83": {"label": "Articolo 83", "heading": "Ammende, penali e interessi imposti dalla Commissione", "anchor": "art_83", "frags": [[null, "<p class=\"norm\">1.  Gli importi riscossi a titolo di ammende, penali e sanzioni, nonché gli interessi e altri proventi prodotti, non sono registrati come entrate di bilancio fino a quando le corrispondenti decisioni possono essere annullate dalla Corte di giustizia dell'Unione europea.</p>"], [null, "<p class=\"norm\">2.  Gli importi di cui al paragrafo 1 sono registrati come entrate di bilancio con la massima tempestività e al più tardi nell'esercizio successivo a quello in cui sono stati esperiti tutti i mezzi di impugnazione. Gli importi che devono essere restituiti all'entità che li ha versati a seguito di una sentenza della Corte di giustizia dell'Unione europea non sono registrati come entrate di bilancio.</p>"], [null, "<p class=\"norm\">3.  Il paragrafo 1 non si applica alle decisioni di liquidazione dei conti o di correzioni finanziarie.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti gli importi riscossi a titolo di ammende, penali e interessi.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "84": {"label": "Articolo 84", "heading": "Decisioni di finanziamento", "anchor": "art_84", "frags": [[null, "<p class=\"norm\">1.  Tutte le spese sono oggetto di un impegno, di una liquidazione, dell'emissione di un ordine di pagamento e di un pagamento.</p>"], [null, "<p class=\"norm\">2.  Con l'eccezione degli stanziamenti che possono essere eseguiti senza un atto di base ai sensi dell'articolo 54, paragrafo 5, primo comma, lettera e), l'impegno della spesa è preceduto da una decisione di finanziamento adottata dall'istituzione o dalle autorità da questa delegate.</p>"], [null, "<p class=\"norm\">3.  La decisione di finanziamento di cui al paragrafo 2 specifica l'obiettivo perseguito, i risultati attesi, il metodo d'esecuzione e il suo importo complessivo. Essa contiene inoltre una descrizione delle azioni da finanziare e un'indicazione dell'importo stanziato per le singole azioni, nonché un calendario d'esecuzione indicativo.</p>"], [null, "<p class=\"norm\">In caso di gestione indiretta, la decisione di finanziamento specifica altresì l'entità o la persona delegate a norma dell'articolo 58, paragrafo 1, lettera c), i criteri utilizzati per la sua scelta e i compiti affidati a detta entità o persona.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti decisioni di finanziamento.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "85": {"label": "Articolo 85", "heading": "Tipi di impegni", "anchor": "art_85", "frags": [[null, "<p class=\"norm\">1.  Un impegno di bilancio consiste nell'operazione con la quale sono riservati gli stanziamenti necessari all'esecuzione di successivi pagamenti in esecuzione di impegni giuridici.</p>"], [null, "<p class=\"norm\">Un impegno giuridico è l'atto con il quale l'ordinatore crea o constata un'obbligazione dalla quale deriva un onere.</p>"], [null, "<p class=\"norm\">Gli impegni di bilancio e gli impegni giuridici sono adottati dallo stesso ordinatore, salvo casi debitamente giustificati previsti dagli atti delegati adottati a norma del presente regolamento.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i tipi di impegni, l'adozione di impegni globali, l'unicità delle firme e le spese amministrative coperte da impegni accantonati.</p>"], [null, "<p class=\"norm\">3.  Gli impegni di bilancio rientrano in una delle seguenti categorie:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>specifico: l'impegno di bilancio è specifico quando il beneficiario e l'importo della spesa sono determinati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>globale: l'impegno di bilancio è globale quando almeno uno degli elementi necessari a definire l'impegno come specifico rimane indeterminato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>accantonato: l'impegno di bilancio è accantonato quando è destinato a coprire le spese di cui all'articolo 170 o spese correnti di natura amministrativa di cui l'importo o i beneficiari finali non sono determinati in modo definitivo.</p>\n</div>"], [null, "<p class=\"norm\">4.  Gli impegni di bilancio per azioni la cui realizzazione si estende su più esercizi possono essere ripartiti su più esercizi in frazioni annue solo quando ciò è previsto dall'atto di base o se si tratta di spese amministrative.</p>"]]}, "86": {"label": "Articolo 86", "heading": "Disposizioni relative agli impegni", "anchor": "art_86", "frags": [[null, "<p class=\"norm\">1.  Per qualsiasi misura da cui derivi una spesa a carico del bilancio, l'ordinatore responsabile procede previamente a un impegno di bilancio prima di concludere un impegno giuridico nei confronti di terzi o di trasferire fondi a un fondo fiduciario sulla base dell'articolo 187.</p>"], [null, "<p class=\"norm\">2.  L'obbligo stabilito dal paragrafo 1 di procedere a un impegno di bilancio prima di concludere un impegno giuridico non si applica agli impegni giuridici contratti a seguito di una dichiarazione di situazione di crisi nel quadro di un piano di continuità operativa, secondo le procedure adottate dalla Commissione o da qualsiasi altra istituzione a titolo della sua autonomia amministrativa.</p>"], [null, "<p class=\"norm\">3.  In caso di operazioni di aiuto umanitario, di operazioni di protezione civile e di aiuti erogati per situazioni di crisi, l'obbligo di cui al paragrafo 1 non si applica se l'efficacia dell'intervento dell'Unione richiede la conclusione immediata di un impegno giuridico nei confronti di terzi e se non é prima possibile procedere a un impegno di bilancio specifico. All'impegno di bilancio si procede senza ritardi dopo aver concluso un impegno giuridico nei confronti di terzi.</p>"], [null, "<p class=\"norm\">4.  Salve le disposizioni speciali del titolo IV della parte seconda, gli impegni di bilancio globali coprono il costo totale dei relativi impegni giuridici specifici contratti fino al 31 dicembre dell'anno n + 1.</p>"], [null, "<p class=\"norm\">Salvo il disposto dell'articolo 85, paragrafo 4, e dell'articolo 203, paragrafo 2, gli impegni giuridici specifici riferentisi a impegni di bilancio specifici o accantonati sono conclusi entro il 31 dicembre dell'anno n.</p>"], [null, "<p class=\"norm\">Alla scadenza dei periodi di cui al primo e secondo comma, il saldo non eseguito di questi impegni di bilancio è disimpegnato dall'ordinatore responsabile.</p>"], [null, "<p class=\"norm\">L'importo corrispondente a ciascun impegno giuridico specifico adottato a seguito di un impegno di bilancio globale, è registrato dall'ordinatore responsabile, prima della firma, nella contabilità di bilancio, mediante imputazione dell'impegno di bilancio globale.</p>"], [null, "<p class=\"norm\">5.  Gli impegni di bilancio e giuridici contratti per azioni la cui realizzazione si estende su più esercizi comportano, tranne quando si tratta di spese di personale, un termine finale d'esecuzione fissato conformemente al principio della sana gestione finanziaria.</p>"], [null, "<p class=\"norm\">Le frazioni di questi impegni non eseguite nei sei mesi successivi a tale data sono oggetto di disimpegno, a norma dell'articolo 15.</p>"], [null, "<p class=\"norm\">L'importo di un impegno di bilancio, corrispondente a un impegno giuridico, per il quale non è stato effettuato alcun pagamento ai sensi dell'articolo 90 entro i due anni successivi alla firma dell'impegno giuridico è oggetto di disimpegno, salvo ove tali importi siano relativi a un caso oggetto di contenzioso in sede giudiziaria o arbitrale o in presenza di disposizioni specifiche stabilite nella normativa settoriale.</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti gli impegni di bilancio e giuridici, compresa la registrazione dei singoli impegni.</p>"]]}, "87": {"label": "Articolo 87", "heading": "Controlli relativi agli impegni", "anchor": "art_87", "frags": [[null, "<p class=\"norm\">1.  Quando procede all'adozione di un impegno di bilancio, l'ordinatore responsabile verifica quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'esattezza dell'imputazione di bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la disponibilità degli stanziamenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>la conformità della spesa rispetto ai trattati, al bilancio, al presente regolamento e agli atti delegati adottati a norma del presente regolamento, nonché a qualsiasi atto emanato in applicazione dei trattati e di qualsiasi altro regolamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>il rispetto del principio della sana gestione finanziaria. L'adeguatezza dei versamenti di prefinanziamenti, il relativo importo e lo scadenzario generale dei pagamenti sono proporzionati alla durata prevista, allo stato di avanzamento dell'esecuzione e ai rischi finanziari che tale prefinanziamento comporta.</p>\n</div>"], [null, "<p class=\"norm\">2.  Quando procede alla registrazione di un obbligo giuridico tramite firma materiale o elettronica, l'ordinatore verifica quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>la copertura dell'obbligo tramite il corrispondente impegno di bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la regolarità e la conformità della spesa rispetto ai trattati, al bilancio, al presente regolamento e agli atti delegati adottati a norma del presente regolamento, nonché a qualsiasi atto emanato in applicazione dei trattati e di qualsiasi altro regolamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il rispetto del principio della sana gestione finanziaria.</p>\n</div>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i controlli applicabili ai diversi impegni.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "88": {"label": "Articolo 88", "heading": "Liquidazione delle spese", "anchor": "art_88", "frags": [[null, "<p class=\"norm\">1.  La liquidazione di una spesa è l'atto con cui l'ordinatore responsabile:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>verifica l'esistenza dei diritti del creditore;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>determina o verifica l'esistenza e l'importo del credito;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>verifica le condizioni di esigibilità del credito.</p>\n</div>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo alla definizione di norme dettagliate concernenti la liquidazione delle spese, inclusi l'ordine di pagamento per le spese del personale e per i pagamenti intermedi e i pagamenti del saldo finale di appalti pubblici e sovvenzioni, la menzione \"conforme ai fatti\" per i prefinanziamenti e la forma del \"visto per pagamento\" e della menzione \"conforme ai fatti\".</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "89": {"label": "Articolo 89", "heading": "Ordinazione delle spese", "anchor": "art_89", "frags": [[null, "<p class=\"norm\">1.  L'ordinazione delle spese è l'atto con il quale l'ordinatore responsabile, previa verifica della disponibilità degli stanziamenti, dà al contabile, mediante l'emissione di un ordine di pagamento, l'istruzione di pagare l'importo della spesa di cui ha effettuato la liquidazione.</p>"], [null, "<p class=\"norm\">Nei casi in cui vengono effettuati pagamenti periodici riguardo a servizi prestati, compresi i servizi di locazione, o beni forniti, e fatta salva l'analisi dei rischi da parte dell'ordinatore, quest'ultimo può ordinare l'applicazione di un sistema di addebito diretto.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'ordinazione delle spese, inclusa la definizione dei dati obbligatori sugli ordini di pagamento e le verifiche degli stessi da parte dell'ordinatore.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "90": {"label": "Articolo 90", "heading": "Tipi di pagamenti", "anchor": "art_90", "frags": [[null, "<p class=\"norm\">1.  Il pagamento si basa sulla prova della conformità dell'azione corrispondente alle disposizioni dell'atto di base o del contratto, e consiste in uno o più dei seguenti atti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il pagamento della totalità degli importi dovuti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il pagamento degli importi dovuti, secondo le modalità seguenti:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>un prefinanziamento, eventualmente frazionato in più versamenti previa firma dell'accordo di delega, del contratto o della convenzione di sovvenzione ovvero notifica della decisione di sovvenzione;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>uno o più pagamenti intermedi in contropartita dell'esecuzione parziale dell'azione;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>un pagamento a saldo degli importi dovuti ove l'azione sia stata integralmente eseguita.</p>\n</div>"], [null, "<p class=\"norm\">2.  Nella preparazione dei conti di bilancio i diversi tipi di pagamento di cui al paragrafo 1 sono distinti al momento dell'esecuzione di ogni pagamento.</p>"], [null, "<p class=\"norm\">3.  Le norme contabili di cui all'articolo 152 comprendono le norme in materia di liquidazione contabile dei prefinanziamenti e di riconoscimento dell'ammissibilità dei costi.</p>"], [null, "<p class=\"norm\">4.  I prefinanziamenti sono liquidati periodicamente dall'ordinatore responsabile in base alla natura economica e al calendario del progetto sottostante.</p>"], [null, "<p class=\"norm\">Qualora l'ordinatore responsabile ritenga inefficace richiedere una scheda finanziaria ai beneficiari e contraenti, per le sovvenzioni o contratti superiori a 5 000 000  EUR ottiene da loro informazioni sulla spesa cumulativa almeno una volta l'anno.</p>"], [null, "<p class=\"norm\">Ai fini del secondo comma, sono inserite le opportune disposizioni nei contratti, nelle decisioni e convenzioni di sovvenzione nonché negli accordi di delega.</p>"], [null, "<p class=\"norm\">Il presente paragrafo non pregiudica le disposizioni specifiche di cui al titolo IV della parte seconda.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i tipi di pagamento e i documenti giustificativi.</p>"]]}, "91": {"label": "Articolo 91", "heading": "Pagamento limitato ai fondi disponibili", "anchor": "art_91", "frags": [[null, "<p class=\"norm\">Il pagamento delle spese è eseguito dal contabile nei limiti dei fondi disponibili.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "92": {"label": "Articolo 92", "heading": "Termini", "anchor": "art_92", "frags": [[null, "<p class=\"norm\">1.  I pagamenti sono effettuati entro:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>90 giorni di calendario per gli accordi di delega, i contratti, le convenzioni e le decisioni di sovvenzione riguardanti servizi o azioni di carattere tecnico la cui valutazione è particolarmente complessa e il cui pagamento dipende dall'approvazione di una relazione o di un certificato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>60 giorni di calendario per tutti gli altri accordi di delega, i contratti, le convenzioni e le decisioni di sovvenzione il cui pagamento dipende dall'approvazione di una relazione o di un certificato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>30 giorni di calendario per tutti gli altri accordi di delega, i contratti, le convenzioni e le decisioni di sovvenzione.</p>\n</div>"], [null, "<p class=\"norm\">2.  L'ordinatore responsabile può sospendere il termine di pagamento nei seguenti casi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'importo del pagamento richiesto non è dovuto; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>non sono stati presentati i documenti giustificativi adeguati.</p>\n</div>"], [null, "<p class=\"norm\">Se l'ordinatore responsabile viene a conoscenza di informazioni che lo inducono a dubitare dell'ammissibilità delle spese in una domanda di pagamento, può sospendere il termine per il pagamento al fine di verificare,anche attraverso un controllo sul posto, il carattere ammissibile delle spese.</p>"], [null, "<p class=\"norm\">3.  Ai creditori interessati sono comunicati per iscritto i motivi della sospensione.</p>"], [null, "<p class=\"norm\">4.  Qualora la sospensione superi due mesi, il creditore può chiedere una decisione dell'ordinatore responsabile se dev'essere continuata la sospensione.</p>"], [null, "<p class=\"norm\">5.  Tranne nel caso degli Stati membri, alla scadenza dei termini fissati al paragrafo 1, il creditore ha diritto agli interessi.</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i termini di pagamento e la specificazione delle condizioni alle quali i creditori pagati in ritardo possono vantare interessi di mora a carico della linea alla quale è imputata la spesa in capitale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "93": {"label": "Articolo 93", "heading": "Gestione elettronica delle operazioni", "anchor": "art_93", "frags": [[null, "<p class=\"norm\">1.  Qualora le entrate e le spese siano gestite mediante sistemi informatici, le firme possono essere apposte mediante procedura informatizzata o elettronica.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la gestione elettronica delle operazioni.</p>"]]}, "94": {"label": "Articolo 94", "heading": "Trasmissione di documenti", "anchor": "art_94", "frags": [[null, "<p class=\"norm\">Previo accordo delle istituzioni e degli Stati membri interessati, la trasmissione di documenti tra di essi può essere effettuata per via elettronica.</p>"]]}, "95": {"label": "Articolo 95", "heading": "Amministrazione elettronica (\"e-Government\")", "anchor": "art_95", "frags": [[null, "<p class=\"norm\">1.  Nella gestione concorrente tutti gli scambi ufficiali di informazioni tra gli Stati membri e la Commissione sono effettuati secondo le modalità indicate nelle norme settoriali che garantiscono l'interoperabilità dei dati raccolti o comunque ricevuti e trasmessi nell'ambito della gestione del bilancio.</p>"], [null, "<p class=\"norm\">2.  Le istituzioni e le agenzie esecutive, nonché gli organismi di cui all'articolo 208 istituiscono e applicano norme uniformi per lo scambio elettronico di informazioni con i terzi che partecipano alle procedure di appalti pubblici e sovvenzioni. In particolare, esse elaborano e applicano quanto più possibile soluzioni per la presentazione, l'archiviazione e il trattamento dei dati presentati nelle procedure di sovvenzione e di appalto e a tal fine realizzano un unico \"spazio di interscambio dei dati elettronici\" per i richiedenti, i candidati e gli offerenti.</p>"], [null, "<p class=\"norm\">3.  La Commissione riferisce periodicamente al Parlamento europeo e al Consiglio sui progressi compiuti nell'attuazione dell'amministrazione elettronica.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "96": {"label": "Articolo 96", "heading": "Buona amministrazione", "anchor": "art_96", "frags": [[null, "<p class=\"norm\">1.  L'ordinatore responsabile rende noto senza indugio la necessità di fornire prove e/o documentazione, la forma delle medesime e il loro contenuto essenziale nonché, se del caso, il calendario indicativo relativo al completamento di procedure di aggiudicazione.</p>"], [null, "<p class=\"norm\">2.  Qualora, a causa di un evidente errore amministrativo da parte del richiedente o del concorrente, si verifichi una mancata presentazione di prove o dichiarazioni, il comitato di valutazione o, se del caso, l'ordinatore responsabile chiede, salvo in casi debitamente motivati, al richiedente o al concorrente di fornire le informazioni mancanti o di chiarire i documenti giustificativi. Tali informazioni o chiarimenti non modificano in modo sostanziale la proposta né mutano i termini dell'offerta.</p>"]]}, "97": {"label": "Articolo 97", "heading": "Indicazione dei mezzi di ricorso", "anchor": "art_97", "frags": [[null, "<p class=\"norm\">Qualora un atto procedurale di un ordinatore leda i diritti di un richiedente o offerente, beneficiario o contraente, l'atto stesso riporta l'indicazione dei mezzi amministrativi e/o di ricorso giudiziario per l'impugnazione.</p>"], [null, "<p class=\"norm\">Sono indicati, in particolare, la natura del ricorso, l'istanza o le istanze che possono essere adite nonché i termini per l'esercizio del ricorso.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "98": {"label": "Articolo 98", "heading": "Designazione del revisore interno", "anchor": "art_98", "frags": [[null, "<p class=\"norm\">Ogni istituzione crea una funzione di revisione contabile interna che viene esercitata nel rispetto delle pertinenti norme internazionali. Il revisore interno, designato dall'istituzione, risponde alla stessa della verifica del corretto funzionamento dei sistemi e delle procedure di esecuzione del bilancio. Il revisore interno non può essere né ordinatore né contabile.</p>"], [null, "<p class=\"norm\">Ai fini della revisione contabile interna del SEAE, i capi delle delegazioni dell'Unione che agiscono in qualità di ordinatori sottodelegati conformemente all'articolo 56, paragrafo 2, sono soggetti ai poteri di verifica del revisore interno della Commissione relativamente alla gestione finanziaria a loro sottodelegata.</p>"], [null, "<p class=\"norm\">Il revisore interno della Commissione svolge anche il ruolo di revisore contabile interno del SEAE relativamente all'esecuzione della sezione del bilancio riguardante il SEAE, alle condizioni di cui all'articolo 2137.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la designazione del revisore interno.</p>"]]}, "99": {"label": "Articolo 99", "heading": "Poteri e funzioni del revisore interno", "anchor": "art_99", "frags": [[null, "<p class=\"norm\">1.  Il revisore interno consiglia la propria istituzione riguardo al controllo dei rischi, esprimendo pareri indipendenti sulla qualità dei sistemi di gestione e di controllo e formulando raccomandazioni mirate a migliorare le condizioni di esecuzione delle operazioni e promuovere una sana gestione finanziaria.</p>"], [null, "<p class=\"norm\">Il revisore interno é incaricato in particolare di quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>verificare l'adeguatezza e l'efficacia dei sistemi interni di gestione, nonché delle prestazioni dei servizi nella realizzazione delle politiche, dei programmi e delle azioni in relazione ai rischi ad essi associati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>valutare l'efficienza e l'efficacia dei sistemi di controllo e di revisione contabile interni relativi a ciascuna operazione di esecuzione del bilancio.</p>\n</div>"], [null, "<p class=\"norm\">2.  Il revisore interno esercita le proprie funzioni in relazione alle attività e ai servizi dell'istituzione. Può accedere integralmente e senza limiti a qualsiasi informazione necessaria per l'esercizio delle sue funzioni, all'occorrenza in loco, sia negli Stati membri sia nei paesi terzi.</p>"], [null, "<p class=\"norm\">Il revisore interno prende conoscenza della relazione annuale di attività degli ordinatori e degli altri elementi d'informazione individuati.</p>"], [null, "<p class=\"norm\">3.  Il revisore interno presenta all'istituzione una relazione con le sue constatazioni e raccomandazioni. L'istituzione provvede a dar seguito alle raccomandazioni risultanti dalle revisioni contabili. Il revisore interno presenta inoltre all'istituzione una relazione annuale di revisione contabile interna che indica il numero e il tipo di revisioni contabili interne effettuate, le raccomandazioni formulate e il seguito dato a queste ultime.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">3 <span class=\"italics\">bis</span>.  Ogni anno la Commissione trasmette su richiesta, nel contesto della procedura di discarico e a norma dell'articolo 319 TFUE, la sua relazione annuale di revisione contabile interna ai sensi del paragrafo 3 del presente articolo, nel debito rispetto dei requisiti in materia di riservatezza.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">4.  L'istituzione comunica i dati di contatto del revisore interno a qualunque persona fisica o giuridica associata alle operazioni di spesa affinché possa contattare in forma riservata il revisore interno.</p>"], [null, "<p class=\"norm\">5.  L'istituzione trasmette annualmente al Parlamento europeo e al Consiglio una relazione che contiene un riepilogo del numero e tipo di revisioni contabili interne effettuate, delle raccomandazioni formulate e del seguito dato a queste ultime.</p>"], [null, "<p class=\"norm\">6.  Le relazioni e le constatazioni del revisore interno, come pure la relazione dell'istituzione, sono accessibili al pubblico solo dopo la convalida da parte del revisore interno delle misure adottate per la loro attuazione.</p>"], [null, "<p class=\"norm\">7.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti poteri e funzioni del revisore interno.</p>"]]}, "100": {"label": "Articolo 100", "heading": "Indipendenza del revisore interno", "anchor": "art_100", "frags": [[null, "<p class=\"norm\">1.  Regole particolari relative al revisore interno sono previste dall'istituzione in modo da garantire che lo stesso eserciti le sue funzioni in totale indipendenza e in modo da definire la sua responsabilità.</p>"], [null, "<p class=\"norm\">Se il revisore interno è un funzionario, egli esercita le sue funzioni esclusive di revisione contabile in piena indipendenza e impegna la sua responsabilità secondo le condizioni previste dallo statuto dei funzionari e precisate negli atti delegati adottati a norma del presente regolamento.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'indipendenza e l'affidabilità del revisore interno, compreso il diritto di quest'ultimo di avviare un'azione dinanzi alla Corte di giustizia dell'Unione europea.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "101": {"label": "Articolo 101", "heading": "Definizioni ai fini del presente titolo", "anchor": "art_101", "frags": [[null, "<p class=\"norm\">1.  Ai fini del presente titolo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>per «appalto» si intende l'acquisizione da parte di una o più amministrazioni aggiudicatrici, mediante contratto, di lavori, forniture o servizi, e l'acquisto o la locazione di terreni, fabbricati esistenti o altri beni immobili, da operatori economici scelti dalle amministrazioni aggiudicatrici stesse;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>per «appalto pubblico» si intende un contratto a titolo oneroso, concluso per iscritto tra uno o più operatori economici e una o più amministrazioni aggiudicatrici ai sensi degli articoli 117 e 190, per ottenere, contro pagamento di un prezzo in tutto o in parte a carico del bilancio, la fornitura di un bene mobile o immobile, l'esecuzione di lavori o la prestazione di servizi.</p>\n</div>"], [null, "<p class=\"list\">Gli appalti pubblici includono:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>gli appalti immobiliari;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>gli appalti di forniture;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>gli appalti di lavori;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>gli appalti di servizi;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>per «contratto di concessione» si intende un contratto a titolo oneroso, concluso per iscritto tra uno o più operatori economici e una o più amministrazioni aggiudicatrici ai sensi degli articoli 117 e 190, per affidare a un operatore economico l'esecuzione di lavori o la prestazione e gestione di servizi («concessione»). La remunerazione consiste unicamente nel diritto di gestire i lavori o i servizi, o in tale diritto accompagnato da un prezzo. L'aggiudicazione di un contratto di concessione comporta il trasferimento al concessionario di un rischio operativo legato alla gestione dei lavori o dei servizi, comprendente un rischio sul lato della domanda o sul lato dell'offerta, o entrambi. Si considera che il concessionario assuma un rischio operativo nel caso in cui, in condizioni operative normali, non sia garantito il recupero degli investimenti effettuati o dei costi sostenuti per la gestione dei lavori o dei servizi in questione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>per «contratto» si intende un appalto pubblico o un contratto di concessione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>per «contratto quadro» si intende un appalto pubblico concluso tra uno o più operatori economici e tra una o più amministrazioni aggiudicatrici il cui scopo è quello di stabilire le clausole relative ad appalti specifici basati su di esso da aggiudicare durante un dato periodo, in particolare per quanto riguarda i prezzi e, se del caso, le quantità previste;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>per «sistema dinamico di acquisizione» si intende un processo di acquisizione interamente elettronico, per acquisti di uso corrente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>per «operatore economico» si intende una persona fisica o giuridica, inclusi gli enti pubblici, o un raggruppamento di tali persone che offra la fornitura di prodotti, l'esecuzione di lavori o la prestazione di servizi o la fornitura di beni immobili;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">h)<span style=\"word-spacing: 15pt\"> </span>per «documento di gara» si intende qualsiasi documento prodotto dall'amministrazione aggiudicatrice o al quale l'amministrazione aggiudicatrice fa riferimento per descrivere o determinare elementi della procedura di appalto, ivi compresi:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>le misure di pubblicità stabilite nell'articolo 103;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>l'invito a presentare offerte;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>il capitolato d'oneri, che include le specifiche tecniche e i pertinenti criteri, o i documenti descrittivi nel caso di un dialogo competitivo;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>il progetto di contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>per «decisione amministrativa definitiva» si intende la decisione di un'autorità amministrativa avente effetto definitivo e vincolante conformemente al diritto del paese in cui è stabilito l'operatore economico o del paese in cui si trova l'amministrazione aggiudicatrice, ovvero secondo il diritto dell'Unione applicabile;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">j)<span style=\"word-spacing: 18pt\"> </span>per «centrale di committenza» si intende un'amministrazione aggiudicatrice che fornisce attività di centralizzazione delle committenze e, se del caso, attività di committenza ausiliarie;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">k)<span style=\"word-spacing: 15pt\"> </span>per «offerente» si intende un operatore economico che ha presentato un'offerta;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">l)<span style=\"word-spacing: 19pt\"> </span>per «candidato» si intende un operatore economico che ha sollecitato un invito o è stato invitato a partecipare a una procedura ristretta, una procedura competitiva con negoziazione, un dialogo competitivo, un partenariato per l'innovazione, un concorso di progettazione o una procedura negoziata;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">m)<span style=\"word-spacing: 13pt\"> </span>per «potenziale offerente» si intende un operatore economico iscritto in un elenco di potenziali offerenti da invitare a presentare domande di partecipazione od offerte;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">n)<span style=\"word-spacing: 15pt\"> </span>per «subappaltatore» si intende un operatore economico proposto da un candidato od offerente o contraente a eseguire parte di un contratto. Il subappaltatore non ha un impegno giuridico diretto nei confronti dell'amministrazione aggiudicatrice.</p>\n</div>"], [null, "<p class=\"norm\">2.  Un contratto misto avente a oggetto due o più tipi di appalti (lavori, forniture o servizi) o concessioni (lavori o servizi), o avente a oggetto sia appalti che concessioni, è aggiudicato secondo le disposizioni applicabili al tipo di appalto che caratterizza l'oggetto principale del contratto in questione.</p>"], [null, "<p class=\"norm\">3.  Fatti salvi gli articoli da 105 <span class=\"italics\">bis</span> a 108, il presente titolo non si applica alle sovvenzioni, né ai contratti di assistenza tecnica definita conformemente all'articolo 125, paragrafo 8, conclusi con la BEI o il Fondo europeo per gli investimenti.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'ulteriore definizione e ambito di applicazione degli appalti pubblici e dei contratti di concessione, la nomenclatura applicabile con riferimento al «Vocabolario comune per gli appalti pubblici», i contratti misti, gli operatori economici nonché i contratti quadro e contratti specifici basati su questi ultimi che coprono la durata massima dei contratti quadro e l'aggiudicazione e le modalità di attuazione dei contratti specifici basati su contratti quadro conclusi rispettivamente con uno o più operatori economici.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "102": {"label": "Articolo 102", "heading": "Principi applicabili agli appalti pubblici", "anchor": "art_102", "frags": [[null, "<p class=\"norm\">1.  Tutti gli appalti pubblici finanziati interamente o parzialmente dal bilancio rispettano i principi di trasparenza, proporzionalità, parità di trattamento e non discriminazione.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">2.  Tutti i contratti sono messi a gara assicurando la più ampia concorrenza, salvo nel caso di ricorso alla procedura di cui all'articolo 104, paragrafo 1, lettera d).</p>"], [null, "<p class=\"norm\">Il valore stimato di un contratto non può essere stabilito con l'intenzione di eludere le norme applicabili e nessun contratto può essere frazionato a tal fine.</p>"], [null, "<p class=\"norm\">L'amministrazione aggiudicatrice divide un contratto in lotti ogniqualvolta sia opportuno tenendo debitamente conto di un'ampia concorrenza.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">3.  Le amministrazioni aggiudicatrici non ricorrono a contratti quadro in modo improprio o in modo tale che abbiano per oggetto o per effetto di impedire, limitare o falsare la concorrenza.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "103": {"label": "Articolo 103", "heading": "Misure di pubblicità", "anchor": "art_103", "frags": [[null, "<p class=\"norm\">1.  Per le procedure di valore pari o superiore alle soglie di cui all'articolo 118, paragrafo 1, o all'articolo 190, l'amministrazione aggiudicatrice pubblica nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>un bando di gara per avviare la procedura, tranne nel caso della procedura di cui all'articolo 104, paragrafo 1, lettera d);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un avviso di aggiudicazione che riporta i risultati della procedura.</p>\n</div>"], [null, "<p class=\"norm\">2.  Le procedure di valore inferiore alle soglie di cui all'articolo 118, paragrafo 1, o all'articolo 190 sono oggetto di un' adeguata pubblicità.</p>"], [null, "<p class=\"norm\">3.  La pubblicazione di talune informazioni relative all'aggiudicazione di un contratto può essere omessa qualora la divulgazione ostacoli l'applicazione della legge, o sia contraria all'interesse pubblico, pregiudichi i legittimi interessi commerciali degli operatori economici oppure possa recare pregiudizio alla concorrenza leale tra di loro.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i requisiti per la pubblicità delle procedure con riferimento al loro valore rispetto alle soglie di cui all'articolo 118, paragrafo 1, la pubblicità da parte dell'amministrazione aggiudicatrice nel pieno rispetto del principio di non discriminazione e il contenuto e la pubblicazione dei bandi di gara.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "104": {"label": "Articolo 104", "heading": "Procedure di appalto", "anchor": "art_104", "frags": [[null, "<p class=\"norm\">1.  Le procedure di aggiudicazione di contratti di concessione o di appalti pubblici, compresi i contratti quadro, assumono una delle seguenti forme:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>procedura aperta;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>procedura ristretta, anche tramite un sistema dinamico di acquisizione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>concorso di progettazione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>procedura negoziata, anche senza previa pubblicazione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>dialogo competitivo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>procedura competitiva con negoziazione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>partenariato per l'innovazione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">h)<span style=\"word-spacing: 15pt\"> </span>procedure a seguito di invito a manifestare interesse.</p>\n</div>"], [null, "<p class=\"norm\">2.  Nelle procedure aperte, qualsiasi operatore economico interessato può presentare un'offerta.</p>"], [null, "<p class=\"norm\">3.  Nelle procedure ristrette, nel dialogo competitivo, nelle procedure competitive con negoziazione e nei partenariati per l'innovazione, qualsiasi operatore economico può presentare una domanda di partecipazione fornendo le informazioni richieste dall'amministrazione aggiudicatrice. L'amministrazione aggiudicatrice invita tutti i candidati che soddisfano i criteri di selezione e che non rientrano in alcuna delle situazioni di cui agli articoli 106 e 107 a presentare un'offerta.</p>"], [null, "<p class=\"norm\">Fatto salvo il primo comma, l'amministrazione aggiudicatrice può limitare il numero di candidati da invitare a partecipare alla procedura sulla base di criteri di selezione oggettivi e non discriminatori, indicati nel bando di gara o nell'invito a manifestare interesse. Il numero di candidati invitati deve essere sufficiente ad assicurare un'effettiva concorrenza.</p>"], [null, "<p class=\"norm\">4.  In tutte le procedure che comportano una negoziazione, l'amministrazione aggiudicatrice negozia con gli offerenti le offerte iniziali e le eventuali offerte successive o parti di esse, tranne le offerte finali, per migliorarne il contenuto. I requisiti minimi e i criteri precisati nei documenti di gara non sono soggetti a negoziazione.</p>"], [null, "<p class=\"norm\">Un'amministrazione aggiudicatrice può aggiudicare un contratto sulla base dell'offerta iniziale senza negoziazione qualora abbia indicato, nei documenti di gara, che si riserva la possibilità di farlo.</p>"], [null, "<p class=\"norm\">5.  L'amministrazione aggiudicatrice può ricorrere:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>alla procedura aperta o ristretta per qualunque acquisto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>a procedure che comportano un invito a manifestare interesse per contratti di valore inferiore alla soglia di cui all'articolo 118, paragrafo 1, per preselezionare candidati da invitare a presentare offerte in risposta a futuri inviti ristretti a presentare offerte o per stilare un elenco di potenziali offerenti da invitare a presentare domande di partecipazione o offerte;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>a un concorso di progettazione per acquisire un piano o un progetto selezionato da una commissione giudicatrice in base a una gara;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>al partenariato per l'innovazione per sviluppare prodotti, servizi o lavori innovativi e acquistare successivamente le forniture, i servizi o i lavori che ne risultano;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>alla procedura competitiva con negoziazione o al dialogo competitivo per contratti di concessione, per i contratti di servizi di cui all'allegato XIV della direttiva 2014/24/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">9</span>\n), nei casi in cui sono state presentate solo offerte irregolari o inaccettabili in risposta a una procedura aperta o ristretta dopo il completamento della procedura iniziale e per i casi in cui ciò sia giustificato da circostanze specifiche legate, tra l'altro, alla natura o alla complessità dell'oggetto del contratto o al tipo specifico di contratto, come ulteriormente precisato negli atti delegati adottati a norma del presente regolamento;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>alle procedure negoziate per contratti di valore inferiore alle soglie di cui all'articolo 118, paragrafo 1, o, alla procedura negoziata senza previa pubblicazione, solo per tipi specifici di acquisti che esulano dall'ambito di applicazione della direttiva 2014/24/UE e in circostanze eccezionali chiaramente definite negli atti delegati adottati a norma del presente regolamento.</p>\n</div>"], [null, "<p class=\"norm\">6.  Il sistema dinamico di acquisizione è aperto per tutta la sua durata a ogni operatore economico che soddisfi i criteri di selezione.</p>"], [null, "<p class=\"norm\">L'amministrazione aggiudicatrice segue le norme relative alla procedura ristretta per gli appalti tramite un sistema dinamico di acquisizione.</p>"], [null, "<p class=\"norm\">7.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i tipi e i meccanismi aggiuntivi di dettaglio delle procedure di appalto per l'aggiudicazione dei contratti di cui al paragrafo 1 con riferimento al loro valore rispetto alle soglie di cui all'articolo 118, paragrafo 1, il numero minimo di candidati da invitare per ciascun tipo di procedura, le ulteriori condizioni per il ricorso alle varie procedure, il sistema dinamico di acquisizione e le offerte irregolari e inaccettabili.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "104a": {"label": "Articolo 104 bis", "heading": "Appalto interistituzionale e appalto congiunto", "anchor": "art_104a", "frags": [[null, "<p class=\"norm\">1.  Nei casi in cui un contratto o un contratto quadro riveste interesse per due o più istituzioni, agenzie esecutive o organismi di cui agli articoli 208 e 209 e ogniqualvolta vi è la possibilità di migliorare l'efficienza, le amministrazioni aggiudicatrici interessate hanno la facoltà di eseguire la procedura e la gestione del susseguente contratto o contratto quadro su base interistituzionale sotto la guida di una delle amministrazioni aggiudicatrici.</p>"], [null, "<p class=\"norm\">Gli organismi istituiti dal Consiglio nell'ambito della PESC di cui al titolo V del TUE possono anch'essi partecipare alle procedure interistituzionali.</p>"], [null, "<p class=\"norm\">Le condizioni stabilite da un contratto quadro sono applicabili solo tra le amministrazioni aggiudicatrici individuate a tale fine dall'avvio della procedura di appalto e gli operatori economici parti del contratto quadro.</p>"], [null, "<p class=\"norm\">2.  Nei casi in cui un contratto o un contratto quadro è necessario per l'attuazione di un'azione comune fra un'istituzione e una o più amministrazioni aggiudicatrici degli Stati membri, la procedura di appalto può essere condotta congiuntamente dall'istituzione e dalle amministrazioni aggiudicatrici.</p>"], [null, "<p class=\"norm\">Con gli Stati dell'EFTA e con i paesi candidati dell'Unione si può procedere a un appalto congiunto, se tale possibilità è stata specificamente prevista in un trattato bilaterale o multilaterale.</p>"], [null, "<p class=\"norm\">In caso di procedura di appalto congiunta, si applicano le disposizioni procedurali delle istituzioni.</p>"], [null, "<p class=\"norm\">Quando l'amministrazione aggiudicatrice di uno Stato membro detiene o gestisce una quota del valore totale stimato del contratto pari o superiore al 50 %, oppure in altri casi debitamente motivati, l'istituzione può decidere che all' appalto congiunto si applichino le norme procedurali dell'amministrazione aggiudicatrice dello Stato membro, purché tali norme possano essere considerate equivalenti a quelle dell'istituzione.</p>"], [null, "<p class=\"norm\">L'istituzione e l'amministrazione aggiudicatrice di uno Stato membro, di uno Stato EFTA o di un paese candidato all'adesione all'Unione che svolgono congiuntamente l'appalto si accordano, in particolare, sulle modalità pratiche della valutazione delle domande di partecipazione o delle offerte, sull'aggiudicazione del contratto, sul diritto da applicare al contratto e sul giudice competente in caso di controversie.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'appalto interistituzionale.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "105": {"label": "Articolo 105", "heading": "Preparazione di una procedura di appalto", "anchor": "art_105", "frags": [[null, "<p class=\"norm\">1.  Prima dell'avvio di una procedura di appalto, l'amministrazione aggiudicatrice può svolgere una consultazione preliminare di mercato ai fini della preparazione della procedura.</p>"], [null, "<p class=\"norm\">2.  Nei documenti di gara l'amministrazione aggiudicatrice individua l'oggetto dell'appalto fornendo una descrizione delle sue esigenze e illustrando le caratteristiche richieste dei lavori, delle forniture o dei servizi da acquistare e specifica i criteri di esclusione, selezione e aggiudicazione applicabili. L'amministrazione aggiudicatrice indica altresì quali elementi definiscono i requisiti minimi che tutte le offerte devono soddisfare. I requisiti minimi comprendono il rispetto degli obblighi applicabili in materia di diritto ambientale, sociale e del lavoro stabiliti dal diritto dell'Unione, dal diritto nazionale, da contratti collettivi o dalle convenzioni internazionali in materia sociale e ambientale applicabili elencate nell'allegato X della direttiva 2014/24/UE.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il contenuto dei documenti di gara, in particolare in merito ai progetti di contratto, alle caratteristiche delle etichettature, alle norme e agli standard ambientali, sociali o di altro tipo e la consultazione preliminare di mercato.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "105a": {"label": "Articolo 105 bis", "heading": "Tutela degli interessi finanziari dell'Unione attraverso l'individuazione dei rischi e l'imposizione di sanzioni amministrative", "anchor": "art_105a", "frags": [[null, "<p class=\"norm\">1.  Al fine di tutelare gli interessi finanziari dell'Unione, la Commissione istituisce e gestisce un sistema di individuazione precoce e di esclusione.</p>"], [null, "<p class=\"norm\">Tale sistema mira a facilitare:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'individuazione precoce dei rischi che minacciano gli interessi finanziari dell'Unione,</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>l'esclusione di un operatore economico che si trovi in una delle situazioni che danno luogo all'esclusione elencate all'articolo 106, paragrafo 1,</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>l'irrogazione di una sanzione pecuniaria nei confronti di un operatore economico a norma dell'articolo 106, paragrafo 13.</p>\n</div>"], [null, "<p class=\"norm\">2.  La decisione di escludere e/o di irrogare una sanzione pecuniaria è adottata dall'amministrazione aggiudicatrice. Essa si basa su una sentenza definitiva o su una decisione amministrativa definitiva.</p>"], [null, "<p class=\"norm\">Tuttavia, nelle situazioni di cui all'articolo 106, paragrafo 2, l'amministrazione aggiudicatrice deferisce il caso all'istanza di cui all'articolo 108, paragrafo 5, al fine di assicurare una valutazione centralizzata di dette situazioni. In tali casi l'amministrazione aggiudicatrice prende la sua decisione sulla base di una qualificazione giuridica preliminare, tenuto conto di una raccomandazione dell'istanza.</p>"], [null, "<p class=\"norm\">Qualora decida di discostarsi dalla raccomandazione dell'istanza, l'amministrazione aggiudicatrice motiva la sua decisione all'istanza.</p>"], [null, "<p class=\"norm\">3.  Nei casi di cui all'articolo 107, l'amministrazione aggiudicatrice decide il rigetto di un operatore economico nell'ambito di una determinata procedura.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "106": {"label": "Articolo 106", "heading": "Criteri di esclusione e sanzioni amministrative", "anchor": "art_106", "frags": [[null, "<p class=\"norm\">1.  L'amministrazione aggiudicatrice esclude un operatore economico dalla partecipazione alle procedure di appalto disciplinate dal presente regolamento se:</p>"], [null, "<p class=\"modref\">\n▼C3\n</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'operatore economico è in stato di fallimento, è oggetto di una procedura concorsuale o di liquidazione, è in stato di amministrazione controllata, ha stipulato un concordato preventivo con i creditori, ha cessato le sue attività o si trova in qualsiasi altra situazione analoga derivante da una procedura simile ai sensi di leggi o regolamenti nazionali;</p>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che l'operatore economico non ha ottemperato agli obblighi relativi al pagamento d'imposte e tasse o agli obblighi relativi al pagamento dei contributi previdenziali e assistenziali secondo il diritto del paese in cui è stabilito, del paese dell'amministrazione aggiudicatrice o del paese in cui deve essere eseguito il contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che l'operatore economico si è reso colpevole di gravi illeciti professionali per aver violato le leggi o i regolamenti applicabili o i principi deontologici della professione da esso esercitata o per aver tenuto qualsiasi condotta illecita che incida sulla sua credibilità professionale, qualora dette condotte denotino un intento doloso o una negligenza grave, compreso in particolare nelle ipotesi seguenti:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>per aver reso in modo fraudolento o negligente false informazioni ai fini della verifica dell'assenza di motivi di esclusione o del rispetto dei criteri di selezione o nell'esecuzione di un contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>per aver concluso accordi con altri operatori economici allo scopo di provocare distorsioni della concorrenza;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>per aver violato diritti di proprietà intellettuale;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>per aver tentato di influenzare il processo decisionale dell'amministrazione aggiudicatrice nel corso della procedura di appalto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">v)<span style=\"word-spacing: 15pt\"> </span>per aver tentato di ottenere informazioni riservate che possano conferirgli vantaggi indebiti nell'ambito della procedura di appalto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>è stato accertato da una sentenza definitiva o decisione amministrativa che l'operatore economico è colpevole di:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>frode ai sensi dell'articolo 1 della convenzione relativa alla tutela degli interessi finanziari delle Comunità europee, stabilita dall'atto del Consiglio del 26 luglio 1995 (\n<span class=\"superscript\">10</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>corruzione, quale definita all'articolo 3 della convenzione relativa alla lotta contro la corruzione nella quale sono coinvolti funzionari delle Comunità europee o degli Stati membri dell'Unione europea, stabilita dall'atto del Consiglio del 26 maggio 1997 (\n<span class=\"superscript\">11</span>\n), e all'articolo 2, paragrafo 1, della decisione quadro 2003/568/GAI del Consiglio (\n<span class=\"superscript\">12</span>\n), nonché corruzione quale definita nel diritto del paese dell'amministrazione aggiudicatrice, del paese in cui è stabilito l'operatore economico o del paese in cui deve essere eseguito il contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>partecipazione a un'organizzazione criminale, quale definita all'articolo 2 della decisione quadro 2008/841/GAI del Consiglio (\n<span class=\"superscript\">13</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>riciclaggio dei proventi di attività criminose o finanziamento del terrorismo, quali definiti all'articolo 1 della direttiva 2005/60/CE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">14</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">v)<span style=\"word-spacing: 15pt\"> </span>reati terroristici o reati connessi ad attività terroristiche, quali definiti rispettivamente all'articolo 1 e all'articolo 3 della decisione quadro 2002/475/GAI del Consiglio (\n<span class=\"superscript\">15</span>\n), ovvero istigazione, concorso o tentativo di commettere un reato, quali definiti all'articolo 4 di detta decisione;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">vi)<span style=\"word-spacing: 19pt\"> </span>lavoro minorile e altre forme di tratta di esseri umani quali definite all'articolo 2 della direttiva 2011/36/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">16</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>l'operatore economico ha mostrato significative carenze nell'ottemperare ai principali obblighi ai fini dell'esecuzione di un contratto finanziato dal bilancio, che hanno causato la cessazione anticipata del contratto o l'applicazione della clausola penale o altre penalità contrattuali o che sono state evidenziate in seguito a verifiche, audit o indagini svolti da un ordinatore, dall'OLAF o dalla Corte dei conti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che l'operatore economico ha commesso un'irregolarità ai sensi dell'articolo 1, paragrafo 2, del regolamento (CE, Euratom) n. 2988/95 del Consiglio (\n<span class=\"superscript\">17</span>\n).</p>\n</div>"], [null, "<p class=\"norm\">2.  In mancanza di una sentenza definitiva o, se del caso, di una decisione amministrativa definitiva nei casi di cui al paragrafo 1, lettere c), d) e f), o nel caso di cui al paragrafo 1, lettera e), l'amministrazione aggiudicatrice esclude l'operatore economico in base a una qualificazione giuridica preliminare delle condotte di cui a dette lettere, tenuto conto dei fatti accertati o di altre risultanze figuranti nella raccomandazione dell'istanza di cui all'articolo 108.</p>"], [null, "<p class=\"norm\">La qualificazione preliminare di cui al primo comma lascia impregiudicata la valutazione della condotta dell'operatore economico in questione da parte delle autorità competenti degli Stati membri a norma del diritto nazionale. L'amministrazione aggiudicatrice rivede senza indugio la sua decisione di escludere l'operatore economico e/o di irrogare nei suoi confronti una sanzione pecuniaria in seguito alla notifica di una sentenza definitiva o decisione amministrativa definitiva. Nei casi in cui la durata dell'esclusione non sia stabilita dalla sentenza definitiva o decisione amministrativa definitiva, spetta all'amministrazione aggiudicatrice stabilirla in base ai fatti accertati e alle risultanze e tenuto conto della raccomandazione dell'istanza di cui all'articolo 108.</p>"], [null, "<p class=\"norm\">Qualora detta sentenza definitiva o decisione amministrativa definitiva non consideri l'operatore economico colpevole della condotta oggetto di qualificazione giuridica preliminare in base alla quale è stato escluso, l'amministrazione aggiudicatrice pone fine senza indugio a tale esclusione e/o rimborsa le eventuali sanzioni pecuniarie irrogate.</p>"], [null, "<p class=\"norm\">I fatti e le risultanze di cui al primo comma includono, in particolare:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>fatti accertati nel contesto di audit o indagini svolti dalla Corte dei conti, dall'OLAF o dal servizio di revisione contabile interna, o di altre verifiche, audit o controlli effettuati sotto la responsabilità dell'ordinatore;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>decisioni amministrative non definitive che possono includere misure disciplinari adottate dall'organo di vigilanza competente responsabile della verifica dell'applicazione dei principi di deontologia professionale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>decisioni della BCE, della BEI, del Fondo europeo per gli investimenti o di organizzazioni internazionali;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>decisioni della Commissione concernenti la violazione delle norme in materia di concorrenza dell'Unione o decisioni di un'autorità nazionale competente concernenti la violazione del diritto della concorrenza dell'Unione o nazionale.</p>\n</div>"], [null, "<p class=\"norm\">3.  Le decisioni dell'amministrazione aggiudicatrice adottate a norma degli articoli da 106 a 108 o, se del caso, le raccomandazioni dell'istanza di cui all'articolo 108 sono emesse conformemente al principio di proporzionalità e tenendo conto, in particolare, della gravità della situazione, ivi compresa la sua incidenza sugli interessi finanziari e sull'immagine dell'Unione, del tempo trascorso dal verificarsi della condotta in questione, della sua durata e ricorrenza, dell'intenzione o del grado di negligenza, dell'entità limitata dell'importo interessato ai fini del paragrafo 1, lettera b), del presente articolo o di altre circostanze attenuanti, come il livello di collaborazione dell'operatore economico con la pertinente autorità competente e il suo contributo all'indagine riconosciuto dall'amministrazione aggiudicatrice o la comunicazione della situazione di esclusione per mezzo della dichiarazione di cui al paragrafo 10 del presente articolo.</p>"], [null, "<p class=\"norm\">4.  L'amministrazione aggiudicatrice esclude l'operatore economico qualora una persona che è membro dell'organo di amministrazione, di direzione o di vigilanza di tale operatore economico o che ha poteri di rappresentanza, di decisione o di controllo nei confronti di tale operatore economico si trovi in una o più delle situazioni di cui al paragrafo 1, lettere da c) ad f). L'amministrazione aggiudicatrice esclude altresì l'operatore economico quando una persona fisica o giuridica che si assume la responsabilità illimitata dei debiti di tale operatore economico si trovi in una o più delle situazioni di cui al paragrafo 1, lettere a) o b).</p>"], [null, "<p class=\"norm\">5.  Qualora il bilancio sia eseguito in regime di gestione indiretta con paesi terzi, la Commissione, tenuto conto, se del caso, della raccomandazione dell'istanza di cui all'articolo 108, può adottare una decisione di esclusione e/o irrogare una sanzione pecuniaria alle condizioni enunciate nel presente articolo, a seguito dell'inadempimento da parte del paese terzo delegato a norma dell'articolo 58, paragrafo 1, lettera c). Ciò non pregiudica la responsabilità del paese terzo, prevista dall'articolo 60, paragrafo 3, di prevenire, individuare, rettificare e notificare irregolarità e frodi o di adottare una decisione di esclusione o irrogare sanzioni pecuniarie.</p>"], [null, "<p class=\"norm\">6.  Nei casi di cui al paragrafo 2 del presente articolo, l'amministrazione aggiudicatrice può escludere un operatore economico a titolo provvisorio, senza previa raccomandazione dell'istanza di cui all'articolo 108, qualora la partecipazione dell'operatore economico in questione a una procedura di appalto costituisca una grave e imminente minaccia per gli interessi finanziari dell'Unione. In tali casi, l'amministrazione aggiudicatrice sottopone immediatamente la questione all'istanza e adotta la decisione definitiva entro 14 giorni dal ricevimento della raccomandazione dell'istanza.</p>"], [null, "<p class=\"norm\">7.  L'amministrazione aggiudicatrice, tenuto conto, se del caso, della raccomandazione dell'istanza di cui all'articolo 108 non esclude un operatore economico dalla partecipazione a una procedura di appalto, se:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'operatore economico ha adottato le misure correttive indicate al paragrafo 8 del presente articolo, dimostrando in tal modo la sua affidabilità. La presente lettera non si applica nel caso di cui al paragrafo 1, lettera d), del presente articolo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>è indispensabile per garantire la continuità del servizio per un periodo di tempo limitato e in attesa dell'adozione delle misure correttive indicate al paragrafo 8 del presente articolo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>una tale esclusione sarebbe sproporzionata in base ai criteri di cui al paragrafo 3 del presente articolo.</p>\n</div>"], [null, "<p class=\"norm\">Inoltre, il paragrafo 1, lettera a), del presente articolo non si applica in caso di acquisto di forniture, a condizioni particolarmente vantaggiose, da un fornitore che sta definitivamente liquidando l'attività commerciale, oppure dal liquidatore di un fallimento, un concordato preventivo o una procedura analoga prevista nel diritto nazionale.</p>"], [null, "<p class=\"norm\">Nei casi di non esclusione di cui al primo e secondo comma del presente paragrafo, l'amministrazione aggiudicatrice specifica i motivi per non escludere l'operatore economico e ne informa l'istanza di cui all'articolo 108.</p>"], [null, "<p class=\"norm\">8.  Le misure di cui al paragrafo 7 che pongono rimedio alla situazione di esclusione possono includere, in particolare:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>misure volte a individuare l'origine delle situazioni che danno adito all'esclusione e provvedimenti concreti di carattere tecnico, organizzativo e relativi al personale nel pertinente settore di attività dell'operatore economico che siano idonei a correggere la condotta e a impedire che essa si verifichi nuovamente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la prova che l'operatore economico abbia adottato misure per compensare o risarcire il danno o il pregiudizio arrecato agli interessi finanziari dell'Unione dai fatti sottostanti che danno origine alla situazione di esclusione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>la prova che l'operatore economico abbia effettuato o garantito il pagamento delle ammende irrogate dall'autorità competente o delle imposte e tasse o dei contributi previdenziali e assistenziali di cui al paragrafo 1, lettera b).</p>\n</div>"], [null, "<p class=\"norm\">9.  L'amministrazione aggiudicatrice, tenuto conto, se del caso, della raccomandazione riveduta dell'istanza di cui all'articolo 108, rivede senza indugio la sua decisione di escludere un operatore economico di propria iniziativa o su richiesta di tale operatore economico qualora quest'ultimo abbia adottato misure correttive sufficienti a dimostrare la sua affidabilità o abbia fornito nuovi elementi comprovanti che non sussiste più la situazione di esclusione di cui al paragrafo 1 del presente articolo.</p>"], [null, "<p class=\"norm\">10.  Un candidato o offerente dichiara, al momento di presentare la domanda di partecipazione od offerta, se si trova in una delle situazioni di cui al paragrafo 1 del presente articolo o all'articolo 107, paragrafo 1, e, se del caso, se ha adottato una delle misure correttive di cui al paragrafo 7, lettera a), del presente articolo. Se del caso, il candidato o offerente fornisce la stessa dichiarazione firmata da un'entità sulla cui capacità intende fare affidamento. Tuttavia, l'amministrazione aggiudicatrice può astenersi dall'esigere tale dichiarazione per i contratti di valore molto modesto da definire negli atti delegati adottati a norma dell'articolo 210.</p>"], [null, "<p class=\"norm\">11.  Se l'amministrazione aggiudicatrice lo esige e qualora ciò sia necessario per assicurare il corretto svolgimento della procedura, il candidato o offerente nonché l'entità sulla cui capacità il candidato o l'offerente intende fare affidamento forniscono:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>adeguata prova che il candidato o l'offerente non si trova in nessuna delle situazioni di esclusione di cui al paragrafo 1;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>informazioni sulle persone che sono membri dell'organo di amministrazione, di direzione o di vigilanza del candidato, offerente o entità o che hanno poteri di rappresentanza, di decisione o di controllo nei confronti del candidato, offerente o entità e adeguata prova che una o più di tali persone non si trovino in una delle situazioni di esclusione di cui al paragrafo 1, lettere da c) a f);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>adeguata prova che le persone fisiche o giuridiche che si assumono la responsabilità illimitata dei debiti di tale candidato, offerente o entità non si trovino in una delle situazioni di esclusione di cui al paragrafo 1, lettere a) o b).</p>\n</div>"], [null, "<p class=\"norm\">12.  L'amministrazione aggiudicatrice può altresì applicare i paragrafi da 1 a 11 a un subappaltatore. In tal caso, l'amministrazione aggiudicatrice esige che un candidato o offerente sostituisca un subappaltatore o un'entità sulla cui capacità il candidato o offerente intende fare affidamento, che si trovi in una situazione di esclusione.</p>"], [null, "<p class=\"norm\">13.  Per garantire un effetto deterrente, l'amministrazione aggiudicatrice, tenuto conto, se del caso, della raccomandazione dell'istanza di cui all'articolo 108, può irrogare una sanzione pecuniaria a un operatore economico che abbia tentato di ottenere l'accesso a fondi dell'Unione partecipando o chiedendo di partecipare a una procedura di appalto allorché, senza averlo dichiarato in conformità del paragrafo 10 del presente articolo, si trova in una delle seguenti situazioni di esclusione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le situazioni di cui al paragrafo 1, lettere c), d), e) e f), del presente articolo, in alternativa a una decisione di escludere l'operatore economico, qualora tale esclusione sia sproporzionata in base ai criteri di cui al paragrafo 3 del presente articolo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le situazioni di cui al paragrafo 1, lettere c), d) ed e), del presente articolo, in aggiunta a un'esclusione che è necessaria per tutelare gli interessi finanziari dell'Unione, qualora l'operatore economico abbia adottato una condotta sistematica e ricorrente nell'intento di ottenere indebitamente fondi dell'Unione.</p>\n</div>"], [null, "<p class=\"norm\">L'importo della sanzione pecuniaria rappresenta tra il 2 % e il 10 % del valore complessivo del contratto.</p>"], [null, "<p class=\"norm\">14.  La durata dell'esclusione non supera uno dei periodi seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'eventuale periodo stabilito dalla sentenza definitiva o dalla decisione amministrativa definitiva di uno Stato membro;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>cinque anni nei casi di cui al paragrafo 1, lettera d);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>tre anni nei casi di cui al paragrafo 1, lettere c), e) ed f).</p>\n</div>"], [null, "<p class=\"norm\">Un operatore economico è escluso fintantoché si trovi in una delle situazioni di cui al paragrafo 1, lettere a) e b).</p>"], [null, "<p class=\"norm\">15.  Il termine di prescrizione per l'esclusione di un operatore economico e/o l'irrogazione di sanzioni pecuniarie nei suoi confronti è di cinque anni a decorrere da una delle seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>la data della condotta che ha dato adito all'esclusione o, in caso di atti continui o ripetuti, la data alla quale la condotta è cessata, nei casi di cui al paragrafo 1, lettere b), c), d) ed e), del presente articolo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la data della sentenza definitiva di un organo giurisdizionale nazionale o della decisione amministrativa definitiva nei casi di cui al paragrafo 1, lettere b), c) e d), del presente articolo.</p>\n</div>"], [null, "<p class=\"norm\">Il termine di prescrizione è interrotto da un atto della Commissione, dell'OLAF, dell'istanza di cui all'articolo 108 o di qualsiasi entità che partecipi all'esecuzione del bilancio, notificato all'operatore economico e riguardante indagini o procedimenti giudiziari. Un nuovo termine di prescrizione comincia a decorrere dal giorno successivo all'interruzione.</p>"], [null, "<p class=\"norm\">Ai fini del paragrafo 1, lettera f), del presente articolo si applica il termine di prescrizione per l'esclusione di un operatore economico e/o l'irrogazione di sanzioni pecuniarie nei suoi confronti di cui all'articolo 3 del regolamento (CE, Euratom) n. 2988/95.</p>"], [null, "<p class=\"norm\">Qualora la condotta dell'operatore economico rientri in più di uno dei motivi elencati nel paragrafo 1 del presente articolo, si applica il termine di prescrizione previsto per tali motivi più gravi.</p>"], [null, "<p class=\"norm\">16.  Per rafforzare, se necessario, l'effetto deterrente dell'esclusione e/o della sanzione pecuniaria, la Commissione pubblica sul proprio sito internet, fatta salva la decisione dell'amministrazione aggiudicatrice, le seguenti informazioni relative all'esclusione e, se del caso, alla sanzione pecuniaria nei casi di cui al paragrafo 1, lettere c), d), e) e f), del presente articolo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il nome dell'operatore economico in questione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la situazione di esclusione con riferimento al paragrafo 1 del presente articolo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>la durata dell'esclusione e/o l'importo della sanzione pecuniaria.</p>\n</div>"], [null, "<p class=\"norm\">Qualora la decisione sull'esclusione e/o la sanzione pecuniaria sia adottata in base alla qualificazione preliminare di cui al paragrafo 2 del presente articolo, la pubblicazione indica che non vi è sentenza definitiva o, se del caso, decisione amministrativa definitiva. In tali casi, le informazioni relative a eventuali ricorsi, al loro stato e al loro esito come pure qualsiasi decisione riveduta dell'amministrazione aggiudicatrice sono pubblicate senza indugio. Qualora sia stata irrogata una sanzione pecuniaria, la pubblicazione indica altresì se la sanzione è stata pagata.</p>"], [null, "<p class=\"norm\">La decisione di pubblicare le informazioni è adottata dall'amministrazione aggiudicatrice a seguito della pertinente sentenza definitiva o, se del caso, della decisione amministrativa definitiva, o a seguito della raccomandazione dell'istanza di cui all'articolo 108, secondo il caso. Tale decisione diviene efficace tre mesi dopo la sua notificazione all'operatore economico.</p>"], [null, "<p class=\"norm\">Le informazioni pubblicate sono rimosse non appena l'esclusione è terminata. In caso di sanzione pecuniaria, la pubblicazione è rimossa sei mesi dopo il pagamento di tale sanzione.</p>"], [null, "<p class=\"norm\">Conformemente al regolamento (CE) n. 45/2001, in ordine ai dati personali l'amministrazione aggiudicatrice informa l'operatore economico dei diritti conferitigli dalle norme applicabili sulla protezione dei dati personali e delle procedure a sua diposizione per esercitarli.</p>"], [null, "<p class=\"norm\">17.  In nessuno dei seguenti casi possono essere pubblicate le informazioni di cui al paragrafo 16 del presente articolo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>qualora occorra garantire la riservatezza dell'indagine o di un procedimento giudiziario nazionale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>qualora la pubblicazione arrechi un danno sproporzionato all'operatore economico in questione o sia altrimenti sproporzionata, in base ai criteri di proporzionalità di cui al paragrafo 3 del presente articolo e all'importo della sanzione pecuniaria;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>qualora siano interessate persone fisiche, a meno che la pubblicazione dei dati personali sia giustificata a titolo eccezionale, fra l'altro, dalla gravità della condotta o dalla sua incidenza sugli interessi finanziari dell'Unione. In tali casi, la decisione di pubblicare le informazioni è presa tenendo debitamente conto del diritto alla vita privata e degli altri diritti previsti dal regolamento (CE) n. 45/2001.</p>\n</div>"], [null, "<p class=\"norm\">18.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il contenuto della dichiarazione di cui al paragrafo 10 del presente articolo e in merito alla prova di cui al paragrafo 11, lettera a), del presente articolo che un operatore economico non si trovi in una delle situazioni di esclusione, anche con riferimento al documento di gara unico europeo ai sensi dell'articolo 59, paragrafo 2, della direttiva 2014/24/UE, e le situazioni in cui l'amministrazione aggiudicatrice può o non può esigere la presentazione di tale dichiarazione o prova.</p>"]]}, "107": {"label": "Articolo 107", "heading": "Rigetto di una procedura di appalto", "anchor": "art_107", "frags": [[null, "<p class=\"norm\">1.  Nell'ambito di una determinata procedura di appalto l'amministrazione aggiudicatrice non aggiudica il contratto a un operatore economico che:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>si trovi in una situazione di esclusione a norma dell'articolo 106;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>abbia reso false dichiarazioni nel fornire le informazioni richieste ai fini della partecipazione alla procedura o non abbia fornito tali informazioni;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>abbia precedentemente partecipato alla preparazione dei documenti di gara se ciò comporta una distorsione della concorrenza non altrimenti risolvibile.</p>\n</div>"], [null, "<p class=\"norm\">2.  Prima di decidere il rigetto di un operatore economico nell'ambito di una determinata procedura di appalto, l'amministrazione aggiudicatrice dà all'operatore economico la possibilità di presentare osservazioni, a meno che il rigetto sia stato motivato in conformità del paragrafo 1, lettera a), da una decisione di esclusione adottata nei confronti dell'operatore economico a seguito di un esame delle sue osservazioni.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti le misure atte a evitare la distorsione della concorrenza nonché in materia di tale dichiarazione e prova che un operatore economico non si trova in alcuna delle situazioni elencate al paragrafo 1 del presente articolo.</p>"]]}, "108": {"label": "Articolo 108", "heading": "Sistema di individuazione precoce e di esclusione", "anchor": "art_108", "frags": [[null, "<p class=\"norm\">1.  Le informazioni scambiate nell'ambito del sistema di individuazione precoce e di esclusione di cui all'articolo 105 <span class=\"italics\">bis</span> del presente regolamento sono centralizzate in una banca dati creata dalla Commissione e sono gestite nel pieno rispetto del diritto alla vita privata e degli altri diritti previsti dal regolamento (CE) n. 45/2001 («banca dati»).</p>"], [null, "<p class=\"norm\">Le informazioni sono registrate nella banca dati dalla pertinente amministrazione aggiudicatrice nel contesto delle procedure d'appalto in corso e dei contratti esistenti previa notifica all'operatore economico in questione. Tale notifica può essere differita in via eccezionale, qualora motivi preminenti e legittimi impongano di garantire la riservatezza dell'indagine o dei procedimenti giudiziari nazionali, fino a che tali motivi preminenti e legittimi a tutela della riservatezza non vengano meno.</p>"], [null, "<p class=\"norm\">In conformità del regolamento (CE) n. 45/2001, un operatore economico soggetto al sistema di individuazione precoce e di esclusione ha il diritto di essere informato dei dati conservati nella banca dati facendone richiesta alla Commissione.</p>"], [null, "<p class=\"norm\">Le informazioni contenute in tale banca dati sono aggiornate, se del caso, in seguito a rettifica, cancellazione o modifica dei dati. Sono pubblicate unicamente in conformità dell'articolo 106, paragrafi 16 e 17, del presente regolamento.</p>"], [null, "<p class=\"norm\">2.  L'individuazione precoce dei rischi che minacciano gli interessi finanziari dell'Unione di cui all'articolo 105 <span class=\"italics\">bis</span>, paragrafo 1, lettera a), del presente regolamento si basa sulla trasmissione di informazioni alla Commissione da parte di uno qualsiasi dei seguenti soggetti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'OLAF, conformemente al regolamento (UE, Euratom) n. 883/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">18</span>\n), ove un'indagine dell'OLAF in corso dimostri che potrebbe essere opportuno adottare misure precauzionali per tutelare gli interessi finanziari dell'Unione, nel pieno rispetto dei diritti procedurali e fondamentali e della protezione degli informatori;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un ordinatore della Commissione, di un ufficio europeo istituito dalla Commissione o di un'agenzia esecutiva in caso di presunti gravi illeciti professionali, irregolarità, frode, corruzione o gravi violazioni del contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>un'istituzione, un ufficio europeo o un'agenzia diversi da quelli di cui alla lettera b) del presente paragrafo o un organismo nei casi di presunti gravi illeciti professionali, irregolarità, frode, corruzione o gravi violazioni del contratto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>le entità che eseguono il bilancio conformemente all'articolo 59 del presente regolamento, nei casi individuati di frodi e/o irregolarità, ove richiesto dalla normativa settoriale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>le entità che eseguono il bilancio conformemente all'articolo 60 del presente regolamento, nei casi individuati di frodi e/o irregolarità.</p>\n</div>"], [null, "<p class=\"norm\">3.  A eccezione dei casi in cui le informazioni devono essere comunicate in conformità della normativa settoriale, le informazioni da comunicare a norma del paragrafo 2 del presente articolo comprendono:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'identificazione dell'operatore economico in questione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>una sintesi dei rischi individuati o dei fatti in questione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>ogni informazione che possa essere d'ausilio all'ordinatore nell'esecuzione della verifica di cui al paragrafo 4 del presente articolo, o nell'adozione di una decisione di esclusione di cui all'articolo 106, paragrafi 1 o 2, o di una decisione di irrogazione di una sanzione pecuniaria di cui all'articolo 106, paragrafo 13;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>se del caso, eventuali misure particolari necessarie a garantire la riservatezza delle informazioni trasmesse, comprese misure per la salvaguardia degli elementi di prova a tutela dell'indagine o dei procedimenti giudiziari nazionali.</p>\n</div>"], [null, "<p class=\"norm\">4.  La Commissione trasmette senza indugio le informazioni di cui al paragrafo 3del presente articolo ai propri ordinatori e a quelli delle sue agenzie esecutive, a tutte le altre istituzioni, organismi, uffici europei e agenzie al fine di consentire loro di eseguire la necessaria verifica in relazione alle procedure d'appalto in corso e ai contratti esistenti.</p>"], [null, "<p class=\"norm\">Nell'eseguire tale verifica l'ordinatore esercita i suoi poteri a norma dell'articolo 66 e non può andare oltre le prescrizioni dei documenti di gara e delle disposizioni contrattuali.</p>"], [null, "<p class=\"norm\">Il periodo di conservazione delle informazioni trasmesse a norma del paragrafo 3 del presente articolo non supera un anno. Se, durante tale periodo, l'amministrazione aggiudicatrice richiede all'istanza di formulare una raccomandazione in un caso di esclusione, il periodo di conservazione può essere prolungato fino a quando l'amministrazione aggiudicatrice ha adottato una decisione.</p>"], [null, "<p class=\"norm\">5.  L'amministrazione aggiudicatrice può adottare una decisione di escludere e/o di irrogare una sanzione pecuniaria e la decisione di pubblicare le relative informazioni soltanto dopo aver ottenuto la raccomandazione dell'istanza, qualora tale decisione si basi sulla qualificazione preliminare di cui all'articolo 106, paragrafo 2.</p>"], [null, "<p class=\"norm\">6.  L'istanza si riunisce su richiesta di una delle amministrazioni aggiudicatrici di cui all'articolo 117.</p>"], [null, "<p class=\"norm\">7.  L'istanza è composta da:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>un presidente permanente indipendente di alto livello;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>due rappresentanti della Commissione in quanto proprietaria del sistema, che esprimono una posizione congiunta; e</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>un rappresentante dell'amministrazione aggiudicatrice richiedente.</p>\n</div>"], [null, "<p class=\"norm\">La composizione dell'istanza è tale da garantire le competenze giuridiche e tecniche appropriate.</p>"], [null, "<p class=\"norm\">L'istanza è assistita da un segretariato permanente, fornito dalla Commissione, il quale ne garantisce la gestione permanente.</p>"], [null, "<p class=\"norm\">8.  Dinanzi all'istanza si applica la seguente procedura:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'amministrazione aggiudicatrice richiedente deferisce il caso all'istanza comunicando le necessarie informazioni di cui al paragrafo 3 del presente articolo, i fatti e le risultanze di cui all'articolo 106, paragrafo 2, e la presunta situazione di esclusione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>l'istanza comunica senza indugio all'operatore economico i fatti in questione, compresa la loro qualificazione giuridica preliminare, i quali potrebbero configurarsi come situazioni di esclusione di cui all'articolo 106, paragrafo 1, lettere c), d), e) e f), e/o determinare l'irrogazione di una sanzione pecuniaria. L'istanza trasmette contestualmente la stessa comunicazione alle altre amministrazioni aggiudicatrici;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>prima di adottare una raccomandazione, l'istanza dà all'operatore economico e alle amministrazioni aggiudicatrici cui è stata trasmessa la comunicazione la possibilità di presentare osservazioni. L'operatore economico e le amministrazioni aggiudicatrici cui è stata trasmessa la comunicazione dispongono di almeno 15 giorni per presentare osservazioni;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>nei casi di cui all'articolo 106, paragrafo 1, lettere d) e f), la comunicazione di cui alla lettera b) del presente paragrafo e la possibilità di cui alla lettera c) del presente paragrafo possono essere differite in via eccezionale, qualora motivi preminenti e legittimi impongano di garantire la riservatezza dell'indagine o dei procedimenti giudiziari nazionali, fino a che tali motivi preminenti e legittimi a tutela della riservatezza non vengano meno;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>ove la richiesta dell'amministrazione aggiudicatrice si fondi, tra l'altro, sulle informazioni fornite dall'OLAF, l'Ufficio collabora con l'istanza a norma del regolamento (UE, Euratom) n. 883/2013, nel pieno rispetto dei diritti procedurali e fondamentali e della protezione degli informatori;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>l'istanza adotta la propria raccomandazione entro 45 giorni dal ricevimento della richiesta da parte dell'amministrazione aggiudicatrice. Qualora l'istanza richieda all'operatore economico informazioni supplementari, detto termine è prorogato di 15 giorni al massimo. In casi eccezionali debitamente giustificati, l'istanza può prorogare ulteriormente il termine per adottare la propria raccomandazione di un mese al massimo. Qualora l'operatore economico non presenti le sue osservazioni o non fornisca le informazioni richieste entro il termine specificato, l'istanza può procedere all'adozione della propria raccomandazione.</p>\n</div>"], [null, "<p class=\"norm\">9.  La raccomandazione dell'istanza di escludere e/o irrogare una sanzione pecuniaria contiene, se del caso, i seguenti elementi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>i fatti o le risultanze di cui all'articolo 106, paragrafo 2, compresa la loro qualificazione giuridica preliminare;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>una valutazione della necessità di irrogare una sanzione pecuniaria e il relativo importo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>una valutazione della necessità di escludere l'operatore economico in questione e, in tal caso, la durata proposta di tale esclusione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>una valutazione della necessità di pubblicare le informazioni relative all'operatore economico oggetto di esclusione e/o di sanzione pecuniaria;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>una valutazione delle eventuali misure correttive adottate dall'operatore economico.</p>\n</div>"], [null, "<p class=\"norm\">Qualora l'amministrazione aggiudicatrice preveda di adottare una decisione più severa di quella che è stata raccomandata dall'istanza, provvede affinché una decisione sia adottata nel debito rispetto del diritto di essere ascoltato e delle norme sulla protezione dei dati personali.</p>"], [null, "<p class=\"norm\">10.  L'istanza rivede la propria raccomandazione durante il periodo di esclusione su richiesta dell'amministrazione aggiudicatrice nei casi di cui all'articolo 106, paragrafo 9, o in seguito alla notifica di una sentenza definitiva o decisione amministrativa definitiva in cui sono stabiliti i motivi dell'esclusione nei casi in cui tale sentenza o decisione non fissi la durata dell'esclusione di cui all'articolo 106, paragrafo 2, secondo comma.</p>"], [null, "<p class=\"norm\">L'istanza notifica senza indugio all'amministrazione aggiudicatrice richiedente la propria raccomandazione riveduta e, a seguito della notifica, l'amministrazione aggiudicatrice rivede la sua decisione.</p>"], [null, "<p class=\"norm\">11.  La Corte di giustizia dell'Unione europea ha una competenza giurisdizionale anche di merito per rivedere una decisione con la quale l'amministrazione aggiudicatrice esclude l'operatore economico e/o irroga nei suoi confronti una sanzione pecuniaria, anche riducendo o aumentando la durata dell'esclusione e/o annullando, riducendo o aumentando la sanzione pecuniaria irrogata.</p>"], [null, "<p class=\"norm\">12.  A tutte le entità che partecipano all'esecuzione del bilancio in conformità dell'articolo 58 è conferito da parte della Commissione l'accesso alle informazioni sulle decisioni di esclusione a norma dell'articolo 106 per consentire loro di verificare se il sistema segnali un'esclusione al fine di prendere tali informazioni in considerazione, come opportuno e sotto la propria responsabilità, per l'aggiudicazione di contratti nell'esecuzione del bilancio.</p>"], [null, "<p class=\"norm\">13.  Nell'ambito della relazione annuale della Commissione al Parlamento europeo e al Consiglio di cui all'articolo 325, paragrafo 5, TFUE, la Commissione fornisce informazioni aggregate sulle decisioni adottate dalle amministrazioni aggiudicatrici ai sensi degli articoli da 105 <span class=\"italics\">bis</span> a 108 del presente regolamento. La relazione fornisce anche ulteriori informazioni su qualsiasi decisione presa dalle amministrazioni aggiudicatrici ai sensi dell'articolo 106, paragrafo 7, lettera b), e dell'articolo 106, paragrafo 17, lettera b), del presente regolamento e sulle decisioni delle amministrazioni aggiudicatrici di discostarsi dalla raccomandazione dell'istanza ai sensi dell'articolo 105 <span class=\"italics\">bis</span>, paragrafo 2, terzo comma, del presente regolamento.</p>"], [null, "<p class=\"norm\">Le informazioni di cui al primo comma del presente paragrafo sono fornite nel debito rispetto dei requisiti in materia di riservatezza e, in particolare, non consentono l'identificazione dell'operatore economico in questione.</p>"], [null, "<p class=\"norm\">14.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il sistema dell'Unione per la tutela degli interessi finanziari dell'Unione, comprendente la banca dati e le procedure standardizzate, sull'organizzazione e sulla composizione dell'istanza, sulla nomina e l'indipendenza del presidente nonché sulla prevenzione e sulla gestione dei conflitti d'interesse del presidente e dei membri dell'istanza.</p>"], [null, "<p class=\"modref\">\n▼M3 —————</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "110": {"label": "Articolo 110", "heading": "Aggiudicazione dei contratti", "anchor": "art_110", "frags": [[null, "<p class=\"norm\">1.  I contratti sono aggiudicati sulla base dei criteri di aggiudicazione, purché l'amministrazione aggiudicatrice abbia verificato le seguenti condizioni:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'offerta è conforme ai requisiti minimi precisati nei documenti di gara;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il candidato od offerente non si trova in situazione di esclusione ai sensi dell'articolo 106 o di rigetto ai sensi dell'articolo 107; e</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il candidato od offerente soddisfa i criteri di selezione indicati nei documenti di gara e non è soggetto a conflitti di interessi che possono influire negativamente sull'esecuzione del contratto.</p>\n</div>"], [null, "<p class=\"norm\">2.  L'amministrazione aggiudicatrice applica i criteri di selezione per valutare la capacità del candidato od offerente. I criteri di selezione possono riguardare unicamente la capacità giuridica e normativa per esercitare l'attività professionale, la capacità economica e finanziaria e la capacità tecnica e professionale.</p>"], [null, "<p class=\"norm\">3.  L'amministrazione aggiudicatrice applica i criteri di aggiudicazione per valutare l'offerta.</p>"], [null, "<p class=\"norm\">4.  L'amministrazione aggiudicatrice procede all'aggiudicazione dei contratti sulla base dell'offerta economicamente più vantaggiosa, applicando uno dei tre metodi di aggiudicazione, vale a dire prezzo più basso, costo più basso o miglior rapporto qualità/prezzo.</p>"], [null, "<p class=\"norm\">Per il metodo del costo più basso, l'amministrazione aggiudicatrice segue un approccio costo/efficacia, compreso il calcolo del costo del ciclo di vita.</p>"], [null, "<p class=\"norm\">Per il miglior rapporto qualità/prezzo, l'amministrazione aggiudicatrice tiene conto del prezzo o costo o di altri criteri di qualità connessi all'oggetto del contratto.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i criteri di selezione, i criteri di aggiudicazione, compresi i criteri di qualità e l'offerta economicamente più vantaggiosa, nonché i metodi applicati per valutare i costi del ciclo di vita dell'acquisto. Alla Commissione è inoltre conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo ai documenti atti a comprovare la capacità giuridica, la capacità economica e finanziaria e la capacità tecnica e professionale, nonché a norme dettagliate concernenti le aste elettroniche e le offerte anormalmente basse.</p>"]]}, "111": {"label": "Articolo 111", "heading": "Presentazione, comunicazione elettronica e valutazione", "anchor": "art_111", "frags": [[null, "<p class=\"norm\">1.  Le modalità di presentazione delle offerte sono tali da garantire una reale concorrenza e la riservatezza del loro contenuto fino al momento dell'apertura simultanea.</p>"], [null, "<p class=\"norm\">2.  La Commissione garantisce con mezzi appropriati e in applicazione dell'articolo 95 che gli offerenti possano registrare il contenuto delle offerte e qualsiasi documento giustificativo in formato elettronico («appalti elettronici»), salvo in casi debitamente giustificati indicati negli atti delegati adottati a norma dell'articolo 210. Qualsiasi sistema di comunicazione elettronica usato a sostegno di comunicazioni e scambi di informazioni ha carattere non discriminatorio, è comunemente disponibile, è compatibile con i prodotti della tecnologia dell'informazione e della comunicazione (TIC) generalmente in uso e non limita l'accesso degli operatori economici alla procedura di appalto.</p>"], [null, "<p class=\"norm\">La Commissione riferisce periodicamente al Parlamento europeo e al Consiglio in merito ai progressi realizzati nell'attuazione del presente paragrafo.</p>"], [null, "<p class=\"norm\">3.  Se ritenuto opportuno e proporzionato, l'amministrazione aggiudicatrice può esigere dagli offerenti una garanzia preliminare a tutela del mantenimento delle offerte presentate. È necessario che la garanzia richiesta sia proporzionata al valore stimato del contratto e sia fissata a un livello adeguato onde prevenire discriminazioni nei confronti dei vari operatori economici.</p>"], [null, "<p class=\"norm\">4.  L'amministrazione aggiudicatrice apre tutte le domande di partecipazione e le offerte. Tuttavia respinge:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le domande di partecipazione e le offerte che non rispettano il termine per la ricezione, senza aprirle;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le offerte pervenute già aperte, senza esaminarne il contenuto.</p>\n</div>"], [null, "<p class=\"norm\">5.  L'amministrazione aggiudicatrice valuta tutte le domande di partecipazione od offerte non respinte nella fase di apertura di cui al paragrafo 4 sulla base dei criteri indicati nei documenti di gara, al fine di aggiudicare il contratto oppure di procedere a un'asta elettronica.</p>"], [null, "<p class=\"norm\">6.  Le domande di partecipazione e le offerte che non rispettino tutte le prescrizioni minime che figurano nei documenti di gara sono respinte.</p>"], [null, "<p class=\"norm\">Salvo in casi debitamente giustificati, il comitato di valutazione o l'amministrazione aggiudicatrice possono chiedere ai candidati o offerenti di presentare documenti supplementari o documenti mancanti, di chiarire i documenti giustificativi relativi ai criteri di esclusione e di selezione, o di spiegare un'offerta anormalmente bassa, entro un termine da essi impartito.</p>"], [null, "<p class=\"norm\">7.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i termini per la ricezione delle offerte e delle domande di partecipazione, l'accesso ai documenti di gara, i termini per la comunicazione di informazioni supplementari, i termini in casi urgenti, nonché i mezzi di comunicazione per la presentazione delle offerte e dei cataloghi elettronici, i requisiti tecnici e giuridici per i sistemi elettronici e la deroga all'uso di mezzi di presentazione elettronica delle offerte in casi debitamente giustificati. Alla Commissione è inoltre conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la possibilità di chiedere una garanzia dell'offerta e le condizioni di riscatto e svincolo della garanzia, l'apertura e la valutazione delle offerte e delle domande di partecipazione e l'istituzione e la composizione dei comitati di apertura e di valutazione.</p>"]]}, "112": {"label": "Articolo 112", "heading": "Contatti durante la procedura di appalto", "anchor": "art_112", "frags": [[null, "<p class=\"norm\">1.  Durante lo svolgimento della procedura di appalto, tutti i contatti tra l'amministrazione aggiudicatrice e i candidati o offerenti hanno luogo soltanto secondo modalità che garantiscano la trasparenza, la parità di trattamento e la buona amministrazione quale definita all'articolo 96. Dopo la scadenza del termine per la ricezione delle offerte, l'amministrazione aggiudicatrice contatta l'offerente al fine di correggere evidenti errori amministrativi o di chiedere conferma di un elemento specifico o tecnico, salvo in casi debitamente giustificati. I suddetti contatti, come pure ogni altro eventuale contatto, non danno luogo a modificazioni dei documenti di gara o a sostanziali modifiche dei termini dell'offerta presentata, a eccezione dei casi in cui una procedura di appalto a norma dell'articolo 104, paragrafo 1, autorizza specificatamente tali possibilità.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i contatti consentiti e i contatti richiesti tra l'amministrazione aggiudicatrice e i candidati o offerenti durante la procedura di appalto.</p>"]]}, "113": {"label": "Articolo 113", "heading": "Decisione di aggiudicazione e informazione dei candidati o offerenti", "anchor": "art_113", "frags": [[null, "<p class=\"norm\">1.  L'ordinatore responsabile designa l'aggiudicatario del contratto, nel rispetto dei criteri di selezione e di aggiudicazione indicati nei documenti di gara.</p>"], [null, "<p class=\"norm\">2.  L'amministrazione aggiudicatrice comunica a ogni candidato o offerente la cui domanda di partecipazione o offerta è stata respinta i motivi del rigetto, nonché la durata del periodo di status quo di cui all'articolo 118, paragrafo 2.</p>"], [null, "<p class=\"norm\">Per l'aggiudicazione di contratti specifici nell'ambito di un contratto quadro con riapertura del confronto competitivo, l'amministrazione aggiudicatrice informa gli offerenti dell'esito della valutazione.</p>"], [null, "<p class=\"norm\">3.  L'amministrazione aggiudicatrice comunica a ogni offerente che non si trova in situazione di esclusione, la cui offerta è conforme ai documenti di gara e che ne fa domanda per iscritto, le informazioni seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il nome dell'aggiudicatario, o degli aggiudicatari nel caso di un contratto quadro, e, a eccezione del caso di un contratto specifico nell'ambito di un contratto quadro con riapertura del confronto competitivo, le caratteristiche e i vantaggi relativi dell'offerta prescelta, il prezzo pagato o il valore del contratto, a seconda del caso;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>l'andamento delle negoziazioni e del dialogo con gli offerenti.</p>\n</div>"], [null, "<p class=\"norm\">Tuttavia, l'amministrazione aggiudicatrice può decidere di non divulgare talune informazioni qualora la loro diffusione ostacoli l'applicazione della legge, sia contraria all'interesse pubblico ovvero pregiudichi i legittimi interessi commerciali degli operatori economici o possa distorcere la concorrenza leale tra loro.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i requisiti e il contenuto della relazione di valutazione e la decisione di aggiudicazione nonché l'informazione dei candidati e offerenti.</p>"]]}, "114": {"label": "Articolo 114", "heading": "Annullamento della procedura di appalto", "anchor": "art_114", "frags": [[null, "<p class=\"norm\">Fino al momento della firma del contratto l'amministrazione aggiudicatrice può annullare la procedura di appalto, senza che i candidati o gli offerenti abbiano diritto ad alcun risarcimento.</p>"], [null, "<p class=\"norm\">La decisione è motivata ed è resa nota ai candidati o offerenti con la massima tempestività.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "114a": {"label": "Articolo 114 bis", "heading": "Esecuzione e modifiche del contratto", "anchor": "art_114a", "frags": [[null, "<p class=\"norm\">1.  L'esecuzione del contratto non ha inizio prima che lo stesso sia stato firmato.</p>"], [null, "<p class=\"norm\">2.  L'amministrazione aggiudicatrice può modificare un contratto o un contratto quadro senza organizzare una procedura di appalto soltanto nei casi di cui al paragrafo 3 e purché la modifica non muti l'oggetto del contratto o del contratto quadro.</p>"], [null, "<p class=\"norm\">3.  Un contratto o un contratto specifico nell'ambito di un contratto quadro può essere modificato senza una nuova procedura di appalto nei seguenti casi:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>se si sono resi necessari lavori, forniture o servizi supplementari da parte del contraente originale che non erano inclusi nell'appalto iniziale, ove siano soddisfatte tutte le seguenti condizioni:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>un cambiamento del contraente risulta impraticabile per motivi tecnici legati ai requisiti di intercambiabilità o interoperabilità tra apparecchiature, servizi o impianti esistenti;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>un cambiamento del contraente comporterebbe per l'amministrazione aggiudicatrice una consistente duplicazione dei costi; e</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>l'eventuale aumento di prezzo, ivi compreso il valore complessivo netto delle successive modifiche, non è superiore al 50 % del valore del contratto iniziale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>ove siano soddisfatte le seguenti condizioni:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>la necessità di modifica è determinata da circostanze che un'amministrazione aggiudicatrice diligente non ha potuto prevedere; e</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>l'eventuale aumento del prezzo non è superiore al 50 % del valore del contratto iniziale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>se il valore della modifica è al di sotto delle soglie seguenti:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>le soglie di cui all'articolo 118, paragrafo 1, e agli atti delegati adottati a norma dell'articolo 190, paragrafo 2, per quanto concerne le azioni esterne applicabili al momento della modifica; e</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>il 10 % del valore del contratto iniziale per i contratti pubblici di servizi e forniture e per i contratti di concessione di lavori o servizi e il 15 % del valore del contratto iniziale per i contratti pubblici di lavori;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>se i requisiti minimi della procedura di appalto iniziale non sono modificati. In tal caso qualsiasi modifica successiva del valore è conforme alle condizioni di cui alla lettera c) del presente comma, a meno che tale modifica di valore non risulti dalla rigorosa applicazione dei documenti di gara o delle disposizioni contrattuali.</p>\n</div>"], [null, "<p class=\"norm\">Le lettere a), c) e d) del primo comma del presente paragrafo si possono altresì applicare ai contratti quadro.</p>"], [null, "<p class=\"norm\">Il valore del contratto iniziale non tiene conto delle revisioni del prezzo.</p>"], [null, "<p class=\"norm\">Il valore complessivo netto di più modifiche successive ai sensi del primo comma, lettera c),del presente paragrafo, non supera alcuna soglia ivi stabilita.</p>"], [null, "<p class=\"norm\">L'amministrazione aggiudicatrice applica ex post le misure di pubblicità di cui all'articolo 103.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "115": {"label": "Articolo 115", "heading": "Garanzie", "anchor": "art_115", "frags": [[null, "<p class=\"norm\">1.  A eccezione dei casi di contratti di valore modesto, l'amministrazione aggiudicatrice può, se lo ritiene opportuno e proporzionato, sulla base di una valutazione caso per caso e previa analisi dei rischi, esigere dai contraenti una garanzia a uno dei fini seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>limitare i rischi finanziari collegati al versamento di prefinanziamenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>garantire il rispetto degli obblighi contrattuali sostanziali nel caso di lavori, forniture o servizi complessi;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>garantire la regolare esecuzione del contratto durante il periodo di responsabilità previsto dello stesso.</p>\n</div>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i tipi di garanzie che possono essere richiesti ai contraenti, inclusi criteri per l'analisi dei rischi, e l'importo massimo di ciascun tipo di garanzia in percentuale del valore complessivo del contratto.</p>"]]}, "116": {"label": "Articolo 116", "heading": "Errori sostanziali, irregolarità o frodi", "anchor": "art_116", "frags": [[null, "<p class=\"norm\">1.  Ai fini del presente articolo, per «errore sostanziale» si intende qualsiasi violazione di una disposizione contrattuale risultante da un atto o da un'omissione che arreca o potrebbe arrecare pregiudizio al bilancio.</p>"], [null, "<p class=\"norm\">2.  Quando la procedura si rivela inficiata da errori sostanziali, irregolarità o frodi, l'amministrazione aggiudicatrice la sospende e può adottare ogni provvedimento necessario, incluso l'annullamento della procedura stessa.</p>"], [null, "<p class=\"norm\">3.  Quando, dopo la firma del contratto, la procedura o l'esecuzione del contratto si rivela inficiata da errori sostanziali, irregolarità o frodi, l'amministrazione aggiudicatrice può sospendere l'esecuzione oppure, se del caso, risolvere il contratto.</p>"], [null, "<p class=\"norm\">Inoltre, l'esecuzione del contratto può essere sospesa al fine di accertare se si sono effettivamente verificati i presunti errori sostanziali e le presunte irregolarità o frodi.</p>"], [null, "<p class=\"norm\">Se gli errori sostanziali, le irregolarità o le frodi sono imputabili al contraente, l'amministrazione aggiudicatrice può inoltre rifiutare il pagamento o recuperare gli importi versati indebitamente, in misura proporzionale alla gravità degli errori sostanziali, delle irregolarità o delle frodi.</p>"], [null, "<p class=\"norm\">4.  L'OLAF esercita il potere conferito alla Commissione dal regolamento (Euratom, CE) n. 2185/96 (\n<span class=\"superscript\">19</span>\n) per effettuare controlli e verifiche sul posto negli Stati membri nonché, conformemente agli accordi vigenti in materia di cooperazione e assistenza reciproca, in paesi terzi e nei locali delle organizzazioni internazionali.</p>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la sospensione dell'esecuzione di un contratto in caso di errori sostanziali, irregolarità o frodi.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "117": {"label": "Articolo 117", "heading": "L'amministrazione aggiudicatrice", "anchor": "art_117", "frags": [[null, "<p class=\"norm\">1.  Le istituzioni ai sensi dell'articolo 2, le agenzie esecutive e gli organismi ai sensi degli articoli 208 e 209 sono considerati amministrazioni aggiudicatrici per i contratti che aggiudicano per proprio conto, salvo quando acquistano da una centrale di committenza. I servizi di dette istituzioni non sono considerati amministrazioni aggiudicatrici se concludono accordi amministrativi tra loro.</p>"], [null, "<p class=\"norm\">Dette istituzioni delegano, a norma dell'articolo 65, i poteri necessari per esercitare la funzione di amministrazione aggiudicatrice.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la delega della funzione di amministrazione aggiudicatrice e le centrali di committenza.</p>"]]}, "118": {"label": "Articolo 118", "heading": "Soglie applicabili e periodo di status quo", "anchor": "art_118", "frags": [[null, "<p class=\"norm\">1.  Ai fini dell'aggiudicazione di appalti pubblici e contratti di concessione, l'amministrazione aggiudicatrice rispetta le soglie stabilite all'articolo 4, lettere a) e b), della direttiva 2014/24/UE all'atto della selezione di una procedura di cui all'articolo 104, paragrafo 1, del presente regolamento. Tali soglie determinano le misure in materia di pubblicazione di cui all'articolo 103, paragrafi 1 e 2, del presente regolamento.</p>"], [null, "<p class=\"norm\">2.  Fatte salve le eccezioni e condizioni specificate negli atti delegati adottati a norma del presente regolamento, nel caso di contratti il cui valore superi le soglie di cui al paragrafo 1 l'amministrazione aggiudicatrice non firma il contratto o il contratto quadro con l'aggiudicatario prima che sia trascorso un periodo di status quo.</p>"], [null, "<p class=\"norm\">3.  Il periodo di status quo ha una durata di dieci giorni se si usano mezzi di comunicazione elettronici, di 15 giorni se si usano altri mezzi.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i contratti distinti e i contratti per lotti, la stima del valore degli appalti pubblici e dei contratti di concessione nonché il periodo di status quo prima della firma del contratto.</p>"]]}, "119": {"label": "Articolo 119", "heading": "Norme in materia di accesso agli appalti", "anchor": "art_119", "frags": [[null, "<p class=\"norm\">La partecipazione alle procedure di appalto è aperta a parità di condizioni a tutte le persone fisiche e giuridiche che rientrano nell'ambito d'applicazione dei trattati e a tutte le persone fisiche e giuridiche stabilite in un paese terzo che abbia concluso un accordo particolare con l'Unione nel settore degli appalti pubblici, secondo il disposto di detto accordo. La partecipazione è inoltre aperta alle organizzazioni internazionali.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la prova che deve essere fornita in relazione all'accesso agli appalti.</p>"]]}, "120": {"label": "Articolo 120", "heading": "Norme dell'Organizzazione mondiale del commercio in materia di appalti", "anchor": "art_120", "frags": [[null, "<p class=\"norm\">Qualora sia applicabile l'accordo plurilaterale sugli appalti pubblici concluso nell'ambito dell'Organizzazione mondiale del commercio, la procedura di appalto è aperta anche agli operatori economici stabiliti negli Stati che hanno ratificato tale accordo, alle condizioni da esso previste.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "121": {"label": "Articolo 121", "heading": "Portata delle sovvenzioni", "anchor": "art_121", "frags": [[null, "<p class=\"norm\">1.  Le sovvenzioni sono contributi finanziari diretti a carico del bilancio, accordati a titolo di liberalità, per finanziare quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>un'azione destinata a promuovere la realizzazione di un obiettivo di politica dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>oppure il funzionamento di un organismo che persegue uno scopo di interesse generale europeo o un obiettivo che si iscrive nel quadro di una politica dell'Unione (\"sovvenzioni di funzionamento\") e la sostiene.</p>\n</div>"], [null, "<p class=\"norm\">Le sovvenzioni sono oggetto di una convenzione scritta oppure di una decisione della Commissione notificata al richiedente selezionato di una sovvenzione.</p>"], [null, "<p class=\"norm\">La Commissione può istituire un sistema elettronico sicuro per gli scambi con i beneficiari.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo alla specificazione dettagliata della portata e del contenuto delle sovvenzioni e alle norme intese a determinare se sia necessario ricorrere a convenzioni o decisioni di sovvenzione. Alla Commissione è inoltre conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo ai dettagli sul sistema di scambio elettronico, comprese le condizioni in cui i documenti presentati per mezzo di tali sistemi, incluse le convenzioni di sovvenzione, sono da considerarsi originali e da firmare, e l'uso di partenariati quadro.</p>"], [null, "<p class=\"norm\">2.  Non costituiscono sovvenzioni ai sensi del presente titolo:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le spese per i membri e il personale delle istituzioni e i contributi alle scuole europee;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>gli appalti pubblici di cui all'articolo 10195, gli aiuti erogati a titolo di assistenza macrofinanziaria e di sostegno al bilancio;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>gli strumenti finanziari, nonché gli azionariati o la partecipazione azionaria in istituzioni finanziarie internazionali quali la Banca europea per la ricostruzione e lo sviluppo (BERS) o organismi specializzati dell'Unione come il Fondo europeo per gli investimenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>le quote versate dall'Unione a titolo di sottoscrizioni presso gli organismi dei quali è membro;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>e spese effettuate nell'ambito della gestione concorrente e della gestione indiretta ai sensi degli articoli 58, 59 e 60, se non diversamente specificato nel regolamento finanziario applicabile al bilancio delle entità o delle persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), o negli accordi di delega;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>i contributi versati a favore di agenzie esecutive di cui all'articolo 62 in virtù dell'atto costitutivo delle agenzie;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>le spese relative ai mercati della pesca di cui all'articolo 3, paragrafo 2, lettera f), del regolamento (CE) n. 1290/2005 del Consiglio, del 21 giugno 2005, relativo al finanziamento della politica agricola comune (\n<span class=\"superscript\">20</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">h)<span style=\"word-spacing: 15pt\"> </span>i rimborsi delle spese di viaggio e di soggiorno sostenute dalle persone invitate dalle istituzioni o munite di mandato delle istituzioni o, se del caso, qualsiasi altra indennità versata ad esse;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>i premi attribuiti in seguito a concorsi, ai quali si applica il titolo VII della parte prima;</p>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">j)<span style=\"word-spacing: 18pt\"> </span>contributi ai partiti politici europei di cui al titolo VIII della Parte seconda.</p>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">3.  Gli abbuoni dei tassi d'interessi e i sussidi per le commissioni di garanzia sono trattati come sovvenzioni, a condizione che non siano combinati in un'unica misura con strumenti finanziari di cui al titolo VIII della parte prima.</p>"], [null, "<p class=\"norm\">Talli abbuoni e sussidi sono soggetti alle disposizioni del presente titolo, ad eccezione di quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il principio del cofinanziamento di cui all'articolo 125, paragrafo 3;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il principio del divieto del fine di lucro di cui all'articolo 125, paragrafo 4;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>per le azioni miranti a rafforzare la capacità finanziaria di un beneficiario o produrre un reddito, la valutazione della capacità finanziaria del richiedente di cui all'articolo 132, paragrafo 1.</p>\n</div>"], [null, "<p class=\"norm\">4.  Ogni istituzione può accordare sovvenzioni per attività di comunicazione se, per motivi debitamente giustificati, non è appropriato il ricorso alle procedure di appalto pubblico.</p>"]]}, "122": {"label": "Articolo 122", "heading": "Beneficiari", "anchor": "art_122", "frags": [[null, "<p class=\"norm\">1.  Se più entità soddisfano i criteri per ottenere una sovvenzione e insieme costituiscono una sola entità, tale entità può essere considerata come l'unico beneficiario, anche quando è specificatamente istituita allo scopo di attuare l'azione da finanziare con la sovvenzione.</p>"], [null, "<p class=\"norm\">2.  Ai fini del presente titolo, le seguenti entità sono considerate entità affiliate al beneficiario:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>entità che costituiscono il beneficiario ai sensi del paragrafo 1;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>entità che soddisfano i criteri di ammissibilità, che non si trovano in una delle situazioni di cui all'articolo 131, paragrafo 4, e che hanno un legame con il beneficiario, in particolare un rapporto giuridico o di capitale, che non è limitato all'azione né istaurato al solo scopo della sua attuazione.</p>\n</div>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo al contenuto minimo delle convenzioni o decisioni di sovvenzione, in particolare, quando una sovvenzione viene concessa a diverse entità, agli obblighi specifici del coordinatore, se del caso, e degli altri beneficiari, al regime di responsabilità applicabile e alle condizioni per l'aggiunta o la cancellazione di un beneficiario.</p>"]]}, "123": {"label": "Articolo 123", "heading": "Forme di sovvenzioni", "anchor": "art_123", "frags": [[null, "<p class=\"norm\">1.  Le sovvenzioni possono assumere una delle seguenti forme:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>rimborso di una determinata percentuale dei costi ammissibili effettivamente sostenuti di cui all'articolo 126;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>rimborso sulla base dei costi unitari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>somme forfettarie;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>finanziamenti a tasso fisso;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>una combinazione delle forme di cui alle lettere da a) a d).</p>\n</div>"], [null, "<p class=\"norm\">2.  Nel determinare la forma appropriata di una sovvenzione, si tiene conto quanto più possibile degli interessi e dei metodi contabili dei potenziali beneficiari.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme relative alle diverse forme di sovvenzione, comprese le sovvenzioni di valore modesto.</p>"]]}, "124": {"label": "Articolo 124", "heading": "Somme forfettarie, costi unitari e finanziamenti a tasso fisso", "anchor": "art_124", "frags": [[null, "<p class=\"norm\">1.  Fatte salve le disposizioni dell'atto di base, il ricorso a somme forfettarie, costi unitari o finanziamenti a tasso fisso è autorizzato mediante una decisione della Commissione che garantisce l'osservanza del principio di parità di trattamento dei beneficiari per la stessa categoria di azioni o di programmi di lavoro.</p>"], [null, "<p class=\"norm\">Qualora l'importo massimo per sovvenzione non sia superiore all'ammontare di una sovvenzione di importo modesto, l'autorizzazione può essere data dall'ordinatore responsabile.</p>"], [null, "<p class=\"norm\">2.  L'autorizzazione è accompagnata almeno dagli elementi seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>una giustificazione concernente l'adeguatezza di tali forme di finanziamento in considerazione della natura delle azioni o dei programmi di lavoro sovvenzionati nonché dei rischi di irregolarità e frode e dei costi del controllo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>l'individuazione dei costi o delle categorie di costi coperti dalle somme forfettarie, dai costi unitari o dai finanziamenti a tasso fisso, ad esclusione dei costi non ammissibili in conformità delle norme applicabili dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>la descrizione dei metodi per determinare gli importi forfetari, i costi unitari o i finanziamenti a tasso fisso e delle condizioni per garantire ragionevolmente che i principi del divieto del fine di lucro e del cofinanziamento siano rispettati e che il doppio finanziamento dei costi sia evitato. Tali metodi si basano su:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>dati statistici o analoghi mezzi obiettivi; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>un approccio beneficiario per beneficiario, facendo riferimento a dati storici certificati o verificabili del beneficiario o alle sue consuete pratiche contabili.</p>\n</div>"], [null, "<p class=\"norm\">3.  Quando è autorizzato il ricorso alle consuete pratiche contabili del beneficiario, l'ordinatore responsabile può valutare, <span class=\"italics\">ex ante</span> o mediante una strategia appropriata di controlli <span class=\"italics\">ex post</span>, la conformità di tali pratiche alle condizioni di cui al paragrafo 2.</p>"], [null, "<p class=\"norm\">Se la conformità delle consuete pratiche contabili del beneficiario alle condizioni di cui al paragrafo 2 è stata stabilita <span class=\"italics\">ex ante</span>, gli importi delle somme forfettarie, dei costi unitari o dei finanziamenti a tasso fisso determinati dall'applicazione di queste pratiche non sono rimessi in discussione da controlli <span class=\"italics\">ex post</span>.</p>"], [null, "<p class=\"norm\">L'ordinatore responsabile può ritenere le consuete pratiche contabili del beneficiario conformi alle condizioni di cui al paragrafo 2 se esse sono accettate dalle autorità nazionali nell'ambito di regimi di finanziamento analoghi.</p>"], [null, "<p class=\"norm\">4.  La decisione o convenzione di sovvenzione può autorizzare o imporre il finanziamento dei costi indiretti del beneficiario mediante applicazione di tassi fissi, sino al massimale del 7 % del totale dei costi diretti ammissibili per l'azione, tranne qualora il beneficiario riceva una sovvenzione di funzionamento finanziata dal bilancio. Il massimale del 7 % può essere superato sulla base di una decisione motivata della Commissione.</p>"], [null, "<p class=\"norm\">5.  I proprietari di PMI e altre persone fisiche che non ricevono uno stipendio possono dichiarare costi ammissibili a livello di personale per il lavoro svolto nell'ambito di un programma d'azione o di lavoro, sulla base dei costi unitari determinati per mezzo di una decisione della Commissione.</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate riguardo alle somme forfettarie, ai costi unitari e ai finanziamenti a tasso fisso.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "125": {"label": "Articolo 125", "heading": "Principi generali applicabili alle sovvenzioni", "anchor": "art_125", "frags": [[null, "<p class=\"norm\">1.  Le sovvenzioni rispettano i principi della trasparenza e della parità di trattamento.</p>"], [null, "<p class=\"norm\">2.  Fatto salvo l'articolo 130, le sovvenzioni non sono cumulative né sono concesse retroattivamente.</p>"], [null, "<p class=\"norm\">3.  Le sovvenzioni sono soggette al regime del cofinanziamento, fatte salve le disposizioni specifiche di cui al titolo IV della parte seconda.</p>"], [null, "<p class=\"modref\">\n▼M2 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">4.  Le sovvenzioni non hanno come oggetto o effetto un profitto nel quadro dell'azione o del programma di lavoro del beneficiario (\"principio del divieto del fine di lucro\").</p>"], [null, "<p class=\"norm\">Il primo comma non si applica a:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>azioni il cui obiettivo è rafforzare la capacità finanziaria di un beneficiario o azioni che producono un reddito al fine di garantire la loro continuità dopo il periodo di finanziamento a carico dell'Unione previsto dalla decisione o convenzione di sovvenzione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>borse di studio, di ricerca o di formazione pagate a persone fisiche.</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>altri aiuti diretti corrisposti a persone fisiche estremamente bisognose, come i disoccupati e i rifugiati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>sovvenzioni sulla base di tassi forfettari e/o importi forfettari e/o costi unitari se conformi alle condizioni di cui all'articolo 124, paragrafo 2;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>sovvenzioni di valore modesto.</p>\n</div>"], [null, "<p class=\"norm\">Qualora si ottenga un profitto, la Commissione ha il diritto di recuperarne la percentuale corrispondente al contributo dell'Unione ai costi ammissibili effettivamente sostenuti dal beneficiario per realizzare l'azione o il programma di lavoro.</p>"], [null, "<p class=\"norm\">5.  Ai fini del presente titolo, il profitto è definito come un surplus di entrate rispetto ai costi ammissibili sostenuti dal beneficiario, quando la richiesta è fatta per il pagamento del saldo.</p>"], [null, "<p class=\"norm\">Le entrate di cui al primo comma sono limitate ai redditi generati dall'azione o dal programma di lavoro, così come ai contributi finanziari assegnati in modo specifico dai donatori al finanziamento dei costi ammissibili.</p>"], [null, "<p class=\"norm\">In caso di una sovvenzione di funzionamento, gli importi destinati alla costituzione di riserve non sono presi in considerazione ai fini della verifica del rispetto del principio del divieto del fine di lucro.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">6.  Se, alla fine di un esercizio finanziario per il quale ha ricevuto una sovvenzione di funzionamento, una fondazione politica a livello europeo ai sensi del regolamento (UE, Euratom) n. 1141/2014 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">21</span>\n) realizza un'eccedenza di entrate rispetto alle spese, può riportare all'esercizio successivo la parte di tale eccedenza corrispondente sino al massimo al 25 % delle entrate totali di quell'esercizio, in deroga al principio del divieto del fine di lucro di cui al paragrafo 4 del presente articolo, a condizione che tale parte sia usata entro il primo trimestre di tale esercizio successivo.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">7.  Le sovvenzioni possono essere assegnate senza invito a presentare proposte alla BEI o al Fondo europeo per gli investimenti per le azioni di assistenza tecnica. In tali casi non si applicano gli articoli 131, paragrafi da 2 a 5, e 132 paragrafo 1.</p>"], [null, "<p class=\"norm\">8.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 ad integrazione dei principi generali applicabili alle sovvenzioni, compresi il principio del divieto del fine di lucro e il principio del cofinanziamento. Alla Commissione è conferito inoltre il potere di adottare atti delegati conformemente all'articolo 210 riguardo alla definizione dell'assistenza tecnica.</p>"]]}, "126": {"label": "Articolo 126", "heading": "Costi ammissibili", "anchor": "art_126", "frags": [[null, "<p class=\"norm\">1.  Le sovvenzioni non superano un massimale globale espresso in termini di valore assoluto, fissato in base ai costi ammissibili stimati.</p>"], [null, "<p class=\"norm\">Le sovvenzioni non superano i costi ammissibili.</p>"], [null, "<p class=\"norm\">2.  Sono costi ammissibili i costi effettivamente sostenuti dal beneficiario di una sovvenzione che soddisfino tutti i seguenti criteri:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>sono sostenuti nel corso della durata dell'azione o del programma di lavoro, ad eccezione dei costi inerenti alle relazioni finali e ai certificati di revisione contabile;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>sono indicati nel bilancio stimato totale dell'azione o del programma di lavoro;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>sono necessari per attuare l'azione o il programma di lavoro oggetto della sovvenzione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>sono identificabili e verificabili, in particolare sono iscritti nei registri contabili del beneficiario e sono determinati secondo i principi contabili vigenti nello Stato nel quale risiede il beneficiario e secondo le consuete pratiche contabili del beneficiario stesso;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>soddisfano le disposizioni della legislazione tributaria e sociale applicabili;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>sono ragionevoli, giustificati e conformi al principio della sana gestione finanziaria, in particolare sotto il profilo dell'economia e dell'efficienza.</p>\n</div>"], [null, "<p class=\"norm\">3.  Gli inviti a presentare proposte precisano le categorie di costi considerati ammissibili al finanziamento dell'Unione.</p>"], [null, "<p class=\"norm\">Fatto salvo l'atto di base e in aggiunta al paragrafo 2, le seguenti categorie di costi sono ammissibili se l'ordinatore responsabile li ha dichiarati tali in base all'invito a presentare proposte:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>costi relativi a una garanzia di pre-finanziamento depositata dal beneficiario della sovvenzione, ove detta garanzia sia richiesta dall'ordinatore responsabile ai sensi dell'articolo 134, paragrafo 1;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>costi relativi alle revisioni contabili esterne ove tali revisioni siano richieste dall'ordinatore responsabile;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>imposta sul valore aggiunto (\"IVA\") quando non è recuperabile ai sensi della normativa nazionale sull'IVA applicabile ed è versata da un beneficiario diverso da un soggetto non passivo come definito dall'articolo 13, paragrafo 1, primo comma, della direttiva 2006/112/CE del Consiglio, del 28 novembre 2006, relativa al sistema comune d’imposta sul valore aggiunto (\n<span class=\"superscript\">22</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>i costi di ammortamento, purché effettivamente sostenuti dal beneficiario;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>i costi relativi alle retribuzioni del personale delle amministrazioni nazionali nella misura in cui essi sono correlati ai costi di attività che la pubblica autorità interessata non svolgerebbe se il progetto in questione non venisse realizzato.</p>\n</div>"], [null, "<p class=\"norm\">4.  I costi sostenuti dalle entità affiliate a un beneficiario di cui all'articolo 122 possono essere considerati ammissibili dall'ordinatore responsabile in base all'invito a presentare proposte. In tal caso, le seguenti condizioni si applicano cumulativamente:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le entità in questione sono individuate nella convenzione o decisione di sovvenzione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le entità interessate si attengono alle norme applicabili al beneficiario ai sensi della convenzione o decisione di sovvenzione per quanto concerne l'ammissibilità dei costi e i diritti di verifiche e di revisioni contabili da parte della Commissione, dell'OLAF e della Corte dei conti.</p>\n</div>"], [null, "<p class=\"norm\">5.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a ulteriori specificazioni sui costi ammissibili.</p>"]]}, "127": {"label": "Articolo 127", "heading": "Cofinanziamento in natura", "anchor": "art_127", "frags": [[null, "<p class=\"norm\">1.  Ai fini del calcolo del profitto generato dalla sovvenzione, non si tiene conto del cofinanziamento sotto forma di contributi in natura.</p>"], [null, "<p class=\"norm\">2.  Se lo ritiene necessario o opportuno, l'ordinatore responsabile può accettare quale cofinanziamento contributi in natura. Ove sia offerto un cofinanziamento in natura a integrazione di sovvenzioni di valore modesto e l'ordinatore responsabile abbia deciso di rifiutarlo, questi indica per quali motivi non lo ritiene necessario o opportuno.</p>"], [null, "<p class=\"norm\">Tali contributi non superano:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>i costi realmente sostenuti da terzi e debitamente giustificati da documenti contabili;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>oppure, in mancanza di tali documenti, i costi che corrispondono a quelli generalmente ammessi sul mercato in questione.</p>\n</div>"], [null, "<p class=\"norm\">I contributi in natura sono presentati separatamente nel bilancio di previsione in modo da evidenziare il totale delle risorse destinate all'azione. Il loro valore unitario è stimato nel bilancio di previsione e non è modificato successivamente.</p>"], [null, "<p class=\"norm\">I contributi in natura sono conformi alla normativa nazionale in materia tributaria e di previdenza sociale.</p>"]]}, "128": {"label": "Articolo 128", "heading": "Trasparenza", "anchor": "art_128", "frags": [[null, "<p class=\"norm\">1.  Le sovvenzioni sono oggetto di un programma di lavoro, che deve essere pubblicato prima dell'attuazione.</p>"], [null, "<p class=\"norm\">Tale programma di lavoro è attuato mediante la pubblicazione di inviti a presentare proposte, tranne in casi d'urgenza eccezionali debitamente giustificati oppure se le caratteristiche del beneficiario o dell'azione lo impongono come l'unica scelta per una determinata azione, oppure se il beneficiario viene individuato in un atto di base.</p>"], [null, "<p class=\"norm\">Il primo comma non si applica agli aiuti in situazioni di crisi, alle operazioni di protezione civile o alle operazioni di aiuto umanitario.</p>"], [null, "<p class=\"norm\">2.  Gli inviti a presentare proposte specificano la data prevista entro la quale tutti i richiedenti sono informati in merito ai risultati della valutazione della loro domanda e alla data indicativa per la firma delle convenzioni di sovvenzione o la notifica delle decisioni di finanziamento.</p>"], [null, "<p class=\"norm\">Tali date sono fissate sulla base dei periodi seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>per informare tutti i candidati dei risultati della valutazione della loro domanda, un massimo di sei mesi dal termine ultimo di presentazione delle proposte complete;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>per firmare con i candidati le convenzioni di sovvenzione o comunicare loro le decisioni di finanziamento, un massimo di tre mesi dalla data in cui i candidati idonei sono stati informati.</p>\n</div>"], [null, "<p class=\"norm\">Tali termini possono essere rettificati per tener conto del tempo necessario a rispettare le procedure specifiche che può essere previsto dall'atto di base ai sensi del regolamento (UE) n. 182/2011 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">23</span>\n) e può essere superato in casi eccezionali, debitamente giustificati, in particolare per azioni complesse, laddove vi sia un elevato numero di proposte o ritardi imputabili ai richiedenti.</p>"], [null, "<p class=\"norm\">L'ordinatore delegato riferisce nella sua relazione annuale di attività sui tempi medi per l'informazione dei candidati e la firma di convenzioni di sovvenzione o la notifica di decisioni di sovvenzione. Qualora vengano superati i termini di cui al secondo comma, l'ordinatore delegato fornisce le motivazioni e, ove non risultino debitamente giustificate ai sensi del terzo comma, propone azioni correttive.</p>"], [null, "<p class=\"norm\">3.  Tutte le sovvenzioni accordate nel corso di un esercizio sono oggetto di una pubblicazione annuale conformemente all'articolo 35, paragrafi 2 e 3.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i requisiti relativi al programma di lavoro, il contenuto degli inviti a presentare proposte, le deroghe a un invito a presentare proposte, le informazioni per i richiedenti e la pubblicazione <span class=\"italics\">ex post</span>.</p>"]]}, "129": {"label": "Articolo 129", "heading": "Divieto di cumulo", "anchor": "art_129", "frags": [[null, "<p class=\"norm\">1.  Per una stessa azione può essere accordata una sola sovvenzione a carico del bilancio, a favore di uno stesso beneficiario, a meno che non autorizzino altrimenti i pertinenti atti di base.</p>"], [null, "<p class=\"norm\">Un beneficiario può ricevere una sola sovvenzione di funzionamento a carico del bilancio per esercizio.</p>"], [null, "<p class=\"norm\">Il richiedente informa immediatamente gli ordinatori di eventuali richieste multiple e sovvenzioni multiple relative alla stessa azione o allo stesso programma di lavoro.</p>"], [null, "<p class=\"norm\">In nessun caso il bilancio finanzia due volte i medesimi costi.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo al principio della concessione non cumulativa di sovvenzioni.</p>"]]}, "130": {"label": "Articolo 130", "heading": "Principio di non retroattività", "anchor": "art_130", "frags": [[null, "<p class=\"norm\">1.  Una sovvenzione per un'azione già avviata può essere concessa solo se il richiedente può provare la necessità di avviare l'azione prima della firma della convenzione di sovvenzione o prima della notifica della decisione di sovvenzione.</p>"], [null, "<p class=\"norm\">In tali casi, i costi ammissibili al finanziamento non sono anteriori alla data di deposito della domanda di sovvenzione, salvo in casi eccezionali debitamente giustificati previsti nell'atto di base o in caso di estrema urgenza per aiuti in situazioni di crisi, operazioni di protezione civile, operazioni di aiuto umanitario ovvero in situazioni di pericolo imminente o immediato che rischino di degenerare in un conflitto armato o di destabilizzare un paese, in relazione a cui un impegno tempestivo dell'Unione sarebbe di grande importanza per promuovere la prevenzione dei conflitti.</p>"], [null, "<p class=\"norm\">È esclusa la sovvenzione retroattiva per azioni già concluse.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il principio di irretroattività.</p>"], [null, "<p class=\"norm\">2.  Nel caso di sovvenzioni di funzionamento, la convenzione di sovvenzione è firmata ovvero la decisione di sovvenzione è notificata entro sei mesi dall'inizio dell'esercizio del beneficiario. I costi ammissibili al finanziamento non possono essere anteriori alla data di deposito della domanda di sovvenzione o all'inizio dell'esercizio del beneficiario.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "131": {"label": "Articolo 131", "heading": "Domande di sovvenzione", "anchor": "art_131", "frags": [[null, "<p class=\"norm\">1.  Le domande di sovvenzione sono presentate per iscritto anche, se del caso, in un formato elettronico sicuro.</p>"], [null, "<p class=\"norm\">Qualora lo ritenga fattibile, la Commissione prevede la possibilità di presentare le domande di sovvenzione online.</p>"], [null, "<p class=\"norm\">2.  Sono ammissibili le domande di sovvenzione presentate da:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>persone giuridiche; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>persone fisiche, se lo esigono la natura o le caratteristiche dell'azione o l'obiettivo perseguito dal richiedente.</p>\n</div>"], [null, "<p class=\"norm\">Ai fini della lettera a) del primo comma, possono essere ammissibili le domande di sovvenzione presentate da entità non aventi personalità giuridica a norma del rispettivo diritto nazionale, purché i loro rappresentanti abbiano la capacità di assumere impegni giuridici in nome dell'entità e offrano garanzie per la tutela degli interessi finanziari dell'Unione equivalenti a quelle offerte dalle persone giuridiche.</p>"], [null, "<p class=\"norm\">3.  La domanda specifica lo status giuridico del richiedente e dimostra la sua capacità finanziaria e operativa di realizzare l'azione o il programma di lavoro oggetto della sua proposta.</p>"], [null, "<p class=\"norm\">A tale scopo, il richiedente presenta una dichiarazione sull'onore e, salvo nel caso di sovvenzioni di valore modesto, tutti i documenti giustificativi richiesti dall'ordinatore responsabile, sulla base di un'analisi dei rischi. L'obbligo di presentare tali documenti è indicato nell'invito a presentare proposte.</p>"], [null, "<p class=\"norm\">La verifica della capacità finanziaria non concerne le persone fisiche beneficiarie di borse di studio, le persone fisiche più bisognose e che ricevono aiuti diretti, gli enti pubblici o le organizzazioni internazionali. In funzione della sua valutazione del rischio, l'ordinatore responsabile può derogare all'obbligo di verificare la capacità operativa di enti pubblici o organizzazioni internazionali.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">4.  L'articolo 105 <span class=\"italics\">bis</span>, l'articolo 106, paragrafi da 1 a 4 e 6 e 7, salvo il primo comma, lettera b) e il secondo comma di tale paragrafo, i paragrafi 8, 9, 11 e da 13 a 17 e l'articolo 108 si applicano ai richiedenti e ai beneficiari di sovvenzioni. L'articolo 107 si applica ai richiedenti. I richiedenti devono dichiarare se si trovano in una delle situazioni di cui all'articolo 106, paragrafo 1, o all'articolo 107 e, se del caso, se hanno adottato le misure correttive di cui all'articolo 106, paragrafo 7, lettera a).</p>"], [null, "<p class=\"norm\">Nell'eseguire la necessaria verifica in relazione alle procedure di sovvenzione in corso e ai contratti esistenti in conformità dell'articolo 108, paragrafo 4, l'ordinatore assicura che al richiedete o al beneficiario sia stata data la possibilità di presentare le sue osservazioni prima dell'adozione di qualsiasi misura che leda i suoi diritti.</p>"], [null, "<p class=\"modref\">\n▼M3 —————</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti le disposizioni relative alle domande di sovvenzione, la prova che non rientrino in una situazione di esclusione, i richiedenti che non hanno personalità giuridica, le persone giuridiche che formano un unico richiedente, i criteri di ammissibilità e le sovvenzioni di valore modesto.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "132": {"label": "Articolo 132", "heading": "Criteri di selezione e di concessione", "anchor": "art_132", "frags": [[null, "<p class=\"norm\">1.  I criteri di selezione previamente enunciati nell'invito a presentare proposte permettono di valutare la capacità del richiedente di realizzare l'azione o il programma di lavoro proposti.</p>"], [null, "<p class=\"norm\">2.  I criteri di concessione previamente enunciati nell'invito a presentare proposte permettono di valutare la qualità delle proposte presentate a fronte degli obiettivi e delle priorità fissati.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i criteri di selezione e di concessione.</p>"]]}, "133": {"label": "Articolo 133", "heading": "Procedura di valutazione", "anchor": "art_133", "frags": [[null, "<p class=\"norm\">1.  Le proposte sono valutate sulla base dei criteri di selezione e di concessione preventivamente annunciati, al fine di individuare quelle che possono beneficiare di un finanziamento.</p>"], [null, "<p class=\"norm\">2.  L'ordinatore responsabile stabilisce successivamente, in base alla valutazione di cui al paragrafo 1, l'elenco dei beneficiari e gli importi approvati.</p>"], [null, "<p class=\"norm\">3.  L'ordinatore responsabile informa per iscritto il richiedente del seguito riservato alla sua domanda. In caso di mancata concessione della sovvenzione, l'istituzione interessata comunica i motivi del rifiuto, tenendo conto in particolare dei criteri di selezione e di concessione.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la valutazione e la concessione di sovvenzioni e informazioni ai richiedenti.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "134": {"label": "Articolo 134", "heading": "Garanzia di prefinanziamento", "anchor": "art_134", "frags": [[null, "<p class=\"norm\">1.  L'ordinatore responsabile può, se lo ritiene opportuno e proporzionato, su una base caso per caso e previa analisi del rischio, esigere dal beneficiario una garanzia preliminare per limitare i rischi finanziari inerenti al versamento dei prefinanziamenti.</p>"], [null, "<p class=\"norm\">2.  Nonostante il paragrafo 1, per le sovvenzioni di valore modesto non sono richieste garanzie.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la garanzia di prefinanziamento.</p>"]]}, "135": {"label": "Articolo 135", "heading": "Pagamento delle sovvenzioni e controlli", "anchor": "art_135", "frags": [[null, "<p class=\"norm\">1.  L'importo della sovvenzione diventa definitivo soltanto dopo l'approvazione da parte dell'ordinatore delegato responsabile delle relazioni e dei conti finali, fatti salvi ulteriori controlli da parte dell'istituzione interessata, che sono effettuati tempestivamente.</p>"], [null, "<p class=\"norm\">2.  Se la procedura di concessione si rivela inficiata da errori sostanziali, irregolarità o frodi, l'ordinatore responsabile sospende la procedura e può adottare ogni misura necessaria, incluso l'annullamento della procedura stessa. L'ordinatore responsabile informa immediatamente l'OLAF dei sospetti casi di frode.</p>"], [null, "<p class=\"norm\">3.  Se, dopo la concessione della sovvenzione, la procedura di concessione o l'esecuzione della sovvenzione si rivelano inficiate da errori sostanziali, irregolarità, frodi o violazioni degli obblighi, l'ordinatore responsabile può, in funzione della fase cui è giunta la procedura e, purché al richiedente o al beneficiario sia stata data la possibilità di formulare le proprie osservazioni:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>rifiutarsi di firmare la convenzione di sovvenzione o di notificare la decisione di sovvenzione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>sospendere l'esecuzione della sovvenzione; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>se del caso, porre fine alla convenzione o alla decisione di sovvenzione.</p>\n</div>"], [null, "<p class=\"norm\">4.  Qualora tali errori, irregolarità o frodi siano imputabili al beneficiario, ovvero qualora il beneficiario viola i propri obblighi ai sensi della convenzione o della decisione di sovvenzione, l'ordinatore responsabile può, inoltre, ridurre la sovvenzione o recuperare gli importi versati indebitamente a titolo della convenzione o decisione di sovvenzione, proporzionalmente alla gravità degli errori, delle irregolarità o delle frodi o della violazione degli obblighi, a condizione che al beneficiario sia data la possibilità di formulare le sue osservazioni.</p>"], [null, "<p class=\"norm\">5.  Qualora dalle verifiche e dai controlli emergano errori, irregolarità, frodi o violazioni degli obblighi sistemici o ricorrenti imputabili al beneficiario, che incidono materialmente su una serie di sovvenzioni concesse a tale beneficiario a condizioni analoghe, l'ordinatore responsabile può sospendere l'esecuzione di tutte le sovvenzioni interessate ovvero, se del caso, porre fine alle convenzioni o alle decisioni di sovvenzione con detto beneficiario, proporzionalmente alla gravità degli errori, delle irregolarità, delle frodi o della violazione degli obblighi, purché sia stata data al beneficiario la possibilità di formulare le sue osservazioni.</p>"], [null, "<p class=\"norm\">L'ordinatore responsabile può, inoltre, a seguito di un procedimento in contraddittorio, ridurre le sovvenzioni o recuperare gli importi indebitamente versati a titolo di tutte le sovvenzioni interessate da errori, irregolarità, frodi o violazione degli obblighi sistemici o ricorrenti, di cui al primo comma, che possono essersi verificati in conformità delle convenzioni o decisioni di sovvenzione.</p>"], [null, "<p class=\"norm\">6.  L'ordinatore responsabile stabilisce gli importi che devono essere ridotti o recuperati, ove possibile e realizzabile, sulla base dei costi indebitamente dichiarati ammissibili per ogni contributo in questione, previa accettazione delle schede finanziarie rivedute presentate dal beneficiario.</p>"], [null, "<p class=\"norm\">7.  Qualora non sia possibile o attuabile quantificare con precisione l'importo dei costi non ammissibili per ogni sovvenzione in questione, gli importi da ridurre o recuperare possono essere determinati estrapolando la riduzione o il tasso di recupero applicato alle sovvenzioni per le quali gli errori o le irregolarità sistemici o ricorrenti sono stati dimostrati, o, laddove i costi ammissibili non possono servire come base per la determinazione degli importi da ridurre o recuperare, applicando un tasso fisso, sulla base del principio di proporzionalità. Al beneficiario é accordata la possibilità di formulare le sue osservazioni sul metodo di estrapolazione o di tariffa forfettaria da applicare e di proporre un metodo o un tasso alternativo debitamente motivato prima che venga effettuata la riduzione o il recupero.</p>"], [null, "<p class=\"norm\">8.  La Commissione garantisce la parità di trattamento dei beneficiari di un programma, in particolare quando è attuato da parte di diversi ordinatori responsabili.</p>"], [null, "<p class=\"norm\">I beneficiari sono informati dei mezzi per impugnare le decisioni adottate a norma dei paragrafi 3, 4, 5, 6 e 7 del presente articolo, conformemente all'articolo 91 quater.</p>"], [null, "<p class=\"norm\">9.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate per il pagamento delle sovvenzioni e i controlli, incluse le norme concernenti i documenti giustificativi e la sospensione e la riduzione delle sovvenzioni.</p>"]]}, "136": {"label": "Articolo 136", "heading": "Periodi per la conservazione dei dati", "anchor": "art_136", "frags": [[null, "<p class=\"norm\">1.  I beneficiari conservano la documentazione, i documenti giustificativi, la documentazione statistica e gli altri dati relativi alle sovvenzioni per i cinque anni successivi al pagamento del saldo, e per tre anni nel caso delle sovvenzioni di valore modesto.</p>"], [null, "<p class=\"norm\">2.  La documentazione inerente alle revisioni contabili, ai ricorsi, ai contenziosi o alle azioni legali derivanti dall'esecuzione del progetto è conservata fintanto che le revisioni contabili, i ricorsi, i contenziosi o le azioni legali non siano stati conclusi.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "137": {"label": "Articolo 137", "heading": "Appalti di esecuzione e sostegno finanziario a favore di terzi", "anchor": "art_137", "frags": [[null, "<p class=\"norm\">1.  Quando l'esecuzione di un'azione o di un programma di lavoro richiede la concessione di un sostegno finanziario a terzi, il beneficiario può concedere tale sostegno purché:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>prima di concedere la sovvenzione, l'ordinatore responsabile abbia verificato che il beneficiario offra garanzie adeguate per quanto riguarda il recupero degli importi dovuti alla Commissione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le condizioni per la concessione di tale sostegno siano rigorosamente definite nella decisione o nella convenzione di sovvenzione conclusa tra il beneficiario e la Commissione, in modo da evitare l'esercizio di poteri discrezionali da parte del beneficiario;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>tale sostegno riguardi importi esigui, a meno che esso non sia l'obiettivo primario dell'azione.</p>\n</div>"], [null, "<p class=\"norm\">2.  Ogni decisione o convenzione di sovvenzione prevede espressamente il potere di controllo della Commissione e della Corte dei conti, per quanto concerne i documenti i locali e le informazioni, anche memorizzate su dispositivi elettronici, di tutti i terzi che hanno beneficiato di fondi dell'Unione.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo alle norme dettagliate concernenti gli appalti di esecuzione e il sostegno finanziario a favore di terzi.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "138": {"label": "Articolo 138", "heading": "Disposizioni generali", "anchor": "art_138", "frags": [[null, "<p class=\"norm\">1.  I premi rispettano i principi della trasparenza e della parità di trattamento e promuovono la realizzazione degli obiettivi strategici dell'Unione.</p>"], [null, "<p class=\"norm\">2.  A tal fine, i premi sono oggetto di un programma di lavoro che deve essere pubblicato prima dell'attuazione. Il programma di lavoro è attuato mediante la pubblicazione di concorsi.</p>"], [null, "<p class=\"norm\">I concorsi a premi con un valore unitario di EUR 1 000 000  o più possono essere pubblicati solo se sono previsti nei rendiconti di attività o in qualsiasi altro documento pertinente di cui all'articolo 38, paragrafo 3, lettera e).</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">Le regole del concorso stabiliscono almeno le condizioni di partecipazione compresi i criteri di esclusione, i criteri di aggiudicazione, l'ammontare del premio e le modalità di pagamento. L'articolo 105 <span class=\"italics\">bis</span>, l'articolo 106, paragrafi da 1 a 4 e 6 e 7, salvo il primo comma, lettera b), e il secondo comma di tale paragrafo, i paragrafi 8, 9, 11 e da 13 a 17 e l'articolo 108 si applicano ai partecipanti e ai vincitori. L'articolo 107 si applica per analogia ai partecipanti.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">I premi non possono essere attribuiti direttamente, senza un concorso, e sono pubblicati annualmente conformemente all'articolo 35, paragrafi 2 e 3.</p>"], [null, "<p class=\"norm\">3.  I partecipanti a un concorso sono valutati da un gruppo di esperti in base alle regole pubblicate del concorso.</p>"], [null, "<p class=\"norm\">I premi sono quindi attribuiti dall'ordinatore responsabile, sulla base della valutazione fornita dal gruppo di esperti, che ha la facoltà di decidere se raccomandarne o meno l'attribuzione, a seconda del loro apprezzamento della qualità dei partecipanti.</p>"], [null, "<p class=\"norm\">4.  L'ammontare del premio non è correlato ai costi sostenuti dal vincitore.</p>"], [null, "<p class=\"norm\">5.  Qualora l'esecuzione di un'azione o di un programma di lavoro richieda l'attribuzione di premi a terzi da parte del beneficiario di una sovvenzione dell'Unione, il beneficiario in questione può attribuire detti premi, purché il contenuto minimo delle regole del concorso di cui al paragrafo 2 sia definito rigorosamente nella decisione o convenzione di sovvenzione conclusa tra il beneficiario e la Commissione, senza alcun margine discrezionale.</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i premi, comprese la programmazione, le regole del concorso, la pubblicazione <span class=\"italics\">ex post</span>, la valutazione, l'informazione e la notifica dei vincitori.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "139": {"label": "Articolo 139", "heading": "Portata", "anchor": "art_139", "frags": [[null, "<p class=\"norm\">1.  Gli strumenti finanziari sono autorizzati mediante un atto di base.</p>"], [null, "<p class=\"norm\">In deroga al primo comma, gli strumenti finanziari possono essere costituiti, in casi debitamente giustificati, senza essere autorizzati per mezzo di un atto di base, a condizione che tali strumenti siano inclusi nel bilancio ai sensi dell'articolo 49, paragrafo 1, lettera e).</p>"], [null, "<p class=\"norm\">2.  Quando il sostegno dell'Unione è fornito attraverso strumenti finanziari e combinato in un'unica misura con elementi direttamente correlati agli strumenti finanziari destinati agli stessi destinatari finali, compresa l'assistenza tecnica, gli abbuoni dei tassi d'interessi e i sussidi per le commissioni di garanzia, il presente titolo si applica a tutti gli elementi della misura.</p>"], [null, "<p class=\"norm\">3.  Quando gli strumenti finanziari sono combinati con sovvenzioni finanziate dal bilancio a norma del titolo VI della parte prima per quanto concerne gli elementi non direttamente connessi agli strumenti finanziari, le registrazioni sono mantenute separate per ciascuna fonte di finanziamento.</p>"], [null, "<p class=\"norm\">4.  La Commissione può attuare gli strumenti finanziari di gestione diretta o indiretta, come previsto nell'atto di base, affidando i compiti alle entità a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii), v) e vi).</p>"], [null, "<p class=\"norm\">Le entità delegate a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii), v) e vi), quando attuano strumenti finanziari, possono inoltre affidare, sotto la loro responsabilità, parte dell'attuazione a intermediari finanziari, a condizione che dette entità assicurino che gli intermediari finanziari soddisfano i criteri di cui all'articolo 140, paragrafi 1, 3 e 5. Gli intermediari finanziari sono selezionati mediante procedure aperte, trasparenti, proporzionate e non discriminatorie, tali da evitare conflitti di interessi.</p>"], [null, "<p class=\"norm\">La Commissione continua a essere responsabile di assicurare che il quadro di attuazione degli strumenti finanziari sia conforme al principio della sana gestione finanziaria e consenta il conseguimento di obiettivi strategici definiti e temporizzati, misurabili in termini di realizzazioni e risultati. La Commissione è responsabile dell'attuazione degli strumenti finanziari fatta salva la responsabilità giuridica e contrattuale delle entità delegate, conformemente alla legislazione applicabile.</p>"], [null, "<p class=\"norm\">5.  Quando gli strumenti finanziari sono attuati nell'ambito della gestione concorrente con gli Stati membri, le disposizioni applicabili a tali strumenti, comprese le norme per i contributi agli strumenti finanziari gestiti direttamente o indirettamente ai sensi del presente titolo, sono stabilite nei regolamenti di cui all'articolo 175.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">5 <span class=\"italics\">bis</span>.  L'articolo 105 <span class=\"italics\">bis</span>, l'articolo 106, paragrafo 1, salvo le lettere e) e f), di tale paragrafo, i paragrafi 2, 3 e 4, da 6 a 9 e da 13 a 17 e gli articoli 107 e 108 si applicano ai veicoli di investimento dedicati o agli intermediari finanziari. I destinatari finali forniscono agli intermediari finanziari una dichiarazione sull'onore firmata che conferma che non si trovano in una delle situazioni di cui all'articolo 106, paragrafo 1, lettere a), b), c) e d), o all'articolo 107, paragrafo 1, lettere b) e c).</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">6.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti gli strumenti finanziari, compresa la selezione delle entità incaricate dell'attuazione degli strumenti finanziari, il contenuto degli accordi di delega, i costi di gestione e le tasse, le norme specifiche per i conti fiduciari, l'attuazione diretta degli strumenti finanziari e la selezione dei gestori, degli intermediari finanziari e dei destinatari finali.</p>"]]}, "140": {"label": "Articolo 140", "heading": "Principi e condizioni applicabili agli strumenti finanziari", "anchor": "art_140", "frags": [[null, "<p class=\"norm\">1.  Gli strumenti finanziari sono utilizzati in conformità dei principi di sana gestione finanziaria, trasparenza, proporzionalità, non discriminazione, parità di trattamento e sussidiarietà e dei loro obiettivi nonché, se del caso, della durata stabilita nell'atto di base applicabile per detti strumenti finanziari.</p>"], [null, "<p class=\"norm\">2.  Gli strumenti finanziari rispettano quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>attuazione intesa a ovviare a situazioni di investimento carenti o non ottimali, che si sono dimostrate finanziariamente sostenibili ma che non danno luogo a un finanziamento sufficiente da parte delle fonti di mercato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>addizionalità: gli strumenti finanziari non sono intesi a sostituire quelli di uno Stato membro, i finanziamenti privati o altri interventi finanziari dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>non distorsione della concorrenza sul mercato interno e coerenza con le norme sugli aiuti di Stato;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>effetto moltiplicatore: il contributo dell'Unione a uno strumento finanziario è inteso a mobilitare un investimento globale che supera l'entità del contributo dell'Unione conformemente agli indicatori previamente definiti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>allineamento degli interessi: nell'attuazione di strumenti finanziari, la Commissione garantisce che vi sia un interesse comune nel conseguire gli obiettivi strategici definiti per uno strumento finanziario, eventualmente rafforzato mediante disposizioni quali requisiti di investimento congiunto, condivisione dei rischi o incentivi finanziari, prevenendo nel contempo un conflitto di interesse con altre attività dell'entità delegata;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>gli strumenti finanziari sono stabiliti sulla base di una valutazione <span class=\"italics\">ex ante</span>, compresa una valutazione del possibile riutilizzo delle risorse aggiuntive di cui al paragrafo 8, lettera f).</p>\n</div>"], [null, "<p class=\"norm\">3.  Le spese di bilancio connesse a uno strumento finanziario e la responsabilità finanziaria dell'Unione non superano in alcun caso l'importo dell'impegno di bilancio a esso corrispondente, escludendo pertanto passività potenziali per il bilancio.</p>"], [null, "<p class=\"norm\">4.  Le entità delegate a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii), v) e vi), e tutti gli intermediari finanziari scelti per partecipare all'esecuzione di operazioni finanziarie nell'ambito di uno strumento finanziario rispettano le norme pertinenti e la legislazione applicabile in materia di prevenzione del riciclaggio di denaro, di lotta al terrorismo e di frode fiscale. Per l'attuazione degli strumenti finanziari ai sensi del presente titolo, le entità delegate a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii), v) e vi, non sono stabilite e non mantengono relazioni commerciali con entità incorporate, in territori le cui giurisdizioni non collaborano con l'Unione relativamente all'applicazione delle norme fiscali convenute a livello internazionale e traspongono questi requisiti nei loro contratti con gli intermediari finanziari scelti.</p>"], [null, "<p class=\"norm\">5.  Le entità delegate a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii), v) e vi), gli intermediari finanziari di cui al paragrafo 4 del presente articolo, che partecipano alla gestione degli strumenti finanziari dell'Unione, e i destinatari finali del sostegno dell'Unione ai sensi del presente titolo forniscono alla Corte dei conti tutti gli strumenti e tutte le informazioni che questa ritiene necessari per l'adempimento dei suoi compiti, ai sensi dell'articolo 161.</p>"], [null, "<p class=\"norm\">Il regolamento (Euratom, CE) n. 2185/96 e il regolamento (CE) n. 1073/1999 del Parlamento europeo e del Consiglio, del 25 maggio 1999, relativo alle indagini svolte dall'Ufficio per la lotta antifrode (OLAF) (\n<span class=\"superscript\">24</span>\n) si applicano al sostegno dell'Unione ai sensi del presente titolo.</p>"], [null, "<p class=\"norm\">6.  Gli importi corrispondenti almeno al contributo dell'Unione o, se del caso, suoi multipli sono utilizzati per il conseguimento degli obiettivi specifici perseguiti attraverso lo strumento finanziario e non generano indebiti vantaggi, in particolare sotto forma di dividendi e di profitti indebiti a favore di terzi.</p>"], [null, "<p class=\"norm\">Fatta salva la normativa settoriale per la gestione concorrente, le entrate, compresi i dividendi, le plusvalenze, le commissioni di garanzia e gli interessi sui prestiti e sugli importi dei conti fiduciari rimborsati alla Commissione o dei conti fiduciari aperti per strumenti finanziari e imputabili al sostegno dal bilancio nell'ambito di uno strumento finanziario, sono iscritti nel bilancio previa detrazione dei costi di gestione e delle tasse.</p>"], [null, "<p class=\"norm\">I rimborsi annuali, compresi i rimborsi di capitale, le garanzie rilasciate e i rimborsi del capitale dei prestiti, versati sui conti della Commissione o su conti fiduciari aperti per strumenti finanziari e imputabili al sostegno dal bilancio nell'ambito di uno strumento finanziario, costituiscono entrate con destinazione specifica interna conformemente all'articolo 21 e sono utilizzati per lo stesso strumento finanziario, fatto salvo il paragrafo 9 del presente articolo, per un periodo non superiore al periodo di impegno degli stanziamenti più due anni, se non diversamente specificato in un atto di base.</p>"], [null, "<p class=\"norm\">7.  I pagamenti su conti fiduciari sono effettuati dalla Commissione sulla base di domande di pagamento debitamente motivate da previsioni di spesa, tenendo conto dei saldi disponibili sui conti fiduciari e della necessità di evitare saldi eccessivi su tali conti. Qualora gli importi sui conti fiduciari siano sufficienti a coprire la riserva minima prevista contrattualmente sui conti fiduciari, aumentata delle previsioni di spesa per l'esercizio in corso, e gli importi necessari per coprire le passività potenziali in relazione agli obblighi di pagamento in valute diverse dall'euro, nessun ulteriore pagamento è effettuato sui conti fiduciari. Le previsioni di spesa vanno fornite su base annuale o, se del caso, su base semestrale.</p>"], [null, "<p class=\"norm\">8.  La Commissione riferisce annualmente al Parlamento europeo e al Consiglio in merito alle attività relative agli strumenti finanziari. Le relazione comprende, per ciascuno strumento finanziario sostenuto:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'identificazione dello strumento finanziario e dell'atto di base;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>una descrizione dello strumento finanziario, delle pertinenti modalità di attuazione e del valore aggiunto del contributo dell'Unione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>le istituzioni finanziarie coinvolte nella realizzazione, comprese le questioni relative all'applicazione del paragrafo 5;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>gli impegni di bilancio aggregati e i pagamenti a titolo del bilancio per ciascuno strumento finanziario;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>le prestazioni degli strumenti finanziari, compresi gli investimenti realizzati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">f)<span style=\"word-spacing: 17pt\"> </span>una valutazione dell'utilizzo delle somme restituite allo strumento come entrate interne con destinazione specifica ai sensi del paragrafo 6;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">g)<span style=\"word-spacing: 15pt\"> </span>il saldo del conto fiduciario;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">h)<span style=\"word-spacing: 15pt\"> </span>entrate e rimborsi ai sensi del paragrafo 6;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>il valore degli investimenti azionari rispetto agli anni precedenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">j)<span style=\"word-spacing: 18pt\"> </span>i dati cumulativi sulle riduzioni durevoli di valore delle attività di strumenti di capitale o di condivisione del rischio e sulle garanzie attivate per gli strumenti di garanzia;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">k)<span style=\"word-spacing: 15pt\"> </span>l'effetto moltiplicatore obiettivo e quello conseguito;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">l)<span style=\"word-spacing: 19pt\"> </span>il suo contributo al conseguimento degli obiettivi del programma in questione misurato mediante gli indicatori stabiliti, compresa, se del caso, la diversificazione geografica.</p>\n</div>"], [null, "<p class=\"norm\">9.  Qualora il Parlamento europeo o il Consiglio ritengano che uno strumento finanziario non abbia raggiunto i suoi obiettivi in modo efficace, possono chiedere alla Commissione di presentare una proposta di atto di base rivisto al fine di chiudere lo strumento. Nel caso della chiusura dello strumento finanziario, eventuali nuovi rimborsi di tale strumento ai sensi del paragrafo 6, terzo comma, sono considerati come entrate generali.</p>"], [null, "<p class=\"norm\">10.  L'obiettivo degli strumenti finanziari e, se del caso, la loro forma giuridica specifica e la sede legale di registrazione sono pubblicati sul sito della Commissione.</p>"], [null, "<p class=\"norm\">11.  Per gli strumenti finanziari l'ordinatore responsabile verifica che le schede finanziarie, che coprono il periodo dal 1 gennaio al 31 dicembre nel rispetto delle norme contabili di cui all'articolo 143 e dei principi contabili internazionali del settore pubblico (IPSAS), nonché tutte le informazioni necessarie per produrre le schede finanziarie ai sensi dell'articolo 68, paragrafo 3, saranno fornite dalle entità delegate a norma dell'articolo 58, paragrafo 1, lettera c), punti ii), iii,) v) e vi) entro il 15 febbraio dell'anno successivo. L'ordinatore responsabile garantisce inoltre che schede finanziarie riviste per gli strumenti finanziari siano fornite da dette entità entro il 15 maggio dell'anno successivo.</p>"], [null, "<p class=\"norm\">12.  La Commissione garantisce una gestione armonizzata degli strumenti finanziari, in particolare nel settore della contabilità, della rendicontazione, del monitoraggio e della gestione del rischio finanziario.</p>"], [null, "<p class=\"norm\">13.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'attuazione degli strumenti finanziari, comprese le condizioni per il loro uso, l'effetto moltiplicatore, la valutazione ex-ante, il monitoraggio e il trattamento dei contributi dei fondi di cui all'articolo 175.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "141": {"label": "Articolo 141", "heading": "Struttura contabile", "anchor": "art_141", "frags": [[null, "<p class=\"norm\">I conti comprendono quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>gli stati finanziari consolidati, che presentano il consolidamento delle informazioni finanziarie contenute negli stati finanziari delle istituzioni finanziate dal bilancio, degli organismi di cui all'articolo 208 e degli altri organismi i cui conti devono essere consolidati in ottemperanza delle norme contabili di cui all'articolo 143;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i conti di bilancio aggregati che presentano le informazioni contenute nella contabilità di bilancio delle istituzioni.</p>\n</div>"]]}, "142": {"label": "Articolo 142", "heading": "Relazione sulla gestione di bilancio e finanziaria", "anchor": "art_142", "frags": [[null, "<p class=\"norm\">1.  Ogni istituzione e organismo di cui all'articolo 141 prepara una relazione sulla gestione di bilancio e finanziaria dell'esercizio.</p>"], [null, "<p class=\"norm\">Essi trasmettono la relazione al Parlamento europeo, al Consiglio e alla Corte dei conti entro il 31 marzo che segue l'esercizio chiuso.</p>"], [null, "<p class=\"norm\">2.  La relazione di cui al paragrafo 1 fornisce, almeno, in termini sia assoluti che percentuali, informazioni sul tasso di esecuzione degli stanziamenti insieme a una sintesi sugli storni di stanziamenti fra le varie voci del bilancio.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la relazione sulla gestione di bilancio e finanziaria.</p>"]]}, "143": {"label": "Articolo 143", "heading": "Norme relative alla contabilità", "anchor": "art_143", "frags": [[null, "<p class=\"norm\">1.  Il contabile della Commissione stabilisce le norme sul modello delle norme contabili internazionalmente ammesse per il settore pubblico. Il contabile può discostarsi da tali norme contabili se lo reputa necessario per dare un'immagine fedele degli elementi di attivo e di passivo, degli oneri e proventi e dei flussi di cassa. Qualora una norma contabile si discosti sensibilmente da dette norme, le note degli stati finanziari indicano tale fatto e i motivi che lo giustificano.</p>"], [null, "<p class=\"norm\">2.  I conti di bilancio di cui all'articolo 141 devono rispettare i principi di bilancio stabiliti dal presente regolamento. Essi forniscono un'immagine fedele delle operazioni di bilancio in entrate e in spese.</p>"]]}, "144": {"label": "Articolo 144", "heading": "Principi contabili", "anchor": "art_144", "frags": [[null, "<p class=\"norm\">1.  Gli stati finanziari di cui all'articolo 141 presentano le informazioni, comprese le informazioni sui metodi contabili, in maniera che garantiscano che sono pertinenti, affidabili, confrontabili e comprensibili. Gli stati finanziari sono formati in conformità dei principi contabili generalmente ammessi enunciati nelle norme contabili di cui all'articolo 143.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati relativi all'adozione del quadro concernente lo svolgimento da parte del contabile dei propri compiti a norma del presente articolo e degli articoli 145, 146, 148, 151, 154, 156 e 157.</p>"]]}, "145": {"label": "Articolo 145", "heading": "Stati finanziari", "anchor": "art_145", "frags": [[null, "<p class=\"norm\">1.  Gli stati finanziari sono presentati in milioni di euro e comprendono quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il bilancio finanziario e il conto economico, che rappresentano l'intera situazione patrimoniale e finanziaria e il risultato economico al 31 dicembre dell'esercizio precedente; sono presentati conformemente alle norme contabili di cui all'articolo 143;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la situazione dei flussi di cassa che fa apparire gli incassi e gli esborsi dell'esercizio e la situazione finale di tesoreria;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>la situazione di variazione dell'attivo netto che presenta una sintesi dei movimenti che durante l'esercizio hanno interessato le riserve e gli utili accantonati.</p>\n</div>"], [null, "<p class=\"norm\">2.  Le note degli stati finanziari completano e commentano le informazioni fornite negli stati di cui al paragrafo 1, fornendo le informazioni supplementari prescritte dalla pratica contabile ammessa a livello internazionale, allorché tali informazioni siano pertinenti per le attività dell'Unione.</p>"]]}, "146": {"label": "Articolo 146", "heading": "Relazioni sull'esecuzione del bilancio", "anchor": "art_146", "frags": [[null, "<p class=\"norm\">1.  Le relazioni sull'esecuzione del bilancio sono presentate in milioni di euro. Esse comprendono:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le relazioni che comprendono la totalità delle operazioni di bilancio dell'esercizio in entrate e in spese;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>le note esplicative che completano e commentano le informazioni fornite nelle relazioni.</p>\n</div>"], [null, "<p class=\"norm\">2.  La struttura delle relazioni sull'esecuzione del bilancio è la stessa del bilancio.</p>"]]}, "147": {"label": "Articolo 147", "heading": "Conti provvisori", "anchor": "art_147", "frags": [[null, "<p class=\"norm\">1.  I contabili delle altre istituzioni e degli organismi di cui all'articolo 141 comunicano i loro conti provvisori al contabile della Commissione e alla Corte dei conti entro il 1<span class=\"superscript\">o</span> marzo che segue l'esercizio chiuso.</p>"], [null, "<p class=\"norm\">2.  I contabili delle altre istituzioni e degli organismi di cui all'articolo 141 comunicano inoltre al contabile della Commissione, entro il 1<span class=\"superscript\">o</span> marzo che segue l'esercizio chiuso, la documentazione contabile in un formato standard stabilito dal contabile della Commissione ai fini del consolidamento.</p>"], [null, "<p class=\"norm\">3.  Il contabile della Commissione consolida tali conti provvisori con quelli provvisori della Commissione e trasmette alla Corte dei conti, entro il 31 marzo che segue l'esercizio chiuso, i conti provvisori della Commissione e i conti provvisori consolidati dell'Unione.</p>"]]}, "148": {"label": "Articolo 148", "heading": "Approvazione dei conti consolidati definitivi", "anchor": "art_148", "frags": [[null, "<p class=\"norm\">1.  La Corte dei conti formula, entro il 1<span class=\"superscript\">o</span> giugno, le sue osservazioni sui conti provvisori delle istituzioni diverse dalla Commissione e degli organismi di cui all'articolo 141 e, entro il 15 giugno, le sue osservazioni sui conti provvisori della Commissione e sui conti provvisori consolidati dell'Unione.</p>"], [null, "<p class=\"norm\">2.  Le istituzioni diverse dalla Commissione e ogni organismo di cui all'articolo 141 formano i rispettivi conti definitivi e li trasmettono al contabile della Commissione, alla Corte dei conti, al Parlamento europeo e al Consiglio entro il 1<span class=\"superscript\">o</span> luglio, in vista della formazione dei conti consolidati definitivi.</p>"], [null, "<p class=\"norm\">I contabili delle altre istituzioni e degli organismi di cui all'articolo 141 comunicano inoltre al contabile della Commissione, entro il 1<span class=\"superscript\">o</span> luglio, la documentazione contabile in un formato standard stabilito dal contabile della Commissione ai fini del consolidamento.</p>"], [null, "<p class=\"norm\">3.  I contabili di ogni istituzione e organismo di cui all'articolo 141 trasmettono altresì alla Corte dei conti, e in copia al contabile della Commissione, contemporaneamente a tali conti definitivi, una dichiarazione a essi relativa.</p>"], [null, "<p class=\"norm\">I conti definitivi sono corredati di una nota redatta dal contabile nella quale quest'ultimo dichiara che i conti definitivi sono stati elaborati nel rispetto del presente titolo e dei principi, delle norme e dei metodi contabili applicabili.</p>"], [null, "<p class=\"norm\">4.  Il contabile della Commissione redige i conti consolidati definitivi in base alle informazioni presentategli a norma del paragrafo 2 del presente articolo dalle istituzioni diverse dalla Commissione e dagli organismi di cui all'articolo 141. I conti consolidati definitivi sono corredati di una nota redatta dal contabile della Commissione, nella quale quest'ultimo dichiara che i conti consolidati definitivi sono stati elaborati nel rispetto del presente titolo e dei principi, delle norme e dei metodi contabili descritti nelle note agli stati finanziari.</p>"], [null, "<p class=\"norm\">5.  La Commissione approva i conti consolidati definitivi ed i propri conti definitivi e li trasmette entro il 31 luglio al Parlamento europeo, al Consiglio e alla Corte dei conti.</p>"], [null, "<p class=\"norm\">Entro la stessa data il contabile della Commissione trasmette alla Corte dei conti una dichiarazione relativa ai conti consolidati definitivi.</p>"], [null, "<p class=\"norm\">6.  I conti consolidati definitivi sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> entro il 15 novembre, corredati della dichiarazione d'affidabilità fornita dalla Corte dei conti a norma dell'articolo 287 TFUE e dell'articolo 106 bis del trattato Euratom.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "149": {"label": "Articolo 149", "heading": "Relazione su garanzie di bilancio e rischi", "anchor": "art_149", "frags": [[null, "<p class=\"norm\">La Commissione, oltre agli stati e alle relazioni di cui agli articoli 145 e 146, riferisce una volta all'anno al Parlamento europeo e al Consiglio sulla situazione delle garanzie di bilancio di cui all'articolo 49, paragrafo 1, lettera d), e dei rischi corrispondenti.</p>"], [null, "<p class=\"norm\">Tali informazioni sono trasmesse contemporaneamente alla Corte dei conti.</p>"]]}, "150": {"label": "Articolo 150", "heading": "Informazioni relative all'esecuzione del bilancio", "anchor": "art_150", "frags": [[null, "<p class=\"norm\">1.  Il contabile della Commissione, oltre agli stati e alle relazioni di cui agli articoli 145 e 146, trasmette una volta al mese al Parlamento europeo e al Consiglio dati in cifre, aggregati almeno a livello dei capitoli, sull'esecuzione del bilancio, per quanto concerne sia le entrate che le spese relative all'insieme degli stanziamenti.</p>"], [null, "<p class=\"norm\">Tali dati forniscono anche informazioni sull'impiego degli stanziamenti riportati.</p>"], [null, "<p class=\"norm\">I dati sono trasmessi entro dieci giorni lavorativi a decorrere dalla fine di ogni mese.</p>"], [null, "<p class=\"norm\">2.  Tre volte all'anno, entro 30 giorni lavorativi successivi al 31 maggio, al 31 agosto e al 31 dicembre, il contabile della Commissione presenta al Parlamento europeo e al Consiglio una relazione sull'esecuzione di bilancio, in entrate e in spese, illustrata in dettaglio per capitoli, articoli e voci.</p>"], [null, "<p class=\"norm\">Dette relazioni comportano anche le informazioni relative all'esecuzione degli stanziamenti riportati dagli esercizi precedenti.</p>"], [null, "<p class=\"norm\">3.  I dati in cifre e la relazione sull'esecuzione del bilancio sono trasmessi contemporaneamente alla Corte dei conti e pubblicati sul sito internet della Commissione.</p>"], [null, "<p class=\"norm\">4.  Entro il 15 settembre di ogni anno, il contabile trasmette al Parlamento europeo e al Consiglio una relazione contenente informazioni concernenti gli attuali rischi osservati, le tendenze generali constatate, i nuovi problemi contabili incontrati, i progressi compiuti su aspetti contabili, compresi quelli evocati dalla Corte dei conti, e le informazioni relative ai recuperi.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "151": {"label": "Articolo 151", "heading": "Il sistema contabile", "anchor": "art_151", "frags": [[null, "<p class=\"norm\">1.  Un sistema contabile delle istituzioni serve a organizzare l'informazione di bilancio e finanziaria che permette di iscrivere, classificare e registrare dati in cifre.</p>"], [null, "<p class=\"norm\">2.  Il sistema contabile si compone di una contabilità generale e di una contabilità di bilancio. Le due contabilità sono tenute in euro e per esercizio.</p>"], [null, "<p class=\"norm\">3.  L'ordinatore delegato può anche tenere una contabilità analitica.</p>"]]}, "152": {"label": "Articolo 152", "heading": "Prescrizioni comuni per i sistemi contabili delle istituzioni", "anchor": "art_152", "frags": [[null, "<p class=\"norm\">Conformemente all'articolo 143, il contabile della Commissione, previa consultazione dei contabili delle altre istituzioni e degli organismi di cui all'articolo 141, stabilisce le norme contabili e il piano contabile armonizzato che deve essere applicato da tutte le istituzioni finanziate dal bilancio, da tutti gli uffici di cui al titolo V della parte seconda e da tutti gli organismi di cui all'articolo 141.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "153": {"label": "Articolo 153", "heading": "La contabilità generale", "anchor": "art_153", "frags": [[null, "<p class=\"norm\">La contabilità generale riproduce in forma cronologica, secondo il metodo della partita doppia, gli eventi e le operazioni che intervengono nella situazione economica, finanziaria e patrimoniale delle istituzioni e degli organismi di cui all'articolo 141.</p>"]]}, "154": {"label": "Articolo 154", "heading": "Scritture contabili", "anchor": "art_154", "frags": [[null, "<p class=\"norm\">1.  I saldi e i movimenti di ciascun conto sono iscritti nei libri contabili.</p>"], [null, "<p class=\"norm\">2.  Ogni scrittura contabile, comprese le rettifiche contabili, è basata su documenti giustificativi ai quali essa fa riferimento.</p>"], [null, "<p class=\"norm\">3.  Il sistema contabile permette di risalire con chiarezza a tutte le scritture contabili.</p>"]]}, "155": {"label": "Articolo 155", "heading": "Rettifiche contabili", "anchor": "art_155", "frags": [[null, "<p class=\"norm\">Dopo la chiusura dell'esercizio e fino alla data del rendiconto, il contabile procede alle correzioni che, senza comportare esborsi o incassi a carico dell'esercizio, sono necessarie per una presentazione regolare, fedele e sincera dei conti. Tali rettifiche rispettano le norme contabili di cui all'articolo 143.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "156": {"label": "Articolo 156", "heading": "Contabilità di bilancio", "anchor": "art_156", "frags": [[null, "<p class=\"norm\">1.  La contabilità di bilancio fornisce un quadro dettagliato dell'esecuzione del bilancio.</p>"], [null, "<p class=\"norm\">2.  Ai fini del paragrafo 1, la contabilità di bilancio registra tutti gli atti d'esecuzione del bilancio in entrate e in spese previsti al titolo IV della prima parte.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "157": {"label": "Articolo 157", "heading": "L'inventario", "anchor": "art_157", "frags": [[null, "<p class=\"norm\">1.  Ogni istituzione e organismo di cui all'articolo 141 tiene, conformemente al modello stabilito dal contabile della Commissione, inventari in numero e in valore di tutte le immobilizzazioni materiali, immateriali e finanziarie che costituiscono il patrimonio dell'Unione.</p>"], [null, "<p class=\"norm\">Ogni istituzione e organismo di cui all'articolo 141 verifica la concordanza tra le scritture d'inventario e la situazione di fatto.</p>"], [null, "<p class=\"norm\">2.  Le vendite di immobilizzazioni materiali dell'Unione sono oggetto di una pubblicità adeguata.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "158": {"label": "Articolo 158", "heading": "Revisione contabile esterna della Corte dei conti", "anchor": "art_158", "frags": [[null, "<p class=\"norm\">Il Parlamento europeo, il Consiglio e la Commissione informano la Corte dei conti, con la massima tempestività, di tutte le decisioni e di tutte le norme da essi emanati a norma degli articoli 13, 16, 21, 25, 26, 29 e 40.</p>"]]}, "159": {"label": "Articolo 159", "heading": "Norme e procedure di revisione contabile esterna", "anchor": "art_159", "frags": [[null, "<p class=\"norm\">1.  L'esame da parte della Corte dei conti della legittimità e della regolarità delle entrate e delle spese è effettuato rispetto ai trattati, al bilancio, al presente regolamento, agli atti delegati adottati a norma del presente regolamento e a tutti gli altri atti emanati in esecuzione dei trattati.</p>"], [null, "<p class=\"norm\">2.  Nell'assolvimento delle proprie attribuzioni, la Corte dei conti può prendere conoscenza, secondo il disposto dell'articolo 161, di tutti i documenti e di tutte le informazioni relativi alla gestione finanziaria dei servizi o organismi riguardanti le operazioni finanziate o cofinanziate dall'Unione. Essa ha il potere di sentire qualsiasi agente responsabile di un'operazione di spesa o di entrata e di avvalersi di tutte le procedure di revisione contabile riconosciute a detti servizi o organismi. Il controllo negli Stati membri si effettua di concerto con le istituzioni nazionali di controllo o, se queste non dispongono delle necessarie competenze, con i servizi nazionali competenti. La Corte dei conti e le istituzioni nazionali di controllo degli Stati membri cooperano in uno spirito di reciproca fiducia, pur mantenendo la loro indipendenza.</p>"], [null, "<p class=\"norm\">Per raccogliere tutte le informazioni necessarie all'assolvimento di compiti ad essa affidati dai trattati o dagli atti adottati in esecuzione dei medesimi, la Corte dei conti, qualora lo richieda, può essere presente alle operazioni di controllo effettuate nel quadro dell'esecuzione del bilancio da parte o per conto di un'istituzione.</p>"], [null, "<p class=\"norm\">Su richiesta della Corte dei conti ogni istituzione autorizza gli organismi finanziari che detengono averi dell'Unione a far sì che la Corte stessa possa accertarsi della corrispondenza dei dati esterni con la situazione contabile.</p>"], [null, "<p class=\"norm\">3.  Per l'assolvimento del suo compito, la Corte dei conti notifica alle istituzioni e alle autorità alle quali si applica il presente regolamento finanziario, i nominativi dei funzionari autorizzati a effettuare controlli presso di esse.</p>"]]}, "160": {"label": "Articolo 160", "heading": "Verifiche relative a titoli e fondi", "anchor": "art_160", "frags": [[null, "<p class=\"norm\">La Corte dei conti provvede a che tutti i titoli e i fondi depositati o in cassa siano verificati mediante attestazioni sottoscritte dai depositari o mediante verbali di situazioni di cassa e di portafoglio. Essa può procedere a tali verifiche direttamente.</p>"]]}, "161": {"label": "Articolo 161", "heading": "Diritto di accesso della Corte dei conti", "anchor": "art_161", "frags": [[null, "<p class=\"norm\">1.  La Commissione, le altre istituzioni, gli organismi che gestiscono entrate o spese a nome dell'Unione, nonché i destinatari, accordano alla Corte dei conti ogni agevolazione e le forniscono tutte le informazioni di cui essa ritenga di aver bisogno per l'assolvimento dei suoi compiti. Mettono a disposizione della Corte dei conti tutti i documenti relativi all'aggiudicazione e all'esecuzione degli appalti finanziati dal bilancio e ogni conto relativo a movimenti di denaro o di materiali, ogni documento contabile o giustificativo e i relativi documenti amministrativi, ogni documentazione relativa alle entrate e alle spese delle Comunità, ogni inventario, ogni organigramma che la Corte dei conti ritenga necessario per la verifica, in base a documenti o a revisioni sul posto, della relazione sul risultato dell'esecuzione del bilancio e finanziaria e, per lo stesso scopo, ogni documento e tutti i dati stabiliti o conservati elettronicamente.</p>"], [null, "<p class=\"norm\">Gli organismi di controllo interni e gli altri servizi di controllo delle amministrazioni nazionali interessate accordano alla Corte dei conti ogni agevolazione di cui essa ritenga di aver bisogno per l'assolvimento dei suoi compiti.</p>"], [null, "<p class=\"norm\">2.  I funzionari soggetti alle verifiche della Corte dei conti sono tenuti a quanto segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>aprire le loro casse, esibire denari, valori e materiali di qualsiasi natura, i documenti giustificativi della loro gestione di cui sono depositari, nonché libri e registri e qualsiasi altro documento attinente;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>esibire la corrispondenza e qualunque altro documento necessario alla completa esecuzione del controllo di cui all'articolo 159, paragrafo 1.</p>\n</div>"], [null, "<p class=\"norm\">La comunicazione delle informazioni di cui alla lettera b) del primo comma può essere chiesta solo dalla Corte dei conti.</p>"], [null, "<p class=\"norm\">3.  La Corte dei conti è abilitata a verificare i documenti relativi alle entrate e alle spese dell'Unione, detenuti dai servizi delle istituzioni e, in particolare, dai servizi responsabili delle decisioni su tali entrate e spese, presso gli organismi che gestiscono entrate o spese in nome dell'Unione e delle persone fisiche o giuridiche beneficiarie di pagamenti provenienti dal bilancio.</p>"], [null, "<p class=\"norm\">4.  La verifica della legittimità e regolarità delle entrate e delle spese e il controllo della sana gestione finanziaria si estendono all'impiego, da parte degli organismi esterni alle istituzioni, dei fondi dell'Unione riscossi a titolo di sovvenzioni.</p>"], [null, "<p class=\"norm\">5.  Qualsiasi finanziamento dell'Unione a destinatari esterni alle istituzioni è subordinato all'accettazione scritta, da parte di tali destinatari o, in mancanza di questa, da parte dei contraenti o dei subcontraenti, di una verifica eseguita dalla Corte dei conti sull'uso dell'importo dei finanziamenti accordati.</p>"], [null, "<p class=\"norm\">6.  La Commissione fornisce alla Corte dei conti, qualora questa le richieda, tutte le informazioni sull'assunzione e sull'erogazione di prestiti.</p>"], [null, "<p class=\"norm\">7.  L'uso di sistemi informatici integrati non ha l'effetto di limitare l'accesso da parte della Corte dei conti ai documenti giustificativi.</p>"]]}, "162": {"label": "Articolo 162", "heading": "Relazione annuale della Corte dei conti", "anchor": "art_162", "frags": [[null, "<p class=\"norm\">1.  La Corte dei conti trasmette entro il 30 giugno alla Commissione e alle istituzioni interessate le osservazioni che ritiene di natura tale da dover figurare nella relazione annuale. Tali osservazioni rimangono riservate e sono oggetto di una procedura in contraddittorio. Tutte le istituzioni inviano le proprie risposte alla Corte dei conti entro il 15 ottobre. Le altre istituzioni inviano contemporaneamente le proprie risposte alla Commissione.</p>"], [null, "<p class=\"norm\">2.  Nella relazione annuale figura una valutazione della sana gestione finanziaria.</p>"], [null, "<p class=\"norm\">3.  La relazione annuale comporta tante suddivisioni quante sono le istituzioni. La Corte dei conti può aggiungere tutte le presentazioni di sintesi o osservazioni di portata generale che ritiene adeguate.</p>"], [null, "<p class=\"norm\">La Corte dei conti adotta tutte i provvedimenti necessari affinché le risposte delle istituzioni alle sue osservazioni siano pubblicate accanto a ciascuna osservazione alla quale si riferiscono o dopo di essa.</p>"], [null, "<p class=\"norm\">4.  La Corte dei conti invia alle autorità preposte al discarico e alle altre istituzioni, entro il 15 novembre, la propria relazione annuale corredata delle risposte delle istituzioni e ne cura la pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"norm\">5.  Dopo la trasmissione da parte della Corte dei conti della relazione annuale, la Commissione comunica immediatamente agli Stati membri interessati gli elementi di tale relazione riguardanti la gestione dei fondi per i quali sono competenti in forza della normativa pertinente.</p>"], [null, "<p class=\"norm\">Una volta ricevuta la comunicazione, gli Stati membri inviano la loro risposta alla Commissione entro 60 giorni. La Commissione ne trasmette una sintesi di dette informazioni alla Corte dei conti, al Parlamento europeo e al Consiglio entro il 28 febbraio.</p>"]]}, "163": {"label": "Articolo 163", "heading": "Relazioni speciali della Corte dei conti", "anchor": "art_163", "frags": [[null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">1.  La Corte dei conti trasmette all'istituzione o all'organismo interessati le eventuali osservazioni che, a suo avviso, dovrebbero figurare in una relazione speciale. Tali osservazioni rimangono riservate e sono oggetto di una procedura in contraddittorio.</p>"], [null, "<p class=\"norm\">In generale, entro sei settimane dalla trasmissione di dette osservazioni, l'istituzione o l'organismo interessati comunicano alla Corte dei conti le proprie eventuali risposte a tali osservazioni. Tale termine è sospeso, in casi debitamente giustificati, in particolare qualora, durante la procedura in contraddittorio, l'istituzione o l'organismo interessati necessitino di un seguito da parte degli Stati membri per mettere a punto la loro risposta.</p>"], [null, "<p class=\"norm\">Le risposte dell'istituzione o dell'organismo interessati riguardano direttamente ed esclusivamente le osservazioni della Corte dei conti.</p>"], [null, "<p class=\"norm\">La Corte dei conti provvede a che le relazioni speciali siano elaborate e adottate entro un congruo periodo di tempo che, in termini generali, non supera i 13 mesi.</p>"], [null, "<p class=\"norm\">Le relazioni speciali corredate delle risposte delle istituzioni o degli organismi interessati sono senza indugio trasmesse al Parlamento europeo e al Consiglio, i quali decidono, eventualmente d'intesa con la Commissione, quale seguito darvi.</p>"], [null, "<p class=\"norm\">La Corte dei conti adotta tutti i provvedimenti necessari affinché le risposte alle sue osservazioni da parte delle istituzioni o degli organismi interessati, nonché il calendario per l'elaborazione della relazione speciale, siano pubblicati unitamente alla relazione speciale.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">2.  I pareri di cui all'articolo 287, paragrafo 4, secondo comma, TFUE che non riguardano proposte o progetti nell'ambito della procedura di consultazione legislativa possono essere pubblicati dalla Corte dei conti nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>. La Corte dei conti decide in merito a tale pubblicazione dopo aver consultato l'istituzione che ha chiesto il parere o l'istituzione cui il parere si riferisce. I pareri pubblicati sono corredati di eventuali commenti delle istituzioni interessate.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "164": {"label": "Articolo 164", "heading": "Calendario della procedura di discarico", "anchor": "art_164", "frags": [[null, "<p class=\"norm\">1.  Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, dà atto alla Commissione, entro il 15 maggio dell'anno n + 2, dell'esecuzione del bilancio dell'esercizio n.</p>"], [null, "<p class=\"norm\">2.  Se la data di cui al paragrafo 1 non può essere rispettata, il Parlamento europeo o il Consiglio informano la Commissione dei motivi per cui la decisione ha dovuto essere differita.</p>"], [null, "<p class=\"norm\">3.  Qualora il Parlamento europeo rinvii la decisione di discarico, la Commissione si adopera per adottare, al più presto, misure che consentano e facilitino la rimozione degli ostacoli che si frappongono alla decisione.</p>"]]}, "165": {"label": "Articolo 165", "heading": "La procedura di discarico", "anchor": "art_165", "frags": [[null, "<p class=\"norm\">1.  La decisione di discarico riguarda i conti della totalità delle entrate e delle spese dell'Unione, nonché il relativo saldo, e l'attivo e il passivo dell'Unione descritti nel bilancio finanziario.</p>"], [null, "<p class=\"norm\">2.  In vista del discarico, il Parlamento europeo esamina, successivamente al Consiglio, i conti, gli stati finanziari e la relazione di valutazione di cui all'articolo 318 TFUE. Esamina anche la relazione annuale della Corte dei conti, corredata delle risposte delle istituzioni controllate, nonché le sue relazioni speciali pertinenti, riguardo all'esercizio interessato, e la sua dichiarazione attestante l'affidabilità dei conti nonché la legittimità e la regolarità delle relative operazioni.</p>"], [null, "<p class=\"norm\">3.  La Commissione presenta al Parlamento europeo, su richiesta dello stesso, tutte le informazioni necessarie al corretto svolgimento della procedura di discarico per l'esercizio in causa, conformemente all'articolo 319 TFUE.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"]]}, "166": {"label": "Articolo 166", "heading": "Misure di follow-up", "anchor": "art_166", "frags": [[null, "<p class=\"norm\">1.  A norma dell'articolo 319 TFUE e dell'articolo 106 <span class=\"italics\">bis</span> del trattato Euratom, la Commissione, le altre istituzioni e gli organismi di cui agli articoli 208 e 209 del presente regolamento adottano ogni misura utile per dar seguito alle osservazioni che accompagnano la decisione di discarico del Parlamento europeo e ai commenti che accompagnano la raccomandazione di discarico adottata dal Consiglio.</p>"], [null, "<p class=\"norm\">2.  Su richiesta del Parlamento europeo o del Consiglio, le istituzioni e gli organismi di cui al paragrafo 1 riferiscono in merito alle misure adottate a seguito di tali osservazioni e commenti, in particolare sulle istruzioni impartite ai servizi incaricati dell'esecuzione del bilancio. Gli Stati membri cooperano con la Commissione informandola delle misure da essi adottate per dare seguito alle osservazioni, affinché essa ne tenga conto nella sua relazione. Le relazioni delle istituzioni sono trasmesse anche alla Corte dei conti.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "167": {"label": "Articolo 167", "heading": "Disposizioni specifiche riguardanti il SEAE", "anchor": "art_167", "frags": [[null, "<p class=\"norm\">Al SEAE si applicano le procedure di cui all'articolo 319 TFUE e agli articoli 164, 165 e 166 del presente regolamento. Il SEAE coopera pienamente con le istituzioni coinvolte nella procedura di discarico e fornisce, se del caso, ogni informazione supplementare necessaria, anche partecipando a riunioni degli organismi competenti.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "168": {"label": "Articolo 168", "heading": "Disposizioni particolari riguardanti il Fondo europeo agricolo di garanzia", "anchor": "art_168", "frags": [[null, "<p class=\"norm\">1.  Le disposizioni delle parti prima e terza, fatte salve le deroghe di cui al presente titolo, si applicano alle spese effettuate dai servizi e organismi di cui alla normativa sul Fondo europeo agricolo di garanzia (FEAGA), nonché alle entrate.</p>"], [null, "<p class=\"norm\">2.  Le operazioni gestite direttamente dalla Commissione sono eseguite secondo le disposizioni delle parti prima e terza.</p>"]]}, "169": {"label": "Articolo 169", "heading": "Impegni relativi a stanziamenti del FEAGA", "anchor": "art_169", "frags": [[null, "<p class=\"norm\">1.  Per ogni esercizio gli stanziamenti del FEAGA includono gli stanziamenti non dissociati, tranne che per le spese correlate alle misure di cui all'articolo 3, paragrafo 2, del regolamento (CE) n. 1290/2005 che saranno coperte con stanziamenti dissociati.</p>"], [null, "<p class=\"norm\">2.  Gli stanziamenti riportati e rimasti inutilizzati alla fine dell'esercizio sono annullati.</p>"], [null, "<p class=\"norm\">3.  Gli stanziamenti non impegnati relativi alle azioni di cui all'articolo 3, paragrafo 1, del regolamento (CE) n. 1290/2005, possono essere oggetto di un riporto limitato esclusivamente all'esercizio successivo.</p>"], [null, "<p class=\"norm\">Tale riporto non può superare, entro il limite del 2 % degli stanziamenti iniziali, l'importo dell'adattamento dei pagamenti diretti di cui all'articolo 11 del regolamento (CE) n. 73/2009 del Consiglio, del 19 gennaio 2009, che stabilisce norme comuni relative ai regimi di sostegno diretto nell'ambito della politica agricola comune e istituisce taluni regimi di sostegno a favore degli agricoltori (\n<span class=\"superscript\">25</span>\n), che era stato applicato nell' esercizio precedente.</p>"], [null, "<p class=\"norm\">Gli stanziamenti riportati sono riversati esclusivamente nelle linee di bilancio che coprono le azioni di cui all'articolo 3, paragrafo 1, lettera c), del regolamento (CE) n. 1290/2005.</p>"], [null, "<p class=\"norm\">Tale riporto può condurre soltanto a un pagamento supplementare a favore dei destinatari finali ai quali è stato applicato, nell' esercizio precedente, l'adattamento dei pagamenti diretti di cui all'articolo 11 del regolamento (CE) n. 73/2009.</p>"], [null, "<p class=\"norm\">La Commissione adotta la decisione di riporto entro il 15 febbraio dell'esercizio verso il quale è previsto il riporto e ne informa il Parlamento europeo e il Consiglio.</p>"]]}, "170": {"label": "Articolo 170", "heading": "Impegni accantonati globali relativi agli stanziamenti del FEAGA", "anchor": "art_170", "frags": [[null, "<p class=\"norm\">1.  La Commissione rimborsa le spese del FEAGA sostenute dagli Stati membri.</p>"], [null, "<p class=\"norm\">2.  Le decisioni della Commissione che stabiliscono l'importo dei rimborsi di tali spese costituiscono impegni accantonati globali, entro i limiti del totale degli stanziamenti iscritti per il FEAGA.</p>"], [null, "<p class=\"norm\">3.  Le spese di gestione corrente del FEAGA possono, a partire dal 15 novembre dell'esercizio, essere oggetto di impegni anticipati a carico degli stanziamenti previsti per l'esercizio successivo. Tali impegni non superano tuttavia i tre quarti del totale dei corrispondenti stanziamenti dell'esercizio in corso. Riguardano unicamente spese il cui principio si fonda su un atto di base esistente.</p>"]]}, "171": {"label": "Articolo 171", "heading": "Scadenzario e programmazione degli impegni di bilancio del FEAGA", "anchor": "art_171", "frags": [[null, "<p class=\"norm\">1.  Le spese effettuate dai servizi e dagli organismi di cui alla normativa sul FEAGA formano oggetto, entro due mesi dalla ricezione degli stati trasmessi dagli Stati membri, di un impegno per capitolo, articolo e voce. Si può procedere a tale impegno dopo la scadenza del suddetto termine di due mesi qualora sia necessaria una procedura di storno di stanziamenti relativi alle pertinenti linee di bilancio. Salvo il caso in cui il pagamento da parte degli Stati membri non sia ancora avvenuto oppure vi siano dubbi quanto all'ammissibilità, l'imputazione in pagamento avviene entro lo stesso termine di due mesi.</p>"], [null, "<p class=\"norm\">Gli impegni di cui al primo comma sono dedotti dall'impegno accantonato globale di cui all'articolo 170.</p>"], [null, "<p class=\"norm\">2.  Gli impegni accantonati globali, effettuati a titolo di un esercizio e che non hanno dato luogo, entro il 1<span class=\"superscript\">o</span> febbraio dell'esercizio successivo, a impegni dettagliati secondo la nomenclatura del bilancio, sono cancellati con riferimento all'esercizio in questione.</p>"], [null, "<p class=\"norm\">3.  I paragrafi 1 e 2 si applicano con riserva dell'esame e dell'accettazione dei conti.</p>"]]}, "172": {"label": "Articolo 172", "heading": "Contabilità delle spese del FEAGA", "anchor": "art_172", "frags": [[null, "<p class=\"norm\">Nei conti di bilancio le spese sono imputate a un esercizio sulla base dei rimborsi effettuati dalla Commissione agli Stati membri entro il 31 dicembre di tale esercizio, a condizione che l'ordine di pagamento sia pervenuto al contabile entro il 31 gennaio dell'esercizio successivo.</p>"]]}, "173": {"label": "Articolo 173", "heading": "Storni di stanziamenti del FEAGA", "anchor": "art_173", "frags": [[null, "<p class=\"norm\">1.  La Commissione, quando a norma dell'articolo 26, paragrafo 1, procede a storni di stanziamenti, adotta la decisione entro il 31 gennaio dell'esercizio successivo e ne informa il Parlamento europeo e il Consiglio come previsto all'articolo 26, paragrafo 1.</p>"], [null, "<p class=\"norm\">2.  Nei casi diversi da quelli previsti al paragrafo 1, la Commissione propone gli storni al Parlamento europeo e al Consiglio entro il 10 gennaio dell'esercizio successivo.</p>"], [null, "<p class=\"norm\">Il Parlamento europeo e il Consiglio decidono gli storni secondo la procedura di cui all'articolo 27, ma ai fini del presente articolo il termine applicabile è di tre settimane.</p>"]]}, "174": {"label": "Articolo 174", "heading": "Entrate con destinazione specifica del FEAGA", "anchor": "art_174", "frags": [[null, "<p class=\"norm\">1.  Le entrate con destinazione specifica di cui al presente titolo sono destinate in funzione dell'origine dell'entrata, a norma dell'articolo 21, paragrafo 3.</p>"], [null, "<p class=\"norm\">2.  Il risultato della decisione di cui all'articolo 30 del regolamento (CE) n. 1290/2005 è imputato su un unico articolo.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "175": {"label": "Articolo 175", "heading": "Disposizioni particolari", "anchor": "art_175", "frags": [[null, "<p class=\"norm\">1.  Le disposizioni delle parti prima e terza si applicano alle spese effettuate dai servizi e dagli organismi di cui al regolamento (CE) n. 1698/2005 del Consiglio, del 20 settembre 2005, relativo al sostegno allo sviluppo rurale da parte del Fondo europeo agricolo per lo sviluppo rurale (\n<span class=\"superscript\">26</span>\n), al regolamento (CE) n. 1080/2006 del Parlamento europeo e del Consiglio, del 5 luglio 2006, relativo al Fondo europeo di sviluppo regionale (\n<span class=\"superscript\">27</span>\n), al regolamento (CE) n. 1081/2006 del Parlamento europeo e del Consiglio, del 5 luglio 2006, relativo al Fondo sociale europeo (\n<span class=\"superscript\">28</span>\n), al regolamento (CE) n. 1083/2006 del Consiglio, dell'11 luglio 2006, recante disposizioni generali sul Fondo europeo di sviluppo regionale, sul Fondo sociale europeo e sul Fondo di coesione (\n<span class=\"superscript\">29</span>\n), al regolamento (CE) n. 1084/2006 del Consiglio, dell'11 luglio 2006, che istituisce un Fondo di coesione (\n<span class=\"superscript\">30</span>\n), al regolamento (CE) n. 1198/2006 del Consiglio, del 27 luglio 2006, relativo al Fondo europeo per la pesca (\n<span class=\"superscript\">31</span>\n), nonché ai fondi del settore libertà, sicurezza e giustizia, inclusi i fondi nel quadro del programma \"Solidarietà e gestione dei flussi migratori\", gestiti mediante gestione concorrente a norma dell'articolo 59 (\"i Fondi\"), nonché alle rispettive entrate, fatte salve le deroghe di cui al presente titolo.</p>"], [null, "<p class=\"norm\">2.  Alle operazioni gestite direttamente dalla Commissione si applicano parimenti le disposizioni delle parti prima e terza.</p>"]]}, "176": {"label": "Articolo 176", "heading": "Rispetto delle dotazioni degli stanziamenti d'impegno", "anchor": "art_176", "frags": [[null, "<p class=\"norm\">Il Parlamento europeo e il Consiglio rispettano le dotazioni in stanziamenti d'impegno previste nei pertinenti atti di base per gli interventi strutturali, lo sviluppo rurale e il Fondo europeo per la pesca.</p>"]]}, "177": {"label": "Articolo 177", "heading": "Versamenti di contributi, pagamenti intermedi e rimborsi", "anchor": "art_177", "frags": [[null, "<p class=\"norm\">1.  Il versamento da parte della Commissione della partecipazione finanziaria dei fondi è effettuato conformemente ai regolamenti citati all'articolo 175.</p>"], [null, "<p class=\"norm\">2.  Il termine entro il quale la Commissione effettua i pagamenti intermedi è fissato conformemente ai regolamenti citati all'articolo 175.</p>"], [null, "<p class=\"norm\">3.  Conformemente ai regolamenti citati all'articolo 175, il rimborso totale o parziale dei prefinanziamenti versati a titolo di un intervento non ha per effetto la riduzione della partecipazione dei fondi all'intervento interessato.</p>"], [null, "<p class=\"norm\">Gli importi rimborsati costituiscono entrate con destinazione specifica interna ai sensi dell'articolo 21, paragrafo 3, lettera c).</p>"], [null, "<p class=\"norm\">Il trattamento dei rimborsi da parte degli Stati membri e le implicazioni di detto trattamento per l'importo della partecipazione finanziaria dei fondi sono disciplinati dai regolamenti citati all'articolo 175.</p>"], [null, "<p class=\"norm\">4.  In deroga all'articolo 14, gli stanziamenti d'impegno disponibili al 31 dicembre derivanti da riversamenti di versamenti di prefinanziamenti possono essere oggetto di riporto fino al termine del programma e utilizzati quando necessario a condizione che non vi siano più altri stanziamenti d'impegno disponibili.</p>"], [null, "<p class=\"norm\">5.  Nei conti di bilancio le spese sono imputate a un esercizio sulla base dei rimborsi effettuati dalla Commissione agli Stati membri entro il 31 dicembre di detto esercizio, comprese le spese imputate entro il 31 gennaio dell'esercizio successivo, a fronte di stanziamenti di pagamento aperti nel mese successivo agli storni di cui all'articolo 179.</p>"]]}, "178": {"label": "Articolo 178", "heading": "Disimpegno di stanziamenti", "anchor": "art_178", "frags": [[null, "<p class=\"norm\">1.  Conformemente ai regolamenti citati all'articolo 175, la Commissione procede al disimpegno automatico degli stanziamenti impegnati.</p>"], [null, "<p class=\"norm\">2.  Gli stanziamenti disimpegnati possono essere ricostituiti in caso di errore manifesto imputabile alla sola Commissione.</p>"], [null, "<p class=\"norm\">A tale scopo, la Commissione esamina i disimpegni intervenuti nel corso dell'esercizio precedente e decide, entro il 15 febbraio dell'esercizio in corso e in funzione del fabbisogno, se è necessaria la ricostituzione degli stanziamenti corrispondenti.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">3.  Gli stanziamenti disimpegnati sono nuovamente ricostituiti se:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>provengono da un programma interessato dalle modalità di applicazione della riserva di efficacia di cui all’articolo 20 del regolamento (UE) n. 1303/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">32</span>\n);</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>provengono da un programma dedicato a uno strumento finanziario specifico a favore delle PMI a seguito della cessazione della partecipazione di uno Stato membro allo strumento finanziario, di cui all’articolo 39, paragrafo 2, settimo comma, del regolamento (UE) n. 1303/2013.</p>\n</div>"]]}, "178a": {"label": "Articolo 178 bis", "heading": "Riporto di stanziamenti di impegno per il meccanismo per collegare l’Europa", "anchor": "art_178a", "frags": [[null, "<p class=\"norm\">1.  Per gli esercizi finanziari 2014, 2015 e 2016, gli stanziamenti di impegno per i progetti finanziati a titolo del meccanismo per collegare l’Europa istituito dal regolamento (UE) n. 1316/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">33</span>\n) e non ancora impegnati alla fine dell’esercizio possono essere oggetto di riporto limitato unicamente all’esercizio successivo.</p>"], [null, "<p class=\"norm\">2.  La Commissione presenta proposte di riporto relativamente all’esercizio precedente al Parlamento europeo e al Consiglio entro il 15 febbraio dell’esercizio in corso.</p>"], [null, "<p class=\"norm\">3.  Il Parlamento europeo e il Consiglio, deliberando quest’ultimo a maggioranza qualificata, si pronunciano su ciascuna proposta di riporto entro il 31 marzo dell’esercizio in corso.</p>"], [null, "<p class=\"norm\">4.  La proposta di riporto è approvata se, entro il termine di cui al paragrafo 3, si verifica una delle situazioni seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>il Parlamento europeo e il Consiglio approvano la proposta;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il Parlamento europeo o il Consiglio approva la proposta e l’altra istituzione si astiene dal deliberare;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>il Parlamento europeo e il Consiglio si astengono dal deliberare oppure non adottano una decisione per respingere la proposta di riporto.</p>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "179": {"label": "Articolo 179", "heading": "Storno di stanziamenti", "anchor": "art_179", "frags": [[null, "<p class=\"norm\">1.  La Commissione può procedere, per quanto concerne le spese operative di cui al presente titolo, tranne che per il Fondo europeo agricolo per lo sviluppo rurale, a storni da titolo a titolo, a condizione che si tratti di stanziamenti destinati allo stesso obiettivo conformemente ai regolamenti citati all'articolo 175, o siano spese di assistenza tecnica. La Commissione adotta la decisione entro il 31 gennaio dell'esercizio successivo.</p>"], [null, "<p class=\"norm\">2.  Nei casi diversi da quelli previsti al paragrafo 1, la Commissione può proporre gli storni di stanziamenti di pagamento a favore dei fondi al Parlamento europeo e al Consiglio entro il 10 gennaio dell'esercizio successivo. Gli storni di stanziamenti di pagamento possono essere effettuati a partire da qualsiasi voce del bilancio. Il Parlamento europeo e il Consiglio decidono gli storni secondo la procedura di cui all'articolo 27, ma ai fini del presente articolo il termine applicabile é di tre settimane.</p>"], [null, "<p class=\"norm\">3.  Se il Parlamento europeo e il Consiglio non approvano o approvano solo parzialmente gli storni, la parte corrispondente delle spese di cui all'articolo 177, paragrafo 5, è imputata agli stanziamenti di pagamento dell'esercizio successivo.</p>"]]}, "180": {"label": "Articolo 180", "heading": "Gestione, selezione e controllo", "anchor": "art_180", "frags": [[null, "<p class=\"norm\">La gestione e la selezione dei progetti, nonché il loro controllo sono disciplinati dall'articolo 175.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "181": {"label": "Articolo 181", "heading": "Fondi per la ricerca", "anchor": "art_181", "frags": [[null, "<p class=\"norm\">1.  Le disposizioni delle parti prima e terza si applicano agli stanziamenti per la ricerca e lo sviluppo tecnologico, fatte salve le deroghe di cui al presente titolo.</p>"], [null, "<p class=\"norm\">Detti stanziamenti sono iscritti in uno dei titoli del bilancio relativo al settore connesso alla \"Ricerca indiretta\" e alla \"Ricerca indiretta\" o in un capitolo relativo alle attività di ricerca inserito in un titolo diverso.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti i tipi di operazioni nel campo della ricerca.</p>"], [null, "<p class=\"norm\">2.  Gli stanziamenti relativi alle entrate risultanti dal Fondo di ricerca carbone e acciaio, di cui al protocollo (n. 37) relativo alle conseguenze finanziarie della scadenza del trattato CECA e al Fondo di ricerca carbone e acciaio allegato al TUE e al TFUE, sono assimilati a entrate con destinazione specifica ai sensi dell'articolo 21. Gli stanziamenti d'impegno risultanti da tali entrate sono aperti a partire dalla previsione di creditio e gli stanziamenti di pagamento a partire dalla riscossione delle entrate.</p>"], [null, "<p class=\"norm\">3.  Per le spese operative di cui al presente titolo la Commissione può procedere a storni da titolo a titolo, purché si tratti di stanziamenti utilizzati per gli stessi fini.</p>"], [null, "<p class=\"norm\">4.  Gli esperti retribuiti con gli stanziamenti per la ricerca e lo sviluppo tecnologico sono assunti secondo le procedure definite dal Parlamento europeo e dal Consiglio nel momento in cui adottano ciascun programma quadro di ricerca o conformemente alle regole per la partecipazione di imprese, centri di ricerca e università.</p>"]]}, "182": {"label": "Articolo 182", "heading": "Impegni relativi al Fondo di ricerca", "anchor": "art_182", "frags": [[null, "<p class=\"norm\">1.  Gli stanziamenti d'impegno corrispondenti all'importo dell'impegno disimpegnato in seguito all'inesecuzione totale o parziale dei progetti di ricerca ai quali gli stanziamenti sono stati assegnati, possono essere ricostituiti, a titolo eccezionale e in casi debitamente giustificati, quando sono essenziali per attuare il programma inizialmente previsto, a meno che nel bilancio dell'esercizio in questione (anno n) non siano iscritti fondi a tale scopo.</p>"], [null, "<p class=\"norm\">2.  Ai fini del paragrafo 1, la Commissione esamina, all'inizio di ogni esercizio, i disimpegni intervenuti nel corso dell'esercizio precedente (anno n-1) e valuta, in base al fabbisogno, la necessità di ricostituire gli stanziamenti.</p>"], [null, "<p class=\"norm\">In base a tale valutazione, entro il 15 febbraio di ogni esercizio la Commissione può sottoporre al Parlamento europeo e al Consiglio adeguate proposte, presentando per ogni voce di bilancio i motivi per i quali essa propone di ricostituire gli stanziamenti.</p>"], [null, "<p class=\"norm\">3.  Il Parlamento europeo e il Consiglio decidono riguardo alle proposte della Commissione entro sei settimane. In mancanza di tale decisione entro il termine suddetto, le proposte si considerano approvate.</p>"], [null, "<p class=\"norm\">L'importo degli stanziamenti di impegno da ricostituire nell'anno n non può superare in nessun caso il 25 % dell'importo totale disimpegnato per la medesima linea di bilancio nell'anno n - 1.</p>"], [null, "<p class=\"norm\">4.  Gli stanziamenti di impegno ricostituiti non sono oggetto di riporto.</p>"], [null, "<p class=\"norm\">Gli impegni giuridici relativi agli stanziamenti di impegno ricostituiti sono conclusi entro il 31 dicembre dell'anno n.</p>"], [null, "<p class=\"norm\">Alla conclusione dell'anno n, l'ordinatore responsabile disimpegna definitivamente il saldo non eseguito di tali stanziamenti di impegno ricostituiti.</p>"]]}, "183": {"label": "Articolo 183", "heading": "Centro comune di ricerca", "anchor": "art_183", "frags": [[null, "<p class=\"norm\">1.  Il Centro comune di ricerca (CCR) può ricevere finanziamenti imputati su stanziamenti iscritti in titoli e capitoli non previsti dall'articolo 181, paragrafo 1, nell'ambito della sua partecipazione a procedure di aggiudicazione degli appalti e di concessione delle sovvenzioni finanziate, in tutto o in parte, dal bilancio.</p>"], [null, "<p class=\"norm\">Ai fini della partecipazione alle procedure di aggiudicazione degli appalti e di concessione delle sovvenzioni, il CCR è considerato una persona giuridica stabilita in uno Stato membro.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il CCR.</p>"], [null, "<p class=\"norm\">2.  Sono assimilati a entrate con destinazione specifica ai sensi dell'articolo 21, paragrafo 2 gli stanziamenti relativi a:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>procedure di concessione delle sovvenzioni e di aggiudicazione degli appalti alle quali partecipa il CCR;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>attività del CCR per conto di terzi; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>attività intraprese sulla base di un accordo amministrativo con altre istituzioni o altri servizi della Commissione per la prestazione di servizi tecnico-scientifici.</p>\n</div>"], [null, "<p class=\"norm\">Gli stanziamenti d'impegno risultanti dalle entrate di cui alle lettere a) e c) del primo comma sono aperti a partire dalla previsione di crediti.</p>"], [null, "<p class=\"norm\">Per le attività di cui alla lettera c) del primo comma gli stanziamenti non utilizzati entro cinque anni sono annullati.</p>"], [null, "<p class=\"norm\">3.  L'esecuzione degli stanziamenti è indicata in una contabilità analitica del conto di risultato dell'esecuzione del bilancio per ogni categoria di azioni alla quale si riferisce; è dissociata dalle entrate provenienti da finanziamenti di terzi, pubblici o privati, e dalle entrate provenienti dalle altre prestazioni per terzi effettuate dalla Commissione.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">4.  Quando partecipa alle procedure di concessione delle sovvenzioni o di aggiudicazione degli appalti conformemente al paragrafo 1 del presente articolo, il CCR non è soggetto alle condizioni di cui agli articoli 105 <span class=\"italics\">bis</span> e 106, all'articolo 107, paragrafo 1, lettere a) e b), all'articolo 108 e all'articolo 131, paragrafo 4, in materia di esclusione e sanzioni relative a appalti e sovvenzioni.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Il CCR è altresì considerato conforme ai criteri di capacità economica e finanziaria.</p>"], [null, "<p class=\"norm\">Il CCR è esonerato dalla presentazione delle garanzie di cui agli articoli 115 e 134.</p>"], [null, "<p class=\"norm\">5.  Le norme sull'aggiudicazione degli appalti di cui al titolo V della parte prima non si applicano alle attività del CCR per conto di terzi.</p>"], [null, "<p class=\"norm\">6.  All'interno del titolo del bilancio relativo al settore \"Ricerca diretta\", la Commissione può procedere, in deroga all'articolo 26, a storni fra capitoli entro il limite del 15 % degli stanziamenti iscritti alla linea a partire dalla quale si procede allo storno.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "184": {"label": "Articolo 184", "heading": "Azioni esterne", "anchor": "art_184", "frags": [[null, "<p class=\"norm\">1.  Le disposizioni delle parti prima e terza si applicano alle azioni esterne finanziate dal bilancio, fatte salve le deroghe di cui al presente titolo.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti le azioni che possono essere finanziate nel quadro di azioni esterne.</p>"], [null, "<p class=\"norm\">2.  Gli stanziamenti destinati alle azioni di cui al paragrafo 1 sono eseguiti dalla Commissione, come segue:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>nel quadro di aiuti concessi a titolo autonomo; oppure</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>in partenariato con un paese terzo di cui all'articolo 58, paragrafo 1, lettera c), punto i), mediante la firma di una convenzione di finanziamento.</p>\n</div>"], [null, "<p class=\"norm\">3.  Se le azioni esterne sono cofinanziate sia da stanziamenti iscritti in bilancio sia da entrate con destinazione specifica esterne di cui all'articolo 21, paragrafo 2, lettera b), i fondi non impegnati dopo la fine del periodo per l'assegnazione dei contratti di cui all'articolo 189, paragrafo 2, dell'azione in questione sono proporzionalmente rimborsati, previa detrazione di una somma forfettaria corrispondente al controllo, alla valutazione e alle spese impreviste che potrà essere impegnato successivamente.</p>"], [null, "<p class=\"norm\">4.  L'articolo 90, paragrafo 4, secondo comma non si applica alle azioni di cui al presente titolo.</p>"], [null, "<p class=\"norm\">Per le sovvenzioni con modalità di gestione diretta superiori a 5 000 000  EUR e destinate al finanziamento di azioni esterne, non più di due versamenti di prefinanziamenti possono restare non liquidati per tutta la durata dell'azione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "185": {"label": "Articolo 185", "heading": "Esecuzione delle azioni esterne", "anchor": "art_185", "frags": [[null, "<p class=\"norm\">Le azioni di cui al presente titolo possono essere eseguite direttamente dalla Commissione a norma dell'articolo 58, paragrafo 1, lettera a), mediante gestione concorrente a norma dell'articolo 58, paragrafo 1, lettera b), o indirettamente dalle entità o dalle persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), secondo le pertinenti disposizioni degli articoli da 58 a 63. Gli stanziamenti destinati alle azioni esterne possono essere associati a fondi provenienti da altre fonti per realizzare un obiettivo congiunto.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "186": {"label": "Articolo 186", "heading": "Ricorso al sostegno di bilancio", "anchor": "art_186", "frags": [[null, "<p class=\"norm\">1.  Qualora previsto dai pertinenti atti di base, la Commissione può fornire il sostegno di bilancio a un paese terzo beneficiario se detta gestione delle pubbliche finanze di tale paese risulta sufficientemente trasparente, affidabile ed efficace.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti il ricorso al sostegno di bilancio e gli obblighi dei beneficiari.</p>"], [null, "<p class=\"norm\">2.  La decisione di finanziamento di cui all'articolo 84 precisa gli obiettivi e i risultati attesi della concessione di un sostegno di bilancio a un paese terzo beneficiario. Il pagamento del contributo dell'Unione si basa sul rispetto delle condizioni di cui al paragrafo 1, compreso il miglioramento della gestione delle pubbliche finanze, e su indicatori di efficienza chiari e obiettivi che serviranno da base per misurare i progressi compiuti nel corso del tempo nei rispettivi settori.</p>"], [null, "<p class=\"norm\">3.  La Commissione include nelle corrispondenti convenzioni di finanziamento concluse conformemente all'articolo 184, paragrafo 2, lettera b), opportune disposizioni a norma delle quali il paese terzo beneficiario deve impegnarsi a rimborsare immediatamente in tutto o in parte i finanziamenti erogati per la relativa operazione, qualora venga accertato che il pagamento dei fondi pertinenti dell'Unione è viziato da gravi irregolarità imputabili al paese beneficiario.</p>"], [null, "<p class=\"norm\">Per procedere al rimborso di cui al primo comma può essere applicato l'articolo 80, paragrafo 1, secondo comma.</p>"], [null, "<p class=\"norm\">4.  La Commissione sostiene lo sviluppo delle capacità di controllo parlamentare e di revisione contabile nei paesi terzi beneficiari, nonché il rafforzamento della trasparenza e dell'accesso del pubblico alle informazioni.</p>"]]}, "187": {"label": "Articolo 187", "heading": "Fondi fiduciari dell'Unione per le azioni esterne", "anchor": "art_187", "frags": [[null, "<p class=\"norm\">1.  Per le azioni di emergenza, di post-emergenza o tematiche la Commissione può costituire fondi fiduciari in base ad un accordo concluso con altri donatori. L'atto costitutivo di ciascun fondo fiduciario indica gli obiettivi dello stesso.</p>"], [null, "<p class=\"norm\">2.  I fondi fiduciari dell'Unione sono attuati secondo i principi della sana gestione finanziaria, trasparenza, proporzionalità, non discriminazione e parità di trattamento, nonché conformemente agli obiettivi specifici definiti in ciascun atto costitutivo.</p>"], [null, "<p class=\"norm\">I fondi fiduciari dell'Unione sono attuati direttamente dalla Commissione a norma dell'articolo 58, paragrafo 1, lettera a), ad eccezione dei fondi fiduciari dell'Unione per le azioni di emergenza o di post-emergenza che possono essere attuate anche indirettamente affidando funzioni di esecuzione del bilancio alle entità a norma dell'articolo 58, paragrafo 1, lettera c), punti i), ii), v) e vi).</p>"], [null, "<p class=\"norm\">3.  I fondi fiduciari dell'Unione rispettano le condizioni seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>vi sia un valore aggiunto dell'intervento dell'Unione: i fondi fiduciari sono costituiti e attuati solo a livello dell'Unione se i loro obiettivi, in particolare a motivo della loro portata o dei loro effetti potenziali, possono essere meglio conseguiti a livello di Unione che non a livello nazionale;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i fondi fiduciari dell'Unione sono accompagnati da una chiara visibilità politica dell'Unione e da vantaggi gestionali nonché un migliore controllo da parte dell'Unione dei rischi e dei pagamenti dei contributi dell'Unione e di altri donatori. Non dovrebbero essere creati se si limitano a duplicare altri canali esistenti di finanziamento o altri strumenti simili senza fornire alcuna addizionalità.</p>\n</div>"], [null, "<p class=\"norm\">4.  Per ciascun fondo fiduciario dell'Unione è istituito un comitato, presieduto dalla Commissione, che garantisce la rappresentanza dei donatori e degli Stati membri non contribuenti in qualità di osservatori e decide in merito all'impiego dei fondi.</p>"], [null, "<p class=\"norm\">5.  I fondi fiduciari dell'Unione sono costituiti per una durata limitata stabilita dal loro atto costituivo. Tale durata può essere prorogata con decisione della Commissione su richiesta del comitato del fondo fiduciario interessato.</p>"], [null, "<p class=\"norm\">Il Parlamento europeo e/o il Consiglio può chiedere alla Commissione, laddove opportuno, di interrompere gli stanziamenti per tale fondo fiduciario o di rivedere l'atto costitutivo al fine di liquidarlo. In tal caso, i fondi rimanenti sono restituiti proporzionalmente al bilancio a titolo di entrate generali e agli Stati membri contribuenti e agli altri donatori.</p>"], [null, "<p class=\"norm\">6.  I contributi dell'Unione e dei donatori sono versati in un apposito conto bancario. I contributi dell'Unione sono trasferiti su tale conto sulla base delle richieste di pagamento debitamente giustificate da previsioni di esborso, tenendo conto del saldo disponibile sul conto e della conseguenza necessità di pagamenti aggiuntivi. Le previsioni di esborso devono essere fornite su base annuale o, se del caso, su base semi-annuale.</p>"], [null, "<p class=\"norm\">I contributi non sono integrati nel bilancio e sono gestiti dalla Commissione sotto la responsabilità dell'ordinatore delegato.</p>"], [null, "<p class=\"norm\">Il contabile del fondo fiduciario dell'Unione è il contabile della Commissione. Egli è incaricato di definire procedure contabili e il piano contabile comuni a tutti i fondi fiduciari dell'Unione.</p>"], [null, "<p class=\"norm\">Il revisore interno della Commissione e la Corte dei conti esercitano nei confronti del fondo fiduciario le stesse competenze attribuite loro nei confronti di altre azioni svolte dalla Commissione.</p>"], [null, "<p class=\"norm\">Il contabile procede all'apertura e alla chiusura dell'apposito conto bancario del fondo fiduciario.</p>"], [null, "<p class=\"norm\">La Commissione garantisce una rigida separazione delle funzioni fra il contabile e l'ordinatore.</p>"], [null, "<p class=\"norm\">I fondi sono impegnati ed erogati dagli agenti finanziari della Commissione, come previsto al capo 3 del titolo IV della parte prima.</p>"], [null, "<p class=\"norm\">7.  La Commissione è autorizzata a ritirare il 5 % massimo degli importi raccolti nel fondo fiduciario per coprire le proprie spese di gestione a decorrere dagli anni in cui i contributi di cui al paragrafo 6 hanno iniziato a essere utilizzati. Per la durata del fondo fiduciario tali spese di gestione sono assimilate a entrate con destinazione specifica, ai sensi dell'articolo 21, paragrafo 2, lettera b).</p>"], [null, "<p class=\"norm\">Il contabile prende a carico gli ordini di riscossione relativi alle azioni finanziate dal fondo fiduciario. Le entrate provenienti dalla restituzione di questi ordini di riscossione sono depositate nuovamente nell'apposito conto bancario del fondo fiduciario. L'annullamento degli ordini di riscossione e la rinuncia a essi avvengono a norma dell'articolo 80.</p>"], [null, "<p class=\"norm\">8.  La Commissione presenta i suoi progetti di decisione relativi alla costituzione, alla proroga e alla liquidazione di un fondo fiduciario dell'Unione al comitato competente previsto nell'atto di base a norma del quale viene erogato il contributo dell'Unione al fondo fiduciario dell'Unione.</p>"], [null, "<p class=\"norm\">9.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate in materia di gestione, rendicontazione e governance dei fondi fiduciari per azioni esterne.</p>"], [null, "<p class=\"norm\">10.  La Commissione presenta ogni anno al Parlamento europeo e al Consiglio una relazione globale e dettagliata concernente le attività sostenute da fondi fiduciari dell'Unione, la loro attuazione e le loro prestazioni, nonché i relativi conti. La Commissione acclude la sua relazione alla sintesi delle relazioni annuali di cui all'articolo 66, paragrafo 9, terzo comma.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "188": {"label": "Articolo 188", "heading": "Attuazione di azioni esterne mediante gestione indiretta", "anchor": "art_188", "frags": [[null, "<p class=\"norm\">1.  L'esecuzione delle azioni attuate indirettamente a norma dell'articolo 58, paragrafo 1, è soggetta al controllo della Commissione e delle delegazioni dell'Unione conformemente all'articolo 56, paragrafo 2. Il controllo è esercitato o mediante previa approvazione o mediante controllo a posteriori o con una procedura mista.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'attuazione di azioni esterne mediante gestione indiretta.</p>"]]}, "189": {"label": "Articolo 189", "heading": "Convenzioni di finanziamento relative all'attuazione di azioni esterne", "anchor": "art_189", "frags": [[null, "<p class=\"norm\">1.  L'esecuzione delle azioni esterne implica uno o più strumenti fra i seguenti:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>un accordo di finanziamento tra la Commissione e un'entità o una persona di cui all'articolo 185;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>un contratto o una convenzione di sovvenzione tra la Commissione e persone fisiche o giuridiche incaricate della realizzazione.</p>\n</div>"], [null, "<p class=\"norm\">Le condizioni alle quali è fornito l'aiuto esterno sono fissate nello strumento che gestisce le convenzioni di finanziamento, i contratti o le convenzioni di sovvenzione di cui alle lettere a) e b) del primo comma.</p>"], [null, "<p class=\"norm\">2.  Le convenzioni di finanziamento con le entità di cui al paragrafo 1, primo comma, lettera a), sono concluse entro il 31 dicembre dell'anno n + 1, dove l'anno n è quello nel corso del quale è stato adottato l'impegno di bilancio.</p>"], [null, "<p class=\"norm\">Le convenzioni di finanziamento stabiliscono il periodo entro il quale le entità di cui al paragrafo 1, primo comma, lettera a), concludono i singoli contratti e le convenzioni di sovvenzione per l'attuazione dell'azione. Detto periodo non può superare i tre anni a decorrere dalla data di conclusione della convenzione di finanziamento, eccetto:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>le azioni finanziate da una pluralità di donatori;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>i singoli contratti relativi alla revisione contabile e alla valutazione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>nelle seguenti circostanze eccezionali:</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>sono aggiunte clausole a contratti che sono già stati conclusi;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>singoli contratti devono essere conclusi dopo la risoluzione anticipata di un contratto esistente;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>variazione dell'entità incaricata dello svolgimento dei compiti.</p>\n</div>"], [null, "<p class=\"norm\">3.  Nei seguenti casi il paragrafo 2 non si applica ai programmi pluriennali attuati mediante impegni frazionati:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>lo strumento di assistenza preadesione;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>lo strumento della politica europea di vicinato e partenariato.</p>\n</div>"], [null, "<p class=\"norm\">In tali casi, gli stanziamenti sono automaticamente disimpegnati dalla Commissione in conformità delle normative settoriali.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti convenzioni di finanziamento riguardanti l'attuazione di azioni esterne.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "190": {"label": "Articolo 190", "heading": "Aggiudicazione degli appalti per l'azione esterna", "anchor": "art_190", "frags": [[null, "<p class=\"norm\">1.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate sull'aggiudicazione degli appalti relativi ad azioni esterne.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">2.  Agli appalti di cui al presente titolo si applicano le disposizioni della parte prima, titolo V, capo 1, relative alle disposizioni generali di aggiudicazione degli appalti, salvo disposizioni specifiche sulle soglie e sulle modalità di aggiudicazione degli appalti esterni previste negli atti delegati adottati a norma del presente regolamento. Gli articoli 117 e 120 non sono applicabili all'aggiudicazione degli appalti di cui al presente capo.</p>"], [null, "<p class=\"norm\">Il presente capo si applica:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>agli appalti non aggiudicati dalla Commissione per proprio conto;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>agli appalti aggiudicati da entità o persone delegate a norma dell'articolo 58, paragrafo 1, lettera c), nei casi previsti dalla convenzione di finanziamento di cui all'articolo 189.</p>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">3.  Le procedure di aggiudicazione degli appalti sono previste nelle convenzioni di finanziamento di cui all'articolo 189.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">4.  Il presente capo non si applica ad azioni previste da atti di base settoriali specifici relativi agli aiuti in situazioni di crisi umanitaria, alle operazioni di protezione civile e alle azioni di aiuto umanitario.</p>"]]}, "191": {"label": "Articolo 191", "heading": "Norme in materia di accesso agli appalti", "anchor": "art_191", "frags": [[null, "<p class=\"norm\">1.  La partecipazione alle procedure di appalto è aperta a parità di condizioni a tutti i soggetti che rientrano nell'ambito d'applicazione dei trattati e a tutte le altre persone fisiche e giuridiche secondo le disposizioni specifiche previste negli atti di base che disciplinano il settore della cooperazione interessato. La partecipazione è inoltre aperta alle organizzazioni internazionali.</p>"], [null, "<p class=\"norm\">2.  Nei casi di cui all'articolo 54, paragrafo 2, possono essere ammessi a partecipare alle gare anche cittadini di paesi terzi diversi da quelli di cui al paragrafo 1 del presente articolo, in circostanze eccezionali debitamente giustificate dall'ordinatore responsabile.</p>"], [null, "<p class=\"norm\">3.  In caso di applicazione di un accordo relativo all'apertura del mercato degli appalti di beni o servizi cui partecipa l'Unione, le procedure di appalto per contratti finanziati tramite il bilancio sono aperti anche alle persone fisiche e giuridiche stabilite in paesi terzi diversi da quelli di cui ai paragrafi 1 e 2, alle condizioni definite in tale accordo.</p>"], [null, "<p class=\"norm\">4.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'accesso alle procedure di appalto.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "192": {"label": "Articolo 192", "heading": "Finanziamento integrale di un'azione esterna", "anchor": "art_192", "frags": [[null, "<p class=\"norm\">Un'azione può essere finanziata integralmente dal bilancio solo quando ciò sia indispensabile per la sua realizzazione.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate sul finanziamento integrale di un'azione esterna.</p>"]]}, "193": {"label": "Articolo 193", "heading": "Norme applicabili alle sovvenzioni a favore di azioni esterne", "anchor": "art_193", "frags": [[null, "<p class=\"norm\">Le procedure di concessione delle sovvenzioni che le entità di cui all'articolo 185 devono applicare, in regime di gestione indiretta, sono previste nelle convenzioni concluse tra la Commissione e tali entità.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate sulle procedure di sovvenzione applicabili nell'ambito della gestione indiretta.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "194": {"label": "Articolo 194", "heading": "Controllo dell'Unione sull'azione esterna", "anchor": "art_194", "frags": [[null, "<p class=\"norm\">Ogni accordo tra la Commissione e un'entità di cui all'articolo 185, o convenzione di sovvenzione o decisione di sovvenzione prevede espressamente il potere di controllo della Commissione e della Corte dei conti, in base a documenti e sul posto, di tutti i contraenti e subcontraenti che hanno beneficiato di fondi dell'Unione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "195": {"label": "Articolo 195", "heading": "Gli uffici europei", "anchor": "art_195", "frags": [[null, "<p class=\"norm\">1.  Sono considerati \"uffici europei\", ai fini del presente titolo, le strutture amministrative create da una o più istituzioni per espletare funzioni orizzontali specifiche.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti l'ambito di attività degli uffici europei e le deleghe da parte delle istituzioni agli uffici europei.</p>"], [null, "<p class=\"norm\">2.  Le disposizioni del presente titolo si applicano alle attività dell'OLAF, ad eccezione degli articoli 198, 199 e 200.</p>"], [null, "<p class=\"norm\">3.  Le disposizioni delle parti prima e terza si applicano al funzionamento degli uffici europei, salve le deroghe di cui al presente titolo.</p>"]]}, "196": {"label": "Articolo 196", "heading": "Stanziamenti relativi agli uffici europei", "anchor": "art_196", "frags": [[null, "<p class=\"norm\">1.  Gli stanziamenti di ciascun ufficio europeo, il cui importo globale è iscritto in una linea di bilancio specifica della sezione del bilancio della Commissione, sono ripresi dettagliatamente in un allegato di detta sezione.</p>"], [null, "<p class=\"norm\">L'allegato è presentato sotto forma di stato delle entrate e delle spese, suddiviso allo stesso modo delle sezioni del bilancio.</p>"], [null, "<p class=\"norm\">Gli stanziamenti iscritti in tale allegato coprono tutte le esigenze finanziarie di ciascun ufficio europeo per l'espletamento delle sue funzioni al servizio delle istituzioni.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti gli stanziamenti per gli uffici europei, inclusi la delega di alcuni compiti da parte dell'ordinatore, la tesoreria e i conti bancari.</p>"], [null, "<p class=\"norm\">2.  La tabella dell'organico di ciascun ufficio europeo è allegata a quella della Commissione.</p>"], [null, "<p class=\"norm\">3.  Il direttore di ciascun ufficio europeo decide gli storni all'interno dell'allegato di cui al paragrafo 1. La Commissione informa il Parlamento europeo e il Consiglio di tali storni.</p>"], [null, "<p class=\"norm\">4.  I conti di ciascun ufficio europeo sono parte integrante dei conti dell'Unione di cui all'articolo 141.</p>"]]}, "197": {"label": "Articolo 197", "heading": "Ordinatore degli uffici europei", "anchor": "art_197", "frags": [[null, "<p class=\"norm\">Per gli stanziamenti iscritti nell'allegato per ciascun ufficio europeo la Commissione delega i poteri di ordinatore al direttore dell'ufficio europeo in questione, a norma dell'articolo 65.</p>"]]}, "198": {"label": "Articolo 198", "heading": "La contabilità degli uffici europei interistituzionali", "anchor": "art_198", "frags": [[null, "<p class=\"norm\">1.  Ciascun ufficio europeo interistituzionale predispone una contabilità analitica delle proprie spese, atta a determinare la quota di prestazioni fornita a ciascuna istituzione. Il direttore dell'ufficio europeo interessato adotta, previa approvazione del suo comitato direttivo, i criteri secondo i quali è tenuta la contabilità.</p>"], [null, "<p class=\"norm\">2.  Il commento della linea di bilancio particolare sulla quale è iscritto il totale degli stanziamenti di ciascun ufficio europeo interistituzionale presenta, sotto forma di previsione, la stima del costo delle prestazioni di detto ufficio a favore di ciascuna istituzione, sulla base della contabilità analitica di cui al paragrafo 1.</p>"], [null, "<p class=\"norm\">3.  Ciascun ufficio europeo interistituzionale comunica i risultati della contabilità analitica alle istituzioni interessate.</p>"]]}, "199": {"label": "Articolo 199", "heading": "Delega di poteri di ordinatore agli uffici europei interistituzionali", "anchor": "art_199", "frags": [[null, "<p class=\"norm\">1.  Per la gestione degli stanziamenti iscritti nella propria sezione ciascuna istituzione può delegare i poteri di ordinatore al direttore di un ufficio europeo interistituzionale, stabilendo i limiti e le condizioni di tale delega.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la delega di poteri dell'ordinatore al direttore di un ufficio europeo interistituzionale.</p>"], [null, "<p class=\"norm\">2.  Il revisore interno della Commissione esercita tutte le responsabilità previste nel titolo IV, capo 9, della parte prima.</p>"]]}, "200": {"label": "Articolo 200", "heading": "Servizi a terzi", "anchor": "art_200", "frags": [[null, "<p class=\"norm\">Se il mandato di un ufficio europeo implica prestazioni a titolo oneroso a terzi, il direttore di tale ufficio determina, previa approvazione del comitato direttivo, le disposizioni specifiche riguardanti le condizioni alle quali tali prestazioni sono fornite e la tenuta della corrispondente contabilità.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "201": {"label": "Articolo 201", "heading": "Disposizioni generali", "anchor": "art_201", "frags": [[null, "<p class=\"norm\">1.  Le disposizioni delle parti prima e terza si applicano agli stanziamenti amministrativi, salve le deroghe di cui al presente titolo.</p>"], [null, "<p class=\"norm\">2.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti la portata degli stanziamenti amministrativi e delle garanzie locative.</p>"]]}, "202": {"label": "Articolo 202", "heading": "Impegni", "anchor": "art_202", "frags": [[null, "<p class=\"norm\">1.  Le spese di gestione corrente possono, a decorrere dal 15 ottobre di ogni anno, essere oggetto di impegni anticipati a carico degli stanziamenti previsti per l'esercizio successivo. Tali impegni non superano tuttavia un quarto degli stanziamenti decisi dal Parlamento europeo e dal Consiglio che figurano alla corrispondente linea di bilancio per l'esercizio in corso. Tali impegni non riguardano spese nuove il cui principio non sia stato ancora ammesso in via di principio nell'ultimo bilancio regolarmente adottato.</p>"], [null, "<p class=\"norm\">2.  Le spese che, in virtù di disposizioni legali o contrattuali, come i canoni di locazione, sono effettuate in anticipo, possono dar luogo a decorrere dal 1<span class=\"superscript\">o</span> dicembre a un pagamento a valere sugli stanziamenti previsti per l'esercizio successivo. In questo caso, non si applica il limite di cui al paragrafo 1.</p>"]]}, "203": {"label": "Articolo 203", "heading": "Disposizioni specifiche riguardanti gli stanziamenti amministrativi", "anchor": "art_203", "frags": [[null, "<p class=\"norm\">1.  Gli stanziamenti amministrativi sono stanziamenti non dissociati.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti stanziamenti amministrativi specifici, inclusi stanziamenti per edifici e anticipi a membri del personale delle istituzioni.</p>"], [null, "<p class=\"norm\">2.  Le spese amministrative risultanti da contratti conclusi per periodi superiori alla durata dell'esercizio, in conformità delle pratiche locali o perché relativi alla fornitura di materiale di dotazione, sono imputate al bilancio dell'esercizio nel corso del quale sono effettuate.</p>"], [null, "<p class=\"norm\">3.  Ogni istituzione trasmette al Parlamento europeo e al Consiglio, entro il 1<span class=\"superscript\">o</span> giugno di ogni anno, un documento di lavoro sulla sua politica immobiliare che include le seguenti informazioni:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>per ogni edificio, la spesa e la superficie coperte dagli stanziamenti delle linee di bilancio corrispondenti;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>la prevedibile evoluzione della programmazione globale della superficie e delle ubicazioni per gli anni successivi, con una descrizione dei progetti immobiliari in fase di progettazione già identificati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>le condizioni e i costi definitivi nonché le informazioni utili per quanto riguarda la realizzazione di nuovi progetti immobiliari già presentati al Parlamento europeo e al Consiglio secondo la procedura di cui ai paragrafi 4 e 5, e non inclusi nei documenti di lavoro dell'anno precedente.</p>\n</div>"], [null, "<p class=\"norm\">4.  Per qualsiasi progetto di natura immobiliare che possa avere incidenze finanziarie significative sul bilancio, l'istituzione informa quanto prima il Parlamento europeo e il Consiglio della superficie immobiliare necessaria e del programma provvisorio prima che abbia luogo qualsiasi esplorazione del mercato locale nel caso di contratti immobiliari o prima della pubblicazione dei bandi di gara nel caso di lavori di costruzione.</p>"], [null, "<p class=\"norm\">5.  Per qualsiasi progetto di natura immobiliare che possa avere incidenze finanziarie significative sul bilancio, l'istituzione presenta il progetto immobiliare, inclusi una stima dettagliata dei costi e il suo finanziamento, nonché un elenco dei progetti di contratto destinati a essere utilizzati, e chiede l'approvazione del Parlamento europeo e del Consiglio prima della conclusione dei contratti. Su richiesta dell'istituzione, i documenti presentati concernenti il progetto immobiliare sono trattati in via riservata.</p>"], [null, "<p class=\"norm\">Salvo in casi di forza maggiore, il Parlamento europeo e il Consiglio si pronunciano sul progetto immobiliare entro quattro settimane dal suo ricevimento da parte delle due istituzioni.</p>"], [null, "<p class=\"norm\">Il progetto immobiliare si considera approvato alla scadenza del termine di quattro settimane, a meno che il Parlamento europeo o il Consiglio non adottino una decisione contraria alla proposta entro tale periodo.</p>"], [null, "<p class=\"norm\">Se durante tale periodo di quattro settimane il Parlamento europeo e/o il Consiglio avanzano obiezioni debitamente giustificate, tale periodo è prorogato una volta di due settimane.</p>"], [null, "<p class=\"norm\">Se il Parlamento europeo e/o il Consiglio adottano una decisione contraria al progetto immobiliare, l'istituzione interessata ritira la proposta e può presentarne una nuova.</p>"], [null, "<p class=\"norm\">6.  In casi di forza maggiore, le informazioni di cui al paragrafo 4 possono essere presentate unitamente al progetto immobiliare. Il Parlamento europeo e il Consiglio si pronunciano sul progetto immobiliare entro due settimane dal suo ricevimento da parte delle due istituzioni. Il progetto immobiliare si considera approvato alla scadenza del termine di due settimane, a meno che il Parlamento europeo e/o il Consiglio non adottino una decisione contraria alla proposta entro tale periodo.</p>"], [null, "<p class=\"norm\">7.  Sono considerati progetti immobiliari che possono comportare conseguenze finanziarie significative per il bilancio:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">i)<span style=\"word-spacing: 19pt\"> </span>qualsiasi acquisto di terreni;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">ii)<span style=\"word-spacing: 23pt\"> </span>l'acquisto, la vendita, la ristrutturazione, la costruzione di edifici o qualsiasi progetto di importo superiore ai 3 000 000  EUR che abbini questi elementi da realizzarsi durante lo stesso periodo;</p>\n</div>"], [null, "<div style=\"margin-left: 36pt; text-indent: -36pt\">\n<p class=\"norm\">iii)<span style=\"word-spacing: 27pt\"> </span>qualsiasi nuovo contratto immobiliare (inclusi l'usufrutto, i contratti di locazione a lungo termine e il rinnovo di contratti immobiliari esistenti a condizioni meno favorevoli) non coperto dal punto ii) con un costo annuale di almeno 750 000  EUR;</p>\n</div>"], [null, "<div style=\"margin-left: 30pt; text-indent: -30pt\">\n<p class=\"norm\">iv)<span style=\"word-spacing: 19pt\"> </span>la proroga o il rinnovo di contratti immobiliari esistenti (compresi l'usufrutto e i contratti di locazione a lungo termine) a condizioni identiche o meno favorevoli con un costo annuale di almeno 3 000 000  EUR.</p>\n</div>"], [null, "<p class=\"norm\">Il presente paragrafo si applica anche ai progetti immobiliari di natura interistituzionale nonché alle delegazioni dell'Unione.</p>"], [null, "<p class=\"norm\">8.  Fatto salvo l'articolo 17, un progetto di acquisto immobiliare può essere finanziato mediante un prestito previa approvazione del Parlamento europeo e del Consiglio.</p>"], [null, "<p class=\"norm\">I prestiti sono contratti e rimborsati conformemente al principio della sana gestione finanziaria e tenendo in debita considerazione l'interesse finanziario dell'Unione europea.</p>"], [null, "<p class=\"norm\">Se l'istituzione propone di finanziare l'acquisto mediante un prestito, il piano finanziario che deve essere presentato, unitamente alla richiesta di approvazione preventiva dell'istituzione interessata, precisa in particolare il livello massimo del finanziamento, il periodo di finanziamento, il tipo di finanziamento, le condizioni finanziarie e i risparmi ottenuti rispetto ad altri tipi di condizioni contrattuali.</p>"], [null, "<p class=\"norm\">Il Parlamento europeo e il Consiglio si pronunciano, previa richiesta di approvazione preventiva, entro un periodo di quattro settimane, prorogabile una volta di due settimane, dal suo ricevimento da parte delle due istituzioni. L'acquisto tramite un prestito è da considerarsi respinto se il Parlamento europeo e il Consiglio non lo approvano esplicitamente entro tale termine.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "204": {"label": "Articolo 204", "heading": "Esperti esterni retribuiti", "anchor": "art_204", "frags": [[null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate sugli esperti esterni retribuiti, comprese procedure specifiche per la selezione di persone fisiche in qualità di esperti esterni retribuiti, incaricati di assistere le istituzioni nella valutazione delle domande di sovvenzione, dei progetti e delle offerte e di fornire pareri e consulenza in casi specifici.</p>"], [null, "<p class=\"norm\">Questi esperti sono retribuiti sulla base di un importo fisso preventivamente annunciato e sono scelti in funzione della loro capacità professionale. La selezione avviene in base a criteri di selezione che rispettano i principi di non discriminazione, parità di trattamento e assenza di conflitto d'interesse.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">Agli esperti si applicano le disposizioni di cui all'articolo 105 <span class=\"italics\">bis</span>, paragrafi da 1 a 3 e 7, salvo il primo comma, lettera b), e il secondo comma di tale paragrafo, i paragrafi da 8 a 10, il paragrafo 11, lettera a), l'articolo 106, paragrafi da 13 a 17, e li articoli 107 e 108.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "204a": {"label": "Articolo 204 bis", "heading": "Disposizioni generali", "anchor": "art_204a", "frags": [[null, "<p class=\"norm\">1.  Ai fini del presente regolamento, per partiti politici europei si intendono le entità registrate come tali a norma del regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<p class=\"norm\">2.  Possono essere concessi contributi finanziari diretti a carico del bilancio ai partiti politici europei affinché possano contribuire a formare una coscienza politica europea e a esprimere la volontà politica dei cittadini dell'Unione, ai sensi del regolamento (UE, Euratom) n. 1141/2014.</p>"]]}, "204b": {"label": "Articolo 204 ter", "heading": "Principi", "anchor": "art_204b", "frags": [[null, "<p class=\"norm\">1.  I contributi sono utilizzati solo per il rimborso della percentuale di cui all'articolo 17, paragrafo 4, del regolamento (UE, Euratom) n. 1141/2014 dei costi di funzionamento dei partiti politici europei direttamente connessi agli obiettivi di tali partiti, come specificato all'articolo 17, paragrafo 5, e all'articolo 21 di tale regolamento.</p>"], [null, "<p class=\"norm\">2.  I contributi possono essere utilizzati per rimborsare spese connesse a contratti conclusi da partiti politici europei, a condizione che all'atto dell'aggiudicazione di tali contratti non vi fossero conflitti di interesse.</p>"], [null, "<p class=\"norm\">3.  I contributi non sono utilizzati per concedere, direttamente o indirettamente, vantaggi personali, in denaro o in natura, ad alcun membro o dipendente di un partito politico europeo. I contributi non sono utilizzati per finanziare, direttamente o indirettamente, attività di terzi, in particolare partiti politici nazionali o fondazioni politiche a livello europeo o nazionale, sotto forma di sovvenzioni, donazioni, prestiti o altri accordi simili. I contributi non sono utilizzati per gli scopi esclusi dall'articolo 22 del regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<p class=\"norm\">4.  I contributi sono subordinati al rispetto dei principi di trasparenza e di parità di trattamento, conformemente ai criteri di cui al regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<p class=\"norm\">5.  I contributi sono concessi dal Parlamento europeo su base annuale e sono pubblicati a norma dell'articolo 35, paragrafo 2, del presente regolamento e dell'articolo 32, paragrafo 1, regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<p class=\"norm\">6.  I partiti politici europei che ricevono un contributo non ricevono, direttamente o indirettamente, altri fondi provenienti dal bilancio. In particolare, sono vietate le donazioni a titolo dei bilanci di gruppi politici rappresentati al Parlamento europeo. Una voce di spesa non può, in nessuna circostanza, essere finanziata due volte dal bilancio.</p>"]]}, "204c": {"label": "Articolo 204 quater", "heading": "Aspetti di bilancio", "anchor": "art_204c", "frags": [[null, "<p class=\"norm\">I contributi sono versati dalla sezione del bilancio relativa al Parlamento europeo. Gli stanziamenti destinati a organismi o esperti indipendenti esterni di revisione contabile di cui all'articolo 23 del regolamento (UE, Euratom) n. 1141/2014 sono imputati direttamente al bilancio del Parlamento europeo.</p>"]]}, "204d": {"label": "Articolo 204 quinquies", "heading": "Bando per la presentazione delle domande di contributi", "anchor": "art_204d", "frags": [[null, "<p class=\"norm\">1.  I contributi sono concessi in esito a bando per la presentazione delle domande di contributi pubblicato ogni anno, almeno sul sito web del Parlamento europeo.</p>"], [null, "<p class=\"norm\">2.  A un partito politico europeo può essere concesso un solo contributo all'anno.</p>"], [null, "<p class=\"norm\">3.  Un partito politico europeo può ricevere un contributo solo se ne fa richiesta nei termini e nel rispetto delle condizioni stabilite nel bando per la presentazione delle domande di contributi.</p>"], [null, "<p class=\"norm\">4.  Il bando per la presentazione delle domande di contributi stabilisce i criteri di ammissibilità del richiedente nonché i criteri di esclusione.</p>"], [null, "<p class=\"norm\">5.  Il bando per la presentazione delle domande di contributi determina, almeno, la natura delle spese che possono essere rimborsate mediante il contributo.</p>"], [null, "<p class=\"norm\">6.  Il bando per la presentazione delle domande di contributi richiede un bilancio di previsione.</p>"]]}, "204e": {"label": "Articolo 204 sexies", "heading": "Procedura di attribuzione", "anchor": "art_204e", "frags": [[null, "<p class=\"norm\">1.  Le domande di contributi sono presentate per iscritto con debito anticipo, e, se del caso, in un formato elettronico protetto.</p>"], [null, "<p class=\"norm\">2.  I contributi non sono concessi a richiedenti che, al momento di una procedura di attribuzione del contributo, si trovano in una delle situazioni previste dall'articolo 106, paragrafo 1, dall'articolo 107 e dall'articolo 109, paragrafo 1, lettera a), e a quelli che sono registrati nella banca dati centrale sull'esclusione di cui all'articolo 108.</p>"], [null, "<p class=\"norm\">3.  I richiedenti sono tenuti ad attestare che non si trovano in una delle situazioni di cui al paragrafo 2.</p>"], [null, "<p class=\"norm\">4.  I contributi sono concessi tramite un accordo o una decisione di contributo come precisato nel bando per la presentazione delle domande di contributi.</p>"], [null, "<p class=\"norm\">5.  L'ordinatore competente può essere assistito da un comitato ai fini della valutazione e dell'adozione dell'accordo o della decisione di contributo. L'ordinatore competente precisa, nel debito rispetto dei principi di trasparenza e di parità di trattamento, le regole in materia di composizione, nomina e funzionamento di detto comitato e le regole volte a prevenire eventuali conflitti d'interesse.</p>"]]}, "204f": {"label": "Articolo 204 septies", "heading": "Procedura di valutazione", "anchor": "art_204f", "frags": [[null, "<p class=\"norm\">1.  Le domande di contributo sono selezionate in base ai criteri di assegnazione stabiliti nel regolamento (UE, Euratom) n. 1141/2014 fra le domande che soddisfano i criteri di ammissibilità e di esclusione.</p>"], [null, "<p class=\"norm\">2.  I criteri di ammissibilità stabiliscono a quali condizioni un richiedente può ricevere un contributo ai sensi delle disposizioni del regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<p class=\"norm\">3.  La decisione dell'ordinatore competente in merito alle domande precisa almeno:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>l'oggetto e l'importo globale del contributo;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>il nome dei richiedenti selezionati e gli importi accettati;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>i nomi dei richiedenti esclusi e le motivazioni di tale esclusione.</p>\n</div>"], [null, "<p class=\"norm\">4.  L'ordinatore competente informa per iscritto il richiedente del seguito riservato alle sue domande. Se la domanda di contributo è respinta o gli importi richiesti non sono concessi in parte o in tutto, l'ordinatore competente comunica i motivi del rifiuto della richiesta o della mancata attribuzione degli importi richiesti, con riferimento in particolare ai criteri di ammissibilità e di attribuzione di cui ai paragrafi 1 e 2. Se la richiesta è respinta, l'ordinatore competente informa il richiedente dei mezzi amministrativi e/o di ricorso giurisdizionale a sua disposizione previsti dall'articolo 97 del presente regolamento.</p>"]]}, "204g": {"label": "Articolo 204 octies", "heading": "Forma dei contributi", "anchor": "art_204g", "frags": [[null, "<p class=\"norm\">1.  I contributi possono assumere una delle seguenti forme:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>rimborso di una percentuale delle spese rimborsabili effettivamente sostenute;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>rimborso sulla base di costi unitari;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>somme forfettarie;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">d)<span style=\"word-spacing: 15pt\"> </span>finanziamenti a tasso fisso;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">e)<span style=\"word-spacing: 15pt\"> </span>una combinazione delle forme di cui alle lettere da a) a d).</p>\n</div>"], [null, "<p class=\"norm\">2.  Possono essere rimborsate solo le spese che soddisfano i criteri stabiliti nel bando per la presentazione delle domande di contributi e che non sono state sostenute prima della data di presentazione della domanda.</p>"]]}, "204h": {"label": "Articolo 204 nonies", "heading": "Regole applicabili ai contributi", "anchor": "art_204h", "frags": [[null, "<p class=\"norm\">1.  Il costo unitario copre tutte o alcune categorie specifiche di spese rimborsabili, chiaramente individuate in anticipo con riferimento a un determinato importo per unità.</p>"], [null, "<p class=\"norm\">2.  Le somme forfettarie coprono in modo generale determinate spese necessarie per lo svolgimento di una specifica attività da parte del partito politico europeo. Le somme forfettarie sono utilizzate solo in combinazione con altre forme di contributi.</p>"], [null, "<p class=\"norm\">3.  Il finanziamento a tasso fisso copre determinate categorie di spese rimborsabili, chiaramente individuate in anticipo, applicando una percentuale.</p>"], [null, "<p class=\"norm\">4.  Quando si utilizzano le somme forfettarie, il finanziamento a tasso fisso o i costi unitari sono definiti nel bando per la presentazione delle domande di contributi, precisando ove necessario i rispettivi importi e tassi. Il bando per la presentazione delle domande di contributi contiene inoltre una descrizione dei metodi per determinare gli importi forfettari, i finanziamenti a tasso fisso o i costi unitari, basati su strumenti obiettivi quali dati statistici, dati storici certificati o verificabili dei partiti politici europei o delle loro consuete prassi contabili. L'accordo o la decisione di contributo contiene disposizioni che consentono di verificare l'osservanza delle condizioni per l'attribuzione di somme forfettarie, finanziamenti a tasso fisso o costi unitari.</p>"]]}, "204i": {"label": "Articolo 204 decies", "heading": "Prefinanziamento", "anchor": "art_204i", "frags": [[null, "<p class=\"norm\">I contributi sono versati nella loro totalità, sotto forma di un unico prefinanziamento, a meno che l'ordinatore competente decida altrimenti in casi debitamente giustificati.</p>"]]}, "204j": {"label": "Articolo 204j", "heading": "Garanzie", "anchor": "art_204j", "frags": [[null, "<p class=\"norm\">L'ordinatore competente può, se lo ritiene opportuno e proporzionato, caso per caso e previa analisi dei rischi, chiedere che il partito politico europeo costituisca una garanzia anticipata per limitare i rischi finanziari connessi al pagamento del prefinanziamento solo quando, alla luce della valutazione dei rischi, il partito politico europeo è esposto al rischio imminente di trovarsi in una delle situazioni di cui all'articolo 106, paragrafo 1, lettere a) e d), del presente regolamento o quando una decisione dell'Autorità per i partiti politici europei e le fondazioni politiche europee, istituita a norma dell'articolo 6 del regolamento (UE, Euratom) n. 1141/2014 («Autorità»), è stata comunicata al Parlamento europeo e al Consiglio a norma dell'articolo 10, paragrafo 4, di tale regolamento.</p>"], [null, "<p class=\"norm\">Le disposizioni di cui all'articolo 134 del presente regolamento sulla garanzia di prefinanziamento per le sovvenzioni si applicano <span class=\"italics\">mutatis mutandis</span> alle garanzie che possono essere richieste nei casi di cui al primo comma del presente articolo per i pagamenti di prefinanziamento a favore dei partiti politici europei.</p>"]]}, "204k": {"label": "Articolo 204k", "heading": "Uso dei contributi", "anchor": "art_204k", "frags": [[null, "<p class=\"norm\">1.  I contributi sono spesi a norma dell'articolo 204 <span class=\"italics\">ter</span>.</p>"], [null, "<p class=\"norm\">2.  Qualsiasi parte del contributo non spesa entro l'esercizio finanziario cui si riferisce tale contributo (anno n) è utilizzata per le spese rimborsabili sostenute entro il 31 dicembre dell'anno n+1. Qualsiasi parte rimanente del contributo non spesa entro tale data è recuperata conformemente al titolo IV, capo 5, della parte prima.</p>"], [null, "<p class=\"norm\">3.  I partiti politici europei rispettano il tasso massimo di cofinanziamento stabilito all'articolo 17, paragrafo 4, del regolamento (UE, Euratom) n. 1141/2014. Gli importi che rimangono dai contributi del precedente esercizio non possono essere utilizzati per finanziare la parte che i partiti politici europei sono tenuti a fornire dalle risorse proprie. I contributi di terzi a eventi congiunti non sono considerati parte delle risorse proprie di un partito politico europeo.</p>"], [null, "<p class=\"norm\">4.  I partiti politici europei utilizzano la parte del contributo che non è stata usata entro l'esercizio finanziario cui si riferisce tale contributo prima di utilizzare i contributi concessi dopo tale esercizio.</p>"], [null, "<p class=\"norm\">5.  Qualsiasi interesse maturato sui pagamenti di prefinanziamento è considerato parte del contributo.</p>"]]}, "204l": {"label": "Articolo 204l", "heading": "Relazione sull'uso dei contributi", "anchor": "art_204l", "frags": [[null, "<p class=\"norm\">1.  A norma dell'articolo 23 del regolamento (UE, Euratom) n. 1141/2014, il partito politico europeo presenta all'ordinatore competente, per approvazione, la sua relazione annuale sull'utilizzo del contributo e i relativi rendiconti finanziari annuali.</p>"], [null, "<p class=\"norm\">2.  L'ordinatore competente redige la sua relazione annuale di attività di cui all'articolo 66, paragrafo 9, del presente regolamento sulla base della relazione annuale e dei rendiconti finanziari annuali di cui al paragrafo 1 del presente articolo. Per redigere la relazione, possono essere utilizzati altri documenti giustificativi.</p>"], [null, "<p class=\"title-article-norm\">Articolo 204 <span class=\"norm\">quaterdecies</span>\n</p>"], [null, "<p class=\"norm\">1.  L'importo del contributo diventa definitivo soltanto dopo l'approvazione della relazione annuale e dei rendiconti finanziari annuali di cui all'articolo 204 <span class=\"italics\">terdecies</span>, paragrafo 1, da parte dell'ordinatore competente. L'approvazione della relazione annuale e dei rendiconti finanziari annuali non pregiudica controlli successivi da parte dell'Autorità.</p>"], [null, "<p class=\"norm\">2.  Qualsiasi importo non speso del prefinanziamento diventa definitivo soltanto dopo che è stato utilizzato dal partito politico europeo per pagare spese rimborsabili che soddisfano i criteri definiti nel bando per la presentazione di domande di contributi.</p>"], [null, "<p class=\"norm\">3.  Quando il partito politico europeo non si conforma agli obblighi che gli incombono in relazione all'uso dei contributi, i contributi sono sospesi, ridotti o revocati dopo aver dato al partito politico europeo la possibilità di presentare le proprie osservazioni.</p>"], [null, "<p class=\"norm\">4.  Prima di effettuare il pagamento del saldo, l'ordinatore competente verifica che il partito politico europeo continui a essere iscritto nel registro di cui all'articolo 7 del regolamento (UE, Euratom) n. 1141/2014 e che non sia stato oggetto di una delle sanzioni previste all'articolo 27 di tale regolamento tra la data della domanda e la fine dell'esercizio finanziario cui si riferisce il contributo.</p>"], [null, "<p class=\"norm\">5.  Quando il partito politico europeo non è più iscritto nel registro di cui all'articolo 7 del regolamento (UE, Euratom) n. 1141/2014 o è stato oggetto di una delle sanzioni previste all'articolo 27 di tale regolamento, l'ordinatore competente può sospendere, ridurre o revocare il contributo e recuperare gli importi indebitamente versati conformemente all'accordo o alla decisione di contributo, in proporzione alla gravità degli errori, delle irregolarità, delle frodi o di un'altra violazione degli obblighi relativi all'uso del contributo, dopo aver dato al partito politico europeo la possibilità di presentare le proprie osservazioni.</p>"], [null, "<p class=\"title-article-norm\">Articolo 204 <span class=\"norm\">quindecies</span>\n</p>"], [null, "<p class=\"norm\">1.  Ogni accordo o decisione di finanziamento prevede espressamente che il Parlamento europeo, l'Ufficio europeo per la lotta antifrode e la Corte dei conti esercitino i loro poteri di controllo, in base a documenti e sul posto, su tutti i partiti politici europei, i contraenti e subcontraenti che hanno ricevuto fondi dell'Unione.</p>"], [null, "<p class=\"norm\">2.  L'ordinatore competente può irrogare ai richiedenti sanzioni amministrative e finanziarie effettive, proporzionate e dissuasive, secondo quanto previsto all'articolo 109 del presente regolamento e all'articolo 27 del regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<p class=\"norm\">3.  Le sanzioni di cui al paragrafo 2 possono altresì essere irrogate ai partiti politici europei che, al momento della presentazione della domanda di contributo o dopo aver ricevuto il contributo, abbiano reso false dichiarazioni fornendo le informazioni richieste dall'ordinatore competente oppure non abbiano fornito tali informazioni.</p>"], [null, "<p class=\"title-article-norm\">Articolo 204 <span class=\"norm\">sexdecies</span>\n</p>"], [null, "<p class=\"norm\">1.  I partiti politici europei tengono tutti i registri e i documenti giustificativi relativi al contributo per cinque anni dopo la presentazione della relazione annuale finale e dei rendiconti finanziari annuali di cui all'articolo 204 <span class=\"italics\">terdecies</span>, paragrafo 1.</p>"], [null, "<p class=\"norm\">2.  La documentazione inerente agli audit, ai ricorsi, ai contenziosi o alla regolarizzazione delle richieste derivanti dall'utilizzo del contributo è conservata fintanto che tali audit, ricorsi, contenzioni od operazioni di regolarizzazione siano stati conclusi.</p>"], [null, "<p class=\"title-article-norm\">Articolo 204 <span class=\"norm\">septdecies</span>\n</p>"], [null, "<p class=\"norm\">Gli organismi o esperti indipendenti esterni di revisione contabile di cui all'articolo 23 del regolamento (UE, Euratom) n. 1141/2014 sono selezionati mediante una procedura d'appalto pubblica. La durata del contratto non può superare i cinque anni. Dopo due rinnovi consecutivi si ritiene che sussista un conflitto di interessi che potrebbe influire negativamente sullo svolgimento della revisione contabile.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "205": {"label": "Articolo 205", "heading": "Disposizioni transitorie", "anchor": "art_205", "frags": [[null, "<p class=\"norm\">1.  Per quanto riguarda i Fondi di cui all'articolo 175, paragrafo 1, per i quali gli atti di base sono abrogati prima del 1<span class=\"superscript\">o</span> gennaio 2013, gli stanziamenti disimpegnati a norma dell'articolo 178 possono essere ricostituiti in caso d'errore manifesto imputabile alla sola Commissione o in caso di forza maggiore con serie ripercussioni sulla realizzazione degli interventi finanziati da tali Fondi.</p>"], [null, "<p class=\"norm\">2.  Per gli storni di stanziamenti riguardanti le spese operative di cui ai regolamenti (CE) n. 1260/1999, (CE) n. 1290/2005, (CE) n. 1080/2006, (CE) n. 1081/2006, (CE) n. 1083/2006, (CE) n. 1084/2006 e (CE) n. 1198/2006 per cui devono ancora essere effettuati pagamenti dell'Unione ai fini della liquidazione finanziaria degli impegni dell'Unione ancora da liquidare fino al termine dell'assistenza, la Commissione può procedere a storni da titolo a titolo, a condizione che gli stanziamenti interessati siano destinati allo stesso obiettivo, oppure riguardino iniziative dell'Unione o azioni innovative e assistenza tecnica e formino oggetto di storno a favore di misure della stessa natura.</p>"], [null, "<p class=\"norm\">3.  Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a norme dettagliate concernenti disposizioni transitorie.</p>"]]}, "206": {"label": "Articolo 206", "heading": "Richieste di informazioni del Parlamento europeo e del Consiglio", "anchor": "art_206", "frags": [[null, "<p class=\"norm\">Per le questioni di bilancio di loro rispettiva competenza il Parlamento europeo e il Consiglio possono ottenere la comunicazione di qualsiasi informazione o giustificazione pertinente.</p>"]]}, "207": {"label": "Articolo 207", "heading": "Soglie e importi", "anchor": "art_207", "frags": [[null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 210 riguardo a tutte le soglie e gli importi stabiliti nel presente regolamento, fatto salvo l'articolo 118.</p>"]]}, "208": {"label": "Articolo 208", "heading": "Regolamento finanziario quadro degli organismi istituiti in virtù del TFUE e del trattato Euratom", "anchor": "art_208", "frags": [[null, "<p class=\"norm\">1.  Alla Commissione è conferito il potere di adottare un regolamento finanziario quadro mediante un atto delegato conformemente all'articolo 210 degli organismi creati in virtù del TFUE e del trattato Euratom dotati di personalità giuridica e che ricevono effettivamente contributi a carico del bilancio.</p>"], [null, "<p class=\"norm\">Il regolamento finanziario quadro si basa sui principi e sulle norme contenuti nel presente regolamento.</p>"], [null, "<p class=\"norm\">I regolamenti finanziari di tali organismi possono discostarsi dal regolamento finanziario quadro soltanto se lo impongano esigenze specifiche e previo accordo della Commissione.</p>"], [null, "<p class=\"norm\">2.  Il discarico per l'esecuzione dei bilanci degli organismi di cui al paragrafo 1 è dato dal Parlamento europeo su raccomandazione del Consiglio. Gli organismi di cui al paragrafo 1 cooperano pienamente con le istituzioni coinvolte nella procedura di discarico e forniscono, se del caso, le informazioni supplementari necessarie, anche partecipando a riunioni degli organi competenti.</p>"], [null, "<p class=\"norm\">3.  Il revisore interno della Commissione esercita nei confronti degli organismi di cui al paragrafo 1 le stesse competenze esercitate nei confronti della Commissione.</p>"], [null, "<p class=\"norm\">4.  Un revisore esterno indipendente verifica che i conti annuali di ciascuno degli organismi di cui al paragrafo 1 presentino correttamente le entrate, le spese e la situazione finanziaria dell'organismo in questione prima del consolidamento nei conti definitivi della Commissione. Salvo disposizione contraria dell'atto di base di cui al paragrafo 1, la Corte dei conti elabora una relazione annuale specifica relativa a ciascun organismo conformemente alle prescrizioni dell'articolo 287, paragrafo 1, TFUE. Nell'elaborare tale relazione la Corte esamina il lavoro di revisione contabile svolto dal revisore esterno indipendente e le azioni adottate in risposta alle conclusioni del revisore.</p>"]]}, "209": {"label": "Articolo 209", "heading": "Regolamento finanziario tipo per organismi di partenariato pubblico-privato", "anchor": "art_209", "frags": [[null, "<p class=\"norm\">\n<span>\n<span class=\"boldface\">►M3</span>\n</span> 1.<span class=\"boldface\"> ◄ </span>  Gli organismi dotati di personalità giuridica istituiti da un atto di base e incaricati di attuare un partenariato pubblico-privato adottano il proprio regolamento finanziario.</p>"], [null, "<p class=\"norm\">Tali regolamenti devono comprendere un insieme di principi necessari ad assicurare la sana gestione finanziaria dei fondi dell'Unione</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare un regolamento finanziario tipo mediante un atto delegato conformemente all'articolo 210 che prevede i principi necessari a garantire una sana gestione finanziaria dei fondi dell'Unione e che è basato sull'articolo 60.</p>"], [null, "<p class=\"norm\">I regolamenti finanziari di tali organismi si discostano dal regolamento finanziario tipo soltanto se lo impongano esigenze specifiche e previo accordo della Commissione.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">2.  Si applica l'articolo 208, paragrafi da 2 a 4.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "210": {"label": "Articolo 210", "heading": "Esercizio della delega", "anchor": "art_210", "frags": [[null, "<p class=\"norm\">1.  Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</p>"], [null, "<p class=\"norm\">2.  La delega di poteri di cui agli articoli 8, 11, 13, 19, 21, 22, 23, 25, 26, 29, 30, 31, 34, 35, 38, 41, 44, 49, 53, 54, 57, 58, 59, 60, 61, 62, 63, 65, 66, 68, 69, 70, 72, 73, 74, 75, 76, 77, 78, 79, 80, 81, 83, 84, 85, 86, 87, 88, 89, 90, 92, 93, 98, 99, 100, 101, 103, 104, 105, 106, 107, 108, 109, 110, 111, 112, 113, 114, 115, 116, 117, 118, 119, 121, 122, 123, 124, 125, 126, 128, 129, 130, 131, 132, 133, 134, 135, 137, 138, 139, 140, 142, 144,181, 183, 184, 186, 187, 188, 189, 190, 191, 192, 193, 195, 196, 199, 201, 203, 204, 205, 207, 208 e 209 è conferita alla Commissione fino alla fine del primo quadro finanziario pluriennale post-2013 di cui all'articolo 312 TFUE. La Commissione elabora una relazione sulla delega di poteri non oltre due anni prima del primo quadro finanziario pluriennale post-2013. La delega di potere è tacitamente prorogata per periodi corrispondenti al successivo quadro finanziario pluriennale, salvo che il Parlamento europeo o il Consiglio non vi si oppongano al più tardi tre mesi prima della scadenza di ciascun periodo di validità del corrispondente quadro finanziario pluriennale.</p>"], [null, "<p class=\"norm\">3.  La delega di poteri di cui agli articoli 8, 11, 13, 19, 21, 22, 23, 25, 26, 29, 30, 31, 34, 35, 38, 41, 44, 49, 53, 54, 57, 58, 59, 60, 61, 62, 63, 64, 65, 66, 67, 68, 69, 70, 72, 73, 74, 75, 76, 77, 78, 79, 80, 81, 83, 84, 85, 86, 87, 88, 89, 90, 92, 93, 98, 99, 100, 101, 103, 104, 105, 106, 107, 108, 109, 110, 111, 112, 113, 114, 115, 116, 117, 118, 119, 121, 122, 123, 124, 125, 126, 128, 129, 130, 131, 132, 133, 134, 135, 137, 138, 139, 140, 142, 144, 181,183, 184, 186, 187, 188, 189, 190, 191, 192, 193, 195, 196, 199, 201, 203, 204, 205, 207, 208 e 209 può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega dei poteri specificati nella decisione medesima. Gli effetti della decisione decorrono il giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> o a una data successiva ivi precisata. La decisione di revoca lascia impregiudicata la validità degli atti delegati già in vigore.</p>"], [null, "<p class=\"norm\">4.  Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</p>"], [null, "<p class=\"norm\">5.  Un atto delegato adottato a norma degli articoli 8, 11, 13, 19, 21, 22, 23, 25, 26, 29, 30, 31, 34, 35, 38, 41, 44, 49, 53, 54, 57, 58, 59, 60, 61, 62, 63, 64, 65, 66, 67, 68, 69, 70, 72, 73, 74, 75, 76, 77, 78, 79, 80, 81, 83, 84, 85, 86, 87, 88, 89, 90, 92, 93, 98, 99, 100, 101, 103, 104, 105, 106, 107, 108, 109, 110, 111, 112, 113, 114, 115, 116, 117, 118, 119, 121, 122, 123, 124, 125, 126, 128, 129, 130, 131, 132, 133, 134, 135, 137, 138, 139, 140, 142, 144, 181,183, 184, 186, 187, 188, 189, 190, 191, 192, 193, 195, 196, 199, 201, 203, 204, 205, 207, 208 e 209 entra in vigore solo se non sono sollevate obiezioni da parte del Parlamento europeo o del Consiglio entro due mesi dalla data di notifica dell'atto stesso o se, prima della scadenza di tale periodo, il Parlamento europeo e il Consiglio hanno entrambi informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</p>"]]}, "211": {"label": "Articolo 211", "heading": "Riesame", "anchor": "art_211", "frags": [[null, "<p class=\"norm\">Il presente regolamento è soggetto a riesame ogniqualvolta ciò risulti necessario e in ogni caso entro due anni dalla fine del primo quadro finanziario pluriennale post-2013.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">Tale riesame riguarda, tra l'altro, l'attuazione delle disposizioni di cui al titolo VIII della parte prima e i termini di cui all'articolo 163, paragrafo 1.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "212": {"label": "Articolo 212", "heading": "Abrogazione", "anchor": "art_212", "frags": [[null, "<p class=\"norm\">Il regolamento (CE, Euratom) n. 1605/2002 è abrogato a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2013 ad eccezione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>degli articoli da 53 a 57 che continuano ad applicarsi a tutti gli impegni assunti fino al 31 dicembre 2013;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>dell'articolo 166, paragrafo 3, lettera a), che continua ad applicarsi a tutti gli impegni assunti fino al 31 dicembre 2012; e</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>dell'articolo 166, paragrafo 3, lettera b), che continua ad applicarsi a tutti gli impegni assunti tra il 1<span class=\"superscript\">o</span> gennaio 2013 e il 31 dicembre 2013.</p>\n</div>"], [null, "<p class=\"norm\">Il titolo VI della parte prima del regolamento (CE, Euratom) n. 1605/2002 può continuare ad applicarsi alle convenzioni di sovvenzione e alle decisioni di sovvenzione notificate fino al 31 dicembre 2013 nel quadro degli impegni globali relativi al bilancio 2012 o agli esercizi precedenti, se l'ordinatore responsabile decide in tal senso tenendo in debita considerazione i principi della parità di trattamento e della trasparenza.</p>"], [null, "<p class=\"norm\">I riferimenti al regolamento abrogato s'intendono fatti al presente regolamento e vanno letti secondo la tavola di concordanza di cui all'allegato.</p>"]]}, "213": {"label": "Articolo 213", "heading": "Riesame concernente il SEAE", "anchor": "art_213", "frags": [[null, "<p class=\"norm\">L'articolo 68, paragrafo 1, terzo comma, e l'articolo 98, paragrafo 2, secondo comma, saranno rivisti nel 2013 tenendo debitamente conto della specificità del SEAE e, in particolare, di quella delle delegazioni dell'Unione e se del caso di una capacità di gestione finanziaria adeguata del SEAE.</p>"]]}, "214": {"label": "Articolo 214", "heading": "Entrata in vigore", "anchor": "art_214", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno successivo a quello della pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"norm\">Esso si applica a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2013, ad eccezione:</p>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">a)<span style=\"word-spacing: 15pt\"> </span>degli articoli da 58 a 63 che si applicano solo agli impegni assunti a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2014;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">b)<span style=\"word-spacing: 15pt\"> </span>dell'articolo 50, paragrafo 1, secondo comma, lettera c), degli articoli 82, 139 e 140 che si applicano a partire dal 1<span class=\"superscript\">o</span> gennaio 2014;</p>\n</div>"], [null, "<div style=\"margin-left: 24pt; text-indent: -24pt\">\n<p class=\"norm\">c)<span style=\"word-spacing: 15pt\"> </span>degli articoli 177, 179 e 210 che si applicano a partire del 27 ottobre 2012.</p>\n</div>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile in ciascuno degli Stati membri.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p>\n<br/>\n</p>"]]}}, "recitals": {}};